// ─── User Preferences (synced to server) ───

// Keys that should be persisted server-side per user
const _syncedPrefKeys = [
    'wolfstack-theme', 'wolfstack-icon-theme', 'wolfstack-mono-icons', 'wolfstack-mono-preset',
    'wolfstack_sidebar_collapsed', 'wolfstack_map_collapsed',
    'wolfstack_dc_layout', 'wolfstack_dc_compact', 'wolfstack_dc_bg_image',
    'wolfstack_dc_bg_brightness', 'wolfstack_dc_bg_blur',
    'wolfstack_bookmarks', 'wolfstack_view_docker', 'wolfstack_view_lxc', 'wolfstack_view_vm',
    'wolfstack_tasklog_closed', 'wolfstack_hidden_features',
];
let _prefsLoaded = false;

// Load user preferences from server and apply to localStorage.
// If the server has no saved prefs yet, upload current localStorage values
// so existing users don't lose their bookmarks or theme on first sync.
async function loadUserPreferences() {
    try {
        var resp = await fetch('/api/user/preferences');
        if (!resp.ok) return;
        var prefs = await resp.json();
        if (!prefs || typeof prefs !== 'object') return;

        var serverHasData = Object.keys(prefs).length > 0;

        if (serverHasData) {
            // Server has prefs — apply to localStorage
            for (var key of _syncedPrefKeys) {
                if (prefs[key] !== undefined && prefs[key] !== null) {
                    localStorage.setItem(key, typeof prefs[key] === 'string' ? prefs[key] : JSON.stringify(prefs[key]));
                }
            }
        } else {
            // Server has nothing — upload current localStorage so existing users keep their settings
            var upload = {};
            var hasAnything = false;
            for (var key of _syncedPrefKeys) {
                var val = localStorage.getItem(key);
                if (val !== null) {
                    upload[key] = val;
                    hasAnything = true;
                }
            }
            if (hasAnything) {
                fetch('/api/user/preferences', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(upload),
                }).catch(function() {});
            }
        }
        _prefsLoaded = true;
    } catch (e) { /* silent — localStorage fallback works */ }
}

// Save a single preference to both localStorage and server
function savePref(key, value) {
    localStorage.setItem(key, value);
    if (_syncedPrefKeys.includes(key)) {
        var patch = {};
        patch[key] = value;
        fetch('/api/user/preferences', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(patch),
        }).catch(function() {});
    }
}

// Remove a preference from both localStorage and server
function removePref(key) {
    localStorage.removeItem(key);
    if (_syncedPrefKeys.includes(key)) {
        var patch = {};
        patch[key] = null;
        fetch('/api/user/preferences', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(patch),
        }).catch(function() {});
    }
}

// ─── State ───
let currentPage = 'datacenter';
let currentComponent = null;
let currentNodeId = null;  // null = datacenter, node ID = specific server
let allNodes = [];         // cached node list
// True once buildServerTree() has successfully rendered the sidebar. If the very
// first render fails or is interrupted (a transient DOM/data race on load),
// allNodes is already set, so later polls take the in-place-update branch and
// NEVER rebuild — the sidebar stays stuck on "Loading…" forever. This flag forces
// a rebuild on every poll until one actually succeeds. (Intermittent stuck-load
// reported 2026-06-25.)
let _serverTreeRendered = false;
let serverTlsEnabled = false; // whether the server has TLS (HTTPS) enabled
let cpuHistory = [];
let memHistory = [];
let netHistory = []; // { timestamp, rx_bytes, tx_bytes } — cumulative
let diskHistory = {}; // mount_point -> array of {timestamp, usage_percent}
const MAX_HISTORY = 300; // 10 minutes at 2s intervals
let displayRange = 150; // default 5 minutes (150 samples at 2s)
let currentConfiguratorTarget = null; // null = host, {runtime:'docker'|'lxc', target:'name'} for containers
let currentConfiguratorNode = null;   // null = the node serving this page; else a wolfstack node object managed via the node proxy

// ─── Sidebar Toggle ───
function isMobileView() {
    return window.innerWidth <= 768;
}

function toggleSidebar() {
    if (isMobileView()) {
        // Mobile: toggle overlay sidebar (ignore collapsed state)
        const isOpen = document.body.classList.toggle('sidebar-open');
        const backdrop = document.querySelector('.sidebar-backdrop');
        if (backdrop) backdrop.style.display = isOpen ? 'block' : 'none';
    } else {
        // Desktop: toggle collapsed sidebar
        document.body.classList.toggle('sidebar-collapsed');
        const collapsed = document.body.classList.contains('sidebar-collapsed');
        savePref('wolfstack_sidebar_collapsed', collapsed ? '1' : '0');
    }
    // Invalidate map size + 3D topology after sidebar transition
    setTimeout(() => {
        if (typeof worldMap !== 'undefined' && worldMap) worldMap.invalidateSize();
        if (_topo && _topo.onResize) _topo.onResize();
    }, 350);
}

function closeSidebarMobile() {
    document.body.classList.remove('sidebar-open');
    const backdrop = document.querySelector('.sidebar-backdrop');
    if (backdrop) backdrop.style.display = 'none';
}

// Restore sidebar state on load (desktop only)
if (localStorage.getItem('wolfstack_sidebar_collapsed') === '1') {
    document.body.classList.add('sidebar-collapsed');
}

// Clean up mobile sidebar state on resize to desktop (debounced)
let _resizeTimer = null;
window.addEventListener('resize', () => {
    if (_resizeTimer) clearTimeout(_resizeTimer);
    _resizeTimer = setTimeout(() => {
        if (!isMobileView()) closeSidebarMobile();
    }, 200);
});

// ─── Map Collapse Toggle ───
let mapCollapsed = localStorage.getItem('wolfstack_map_collapsed') === '1'; // default expanded

function toggleMapCollapse() {
    mapCollapsed = !mapCollapsed;
    savePref('wolfstack_map_collapsed', mapCollapsed ? '1' : '0');
    applyMapCollapse();
}

function applyMapCollapse() {
    const wrap = document.getElementById('world-map-wrap');
    const icon = document.getElementById('map-toggle-icon');
    if (!wrap) return;
    if (mapCollapsed) {
        wrap.style.height = '0';
        if (icon) icon.style.transform = 'rotate(-90deg)';
    } else {
        wrap.style.height = '220px';
        if (icon) icon.style.transform = 'rotate(0deg)';
        setTimeout(() => { if (worldMap) worldMap.invalidateSize(); }, 350);
    }
}

