// ─── Docker ───

async function loadDockerContainers() {
    // Cancel any existing poll timer immediately
    if (containerPollTimer) { clearInterval(containerPollTimer); containerPollTimer = null; }

    // Capture generation and node to detect stale responses
    const gen = ++_dockerLoadGeneration;
    const loadNodeId = currentNodeId;

    // Fetch runtime status first
    fetchContainerStatus();
    // Pull the set of containers that already have VNC installed (drives the icon colour)
    loadContainerVncKeys();

    try {
        // Fetch containers and stats in parallel (images fetched separately on tab click)
        const [containersResp, statsResp] = await Promise.all([
            fetch(apiUrl('/api/containers/docker')),
            fetch(apiUrl('/api/containers/docker/stats')),
        ]);

        // Discard response if user switched to a different server/page
        if (gen !== _dockerLoadGeneration || currentNodeId !== loadNodeId) return;

        // Only render a genuinely OK array response — a transient proxy failure
        // (Pangolin/Traefik) must not blank a populated list (keep what's shown
        // and let the 15s poll retry). The timer is still armed below.
        if (containersResp.ok) {
            const containers = await containersResp.json();
            if (Array.isArray(containers)) {
                const stats = statsResp.ok ? await statsResp.json() : [];
                const statsArr = Array.isArray(stats) ? stats : [];
                dockerStats = {};
                statsArr.forEach(s => { dockerStats[s.name] = s; });
                renderDockerContainers(containers);
                renderDockerCards(containers);
                applyContainerView('docker');
                renderDockerStats(statsArr);
            }
        }
        // Load images only on initial page load (not on every poll)
        try {
            const imagesResp = await fetch(apiUrl('/api/containers/docker/images'));
            if (gen === _dockerLoadGeneration && currentNodeId === loadNodeId) {
                renderDockerImages(await imagesResp.json());
            }
        } catch(e) { /* images are non-critical */ }
        applyUpdateBadges();
        fetchContainerUpdateSummary();
        // Docker image-watcher status (separate from inside-container
        // package update summary above). Fires non-blocking; if the
        // watcher is disabled, the endpoint returns an empty list and
        // no badges render.
        fetchImageUpdateStatus();
    } catch (e) {
        console.error('Failed to load Docker containers:', e);
    }

    // Only set poll timer if we're still on this view/node
    if (gen === _dockerLoadGeneration && currentPage === 'containers') {
        containerPollTimer = setInterval(refreshDockerStats, isMobileView() ? 30000 : 15000);
    }
}

async function refreshDockerStats() {
    if (currentPage !== 'containers') {
        clearInterval(containerPollTimer);
        containerPollTimer = null;
        return;
    }
    try {
        const [containersResp, statsResp] = await Promise.all([
            fetch(apiUrl('/api/containers/docker')),
            fetch(apiUrl('/api/containers/docker/stats')),
        ]);
        // A flaky reverse proxy (Pangolin/Traefik) returns transient non-OK or
        // non-array bodies; rendering one would blank the whole list until the
        // next good poll — the flicker wabil saw behind Pangolin but never nginx.
        // Skip this tick and keep the current list instead.
        if (!containersResp.ok) return;
        const containers = await containersResp.json();
        if (!Array.isArray(containers)) return;
        const stats = statsResp.ok ? await statsResp.json() : [];
        const statsArr = Array.isArray(stats) ? stats : [];
        dockerStats = {};
        statsArr.forEach(s => { dockerStats[s.name] = s; });
        renderDockerContainers(containers);
        renderDockerCards(containers);
        applyContainerView('docker');
        renderDockerStats(statsArr);
    } catch (e) { /* silent — keep the existing list on any transient error */ }
}

// ─── Card/Table View Toggle System ───

function getContainerView(type) {
    return localStorage.getItem(`wolfstack_view_${type}`) || 'table';
}

function setContainerView(type, view) {
    savePref(`wolfstack_view_${type}`, view);
    // A table↔card switch is a pure presentation flip — both layouts are
    // already rendered on every load/poll (renderX + renderXCards), so
    // applyContainerView just toggles which one is visible.
    applyContainerView(type);
    // Docker and LXC must NOT re-fetch on a toggle: their loaders fire the
    // heavy /api/containers/updates/summary (a docker exec per running
    // container), and re-firing it on every toggle churned the connection
    // pool / actix workers enough to trip the connection-lost banner (Gary
    // KO4BSR 2026-06-10). Their 15s poll timers keep the data live.
    // VMs have no poll timer and loadVms() is cheap (VM list only, no update
    // summary), so a toggle is the VM view's only refresh trigger — keep it.
    if (type === 'vms') loadVms();
}

function applyContainerView(type) {
    const view = getContainerView(type);
    const table = document.getElementById(`${type}-table-view`);
    const grid = document.getElementById(`${type}-card-grid`);
    if (table) table.style.display = view === 'table' ? '' : 'none';
    if (grid) grid.style.display = view === 'card' ? 'grid' : 'none';
    // Update toggle button styling
    const toggle = document.getElementById(`${type}-view-toggle`);
    if (toggle) {
        toggle.querySelectorAll('.view-toggle-btn').forEach(btn => {
            const isActive = btn.dataset.view === view;
            btn.style.background = isActive ? 'var(--accent)' : 'none';
            btn.style.color = isActive ? '#fff' : 'var(--text-muted)';
        });
    }
}

// SVG pie chart helper — tiny donut chart
function svgPie(pct, color, size = 48, label = '') {
    const r = (size - 6) / 2;
    const circ = 2 * Math.PI * r;
    const offset = circ - (pct / 100) * circ;
    return `<div style="position:relative;width:${size}px;height:${size}px;flex-shrink:0;">
        <svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">
            <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="var(--bg-tertiary)" stroke-width="5"/>
            <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${color}" stroke-width="5"
                stroke-dasharray="${circ}" stroke-dashoffset="${offset}"
                transform="rotate(-90 ${size/2} ${size/2})" stroke-linecap="round"/>
        </svg>
        <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;color:var(--text-secondary);">${Math.round(pct)}%</div>
    </div>
    ${label ? `<div style="font-size:10px;color:var(--text-secondary);text-align:center;margin-top:2px;">${label}</div>` : ''}`;
}

function renderDockerCards(containers) {
    const grid = document.getElementById('docker-card-grid');
    if (!grid) return;
    // Tab-level alert: count containers with at least one
    // requested-but-unpublished port. The whole point of this banner
    // is that Klas's reboot scenario produced an empty Ports column
    // and no warning anywhere — even one such container is worth a
    // loud strip at the top of the tab so it can never be missed.
    const banner = document.getElementById('docker-port-warning');
    // Only running containers count — a stopped container's empty
    // NetworkSettings.Ports is the expected state, not a bug.
    const offenders = containers.filter(c =>
        c.state === 'running' &&
        Array.isArray(c.port_mappings) && c.port_mappings.some(m => !m.published));
    if (banner) {
        if (offenders.length > 0) {
            banner.innerHTML = `<div style="padding:10px 14px;margin:0 0 12px;background:rgba(239,68,68,0.12);border:1px solid #ef4444;border-radius:8px;color:#fca5a5;font-size:13px;">
                <strong>${offenders.length} container${offenders.length === 1 ? '' : 's'}</strong> requested host ports the Docker daemon never bound — those services are offline.
                Likely a host-port conflict. Affected: ${offenders.slice(0, 5).map(c => `<code>${escapeHtml(c.name)}</code>`).join(', ')}${offenders.length > 5 ? `, +${offenders.length - 5} more` : ''}.
                See the Predictive Inbox for the conflict detail.
            </div>`;
            banner.style.display = '';
        } else {
            banner.innerHTML = '';
            banner.style.display = 'none';
        }
    }
    if (containers.length === 0) { grid.innerHTML = ''; return; }
    grid.innerHTML = containers.map(c => dockerCardHtml(c)).join('');
}

function dockerCardHtml(c) {
    const bs = 'margin:1px;font-size:16px;line-height:1;padding:3px 5px;background:none;border:1px solid var(--border);border-radius:4px;cursor:pointer;';
    const bd = bs + 'opacity:0.3;cursor:not-allowed;pointer-events:none;';
    const s = dockerStats[c.name] || {};
    const isRunning = c.state === 'running';
    const isPaused = c.state === 'paused';
    const borderColor = isRunning ? '#10b981' : isPaused ? '#f59e0b' : '#6b7280';
    const cpuPct = s.cpu_percent !== undefined ? Math.min(s.cpu_percent, 100) : -1;
    const cpuColor = cpuPct > 80 ? '#ef4444' : cpuPct > 50 ? '#f59e0b' : '#10b981';
    const memPct = (s.memory_usage && s.memory_limit) ? Math.min(Math.round((s.memory_usage / s.memory_limit) * 100), 100) : -1;
    const memColor = memPct > 90 ? '#ef4444' : memPct > 70 ? '#f59e0b' : '#10b981';
    const hasStorage = c.disk_usage !== undefined && c.disk_total;
    const diskPct = hasStorage ? Math.round((c.disk_usage / c.disk_total) * 100) : 0;
    const diskColor = diskPct > 90 ? '#ef4444' : diskPct > 70 ? '#f59e0b' : '#10b981';
    // Port column: prefer the structured `port_mappings` (which carry
    // the requested-vs-published flag) over the legacy free-form
    // `ports`. Unpublished mappings render with a strikethrough +
    // warning glyph so a silent publish failure (compose collision
    // after reboot — the bug Klas reported) is impossible to miss.
    let ports;
    // A stopped container's NetworkSettings.Ports is empty by design —
    // counting that as "unpublished" would tag every stopped container
    // red. Mirror the backend analyzer: only running containers can
    // have a true unpublished-port problem.
    let unpublishedCount = 0;
    if (c.port_mappings && c.port_mappings.length > 0) {
        if (isRunning) {
            unpublishedCount = c.port_mappings.filter(m => !m.published).length;
        }
        const formatPm = pm => {
            const ip = (!pm.host_ip || pm.host_ip === '0.0.0.0') ? '' : pm.host_ip + ':';
            const text = `${ip}${pm.host_port}→${pm.container_port}/${pm.proto}`;
            // For stopped containers we render every mapping in muted
            // grey — the binding state is "expected absent", not
            // "broken", so don't use the alarming red strikethrough.
            if (!isRunning) {
                return `<span style="color:var(--text-muted);" title="Container is not running — mapping is requested but not yet bound">${escapeHtml(text)}</span>`;
            }
            if (pm.published) {
                return `<span style="color:#34d399;" title="Published — daemon confirms this binding is live">${escapeHtml(text)}</span>`;
            }
            return `<span style="color:#ef4444;text-decoration:line-through;" title="UNPUBLISHED — Docker accepted the container start but never bound this host port. Service is offline. Check the Predictive Inbox for the conflict.">${escapeHtml(text)}</span>`;
        };
        const shown = c.port_mappings.slice(0, 3).map(formatPm).join(', ');
        const overflow = c.port_mappings.length > 3 ? ` +${c.port_mappings.length - 3}` : '';
        ports = shown + overflow;
    } else {
        ports = c.ports && c.ports.length > 0 ? c.ports.slice(0, 3).map(p => escapeHtml(p)).join(', ') : '-';
    }
    const portWarning = unpublishedCount > 0
        ? `<div style="grid-column:1/-1;margin-top:4px;padding:4px 8px;background:rgba(239,68,68,0.12);border-left:3px solid #ef4444;font-size:10px;color:#fca5a5;">${unpublishedCount} requested port${unpublishedCount === 1 ? '' : 's'} not bound by the daemon — service is unreachable. Check Predictive Inbox.</div>`
        : '';
    const svcItems = (c.services && c.services.length > 0) ? c.services.map(sv => {
        const sColor = sv.status === 'running' ? '#10b981' : '#ef4444';
        return `<span style="font-size:9px;padding:1px 4px;border-radius:2px;background:${sColor}22;color:${sColor};">${sv.name}</span>`;
    }).join(' ') : '';

    const pies = [];
    if (cpuPct >= 0) pies.push(`<div style="text-align:center;flex:1;">${svgPie(cpuPct, cpuColor, 64)}<div style="font-size:9px;color:var(--text-muted);">CPU</div></div>`);
    if (memPct >= 0) pies.push(`<div style="text-align:center;flex:1;">${svgPie(memPct, memColor, 64)}<div style="font-size:9px;color:var(--text-muted);">RAM</div></div>`);
    if (hasStorage) pies.push(`<div style="text-align:center;flex:1;">${svgPie(diskPct, diskColor, 64)}<div style="font-size:9px;color:var(--text-muted);">Disk</div></div>`);

    return `<div style="background:var(--bg-card);border:1px solid var(--border);border-left:4px solid ${borderColor};border-radius:10px;overflow:hidden;">
        <div style="display:flex;flex-wrap:wrap;padding:6px 8px;background:var(--bg-secondary);border-bottom:1px solid var(--border);gap:1px;">
            ${isRunning ? `<button class="btn btn-sm" style="${bd}" disabled title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button><button class="btn btn-sm" style="${bs}" onclick="dockerAction('${c.name}','stop',this)" title="Stop"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button><button class="btn btn-sm" style="${bs}" onclick="dockerAction('${c.name}','restart',this)" title="Restart"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button><button class="btn btn-sm" style="${bs}" onclick="dockerAction('${c.name}','pause',this)" title="Pause"><span class="ws-icon-clean-wrap" data-icon="pause"></span></button><button class="btn btn-sm" style="${bs}" onclick="openConsole('docker','${c.name}')" title="Console"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>${_containerVncBtnHtml('docker', c.name, c.name, bs, true)}` : isPaused ? `<button class="btn btn-sm" style="${bs}" onclick="dockerAction('${c.name}','unpause',this)" title="Unpause"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>` : `<button class="btn btn-sm" style="${bs}" onclick="dockerAction('${c.name}','start',this)" title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button><button class="btn btn-sm" style="${bd}" disabled></button><button class="btn btn-sm" style="${bd}" disabled></button>`}
            <button class="btn btn-sm" style="${bs}" onclick="viewContainerLogs('docker','${c.name}')" title="Logs"><span class="ws-icon-clean-wrap" data-icon="logs"></span></button><button class="btn btn-sm" style="${bs}" onclick="viewDockerVolumes('${c.name}')" title="Volumes"><span class="ws-icon-clean-wrap" data-icon="database"></span></button><button class="btn btn-sm" style="${bs}" onclick="browseContainerFiles('docker','${c.name}')" title="Files"><span class="ws-icon-clean-wrap" data-icon="folder-open"></span></button><button class="btn btn-sm" style="${bs}" onclick="openDockerSettings('${c.name}')" title="Settings"><span class="ws-icon-clean-wrap" data-icon="settings"></span></button><button class="btn btn-sm" style="${bs}" onclick="openContainerConfigurator('docker','${c.name}')" title="Configure"><span class="ws-icon-clean-wrap" data-icon="configure"></span></button><button class="btn btn-sm" style="${bs}" onclick="openContainerUpdates('docker','${c.name}')" title="Updates"><span class="ws-icon-clean-wrap" data-icon="updates"></span></button><button class="btn btn-sm" style="${bs}" onclick="openContainerCron('docker','${c.name}')" title="Cron"><span class="ws-icon-clean-wrap" data-icon="calendar"></span></button><button class="btn btn-sm" style="${bs}" onclick="cloneDockerContainer('${c.name}')" title="Clone"><span class="ws-icon-clean-wrap" data-icon="copy"></span></button><button class="btn btn-sm" style="${bs}" onclick="migrateDockerContainer('${c.name}')" title="Migrate"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>${!isRunning ? `<button class="btn btn-sm" style="${bs}color:#ef4444;" onclick="dockerAction('${c.name}','remove',this)" title="Remove"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>` : ''}
        </div>
        ${pies.length > 0 ? `<div style="display:flex;justify-content:space-evenly;padding:12px 8px;border-bottom:1px solid var(--border);">${pies.join('')}</div>` : ''}
        <div style="padding:10px 12px;">
            <div style="display:flex;justify-content:space-between;align-items:start;">
                <div><div style="font-weight:700;font-size:14px;">${escapeHtml(c.name)}</div><div style="font-size:11px;color:var(--text-muted);">${escapeHtml(c.image)}</div></div>
                <span style="font-size:10px;padding:2px 8px;border-radius:4px;background:${borderColor}22;color:${borderColor};font-weight:600;">${c.state}</span>
            </div>
            ${svcItems ? `<div style="margin-top:4px;">${svcItems}</div>` : ''}
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px;margin-top:8px;font-size:11px;color:var(--text-muted);">
                <span>${c.ip_address || '-'}</span><span>${ports}</span>
                ${c.gateway ? `<span>GW: ${escapeHtml(c.gateway)}</span>` : ''}${c.mac_address ? `<span>MAC: ${escapeHtml(c.mac_address)}</span>` : ''}
                <span>${c.autostart ? 'Autostart' : 'Manual'}</span>
                ${hasStorage ? `<span>${formatBytes(c.disk_usage)}/${formatBytes(c.disk_total)}</span>` : ''}
                ${memPct >= 0 ? `<span>${formatBytes(s.memory_usage)}/${formatBytes(s.memory_limit)}</span>` : ''}
                ${cpuPct >= 0 ? `<span>${s.cpu_percent.toFixed(1)}%</span>` : ''}
                ${portWarning}
            </div>
            <span data-update-badge="docker:${c.name}"></span>
            <span data-image-update-badge="${escapeAttr(c.name)}"></span>
        </div>
    </div>`;
}

function renderLxcCards(containers, stats) {
    const grid = document.getElementById('lxc-card-grid');
    if (!grid) return;
    if (containers.length === 0) { grid.innerHTML = ''; return; }
    if (!stats) stats = {};
    grid.innerHTML = containers.map(c => lxcCardHtml(c, stats[c.name] || {})).join('');
}

function lxcCardHtml(c, s) {
    const bs = 'margin:1px;font-size:16px;line-height:1;padding:3px 5px;background:none;border:1px solid var(--border);border-radius:4px;cursor:pointer;';
    const bd = bs + 'opacity:0.3;cursor:not-allowed;pointer-events:none;';
    if (!s) s = {};
    const isRunning = c.state === 'running';
        const isFrozen = c.state === 'frozen';
        const borderColor = isRunning ? '#10b981' : isFrozen ? '#f59e0b' : '#6b7280';
        const cpuPct = s.cpu_percent !== undefined ? Math.min(s.cpu_percent, 100) : -1;
        const cpuColor = cpuPct > 80 ? '#ef4444' : cpuPct > 50 ? '#f59e0b' : '#10b981';
        const memPct = (s.memory_usage && s.memory_limit) ? Math.min(Math.round((s.memory_usage / s.memory_limit) * 100), 100) : -1;
        const memColor = memPct > 90 ? '#ef4444' : memPct > 70 ? '#f59e0b' : '#10b981';
        const hasStorage = c.disk_usage !== undefined && c.disk_total;
        const diskPct = hasStorage ? Math.round((c.disk_usage / c.disk_total) * 100) : 0;
        const diskColor = diskPct > 90 ? '#ef4444' : diskPct > 70 ? '#f59e0b' : '#10b981';

        const svcItems = (c.services && c.services.length > 0) ? c.services.map(sv => {
            const sColor = sv.status === 'running' ? '#10b981' : '#ef4444';
            return `<span style="font-size:9px;padding:1px 4px;border-radius:2px;background:${sColor}22;color:${sColor};">${sv.name}</span>`;
        }).join(' ') : '';

        const pies = [];
        if (cpuPct >= 0) pies.push(`<div style="text-align:center;flex:1;">${svgPie(cpuPct, cpuColor, 64)}<div style="font-size:9px;color:var(--text-muted);">CPU</div></div>`);
        if (memPct >= 0) pies.push(`<div style="text-align:center;flex:1;">${svgPie(memPct, memColor, 64)}<div style="font-size:9px;color:var(--text-muted);">RAM</div></div>`);
        if (hasStorage) pies.push(`<div style="text-align:center;flex:1;">${svgPie(diskPct, diskColor, 64)}<div style="font-size:9px;color:var(--text-muted);">Disk</div></div>`);

        return `<div style="background:var(--bg-card);border:1px solid var(--border);border-left:4px solid ${borderColor};border-radius:10px;overflow:hidden;">
            <div style="display:flex;flex-wrap:wrap;padding:6px 8px;background:var(--bg-secondary);border-bottom:1px solid var(--border);gap:1px;">
                <button class="btn btn-sm" style="${isRunning ? bd : bs}" ${isRunning ? 'disabled' : ''} ${!isRunning ? `onclick="lxcAction('${c.name}','start',this)"` : ''} title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}','stop',this)"` : ''} title="Stop"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}','restart',this)"` : ''} title="Restart"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}','freeze',this)"` : ''} title="Freeze"><span class="ws-icon-clean-wrap" data-icon="snowflake"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="openLxcConsole('${c.name}','${c.hostname || c.name}')"` : ''} title="Console"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
                ${_containerVncBtnHtml('lxc', c.name, c.hostname || c.name, bs, isRunning)}
                ${isRunning ? `<button class="btn btn-sm" style="${bs}" onclick="reclaimLxcCache('${c.name}', this)" title="Reclaim cache — free this container's clean page cache. Safe: never touches its working memory, so the running app is not disrupted."><span class="ws-icon-clean-wrap" data-icon="memory"></span></button>` : ''}
                <button class="btn btn-sm" style="${isRunning ? bd : bs}" ${isRunning ? 'disabled' : ''} ${!isRunning ? `onclick="lxcAction('${c.name}','destroy',this)"` : ''} title="Destroy"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="viewContainerLogs('lxc','${c.name}')" title="Logs"><span class="ws-icon-clean-wrap" data-icon="logs"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="browseContainerFiles('lxc','${c.name}','${(c.storage_path||'').replace(/'/g,"\\'")}')" title="Files"><span class="ws-icon-clean-wrap" data-icon="folder-open"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="editContainerConfigFile('lxc','${c.name}')" title="Edit Config File"><span class="ws-icon-clean-wrap" data-icon="file-code"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="openLxcSettings('${c.name}')" title="Settings"><span class="ws-icon-clean-wrap" data-icon="settings"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="openContainerConfigurator('lxc','${c.name}')" title="Configure"><span class="ws-icon-clean-wrap" data-icon="configure"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="openContainerUpdates('lxc','${c.name}')" title="Updates"><span class="ws-icon-clean-wrap" data-icon="updates"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="openContainerCron('lxc','${c.name}')" title="Cron"><span class="ws-icon-clean-wrap" data-icon="calendar"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="cloneLxcContainer('${c.name}')" title="Clone"><span class="ws-icon-clean-wrap" data-icon="copy"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="migrateLxcContainer('${c.name}')" title="Migrate"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="openLxcStorage('${escapeHtml(c.name)}')" title="Storage (resize / move)"><span class="ws-icon-clean-wrap" data-icon="hard-drive"></span></button>
                <button class="btn btn-sm" style="${bs}" onclick="exportLxcContainer('${c.name}')" title="Export"><span class="ws-icon-clean-wrap" data-icon="export"></span></button>
            </div>
            ${pies.length > 0 ? `<div style="display:flex;justify-content:space-evenly;padding:12px 8px;border-bottom:1px solid var(--border);">${pies.join('')}</div>` : ''}
            <div style="padding:10px 12px;">
                <div style="display:flex;justify-content:space-between;align-items:start;">
                    <div><div style="font-weight:700;font-size:14px;">${escapeHtml(c.hostname || c.name)}</div>${c.hostname ? `<div style="font-size:11px;color:var(--text-muted);">CT ${c.name}</div>` : ''}<div style="font-size:11px;color:var(--text-secondary);">${c.version || ''}</div></div>
                    <span style="font-size:10px;padding:2px 8px;border-radius:4px;background:${borderColor}22;color:${borderColor};font-weight:600;">${c.state}</span>
                </div>
                ${svcItems ? `<div style="margin-top:4px;">${svcItems}</div>` : ''}
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px;margin-top:8px;font-size:11px;color:var(--text-muted);">
                    <span>${c.ip_address || '-'}</span>
                    <span>${c.autostart ? 'Autostart' : 'Manual'}</span>
                    ${c.gateway ? `<span>GW: ${escapeHtml(c.gateway)}</span>` : ''}
                    ${c.mac_address ? `<span>MAC: ${escapeHtml(c.mac_address)}</span>` : ''}
                    ${hasStorage ? `<span>${formatBytes(c.disk_usage)}/${formatBytes(c.disk_total)}</span>` : ''}
                    ${memPct >= 0 ? `<span>${formatBytes(s.memory_usage)}/${formatBytes(s.memory_limit)}</span>` : ''}
                    ${cpuPct >= 0 ? `<span>${s.cpu_percent.toFixed(1)}%</span>` : ''}
                    ${c.fs_type ? `<span>FS: ${escapeHtml(c.fs_type)}</span>` : ''}
                </div>
                <span data-update-badge="lxc:${c.name}"></span>
            </div>
        </div>`;
}

function renderVmCards(vms) {
    const grid = document.getElementById('vms-card-grid');
    if (!grid) return;
    if (vms.length === 0) { grid.innerHTML = ''; return; }
    grid.innerHTML = vms.map(vm => vmCardHtml(vm)).join('');
}

function vmCardHtml(vm) {
    const bs = 'margin:1px;font-size:16px;line-height:1;padding:3px 5px;background:none;border:1px solid var(--border);border-radius:4px;cursor:pointer;';
    const bd = bs + 'opacity:0.3;cursor:not-allowed;pointer-events:none;';
    const isRunning = vm.running;
    const isPaused = !!vm.paused;
    const borderColor = isPaused ? '#eab308' : (isRunning ? '#10b981' : '#6b7280');
    let vncHost = window.location.hostname;
    let vncNodeParam = '';
    if (currentNodeId) {
        const node = allNodes.find(n => n.id === currentNodeId);
        if (node && !node.is_self) {
            vncHost = node.address;
            // Route the console through this node's remote-console bridge —
            // the VM doesn't exist locally here (see vnc.html node param).
            vncNodeParam = `&node=${encodeURIComponent(currentNodeId)}`;
        }
    }
    const vncBridgePort2 = vm.vnc_ws_port || vm.vnc_port;
    const vncLink = (vm.running && vncBridgePort2) ? `/vnc.html?name=${encodeURIComponent(vm.name)}&port=${vncBridgePort2}&host=${encodeURIComponent(vncHost)}${vncNodeParam}` : '';

    return `<div style="background:var(--bg-card);border:1px solid var(--border);border-left:4px solid ${borderColor};border-radius:10px;overflow:hidden;">
        <div style="display:flex;flex-wrap:wrap;padding:6px 8px;background:var(--bg-secondary);border-bottom:1px solid var(--border);gap:1px;">
            <button class="btn btn-sm" style="${isRunning ? bd : bs}" ${isRunning ? 'disabled' : `onclick="vmAction('${vm.name}','start',this)"`} title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : `onclick="vmAction('${vm.name}','stop',this)"`} title="Stop (graceful ACPI shutdown)"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bd : bs}color:#b91c1c;" ${!isRunning ? 'disabled' : `onclick="vmForceStopConfirm('${vm.name}', this)"`} title="Force Stop (power off immediately)"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
            <button class="btn btn-sm" style="${isRunning && !isPaused ? bs : bd}" ${isRunning && !isPaused ? `onclick="vmAction('${vm.name}','restart',this)"` : 'disabled'} title="Restart (reboot the guest)"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button>
            ${isPaused
                ? `<button class="btn btn-sm" style="${bs}color:#22c55e;" onclick="vmAction('${vm.name}','resume',this)" title="Resume (unpause)"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>`
                : `<button class="btn btn-sm" style="${isRunning ? bs : bd}" ${isRunning ? `onclick="vmAction('${vm.name}','pause',this)"` : 'disabled'} title="Pause (suspend to RAM)"><span class="ws-icon-clean-wrap" data-icon="snowflake"></span></button>`}
            ${vncLink ? `<button class="btn btn-sm" style="${bs}" onclick="window.open('${vncLink}')" title="VNC"><span class="ws-icon-clean-wrap" data-icon="monitor"></span></button>` : ''}
            <button class="btn btn-sm" style="${!isRunning ? bd : bs}" ${!isRunning ? 'disabled' : `onclick="openVmConsole('${vm.name}')"`} title="Serial terminal (guest must have serial console enabled)"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
            <button class="btn btn-sm" style="${bs}" onclick="showVmSettings('${vm.name}')" title="Settings"><span class="ws-icon-clean-wrap" data-icon="settings"></span></button>
            <button class="btn btn-sm" style="${bs}" onclick="showVmLogs('${vm.name}')" title="Logs"><span class="ws-icon-clean-wrap" data-icon="logs"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bs : bd}color:#a855f7;" ${!isRunning ? `onclick="backupSingleVm('${vm.name}')"` : 'disabled'} title="${!isRunning ? 'Back up this VM now (portable tar.gz to local storage)' : 'Stop the VM first — backup of a running VM produces an inconsistent disk image'}"><span class="ws-icon-clean-wrap" data-icon="save"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bs : bd}color:#eab308;" ${!isRunning ? `onclick="cloneVm('${vm.name}')"` : 'disabled'} title="${!isRunning ? 'Clone this VM (full copy of disks, fresh MACs)' : 'Stop the VM first — cloning a running VM produces an inconsistent disk image'}"><span class="ws-icon-clean-wrap" data-icon="copy"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bs : bd}" ${!isRunning ? `onclick="migrateVm('${vm.name}')"` : 'disabled'} title="${!isRunning ? 'Migrate to another node' : 'Stop the VM first — migration must export a consistent disk image'}"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>
            <button class="btn btn-sm" style="${!isRunning ? bs : bd}" ${!isRunning ? `onclick="migrateVmDiskStorage('${vm.name}')"` : 'disabled'} title="${!isRunning ? 'Move disk to different storage (same node)' : 'Stop the VM first — moving a live disk would corrupt it'}"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>
            ${!isRunning ? `<button class="btn btn-sm" style="${bs}color:#ef4444;" onclick="deleteVm('${vm.name}')" title="Delete"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>` : ''}
        </div>
        <div style="padding:10px 12px;">
            <div style="display:flex;justify-content:space-between;align-items:start;">
                <div><div style="font-weight:700;font-size:14px;">${escapeHtml(vm.name)}</div><div style="font-size:11px;color:var(--text-muted);">${vm.bios_type === 'ovmf' ? 'UEFI' : 'BIOS'} · ${vm.os_disk_bus} · ${vm.net_model || 'virtio'}</div></div>
                <span style="font-size:10px;padding:2px 8px;border-radius:4px;background:${borderColor}22;color:${borderColor};font-weight:600;">${isPaused ? 'Paused' : (isRunning ? 'Running' : 'Stopped')}</span>
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px;margin-top:8px;font-size:11px;color:var(--text-muted);">
                <span>${vm.cpus} vCPU</span>
                <span>${vm.memory_mb} MB</span>
                <span>${vm.disk_size_gb} GB</span>
                <span>${vm.wolfnet_ip || '-'}</span>
                <span>${vm.auto_start ? 'Autostart' : 'Manual'}</span>
                <span>${vm.mac_address || '-'}</span>
                ${vm.iso_path ? `<span>${escapeHtml(vm.iso_path.split('/').pop())}</span>` : ''}
                ${vm.extra_nics && vm.extra_nics.length > 0 ? `<span>${vm.extra_nics.length} extra NIC${vm.extra_nics.length > 1 ? 's' : ''}</span>` : ''}
                ${vm.usb_devices && vm.usb_devices.length > 0 ? `<span>${vm.usb_devices.length} USB</span>` : ''}
                ${vm.pci_devices && vm.pci_devices.length > 0 ? `<span>${vm.pci_devices.length} PCI</span>` : ''}
            </div>
        </div>
    </div>`;
}

function renderDockerContainers(containers) {
    const table = document.getElementById('docker-containers-table');
    const empty = document.getElementById('docker-empty');
    if (!table) return;

    if (containers.length === 0) {
        table.innerHTML = '';
        if (empty) empty.style.display = '';
        return;
    }
    if (empty) empty.style.display = 'none';

    table.innerHTML = containers.map(c => {
        const s = dockerStats[c.name] || {};
        const isRunning = c.state === 'running';
        const isPaused = c.state === 'paused';
        const stateColor = isRunning ? '#10b981' : (isPaused ? '#f59e0b' : '#6b7280');
        // Same requested-vs-published treatment as the card view —
        // stopped containers render in muted grey; only running
        // containers earn the red unpublished marker.
        let ports;
        if (c.port_mappings && c.port_mappings.length > 0) {
            ports = c.port_mappings.map(pm => {
                const ip = (!pm.host_ip || pm.host_ip === '0.0.0.0') ? '' : pm.host_ip + ':';
                const text = `${ip}${pm.host_port}→${pm.container_port}/${pm.proto}`;
                if (!isRunning) {
                    return `<span style="color:var(--text-muted);">${escapeHtml(text)}</span>`;
                }
                if (pm.published) {
                    return `<span style="color:#34d399;">${escapeHtml(text)}</span>`;
                }
                return `<span style="color:#ef4444;text-decoration:line-through;" title="UNPUBLISHED — daemon never bound this host port. Service is offline.">${escapeHtml(text)}</span>`;
            }).join('<br>');
        } else {
            ports = c.ports.length > 0 ? c.ports.join('<br>') : '-';
        }
        const hasStorage = c.disk_usage !== undefined && c.disk_total;
        const pct = hasStorage ? Math.round((c.disk_usage / c.disk_total) * 100) : 0;
        const barColor = pct > 90 ? '#ef4444' : pct > 70 ? '#f59e0b' : '#10b981';
        const fsLabel = c.fs_type ? `<span style="color:var(--text-muted);font-size:10px;margin-left:8px;">${c.fs_type}</span>` : '';
        const pathLabel = c.storage_path ? `<span style="color:var(--text-muted);font-size:10px;" title="${c.storage_path}">${c.storage_path.length > 30 ? '...' + c.storage_path.slice(-27) : c.storage_path}</span>` : '';
        const cpuPct = s.cpu_percent !== undefined ? Math.min(s.cpu_percent, 100) : -1;
        const cpuColor = cpuPct > 80 ? '#ef4444' : cpuPct > 50 ? '#f59e0b' : '#10b981';
        const memPct = (s.memory_usage && s.memory_limit) ? Math.min(Math.round((s.memory_usage / s.memory_limit) * 100), 100) : -1;
        const memColor = memPct > 90 ? '#ef4444' : memPct > 70 ? '#f59e0b' : '#10b981';

        const barSeg = (icon, pctVal, color, label) => `<div style="flex:1;display:flex;align-items:center;gap:6px;min-width:0;">
            <span>${icon}</span>
            <div style="flex:1;height:8px;background:var(--bg-tertiary,#333);border-radius:4px;overflow:hidden;">
                <div style="width:${pctVal}%;height:100%;background:${color};border-radius:4px;transition:width 0.3s;"></div>
            </div>
            <span style="white-space:nowrap;">${label}</span>
        </div>`;

        const statsSegs = [];
        if (cpuPct >= 0) statsSegs.push(barSeg('', cpuPct, cpuColor, s.cpu_percent.toFixed(1) + '%'));
        if (memPct >= 0) statsSegs.push(barSeg('', memPct, memColor, formatBytes(s.memory_usage) + ' / ' + formatBytes(s.memory_limit) + ' (' + memPct + '%)'));
        if (hasStorage) statsSegs.push(barSeg('', pct, barColor, formatBytes(c.disk_usage) + ' / ' + formatBytes(c.disk_total) + ' (' + pct + '%)'));

        const statsSubRow = statsSegs.length > 0 ? `<tr class="storage-sub-row" data-stats="${c.name}" style="background:var(--bg-secondary);"><td colspan="7" style="padding:4px 16px 6px 24px;border-top:none;">
            <div style="display:flex;align-items:center;gap:16px;font-size:11px;">${statsSegs.join('')}</div>
        </td></tr>` : '';

        const svcItems = (c.services && c.services.length > 0) ? c.services.map(s => {
            const sColor = s.status === 'running' ? '#10b981' : '#ef4444';
            return `<span style="display:inline-block;font-size:10px;padding:1px 6px;border-radius:3px;background:${sColor}22;color:${sColor};border:1px solid ${sColor}44;">${s.name}</span>`;
        }).join('') : '';
        const badgeRow = `<div style="display:flex;flex-wrap:wrap;align-items:center;gap:4px;margin-top:3px;">${svcItems}<span data-update-badge="docker:${c.name}"></span><span data-image-update-badge="${escapeAttr(c.name)}"></span></div>`;

        return `<tr data-name="${c.name}">
            <td><strong>${c.name}</strong>${badgeRow}<span style="font-size:11px;color:var(--text-muted)">${c.id.substring(0, 12)}</span></td>
            <td>${c.image}</td>
            <td><span style="color:${stateColor}">●</span> ${c.status}</td>
            <td style="font-size:12px; font-family:monospace;">${c.ip_address || '-'}${c.gateway ? '<div style="font-size:10px;color:var(--text-muted);">GW: ' + escapeHtml(c.gateway) + '</div>' : ''}${c.mac_address ? '<div style="font-size:10px;color:var(--text-muted);">MAC: ' + escapeHtml(c.mac_address) + '</div>' : ''}</td>
            <td style="font-size:11px;">${ports}</td>
            <td><input type="checkbox" ${c.autostart ? 'checked' : ''} onchange="toggleDockerAutostart('${c.id}', this.checked)"></td>
            <td><div style="display:flex; flex-wrap:wrap; gap:2px; min-width:0;">
                ${isRunning ? `
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="dockerAction('${c.name}', 'stop', this)" title="Stop"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="dockerAction('${c.name}', 'restart', this)" title="Restart"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="dockerAction('${c.name}', 'pause', this)" title="Pause"><span class="ws-icon-clean-wrap" data-icon="pause"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="openConsole('docker', '${c.name}')" title="Console"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
                    ${_containerVncBtnHtml('docker', c.name, c.name, 'margin:2px;font-size:20px;line-height:1;padding:4px 6px;', true)}
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Remove"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                ` : isPaused ? `
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="dockerAction('${c.name}', 'unpause', this)" title="Unpause"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
                ` : `
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="dockerAction('${c.name}', 'start', this)" title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Stop"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Restart"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Freeze"><span class="ws-icon-clean-wrap" data-icon="snowflake"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;opacity:0.4;cursor:not-allowed;pointer-events:none;" disabled title="Console"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
                    <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;color:#ef4444;" onclick="dockerAction('${c.name}', 'remove', this)" title="Remove"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                `}
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="viewContainerLogs('docker', '${c.name}')" title="Logs"><span class="ws-icon-clean-wrap" data-icon="logs"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="viewDockerVolumes('${c.name}')" title="Volumes"><span class="ws-icon-clean-wrap" data-icon="database"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="browseContainerFiles('docker', '${c.name}')" title="Browse Files"><span class="ws-icon-clean-wrap" data-icon="folder-open"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="editContainerConfigFile('docker', '${c.name}')" title="Edit Config File"><span class="ws-icon-clean-wrap" data-icon="file-code"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="openDockerSettings('${c.name}')" title="Settings"><span class="ws-icon-clean-wrap" data-icon="settings"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="openContainerConfigurator('docker', '${c.name}')" title="Configure"><span class="ws-icon-clean-wrap" data-icon="configure"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="openContainerUpdates('docker', '${c.name}')" title="Check Updates"><span class="ws-icon-clean-wrap" data-icon="updates"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="openContainerCron('docker', '${c.name}')" title="Cron Jobs"><span class="ws-icon-clean-wrap" data-icon="calendar"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="cloneDockerContainer('${c.name}')" title="Clone"><span class="ws-icon-clean-wrap" data-icon="copy"></span></button>
                <button class="btn btn-sm" style="margin:2px;font-size:20px;line-height:1;padding:4px 6px;" onclick="migrateDockerContainer('${c.name}')" title="Migrate"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>
            </div></td>
        </tr>${statsSubRow}`;
    }).join('');

    // Surface freshness — Docker stats poll every few seconds; show
    // "Updated Xs ago" so operators can tell live from stale data.
    try {
        const wrap = table.closest('.card') || table.parentElement;
        if (wrap) attachLastUpdated(wrap)();
    } catch (_) {}
}

function renderDockerStats(stats) {
    const summary = document.getElementById('docker-stats-summary');
    if (!stats || stats.length === 0) {
        summary.innerHTML = '';
        return;
    }

    const totalCpu = stats.reduce((sum, s) => sum + s.cpu_percent, 0);
    const totalMem = stats.reduce((sum, s) => sum + s.memory_usage, 0);
    const totalPids = stats.reduce((sum, s) => sum + s.pids, 0);
    const running = stats.length;

    summary.innerHTML = `
        <div class="stat-card">
            <div class="stat-icon"><span class="ws-icon-clean-wrap" data-icon="box"></span></div>
            <div class="stat-info">
                <div class="stat-value">${running}</div>
                <div class="stat-label">Running</div>
            </div>
        </div>
        <div class="stat-card">
            <div class="stat-icon"><span class="ws-icon-clean-wrap" data-icon="cpu"></span></div>
            <div class="stat-info">
                <div class="stat-value">${totalCpu.toFixed(1)}%</div>
                <div class="stat-label">Total CPU</div>
            </div>
        </div>
        <div class="stat-card">
            <div class="stat-icon"><span class="ws-icon-clean-wrap" data-icon="memory"></span></div>
            <div class="stat-info">
                <div class="stat-value">${formatBytes(totalMem)}</div>
                <div class="stat-label">Total Memory</div>
            </div>
        </div>
        <div class="stat-card">
            <div class="stat-icon"><span class="ws-icon-clean-wrap" data-icon="list"></span></div>
            <div class="stat-info">
                <div class="stat-value">${totalPids}</div>
                <div class="stat-label">Total PIDs</div>
            </div>
        </div>
    `;
}

function renderDockerImages(images) {
    const table = document.getElementById('docker-images-table');
    if (!images || images.length === 0) {
        table.innerHTML = '<tr><td colspan="6" style="text-align:center;color:var(--text-muted);">No images found</td></tr>';
        return;
    }
    table.innerHTML = images.map(img => {
        const imageRef = img.repository + (img.tag && img.tag !== '<none>' ? ':' + img.tag : '');
        return `
        <tr>
            <td>${img.repository}</td>
            <td>${img.tag}</td>
            <td style="font-family:monospace;font-size:12px;">${img.id.substring(0, 12)}</td>
            <td>${img.size}</td>
            <td>${img.created}</td>
            <td>
                <button class="btn btn-sm btn-primary" style="margin:2px;font-size:11px;" onclick="selectDockerImage('${imageRef.replace(/'/g, "\\'")}')" title="Create container from this image">▶ Use</button>
                <button class="btn btn-sm" style="margin:2px;font-size:11px;color:#ef4444;" onclick="deleteDockerImage('${img.id}', '${imageRef.replace(/'/g, "\\'")}')" title="Delete image">Delete</button>
            </td>
        </tr>`;
    }).join('');
}

async function deleteDockerImage(id, name) {
    if (!(await showConfirm(`Delete Docker image '${name}'?\n\nThis will fail if the image is used by any container.`))) return;

    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/images/${encodeURIComponent(id)}`), {
            method: 'DELETE',
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(`Image '${name}' deleted`, 'success');
            setTimeout(loadDockerContainers, 500);
        } else {
            showToast(data.error || 'Failed to delete image', 'error');
        }
    } catch (e) {
        showToast(`Failed: ${e.message}`, 'error');
    }
}


async function dockerAction(container, action, btn) {
    if (action === 'remove' && !(await showConfirm(`Remove container '${container}'? This cannot be undone.`))) return;

    activityStart();
    const row = btn?.closest('tr');
    const buttons = row ? row.querySelectorAll('button') : [];
    buttons.forEach(b => { b.disabled = true; b.style.opacity = '0.4'; b.style.pointerEvents = 'none'; });
    if (btn) btn.innerHTML = '<span style="display:inline-block;width:16px;height:16px;border:2px solid rgba(255,255,255,0.2);border-top-color:#fff;border-radius:50%;animation:spin 0.7s linear infinite;"></span>';

    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/${container}/action`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(`${action} ${container}: OK`, 'success');
            taskLog('Docker ' + action + ': ' + container);
            setTimeout(loadDockerContainers, 500);
        } else {
            showToast(data.error || `Failed to ${action}`, 'error');
            taskLog('Docker ' + action + ': ' + container, 'failed');
            buttons.forEach(b => { b.disabled = false; b.style.opacity = ''; b.style.pointerEvents = ''; });
        }
    } catch (e) {
        showToast(`Failed: ${e.message}`, 'error');
        taskLog('Docker ' + action + ': ' + container, 'failed');
        buttons.forEach(b => { b.disabled = false; b.style.opacity = ''; b.style.pointerEvents = ''; });
    } finally {
        activityStop();
    }
}

async function viewDockerVolumes(container) {
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');

    title.textContent = `${container} — Volumes`;
    body.innerHTML = renderBlockSkeleton({lines:3});
    modal.classList.add('active');

    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/${encodeURIComponent(container)}/volumes`));
        const mounts = await resp.json();

        if (mounts.length === 0) {
            body.innerHTML = `
                <div style="text-align:center; padding:2rem; color:var(--text-muted);">
                    <div style="font-size:32px; margin-bottom:8px;"></div>
                    <p>No volumes mounted on this container.</p>
                    <p style="font-size:12px;">Add volumes when creating the container using the Volumes section.</p>
                </div>
            `;
        } else {
            body.innerHTML = `
                <div style="padding:12px; background:var(--bg-tertiary); border-radius:8px; border:1px solid var(--border);">
                    <div style="display:flex; align-items:center; gap:8px; margin-bottom:10px;">
                        <span></span>
                        <strong style="font-size:13px;">Volume Mounts (${mounts.length})</strong>
                    </div>
                    ${mounts.map(m => `
                        <div style="display:flex; align-items:center; gap:8px; padding:8px; margin-bottom:4px; background:var(--bg-primary); border-radius:6px; border:1px solid var(--border);">
                            <span class="badge" style="font-size:10px; min-width:45px; text-align:center;">${m.mount_type}</span>
                            <code style="flex:1; font-size:12px; color:var(--accent); word-break:break-all;">${m.host_path}</code>
                            <span style="color:var(--text-muted); font-size:12px;">→</span>
                            <code style="flex:1; font-size:12px; color:var(--text-primary);">${m.container_path}</code>
                            ${m.read_only ? '<span class="badge" style="font-size:10px; background:var(--warning-bg); color:var(--warning);">RO</span>' : '<span class="badge" style="font-size:10px;">RW</span>'}
                        </div>
                    `).join('')}
                </div>
                <div style="font-size:11px; color:var(--text-muted); margin-top:8px;">
                    Docker volumes can only be modified by recreating the container.
                </div>
            `;
        }
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to load volumes: ${e.message}</p>`;
    }
}

// ─── Docker Settings Editor ───

var _dockerSettingsTab = 1;

function switchDockerTab(tab) {
    _dockerSettingsTab = tab;
    document.querySelectorAll('.docker-tab-page').forEach(p => p.style.display = 'none');
    document.querySelectorAll('.docker-tab-btn').forEach(b => {
        b.style.borderBottomColor = 'transparent';
        b.style.color = 'var(--text-muted)';
    });
    var page = document.getElementById('docker-tab-' + tab);
    var btn = document.querySelector('.docker-tab-btn[data-dtab="' + tab + '"]');
    if (page) page.style.display = 'block';
    if (btn) { btn.style.borderBottomColor = 'var(--accent)'; btn.style.color = 'var(--text-primary)'; }
}

async function openDockerSettings(name) {
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');

    title.textContent = `${name} — Settings`;
    body.innerHTML = renderBlockSkeleton({lines:3});
    modal.classList.add('active');
    _dockerSettingsTab = 1;
    window._dockerSystemEnv = []; // Clear stale system env from previous modal open

    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/${encodeURIComponent(name)}/inspect`));
        if (!resp.ok) throw new Error('Failed to load config');
        const cfg = await resp.json();

        // Extract useful fields from docker inspect JSON
        const hostname = cfg.Config?.Hostname || '';
        const image = cfg.Config?.Image || '';
        const restartPolicy = cfg.HostConfig?.RestartPolicy?.Name || 'no';
        const isAutostart = restartPolicy === 'always' || restartPolicy === 'unless-stopped';
        const memoryBytes = cfg.HostConfig?.Memory || 0;
        const memoryMb = memoryBytes > 0 ? Math.round(memoryBytes / 1048576) : '';
        const nanoCpus = cfg.HostConfig?.NanoCpus || 0;
        const cpus = nanoCpus > 0 ? (nanoCpus / 1e9).toFixed(1) : '';
        const cpuShares = cfg.HostConfig?.CpuShares || 0;
        const cpusetCpus = cfg.HostConfig?.CpusetCpus || '';
        const env = (cfg.Config?.Env || []);
        const ports = cfg.HostConfig?.PortBindings || {};
        const networks = cfg.NetworkSettings?.Networks || {};

        // Format port bindings for display
        var portRows = '';
        for (const [containerPort, bindings] of Object.entries(ports)) {
            if (bindings && bindings.length > 0) {
                bindings.forEach(b => {
                    const hostPort = b.HostPort || '';
                    const hostIp = b.HostIp || '0.0.0.0';
                    const proto = containerPort.includes('/') ? containerPort.split('/')[1].toUpperCase() : 'TCP';
                    portRows += `<div style="display:flex;align-items:center;gap:8px;padding:6px 8px;margin-bottom:4px;background:var(--bg-primary);border-radius:6px;border:1px solid var(--border);">
                        <code style="font-size:12px;color:var(--accent);">${hostIp}:${hostPort}</code>
                        <span style="color:var(--text-muted);font-size:12px;">→</span>
                        <code style="font-size:12px;color:var(--text-primary);">${containerPort}</code>
                        <span style="font-size:10px;padding:2px 6px;border-radius:4px;background:${proto === 'UDP' ? 'rgba(234,179,8,0.15)' : 'rgba(59,130,246,0.15)'};color:${proto === 'UDP' ? '#eab308' : '#3b82f6'};font-weight:600;">${proto}</span>
                    </div>`;
                });
            }
        }
        if (!portRows) portRows = '<div style="color:var(--text-muted);font-size:12px;padding:8px;">No port mappings configured</div>';

        // Format network info
        var networkRows = '';
        for (const [netName, netInfo] of Object.entries(networks)) {
            const prefix = netInfo.IPPrefixLen ? `/${netInfo.IPPrefixLen}` : '';
            const ip6 = netInfo.GlobalIPv6Address ? `<span>IPv6: ${netInfo.GlobalIPv6Address}/${netInfo.GlobalIPv6PrefixLen || 0}</span>` : '';
            const ip6gw = netInfo.IPv6Gateway ? `<span>IPv6 GW: ${netInfo.IPv6Gateway}</span>` : '';
            networkRows += `<div style="padding:8px 10px;margin-bottom:4px;background:var(--bg-primary);border-radius:6px;border:1px solid var(--border);">
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">
                    <span style="font-size:14px;"></span>
                    <span style="font-weight:600;font-size:12px;">${escapeHtml(netName)}</span>
                </div>
                <div style="font-size:11px;color:var(--text-muted);font-family:monospace;display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:2px 12px;padding-left:24px;">
                    <span>IP: ${netInfo.IPAddress || '-'}${prefix}</span>
                    <span>Gateway: ${netInfo.Gateway || '-'}</span>
                    <span>MAC: ${netInfo.MacAddress || '-'}</span>
                    ${ip6}${ip6gw}
                </div>
            </div>`;
        }
        if (!networkRows) networkRows = '<div style="color:var(--text-muted);font-size:12px;padding:8px;">No networks connected</div>';

        // Separate system env vars (PATH, HOME, etc.) from user-editable ones
        const systemEnvPrefixes = ['PATH=', 'HOME=', 'HOSTNAME=', 'TERM='];
        const systemEnv = env.filter(e => systemEnvPrefixes.some(p => e.startsWith(p)));
        const userEnv = env.filter(e => !systemEnvPrefixes.some(p => e.startsWith(p)));
        // Store system env vars so we can preserve them on save
        window._dockerSystemEnv = systemEnv;
        var envRows = userEnv.map((e, i) => {
            const eqIdx = e.indexOf('=');
            const key = eqIdx >= 0 ? e.substring(0, eqIdx) : e;
            const val = eqIdx >= 0 ? e.substring(eqIdx + 1) : '';
            return `<div class="docker-env-row" style="display:flex;align-items:center;gap:6px;padding:4px 0;margin-bottom:2px;">
                <input type="text" class="docker-env-key" value="${escapeHtml(key)}" placeholder="KEY"
                    style="width:180px;padding:4px 8px;border-radius:4px;border:1px solid var(--border);background:var(--bg-primary);color:var(--accent);font-family:var(--font-mono);font-size:11px;">
                <span style="color:var(--text-muted);">=</span>
                <input type="text" class="docker-env-val" value="${escapeHtml(val)}" placeholder="value"
                    style="flex:1;padding:4px 8px;border-radius:4px;border:1px solid var(--border);background:var(--bg-primary);color:var(--text-primary);font-family:var(--font-mono);font-size:11px;">
                <button class="btn btn-sm" onclick="this.closest('.docker-env-row').remove()" style="font-size:14px;padding:2px 6px;color:var(--danger-color,#ef4444);" title="Remove">&times;</button>
            </div>`;
        }).join('');
        if (!envRows) envRows = '<div id="docker-env-empty" style="color:var(--text-muted);font-size:12px;padding:8px;">No environment variables</div>';

        // WolfNet IP from labels
        const labels = cfg.Config?.Labels || {};
        const wolfnetIp = labels['wolfnet.ip'] || '';

        var tabBtnStyle = 'flex:1;padding:10px 12px;border:none;background:none;font-size:13px;font-weight:600;cursor:pointer;transition:all .2s;';

        body.innerHTML = `
            <!-- Tab Bar -->
            <div style="display:flex;border-bottom:1px solid var(--border);background:var(--bg-secondary);margin:-24px -24px 16px -24px;">
                <button class="docker-tab-btn" data-dtab="1" onclick="switchDockerTab(1)"
                    style="${tabBtnStyle}border-bottom:2px solid var(--accent);color:var(--text-primary);">
                    General
                </button>
                <button class="docker-tab-btn" data-dtab="2" onclick="switchDockerTab(2)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Network
                </button>
                <button class="docker-tab-btn" data-dtab="3" onclick="switchDockerTab(3)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Resources
                </button>
                <button class="docker-tab-btn" data-dtab="4" onclick="switchDockerTab(4)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Raw Config
                </button>
            </div>

            <!-- ═══ Tab 1: General ═══ -->
            <div class="docker-tab-page" id="docker-tab-1">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div class="form-group">
                        <label>Container Name</label>
                        <input type="text" class="form-control" value="${escapeHtml(name)}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                    <div class="form-group">
                        <label>Image</label>
                        <input type="text" class="form-control" value="${escapeHtml(image)}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                    <div class="form-group">
                        <label>Hostname</label>
                        <input type="text" class="form-control" value="${escapeHtml(hostname)}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">Set automatically by Docker</small>
                    </div>
                    <div class="form-group">
                        <label>Restart Policy</label>
                        <select id="docker-restart-policy" class="form-control">
                            <option value="no" ${restartPolicy === 'no' ? 'selected' : ''}>No (manual only)</option>
                            <option value="always" ${restartPolicy === 'always' ? 'selected' : ''}>Always</option>
                            <option value="unless-stopped" ${restartPolicy === 'unless-stopped' ? 'selected' : ''}>Unless Stopped</option>
                            <option value="on-failure" ${restartPolicy === 'on-failure' ? 'selected' : ''}>On Failure</option>
                        </select>
                    </div>
                </div>

                <div style="margin-top:12px;padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
                        <h4 style="margin:0;font-size:13px;color:var(--text-primary);">Environment Variables (${userEnv.length})</h4>
                        <button class="btn btn-sm" onclick="addDockerEnvRow()" style="font-size:11px;padding:2px 8px;">+ Add</button>
                    </div>
                    <div id="docker-env-list" style="max-height:240px;overflow-y:auto;">
                        ${envRows}
                    </div>
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-top:8px;">
                        <div style="font-size:11px;color:var(--text-muted);">Saving env changes will recreate the container (volumes and settings preserved).</div>
                        <button class="btn btn-sm btn-primary" onclick="saveDockerEnv('${escapeHtml(name)}')" style="font-size:11px;padding:4px 12px;">Save Env</button>
                    </div>
                </div>
            </div>

            <!-- ═══ Tab 2: Network ═══ -->
            <div class="docker-tab-page" id="docker-tab-2" style="display:none;">
                <div style="padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);margin-bottom:12px;">
                    <h4 style="margin:0 0 8px 0;font-size:13px;">Networks</h4>
                    ${networkRows}
                </div>
                <div style="padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);margin-bottom:12px;">
                    <h4 style="margin:0 0 8px 0;font-size:13px;">Port Mappings</h4>
                    ${portRows}
                    <div style="font-size:11px;color:var(--text-muted);margin-top:6px;">Port mappings can only be changed by recreating the container.</div>
                </div>
                <div style="padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <h4 style="margin:0 0 8px 0;font-size:13px;">WolfNet</h4>
                    <div style="display:grid;grid-template-columns:1fr auto;gap:8px;align-items:end;">
                        <div class="form-group" style="margin:0;">
                            <label>WolfNet IP</label>
                            <input type="text" id="docker-wolfnet-ip" class="form-control" value="${escapeHtml(wolfnetIp)}" onchange="checkWolfnetIpReuse(this)"
                                placeholder="e.g. 10.10.10.50 (leave blank for none)">
                        </div>
                        <div style="display:flex;gap:4px;padding-bottom:2px;">
                            <button class="btn btn-sm" onclick="findNextWolfnetIp()" title="Find next available WolfNet IP"
                                style="padding:6px 10px;font-size:11px;">Next Available</button>
                        </div>
                    </div>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:6px;">WolfNet IP is applied at container start time via host routing.</div>
                </div>
            </div>

            <!-- ═══ Tab 3: Resources ═══ -->
            <div class="docker-tab-page" id="docker-tab-3" style="display:none;">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div class="form-group">
                        <label>Memory Limit (MB)</label>
                        <input type="number" id="docker-memory" class="form-control" value="${memoryMb}"
                            placeholder="Leave blank for unlimited" min="0">
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">Enter value in MB. Leave blank for unlimited. Can be changed live.</small>
                    </div>
                    <div class="form-group">
                        <label>CPU Limit (cores)</label>
                        <input type="number" id="docker-cpus" class="form-control" value="${cpus}"
                            placeholder="Leave blank for unlimited" min="0" step="0.1">
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">e.g. 2.0 for 2 cores. Can be changed live.</small>
                    </div>
                    <div class="form-group">
                        <label>CPU Shares</label>
                        <input type="text" class="form-control" value="${cpuShares || 'Default (1024)'}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                    <div class="form-group">
                        <label>CPU Set (pinned cores)</label>
                        <input type="text" class="form-control" value="${escapeHtml(cpusetCpus) || 'All cores'}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                </div>

                <div style="margin-top:12px;padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <details>
                        <summary style="cursor:pointer;color:var(--accent);font-size:12px;margin-bottom:8px;">
                            Raw Docker Inspect (JSON)
                        </summary>
                        <pre style="background:var(--bg-primary);border:1px solid var(--border);border-radius:8px;padding:12px;
                            font-family:'JetBrains Mono',monospace;font-size:11px;max-height:300px;overflow-y:auto;
                            color:var(--text-primary);white-space:pre-wrap;word-break:break-all;">${escapeHtml(JSON.stringify(cfg, null, 2))}</pre>
                    </details>
                </div>
            </div>

            <!-- ═══ Tab 4: Raw Config (editable) ═══ -->
            <div class="docker-tab-page" id="docker-tab-4" style="display:none;">
                <div style="display:flex; align-items:flex-start; gap:10px; padding:10px 12px; margin-bottom:12px;
                            background:rgba(239,68,68,0.08); border:1px solid rgba(239,68,68,0.3); border-radius:8px;">
                    <span style="font-size:18px;line-height:1;"></span>
                    <div style="font-size:12px; line-height:1.5;">
                        <strong style="color:#fca5a5;">Danger zone.</strong> Saving this tab RECREATES the container — old one is stopped, renamed to <code>${escapeHtml(name)}_wolfstack_old</code>, replaced with a fresh container matching the JSON below, then the old one is removed on success.
                        The JSON's read-only fields (State, NetworkSettings, Created timestamps, etc.) are ignored — we only honour fields that are part of a container spec.
                        Use this to add a bind mount, tweak port bindings, change labels — anything <code>docker update</code> can't do live. Env vars have their own tab on the Network page.
                    </div>
                </div>
                <label style="font-size:12px; color:var(--text-muted); display:block; margin-bottom:6px;">
                    <code>docker inspect</code> JSON — edit any field, press <strong>Save Raw Config</strong> to apply.
                </label>
                <textarea id="docker-raw-config" class="form-control"
                    style="font-family:'JetBrains Mono',monospace;font-size:11px;height:520px;white-space:pre;
                           overflow:auto; background:var(--bg-primary); color:var(--text-primary);
                           border:1px solid var(--border); border-radius:8px; padding:12px;"
                    spellcheck="false"
                >${escapeHtml(JSON.stringify(cfg, null, 2))}</textarea>
                <div style="display:flex; gap:8px; margin-top:10px; align-items:center;">
                    <button class="btn btn-sm btn-primary" onclick="saveDockerRawConfig('${name}')" style="background:#ef4444; border-color:#ef4444;">
                        Save Raw Config (recreates container)
                    </button>
                    <button class="btn btn-sm" onclick="resetDockerRawConfig()">Reset</button>
                    <span id="docker-raw-config-status" style="font-size:12px; color:var(--text-muted);"></span>
                </div>
            </div>

            <!-- Save/Cancel Bar -->
            <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px;padding-top:12px;border-top:1px solid var(--border);">
                <button class="btn btn-sm" onclick="closeContainerDetail()">Cancel</button>
                <button class="btn btn-sm btn-primary" onclick="saveDockerSettings('${name}')">Save Settings</button>
            </div>
        `;
        // Stash the as-loaded JSON so the Reset button can restore it.
        window._dockerRawConfigOriginal = JSON.stringify(cfg, null, 2);
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to load config: ${e.message}</p>`;
    }
}

/// Restore the raw-config textarea to the JSON captured at modal-open
/// time. Discards any edits the operator has been poking at.
function resetDockerRawConfig() {
    const ta = document.getElementById('docker-raw-config');
    if (!ta) return;
    ta.value = window._dockerRawConfigOriginal || '';
    const status = document.getElementById('docker-raw-config-status');
    if (status) status.textContent = 'Restored the as-loaded JSON.';
}
window.resetDockerRawConfig = resetDockerRawConfig;

/// Save the edited docker-inspect JSON — recreates the container
/// from the new spec. Parses the JSON client-side before submitting
/// so we surface syntax errors immediately; backend then walks the
/// parsed object and rebuilds the container.
async function saveDockerRawConfig(name) {
    const ta = document.getElementById('docker-raw-config');
    const status = document.getElementById('docker-raw-config-status');
    if (!ta) return;
    const text = ta.value;
    let parsed;
    try {
        parsed = JSON.parse(text);
    } catch (e) {
        if (status) {
            status.style.color = '#ef4444';
            status.textContent = 'Invalid JSON: ' + e.message;
        }
        return;
    }
    // Sanity prompt — this is destructive enough to deserve explicit
    // confirmation with a countdown, same UX as host-DNS release.
    const confirmed = (typeof showDangerConfirm === 'function')
        ? await showDangerConfirm({
            title: 'Recreate container from edited JSON?',
            danger: 'The running container "' + name + '" will be stopped and renamed; a fresh one is created from the JSON below, then the old one is removed on success.',
            detail: 'Data in named volumes and bind mounts survives (those are OUTSIDE the container layer). Logs and /var/log inside the container do NOT — they are in the layer and get discarded with the old container.',
            countdown: 6,
            confirmLabel: 'Recreate',
        })
        : await showConfirm('Recreate container "' + name + '" from the edited JSON?');
    if (!confirmed) return;
    if (status) {
        status.style.color = 'var(--text-muted)';
        status.textContent = 'Applying…';
    }
    try {
        const r = await fetch(apiUrl('/api/containers/docker/' + encodeURIComponent(name) + '/raw-config'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(parsed),
        });
        const data = await r.json().catch(() => ({}));
        if (!r.ok) {
            if (status) {
                status.style.color = '#ef4444';
                status.textContent = 'Failed: ' + (data.error || ('HTTP ' + r.status));
            }
            return;
        }
        if (status) {
            status.style.color = '#10b981';
            status.textContent = data.message || 'Recreated.';
        }
        showToast(data.message || 'Container recreated', 'success');
        // Refresh the list so the new container's state is visible.
        if (typeof loadDockerContainers === 'function') loadDockerContainers();
    } catch (e) {
        if (status) {
            status.style.color = '#ef4444';
            status.textContent = 'Error: ' + e.message;
        }
    }
}
window.saveDockerRawConfig = saveDockerRawConfig;

async function saveDockerSettings(name) {
    var restartPolicy = (document.getElementById('docker-restart-policy') || {}).value || 'no';
    var autostart = restartPolicy === 'always' || restartPolicy === 'unless-stopped';
    var memoryStr = (document.getElementById('docker-memory') || {}).value || '';
    var cpusStr = (document.getElementById('docker-cpus') || {}).value || '';

    var memoryMb = memoryStr ? parseInt(memoryStr) : null;
    var cpus = cpusStr ? parseFloat(cpusStr) : null;

    // Validate
    if (memoryMb !== null && (isNaN(memoryMb) || memoryMb < 0)) {
        showToast('Invalid memory value', 'error');
        return;
    }
    if (cpus !== null && (isNaN(cpus) || cpus < 0)) {
        showToast('Invalid CPU value', 'error');
        return;
    }

    var wolfnetIp = (document.getElementById('docker-wolfnet-ip') || {}).value || '';

    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/${encodeURIComponent(name)}/config`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                autostart: autostart,
                memory_mb: memoryMb,
                cpus: cpus,
                wolfnet_ip: wolfnetIp,
            })
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast('Settings saved — changes applied immediately', 'success');
            closeContainerDetail();
            if (typeof loadDockerContainers === 'function') loadDockerContainers();
        } else {
            showToast(data.error || 'Failed to save settings', 'error');
        }
    } catch (e) {
        showToast('Error saving settings: ' + e.message, 'error');
    }
}

function addDockerEnvRow() {
    const list = document.getElementById('docker-env-list');
    if (!list) return;
    // Remove the "no env vars" placeholder if present
    const empty = document.getElementById('docker-env-empty');
    if (empty) empty.remove();
    const row = document.createElement('div');
    row.className = 'docker-env-row';
    row.style.cssText = 'display:flex;align-items:center;gap:6px;padding:4px 0;margin-bottom:2px;';
    row.innerHTML = `
        <input type="text" class="docker-env-key" value="" placeholder="KEY"
            style="width:180px;padding:4px 8px;border-radius:4px;border:1px solid var(--border);background:var(--bg-primary);color:var(--accent);font-family:var(--font-mono);font-size:11px;">
        <span style="color:var(--text-muted);">=</span>
        <input type="text" class="docker-env-val" value="" placeholder="value"
            style="flex:1;padding:4px 8px;border-radius:4px;border:1px solid var(--border);background:var(--bg-primary);color:var(--text-primary);font-family:var(--font-mono);font-size:11px;">
        <button class="btn btn-sm" onclick="this.closest('.docker-env-row').remove()" style="font-size:14px;padding:2px 6px;color:var(--danger-color,#ef4444);" title="Remove">&times;</button>`;
    list.appendChild(row);
    row.querySelector('.docker-env-key').focus();
}

async function saveDockerEnv(name) {
    const rows = document.querySelectorAll('#docker-env-list .docker-env-row');
    const userVars = [];
    const keyPattern = /^[A-Za-z_][A-Za-z0-9_]*$/;
    for (const row of rows) {
        const key = row.querySelector('.docker-env-key').value.trim();
        const val = row.querySelector('.docker-env-val').value;
        if (key) {
            if (!keyPattern.test(key)) {
                showToast(`Invalid env key "${key}" — must match [A-Za-z_][A-Za-z0-9_]*`, 'error');
                row.querySelector('.docker-env-key').focus();
                return;
            }
            userVars.push(`${key}=${val}`);
        }
    }

    // Preserve system env vars (PATH, HOME, etc.)
    const systemVars = window._dockerSystemEnv || [];
    const env = [...systemVars, ...userVars];

    if (!await showConfirm(
        `This will recreate the container "${name}" with the updated environment variables. ` +
        `Volumes, ports, and other settings will be preserved. ` +
        `${userVars.length === 0 ? 'All user environment variables will be removed.' : `${userVars.length} user variable${userVars.length !== 1 ? 's' : ''} will be set.`}` +
        `${systemVars.length ? ` (${systemVars.length} system variables preserved)` : ''}\n\nContinue?`,
        'Update Environment'
    )) return;

    try {
        showToast(`Recreating "${name}" with updated env...`, 'info');
        const resp = await fetch(apiUrl(`/api/containers/docker/${encodeURIComponent(name)}/env`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ env }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || 'Environment updated', 'success');
            closeContainerDetail();
            if (typeof loadDockerContainers === 'function') loadDockerContainers();
        } else {
            showToast(data.error || 'Failed to update environment', 'error');
        }
    } catch (e) {
        showToast('Error updating environment: ' + e.message, 'error');
    }
}

// ─── LXC ───

let lxcPollTimer = null;
let _lxcLoadGeneration = 0;

async function loadLxcContainers() {
    // Cancel any existing poll timer immediately
    if (lxcPollTimer) { clearInterval(lxcPollTimer); lxcPollTimer = null; }

    // Pull the set of containers that already have VNC installed (drives the icon colour)
    loadContainerVncKeys();

    // Capture generation and node to detect stale responses
    const gen = ++_lxcLoadGeneration;
    const loadNodeId = currentNodeId;

    fetchContainerStatus();

    try {
        const [containersResp, statsResp] = await Promise.all([
            fetch(apiUrl('/api/containers/lxc')),
            fetch(apiUrl('/api/containers/lxc/stats')),
        ]);

        // Discard response if user switched to a different server/page
        if (gen !== _lxcLoadGeneration || currentNodeId !== loadNodeId) return;

        // A transient proxy failure (Pangolin/Traefik) returns a non-OK / non-
        // array body; rendering it (the old `: []` fallback did) would blank a
        // populated list until the next good poll — the flicker wabil saw behind
        // Pangolin but never nginx. Skip the render and keep what's shown; the
        // 15s poll retries (the timer below is still armed).
        if (containersResp.ok) {
            const containersData = await containersResp.json();
            if (Array.isArray(containersData)) {
                const statsData = statsResp.ok ? await statsResp.json() : [];
                // Hide ghost husks entirely (Paul 2026-06-24). Leftover PVE husks
                // (numeric old-VMID hostname, stopped) were never meant to be here;
                // listing them — even with a badge — led to an accidental destroy of
                // the wrong-looking VMID. The backend flag is stopped-only, so a
                // running container can never be hidden.
                const containers = containersData.filter(c => !c.possible_ghost);
                const hiddenGhosts = containersData.length - containers.length;
                if (hiddenGhosts > 0) console.info(`Hid ${hiddenGhosts} ghost husk container(s) from the LXC list`);
                const stats = Array.isArray(statsData) ? statsData : [];

                // Index stats by name
                const lxcStats = {};
                stats.forEach(s => { lxcStats[s.name] = s; });

                renderLxcContainers(containers, lxcStats);
                renderLxcCards(containers, lxcStats);
                applyContainerView('lxc');
                applyUpdateBadges();
                // Fire update summary check in background — don't block page render
                fetchContainerUpdateSummary();
            }
        }
    } catch (e) {
        console.error('Failed to load LXC containers:', e);
    }

    // Only set poll timer if we're still on this view/node
    if (gen === _lxcLoadGeneration && currentPage === 'lxc') {
        lxcPollTimer = setInterval(async () => {
            if (currentPage !== 'lxc') { clearInterval(lxcPollTimer); lxcPollTimer = null; return; }
            loadLxcContainers();
        }, isMobileView() ? 30000 : 15000);
    }
}

function renderLxcContainers(containers, stats) {
    const table = document.getElementById('lxc-containers-table');
    const empty = document.getElementById('lxc-empty');
    if (!table) return;

    if (containers.length === 0) {
        table.innerHTML = '';
        if (empty) empty.style.display = '';
        return;
    }
    if (empty) empty.style.display = 'none';

    const btnStyle = 'margin:2px;font-size:20px;line-height:1;padding:4px 6px;';
    const disStyle = 'margin:2px;font-size:20px;line-height:1;padding:4px 6px;color:#ef4444;opacity:0.4;cursor:not-allowed;pointer-events:none;';

    table.innerHTML = containers.map(c => {
        const s = stats[c.name] || {};
        const isRunning = c.state === 'running';
        const isFrozen = c.state === 'frozen';
        const stateColor = isRunning ? '#10b981' : isFrozen ? '#f59e0b' : '#6b7280';
        const hasStorage = c.disk_usage !== undefined && c.disk_total;
        const pct = hasStorage ? Math.round((c.disk_usage / c.disk_total) * 100) : 0;
        const barColor = pct > 90 ? '#ef4444' : pct > 70 ? '#f59e0b' : '#10b981';
        const fsLabel = c.fs_type ? `<span style="color:var(--text-muted);font-size:10px;margin-left:8px;">${c.fs_type}</span>` : '';
        const pathLabel = c.storage_path ? `<span style="color:var(--text-muted);font-size:10px;" title="${c.storage_path}">${c.storage_path.length > 30 ? '...' + c.storage_path.slice(-27) : c.storage_path}</span>` : '';
        const cpuPct = s.cpu_percent !== undefined ? Math.min(s.cpu_percent, 100) : -1;
        const cpuColor = cpuPct > 80 ? '#ef4444' : cpuPct > 50 ? '#f59e0b' : '#10b981';
        const memPct = (s.memory_usage && s.memory_limit) ? Math.min(Math.round((s.memory_usage / s.memory_limit) * 100), 100) : -1;
        const memColor = memPct > 90 ? '#ef4444' : memPct > 70 ? '#f59e0b' : '#10b981';

        const barSeg = (icon, pctVal, color, label) => `<div style="flex:1;display:flex;align-items:center;gap:6px;min-width:0;">
            <span>${icon}</span>
            <div style="flex:1;height:8px;background:var(--bg-tertiary,#333);border-radius:4px;overflow:hidden;">
                <div style="width:${pctVal}%;height:100%;background:${color};border-radius:4px;transition:width 0.3s;"></div>
            </div>
            <span style="white-space:nowrap;">${label}</span>
        </div>`;

        const statsSegs = [];
        if (cpuPct >= 0) statsSegs.push(barSeg('', cpuPct, cpuColor, s.cpu_percent.toFixed(1) + '%'));
        if (memPct >= 0) statsSegs.push(barSeg('', memPct, memColor, formatBytes(s.memory_usage) + ' / ' + formatBytes(s.memory_limit) + ' (' + memPct + '%)'));
        if (hasStorage) statsSegs.push(barSeg('', pct, barColor, formatBytes(c.disk_usage) + ' / ' + formatBytes(c.disk_total) + ' (' + pct + '%)'));

        const statsSubRow = statsSegs.length > 0 ? `<tr class="storage-sub-row" style="background:var(--bg-secondary);"><td colspan="6" style="padding:4px 16px 6px 24px;border-top:none;">
            <div style="display:flex;align-items:center;gap:16px;font-size:11px;">${statsSegs.join('')}</div>
        </td></tr>` : '';

        const lxcSvcItems = (c.services && c.services.length > 0) ? c.services.map(s => {
            const sColor = s.status === 'running' ? '#10b981' : '#ef4444';
            return `<span style="display:inline-block;font-size:10px;padding:1px 6px;border-radius:3px;background:${sColor}22;color:${sColor};border:1px solid ${sColor}44;">${s.name}</span>`;
        }).join('') : '';
        const lxcBadgeRow = `<div style="display:flex;flex-wrap:wrap;align-items:center;gap:4px;margin-top:3px;">${lxcSvcItems}<span data-update-badge="lxc:${c.name}"></span></div>`;

        return `<tr>
            <td><strong>${c.hostname || c.name}</strong>${lxcBadgeRow}${c.hostname ? `<div style="font-size:11px;color:var(--text-muted);">CT ${c.name}</div>` : ''}</td>
            <td style="font-size:12px;color:var(--text-secondary);">${c.version || '<span style="color:var(--text-muted)">—</span>'}</td>
            <td><span style="color:${stateColor}">●</span> ${c.state}</td>
            <td style="font-size:12px; font-family:monospace;">${c.ip_address || '-'}${c.gateway ? '<div style="font-size:10px;color:var(--text-muted);">GW: ' + escapeHtml(c.gateway) + '</div>' : ''}${c.mac_address ? '<div style="font-size:10px;color:var(--text-muted);">MAC: ' + escapeHtml(c.mac_address) + '</div>' : ''}</td>
            <td><input type="checkbox" ${c.autostart ? 'checked' : ''} onchange="toggleLxcAutostart('${c.name}', this.checked)"></td>
            <td><div style="display:flex; flex-wrap:wrap; gap:2px; min-width:0;">
                <button class="btn btn-sm" style="${isRunning ? disStyle : btnStyle}" ${isRunning ? 'disabled' : ''} ${!isRunning ? `onclick="lxcAction('${c.name}', 'start', this)"` : ''} title="Start"><span class="ws-icon-clean-wrap" data-icon="play"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? disStyle : btnStyle}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}', 'stop', this)"` : ''} title="Stop"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? disStyle : btnStyle}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}', 'restart', this)"` : ''} title="Restart"><span class="ws-icon-clean-wrap" data-icon="restart"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? disStyle : btnStyle}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="lxcAction('${c.name}', 'freeze', this)"` : ''} title="Freeze"><span class="ws-icon-clean-wrap" data-icon="snowflake"></span></button>
                <button class="btn btn-sm" style="${!isRunning ? disStyle : btnStyle}" ${!isRunning ? 'disabled' : ''} ${isRunning ? `onclick="openLxcConsole('${c.name}', '${c.hostname || c.name}')"` : ''} title="Console"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
                ${_containerVncBtnHtml('lxc', c.name, c.hostname || c.name, btnStyle, isRunning)}
                ${isRunning ? `<button class="btn btn-sm" style="${btnStyle}" onclick="reclaimLxcCache('${c.name}', this)" title="Reclaim cache — free this container's clean page cache. Safe: never touches its working memory, so the running app is not disrupted."><span class="ws-icon-clean-wrap" data-icon="memory"></span></button>` : ''}
                <button class="btn btn-sm" style="${isRunning ? disStyle : btnStyle}" ${isRunning ? 'disabled' : ''} ${!isRunning ? `onclick="lxcAction('${c.name}', 'destroy', this)"` : ''} title="Destroy"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="viewContainerLogs('lxc', '${c.name}')" title="Logs"><span class="ws-icon-clean-wrap" data-icon="logs"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="browseContainerFiles('lxc', '${c.name}', '${(c.storage_path || '').replace(/'/g, "\\'")}')" title="Browse Files"><span class="ws-icon-clean-wrap" data-icon="folder-open"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="editContainerConfigFile('lxc', '${c.name}')" title="Edit Config File"><span class="ws-icon-clean-wrap" data-icon="file-code"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="openLxcSettings('${c.name}')" title="Settings"><span class="ws-icon-clean-wrap" data-icon="settings"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="openContainerConfigurator('lxc', '${c.name}')" title="Configure"><span class="ws-icon-clean-wrap" data-icon="configure"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="openContainerUpdates('lxc', '${c.name}')" title="Check Updates"><span class="ws-icon-clean-wrap" data-icon="updates"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="openContainerCron('lxc', '${c.name}')" title="Cron Jobs"><span class="ws-icon-clean-wrap" data-icon="calendar"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="cloneLxcContainer('${c.name}')" title="Clone"><span class="ws-icon-clean-wrap" data-icon="copy"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="migrateLxcContainer('${c.name}')" title="Migrate"><span class="ws-icon-clean-wrap" data-icon="migrate"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="openLxcStorage('${escapeHtml(c.name)}')" title="Storage (resize / move)"><span class="ws-icon-clean-wrap" data-icon="hard-drive"></span></button>
                <button class="btn btn-sm" style="${btnStyle}" onclick="exportLxcContainer('${c.name}')" title="Export"><span class="ws-icon-clean-wrap" data-icon="export"></span></button>
            </div></td>
        </tr>${statsSubRow}`;
    }).join('');
}

// Reclaim a running LXC container's clean page cache (cgroup v2
// memory.reclaim, cache-only on the backend — never touches its working set,
// so the app keeps running). No confirm: it's non-destructive.
async function reclaimLxcCache(container, btn) {
    activityStart();
    const origHtml = btn ? btn.innerHTML : null;
    if (btn) {
        btn.disabled = true; btn.style.pointerEvents = 'none';
        btn.innerHTML = '<span style="display:inline-block;width:16px;height:16px;border:2px solid rgba(255,255,255,0.2);border-top-color:#fff;border-radius:50%;animation:spin 0.7s linear infinite;"></span>';
    }
    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${container}/reclaim-cache`), { method: 'POST' });
        const data = await resp.json();
        if (resp.ok) {
            const freed = data.freed_bytes || 0;
            showToast(freed > 0 ? `Reclaimed ${formatBytes(freed)} of cache from ${container}` : `No reclaimable cache in ${container}`, 'success');
            taskLog('LXC reclaim-cache: ' + container + ' freed ' + formatBytes(freed));
            setTimeout(loadLxcContainers, 500);
        } else {
            showToast(data.error || 'Cache reclaim failed', 'error');
            taskLog('LXC reclaim-cache: ' + container, 'failed');
        }
    } catch (e) {
        showToast(`Failed: ${e.message}`, 'error');
        taskLog('LXC reclaim-cache: ' + container, 'failed');
    } finally {
        // Restore the button (works in both the table and card views, neither
        // of which is guaranteed to re-render before this runs).
        if (btn && origHtml !== null) { btn.disabled = false; btn.style.pointerEvents = ''; btn.innerHTML = origHtml; }
        activityStop();
    }
}

async function lxcAction(container, action, btn) {
    if (action === 'destroy' && !(await showConfirm(`Destroy LXC container '${container}'? This cannot be undone.`))) return;
    if (action === 'freeze' && !(await showConfirm(
        `Freeze LXC container '${container}'?\n\nFreezing pauses every process inside the container. Network connections, DB writes, and anything holding a lock will stall until you Unfreeze. Click Confirm only if that's what you intended.`,
        'Freeze container'))) return;

    activityStart();
    const row = btn?.closest('tr');
    const buttons = row ? row.querySelectorAll('button') : [];
    buttons.forEach(b => { b.disabled = true; b.style.opacity = '0.4'; b.style.pointerEvents = 'none'; });
    if (btn) btn.innerHTML = '<span style="display:inline-block;width:16px;height:16px;border:2px solid rgba(255,255,255,0.2);border-top-color:#fff;border-radius:50%;animation:spin 0.7s linear infinite;"></span>';

    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${container}/action`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(`${action} ${container}: OK`, 'success');
            taskLog('LXC ' + action + ': ' + container);
            setTimeout(loadLxcContainers, 500);
        } else {
            showToast(data.error || `Failed to ${action}`, 'error');
            taskLog('LXC ' + action + ': ' + container, 'failed');
            buttons.forEach(b => { b.disabled = false; b.style.opacity = ''; b.style.pointerEvents = ''; });
        }
    } catch (e) {
        showToast(`Failed: ${e.message}`, 'error');
        taskLog('LXC ' + action + ': ' + container, 'failed');
        buttons.forEach(b => { b.disabled = false; b.style.opacity = ''; b.style.pointerEvents = ''; });
    } finally {
        activityStop();
    }
}

// ─── Shared Container Functions ───

async function viewContainerLogs(runtime, container) {
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');

    title.textContent = `${container} — Logs`;
    body.innerHTML = renderBlockSkeleton({lines:3});
    modal.classList.add('active');

    try {
        const resp = await fetch(apiUrl(`/api/containers/${runtime}/${container}/logs`));
        const data = await resp.json();
        const logs = data.logs || [];

        body.innerHTML = `
            <pre style="background: var(--bg-primary); border: 1px solid var(--border); border-radius: 8px; padding: 12px;
                font-family: 'JetBrains Mono', monospace; font-size: 12px; max-height: 400px; overflow-y: auto;
                color: var(--text-primary); white-space: pre-wrap; word-break: break-all;">${logs.length > 0 ? logs.join('\n') : 'No logs available'}</pre>
        `;
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to load logs: ${e.message}</p>`;
    }
}

function closeContainerDetail() {
    document.getElementById('container-detail-modal').classList.remove('active');
}

// ─── Container Update Checking ───

async function openContainerUpdates(runtime, container) {
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');
    const icon = runtime === 'docker' ? '' : '';

    title.textContent = `${container} — Package Updates`;
    body.innerHTML = `<p style="color:var(--text-muted);">Checking for updates inside ${icon} ${container}...</p>
        <div style="text-align:center;padding:20px;"><span style="display:inline-block;width:24px;height:24px;border:3px solid rgba(255,255,255,0.2);border-top-color:#fff;border-radius:50%;animation:spin 0.7s linear infinite;"></span></div>`;
    modal.classList.add('active');

    try {
        const resp = await fetch(apiUrl(`/api/containers/${runtime}/${encodeURIComponent(container)}/updates/check`), { method: 'POST' });
        const data = await resp.json();
        const count = data.count || 0;
        const list = data.list || '';
        const pm = data.package_manager || 'unknown';

        const countBadge = count > 0
            ? `<span style="display:inline-block;padding:4px 12px;border-radius:8px;font-size:14px;font-weight:600;background:rgba(245,158,11,0.15);color:#f59e0b;">${count} update${count !== 1 ? 's' : ''} available</span>`
            : '<span style="display:inline-block;padding:4px 12px;border-radius:8px;font-size:14px;font-weight:600;background:rgba(16,185,129,0.15);color:#10b981;">System is up to date</span>';

        body.innerHTML = `
            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;">
                <div>
                    ${countBadge}
                    <span style="margin-left:12px;font-size:12px;color:var(--text-muted);">Package manager: <strong>${pm}</strong></span>
                </div>
                <div style="display:flex;gap:8px;">
                    <button class="btn btn-sm" onclick="openContainerUpdates('${runtime}', '${container.replace(/'/g, "\\'")}')">Refresh</button>
                    ${count > 0 ? `<button class="btn btn-sm btn-primary" onclick="applyContainerUpdates('${runtime}', '${container.replace(/'/g, "\\'")}')">⬆️ Apply Updates</button>` : ''}
                </div>
            </div>
            ${list ? `<pre style="background:var(--bg-primary);border:1px solid var(--border);border-radius:8px;padding:12px;font-family:var(--font-mono);font-size:12px;max-height:400px;overflow-y:auto;color:var(--text);white-space:pre-wrap;word-break:break-all;">${escapeHtml(list)}</pre>` : ''}
        `;
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to check updates: ${escapeHtml(e.message)}</p>`;
    }
}

async function applyContainerUpdates(runtime, container) {
    if (!(await showConfirm(`Apply all pending updates inside ${container}? This may take a while.`))) return;

    const body = document.getElementById('container-detail-body');
    body.innerHTML = `<p style="color:var(--text-muted);">Applying updates inside ${container}...</p>
        <div style="text-align:center;padding:20px;"><span style="display:inline-block;width:24px;height:24px;border:3px solid rgba(255,255,255,0.2);border-top-color:#fff;border-radius:50%;animation:spin 0.7s linear infinite;"></span></div>
        <p style="color:var(--text-muted);font-size:12px;text-align:center;">This may take several minutes...</p>`;

    try {
        const resp = await fetch(apiUrl(`/api/containers/${runtime}/${encodeURIComponent(container)}/updates/apply`), { method: 'POST' });
        const data = await resp.json();
        if (data.ok) {
            const rawOutput = data.output || '';
            const lines = rawOutput.split('\n').filter(l => l.trim());
            const lineCount = lines.length;
            const preview = lines.slice(-20).join('\n');
            body.innerHTML = `
                <div style="margin-bottom:16px;">
                    <span style="display:inline-block;padding:4px 12px;border-radius:8px;font-size:14px;font-weight:600;background:rgba(16,185,129,0.15);color:#10b981;">Updates applied successfully</span>
                    <button class="btn btn-sm" style="margin-left:12px;" onclick="openContainerUpdates('${runtime}', '${container.replace(/'/g, "\\'")}')">Check Again</button>
                </div>
                <p style="font-size:12px;color:var(--text-muted);">${lineCount} packages processed</p>`;
            showToast('Updates applied to ' + container, 'success');
        } else {
            body.innerHTML = `<p style="color:#ef4444;">Failed to apply updates: ${escapeHtml(data.error || 'Unknown error')}</p>
                <button class="btn btn-sm" onclick="openContainerUpdates('${runtime}', '${container.replace(/'/g, "\\'")}')">Check Again</button>`;
        }
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed: ${escapeHtml(e.message)}</p>`;
    }
}

// ─── Container Cron Job Management ───

var _containerCronRuntime = '';
var _containerCronName = '';

async function openContainerCron(runtime, container) {
    _containerCronRuntime = runtime;
    _containerCronName = container;

    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');
    const icon = runtime === 'docker' ? '' : '';

    title.textContent = `${container} — Cron Jobs`;
    body.innerHTML = `<p style="color:var(--text-muted);">Loading cron jobs from ${icon} ${container}...</p>`;
    modal.classList.add('active');

    try {
        const resp = await fetch(apiUrl(`/api/containers/${runtime}/${encodeURIComponent(container)}/cron`));
        const data = await resp.json();
        const entries = data.entries || [];
        const raw = data.raw || '';

        let html = `
            <div class="card" style="margin-bottom:16px;">
                <div class="card-header"><h3 style="font-size:14px;">Add Cron Job</h3></div>
                <div class="card-body">
                    <div style="display:grid;grid-template-columns:180px 1fr auto;gap:10px;align-items:end;">
                        <div>
                            <label style="font-size:11px;color:var(--text-muted);">Schedule</label>
                            <select id="ct-cron-preset" class="form-control" style="font-size:12px;" onchange="onCtCronPresetChange()">
                                <option value="0 * * * *">Every Hour</option>
                                <option value="*/5 * * * *">Every 5 Minutes</option>
                                <option value="*/15 * * * *">Every 15 Minutes</option>
                                <option value="0 0 * * *">Daily at Midnight</option>
                                <option value="0 3 * * *">Daily at 3 AM</option>
                                <option value="0 0 * * 1">Every Monday</option>
                                <option value="0 0 1 * *">Monthly (1st)</option>
                                <option value="@reboot">On Reboot</option>
                                <option value="custom">Custom...</option>
                            </select>
                        </div>
                        <div>
                            <label style="font-size:11px;color:var(--text-muted);">Command</label>
                            <input type="text" id="ct-cron-command" class="form-control" placeholder="e.g. /usr/bin/backup.sh" style="font-family:var(--font-mono);font-size:12px;">
                        </div>
                        <button class="btn btn-primary btn-sm" onclick="addContainerCronJob()" style="height:34px;">Add</button>
                    </div>
                    <div id="ct-cron-custom-group" hidden style="margin-top:8px;">
                        <label style="font-size:11px;color:var(--text-muted);">Custom Schedule</label>
                        <input type="text" id="ct-cron-custom" class="form-control" placeholder="* * * * *" style="font-family:var(--font-mono);font-size:12px;max-width:200px;">
                    </div>
                    <div style="margin-top:8px;">
                        <label style="font-size:11px;color:var(--text-muted);">Comment (optional)</label>
                        <input type="text" id="ct-cron-comment" class="form-control" placeholder="Description" style="font-size:12px;">
                    </div>
                </div>
            </div>

            <div class="card" style="margin-bottom:16px;">
                <div class="card-header"><h3 style="font-size:14px;">Quick Actions</h3></div>
                <div class="card-body" style="display:flex;flex-wrap:wrap;gap:8px;">
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('apt-update')">System Updates (weekly)</button>
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('log-cleanup')">Clean Logs (daily)</button>
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('tmp-cleanup')">Clean /tmp (daily)</button>
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('certbot-renew')">Renew SSL Certs</button>
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('disk-usage')">Log Disk Usage (hourly)</button>
                    <button class="btn btn-sm" onclick="addContainerPremadeCron('health-check')">Health Check (5 min)</button>
                </div>
            </div>`;

        if (entries.length === 0) {
            html += '<div style="padding:20px;text-align:center;color:var(--text-muted);font-size:13px;">No cron jobs found in this container.</div>';
        } else {
            html += '<table style="width:100%;border-collapse:collapse;font-size:13px;">';
            html += '<thead><tr style="border-bottom:2px solid var(--border);">' +
                '<th style="padding:8px 10px;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Status</th>' +
                '<th style="padding:8px 10px;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Schedule</th>' +
                '<th style="padding:8px 10px;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Command</th>' +
                '<th style="padding:8px 10px;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Comment</th>' +
                '<th style="padding:8px 10px;color:var(--text-muted);font-size:11px;text-transform:uppercase;text-align:right;">Actions</th>' +
                '</tr></thead><tbody>';

            entries.forEach(function (e) {
                var statusBadge = e.enabled
                    ? renderStatusPill({ tone: 'ok', label: 'Active' })
                    : renderStatusPill({ tone: 'danger', label: 'Disabled' });

                html += '<tr style="border-bottom:1px solid var(--border);">' +
                    '<td style="padding:8px 10px;">' + statusBadge + '</td>' +
                    '<td style="padding:8px 10px;"><div style="font-weight:600;font-size:12px;">' + escapeHtml(e.human) + '</div>' +
                    '<div style="font-size:10px;color:var(--text-muted);font-family:var(--font-mono);">' + escapeHtml(e.schedule) + '</div></td>' +
                    '<td style="padding:8px 10px;font-family:var(--font-mono);font-size:11px;max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + escapeHtml(e.command) + '">' + escapeHtml(e.command) + '</td>' +
                    '<td style="padding:8px 10px;color:var(--text-muted);font-size:11px;">' + escapeHtml(e.comment || '—') + '</td>' +
                    '<td style="padding:8px 10px;text-align:right;white-space:nowrap;">' +
                    '<button class="btn btn-sm" onclick="toggleContainerCronJob(' + e.index + ', ' + e.enabled + ', \'' + escapeHtml(e.schedule).replace(/'/g, "\\'") + '\', \'' + escapeHtml(e.command).replace(/'/g, "\\'") + '\', \'' + escapeHtml(e.comment).replace(/'/g, "\\'") + '\')" title="' + (e.enabled ? 'Disable' : 'Enable') + '" style="font-size:14px;">' + (e.enabled ? '' : '▶️') + '</button> ' +
                    '<button class="btn btn-sm" onclick="deleteContainerCronJob(' + e.index + ')" title="Delete" style="color:var(--danger);font-size:14px;"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>' +
                    '</td></tr>';
            });
            html += '</tbody></table>';
        }

        if (raw) {
            html += `<details style="margin-top:16px;">
                <summary style="cursor:pointer;color:var(--text-muted);font-size:12px;">Raw Crontab</summary>
                <pre style="margin-top:8px;background:var(--bg-primary);border:1px solid var(--border);border-radius:8px;padding:12px;font-family:var(--font-mono);font-size:11px;color:var(--text);white-space:pre-wrap;word-break:break-all;">${escapeHtml(raw)}</pre>
            </details>`;
        }

        body.innerHTML = html;
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to load cron jobs: ${escapeHtml(e.message)}</p>`;
    }
}

var CONTAINER_PREMADE_CRON_JOBS = {
    'apt-update': { schedule: '0 2 * * 1', command: 'command -v apt >/dev/null && apt-get update -qq && apt-get upgrade -y -qq || command -v dnf >/dev/null && dnf upgrade -y -q || command -v yum >/dev/null && yum update -y -q || command -v apk >/dev/null && apk update && apk upgrade || command -v pacman >/dev/null && pacman -Syu --noconfirm', comment: 'System updates (weekly Mon 2AM)' },
    'log-cleanup': { schedule: '0 4 * * *', command: 'find /var/log -name "*.gz" -mtime +7 -delete 2>/dev/null; find /var/log -name "*.old" -mtime +7 -delete 2>/dev/null; find /var/log -name "*.[0-9]" -mtime +7 -delete 2>/dev/null', comment: 'Clean old logs (daily 4AM)' },
    'tmp-cleanup': { schedule: '0 6 * * *', command: 'find /tmp -type f -atime +7 -delete 2>/dev/null', comment: 'Clean /tmp files older than 7 days' },
    'certbot-renew': { schedule: '0 5 * * *', command: 'certbot renew --quiet 2>/dev/null', comment: 'Renew SSL certificates (daily 5AM)' },
    'disk-usage': { schedule: '0 * * * *', command: 'df -h / | tail -1 >> /var/log/disk-usage.log', comment: 'Log disk usage (hourly)' },
    'health-check': { schedule: '*/5 * * * *', command: 'ping -c 1 -W 2 8.8.8.8 >/dev/null 2>&1 || echo "$(date): Network unreachable" >> /var/log/health-check.log', comment: 'Health check (every 5 min)' }
};

async function addContainerPremadeCron(type) {
    var job = CONTAINER_PREMADE_CRON_JOBS[type];
    if (!job) return;
    if (!(await showConfirm('Add premade cron job to ' + _containerCronName + '?\n\nSchedule: ' + job.schedule + '\nCommand: ' + job.command + '\nComment: ' + job.comment))) return;
    try {
        var resp = await fetch(apiUrl(`/api/containers/${_containerCronRuntime}/${encodeURIComponent(_containerCronName)}/cron`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ schedule: job.schedule, command: job.command, comment: job.comment, enabled: true })
        });
        var data = await resp.json();
        if (data.status === 'saved') {
            showToast('Cron job added to ' + _containerCronName, 'success');
            openContainerCron(_containerCronRuntime, _containerCronName);
        } else {
            showToast('Error: ' + (data.error || 'Failed'), 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

function onCtCronPresetChange() {
    var sel = document.getElementById('ct-cron-preset');
    var custom = document.getElementById('ct-cron-custom-group');
    if (sel && custom) custom.hidden = (sel.value !== 'custom');
}

async function addContainerCronJob() {
    var sel = document.getElementById('ct-cron-preset');
    var schedule = sel.value;
    if (schedule === 'custom') {
        schedule = (document.getElementById('ct-cron-custom') || {}).value || '';
    }
    var command = (document.getElementById('ct-cron-command') || {}).value || '';
    var comment = (document.getElementById('ct-cron-comment') || {}).value || '';

    if (!schedule || !command) {
        showToast('Please enter both a schedule and a command.', 'warning');
        return;
    }

    try {
        var resp = await fetch(apiUrl(`/api/containers/${_containerCronRuntime}/${encodeURIComponent(_containerCronName)}/cron`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ schedule: schedule, command: command, comment: comment, enabled: true })
        });
        var data = await resp.json();
        if (data.status === 'saved') {
            showToast('Cron job added to ' + _containerCronName, 'success');
            openContainerCron(_containerCronRuntime, _containerCronName);
        } else {
            showToast('Error: ' + (data.error || 'Failed to save'), 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

async function deleteContainerCronJob(index) {
    if (!(await showConfirm('Delete this cron job from ' + _containerCronName + '?'))) return;
    try {
        var resp = await fetch(apiUrl(`/api/containers/${_containerCronRuntime}/${encodeURIComponent(_containerCronName)}/cron/${index}`), { method: 'DELETE' });
        var data = await resp.json();
        if (data.status === 'deleted') {
            showToast('Cron job deleted.', 'success');
            openContainerCron(_containerCronRuntime, _containerCronName);
        } else {
            showToast('Error: ' + (data.error || 'Failed to delete'), 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

async function toggleContainerCronJob(index, currentlyEnabled, schedule, command, comment) {
    try {
        var resp = await fetch(apiUrl(`/api/containers/${_containerCronRuntime}/${encodeURIComponent(_containerCronName)}/cron`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                schedule: schedule,
                command: command,
                comment: comment || '',
                index: index,
                enabled: !currentlyEnabled
            })
        });
        var data = await resp.json();
        if (data.status === 'saved') {
            showToast(currentlyEnabled ? 'Cron job disabled.' : 'Cron job enabled.', 'success');
            openContainerCron(_containerCronRuntime, _containerCronName);
        } else {
            showToast('Error: ' + (data.error || 'Failed'), 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

// ─── LXC Settings Editor (Tabbed) ───

var _lxcSettingsTab = 1;
var _lxcParsedCfg = null;
var _lxcPhysicalNics = [];  // physical NICs for the vSwitch-uplink picker; loaded by openLxcSettings
var _lxcSaving = false;     // re-entrancy guard for saveLxcSettings — blocks double-click double-saves

function switchLxcTab(tab) {
    _lxcSettingsTab = tab;
    document.querySelectorAll('.lxc-tab-page').forEach(p => p.style.display = 'none');
    document.querySelectorAll('.lxc-tab-btn').forEach(b => {
        b.style.borderBottomColor = 'transparent';
        b.style.color = 'var(--text-muted)';
    });
    var page = document.getElementById('lxc-tab-' + tab);
    var btn = document.querySelector('.lxc-tab-btn[data-ltab="' + tab + '"]');
    if (page) page.style.display = 'block';
    if (btn) { btn.style.borderBottomColor = 'var(--accent)'; btn.style.color = 'var(--text-primary)'; }
}

function generateMac() {
    var hex = '0123456789ABCDEF';
    var mac = '02';
    for (var i = 0; i < 5; i++) {
        mac += ':' + hex[Math.floor(Math.random() * 16)] + hex[Math.floor(Math.random() * 16)];
    }
    var el = document.getElementById('lxc-net-hwaddr');
    if (el) el.value = mac;
}

function generateMacFor(nicIndex) {
    var hex = '0123456789ABCDEF';
    var mac = '02';
    for (var i = 0; i < 5; i++) {
        mac += ':' + hex[Math.floor(Math.random() * 16)] + hex[Math.floor(Math.random() * 16)];
    }
    var el = document.querySelector(`.lxc-nic-field[data-nic="${nicIndex}"][data-field="hwaddr"]`);
    if (el) el.value = mac;
}

function toggleNicEditor(nicIndex) {
    var editor = document.getElementById('lxc-nic-editor-' + nicIndex);
    if (!editor) return;

    // If already showing, close it
    if (editor.style.display === 'block') {
        closeNicEditor();
        return;
    }

    // Close any other open editor first
    closeNicEditor();

    // Show as popup overlay
    var backdrop = document.getElementById('lxc-nic-backdrop');
    if (!backdrop) {
        backdrop = document.createElement('div');
        backdrop.id = 'lxc-nic-backdrop';
        backdrop.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:10001;display:flex;align-items:center;justify-content:center;';
        backdrop.onclick = function (e) { if (e.target === backdrop) closeNicEditor(); };
        document.body.appendChild(backdrop);
    }
    backdrop.style.display = 'flex';

    // Move the editor into the backdrop as a popup
    editor.style.display = 'block';
    editor.style.cssText = 'display:block;background:var(--bg-primary);border:1px solid var(--border);border-radius:12px;padding:20px;width:520px;max-width:90vw;max-height:80vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,0.4);';
    editor.setAttribute('data-was-nic', nicIndex);
    backdrop.innerHTML = '';
    backdrop.appendChild(editor);

    // Mark arrow
    var arrow = document.getElementById('lxc-nic-arrow-' + nicIndex);
    if (arrow) arrow.style.transform = 'rotate(90deg)';
}

function closeNicEditor() {
    var backdrop = document.getElementById('lxc-nic-backdrop');
    if (backdrop) {
        // Move editor back to its NIC item
        var editor = backdrop.querySelector('.lxc-nic-editor');
        if (editor) {
            var nicIdx = editor.getAttribute('data-was-nic');
            var nicItem = document.querySelector('.lxc-nic-item[data-nic-index="' + nicIdx + '"]');
            if (nicItem) {
                editor.style.cssText = 'display:none;padding:14px;border-top:1px solid var(--border);background:var(--bg-primary);';
                nicItem.appendChild(editor);
            }
            var arrow = document.getElementById('lxc-nic-arrow-' + nicIdx);
            if (arrow) arrow.style.transform = 'rotate(0deg)';
        }
        backdrop.style.display = 'none';
    }
}

// Build the <option> list for a NIC editor's "vSwitch uplink NIC"
// picker from the physical NICs openLxcSettings detected. `selected`
// is the NIC's currently-saved uplink (recovered by the backend from
// the VLAN attachment store) — it must be marked so the editor shows
// the real value instead of always falling back to "— none —".
function lxcUplinkOptions(selected) {
    var sel = (selected || '').trim();
    var opts = '<option value=""' + (sel ? '' : ' selected') + '>— none —</option>';
    var nics = (_lxcPhysicalNics || []).slice();
    // The saved uplink may not be in the detected list (NIC renamed, or
    // the node failed to enumerate interfaces). Keep it as an option so
    // the value still displays and round-trips on Save.
    if (sel && nics.indexOf(sel) === -1) nics.push(sel);
    nics.forEach(function (n) {
        var s = (n === sel) ? ' selected' : '';
        opts += `<option value="${escapeHtml(n)}"${s}>${escapeHtml(n)}</option>`;
    });
    return opts;
}

// When a vSwitch uplink NIC is chosen, the bridge is created and
// assigned automatically, so the Bridge / Link field is not used —
// grey it out (and clear it) to make that obvious.
function vswUplinkChanged(idx) {
    var sel = document.querySelector('.lxc-nic-field[data-nic="' + idx + '"][data-field="vsw_uplink"]');
    var link = document.querySelector('.lxc-nic-field[data-nic="' + idx + '"][data-field="link"]');
    if (!sel || !link) return;
    if (sel.value) {
        link.value = '';
        link.disabled = true;
        link.placeholder = 'set automatically by the vSwitch';
    } else {
        link.disabled = false;
        link.placeholder = 'e.g. lxcbr0, vmbr0';
    }
}

// Remove a network interface from the LXC settings editor. It's gone
// once the operator clicks Save — saveLxcSettings rebuilds the
// container's network config from whatever .lxc-nic-item rows remain.
async function removeLxcNic(idx) {
    if (typeof wolfConfirm === 'function' &&
        !await wolfConfirm('Remove this network interface? It is deleted when you click Save Settings.', 'Remove interface')) {
        return;
    }
    closeNicEditor();  // fold any open editor back so none is left orphaned
    var item = document.querySelector('.lxc-nic-item[data-nic-index="' + idx + '"]');
    if (item) item.remove();
}

function addLxcNic(name) {
    var list = document.getElementById('lxc-nic-list');
    if (!list) return;
    // Find the next available index
    var existing = list.querySelectorAll('.lxc-nic-item');
    var maxIdx = -1;
    existing.forEach(function (item) {
        var idx = parseInt(item.getAttribute('data-nic-index'));
        if (idx > maxIdx) maxIdx = idx;
    });
    var newIdx = maxIdx + 1;
    var html = `
        <div class="lxc-nic-item" data-nic-index="${newIdx}" style="margin-bottom:8px;border:1px solid var(--border);border-radius:8px;overflow:hidden;">
            <div class="lxc-nic-summary" onclick="toggleNicEditor(${newIdx})" style="display:flex;align-items:center;gap:12px;padding:10px 14px;cursor:pointer;background:var(--bg-tertiary);transition:background .15s;"
                 onmouseenter="this.style.background='var(--bg-secondary)'" onmouseleave="this.style.background='var(--bg-tertiary)'">
                <span style="font-size:16px;"></span>
                <div style="flex:1;min-width:0;">
                    <div style="font-weight:600;font-size:13px;">net${newIdx} — eth${newIdx}</div>
                    <div style="font-size:11px;color:var(--text-muted);font-family:monospace;">New interface</div>
                </div>
                <button class="btn btn-sm" onclick="event.stopPropagation(); removeLxcNic(${newIdx})" title="Remove interface" style="padding:2px 8px;line-height:1;color:#ef4444;"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                <span class="lxc-nic-arrow" id="lxc-nic-arrow-${newIdx}" style="font-size:12px;color:var(--text-muted);transition:transform .2s;">▶</span>
            </div>
            <div class="lxc-nic-editor" id="lxc-nic-editor-${newIdx}" style="display:none;padding:14px;border-top:1px solid var(--border);background:var(--bg-primary);">
                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;">
                    <h4 style="margin:0;font-size:14px;">Edit net${newIdx} — eth${newIdx}</h4>
                    <button class="btn btn-sm" onclick="closeNicEditor()" style="font-size:16px;padding:2px 8px;line-height:1;" title="Close"><span class="ws-icon-clean-wrap" data-icon="close"></span></button>
                </div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">Interface Name</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="name" value="eth${newIdx}" placeholder="eth${newIdx}">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">Type</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="net_type" value="veth" placeholder="veth">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">Bridge / Link</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="link" value="" placeholder="e.g. lxcbr0, vmbr0">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">MAC Address</label>
                        <div style="display:flex;gap:4px;">
                            <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="hwaddr" value="" placeholder="AA:BB:CC:DD:EE:FF" style="flex:1;">
                            <button class="btn btn-sm" onclick="generateMacFor(${newIdx})" title="Generate MAC" style="padding:4px 6px;font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="add"></span></button>
                        </div>
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">IPv4 Address / CIDR</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="ipv4" value="" placeholder="192.168.1.100/24 or blank for DHCP">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">IPv4 Gateway</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="ipv4_gw" value="" placeholder="192.168.1.1">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">IPv6 Address / CIDR</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="ipv6" value="" placeholder="fd00::100/64 or blank">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">IPv6 Gateway</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="ipv6_gw" value="" placeholder="fd00::1">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">MTU</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="mtu" value="" placeholder="Default">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">VLAN Tag</label>
                        <input type="text" class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="vlan" value="" placeholder="e.g. 4000">
                    </div>
                    <div class="form-group" style="margin:0;">
                        <label style="font-size:11px;">vSwitch uplink NIC</label>
                        <select class="form-control lxc-nic-field" data-nic="${newIdx}" data-field="vsw_uplink" onchange="vswUplinkChanged(${newIdx})">${lxcUplinkOptions()}</select>
                    </div>
                </div>
                <div style="font-size:11px;color:var(--text-muted);margin-top:8px;line-height:1.5;">
                    <strong>vSwitch VLAN:</strong> pick a <em>vSwitch uplink NIC</em> and set the <em>VLAN Tag</em> —
                    the VLAN ID your provider assigned (Hetzner: Robot → vSwitches, 4000–4091; OVH: your vRack VLAN
                    number). Leave <em>Bridge / Link</em> blank — on Save, WolfStack auto-creates the tagged
                    sub-interface and bridge (<code>vmbr&lt;vlan&gt;</code>) and attaches this NIC. Leave the uplink
                    on <em>— none —</em> for a plain bridge.
                </div>
                <div style="display:flex;justify-content:flex-end;margin-top:10px;">
                    <button class="btn btn-sm btn-primary" onclick="saveLxcSettings('${name}')">Save Settings</button>
                </div>
            </div>
        </div>`;
    list.insertAdjacentHTML('beforeend', html);
    // Auto-open the editor popup for the new NIC
    toggleNicEditor(newIdx);
}

function toggleIpv4Mode() {
    var mode = document.querySelector('input[name="lxc-ipv4-mode"]:checked');
    var staticFields = document.getElementById('lxc-ipv4-static-fields');
    if (staticFields) staticFields.style.display = (mode && mode.value === 'static') ? 'block' : 'none';
}

function toggleIpv6Mode() {
    var mode = document.querySelector('input[name="lxc-ipv6-mode"]:checked');
    var staticFields = document.getElementById('lxc-ipv6-static-fields');
    if (staticFields) staticFields.style.display = (mode && mode.value === 'static') ? 'block' : 'none';
}

async function findNextWolfnetIp() {
    try {
        var resp = await fetch(apiUrl('/api/wolfnet/next-ip'));
        var data = await resp.json();
        if (data.ip) {
            // The allocator hands out never-used IPs first; it only returns a
            // previously-used one when fresh addresses are exhausted. Reusing a
            // released IP can be unreachable if the old node's routing wasn't
            // fully withdrawn — so confirm before filling it in.
            if (data.previously_used && !(await showConfirm(
                `All fresh WolfNet IPs are taken, so ${data.ip} — which has been used before — is the next free one.\n\nIf its previous assignment isn't fully cleared, the address may not be reachable from other nodes. Use ${data.ip} anyway?`,
                'Reusing a WolfNet IP'))) {
                return;
            }
            var el = document.getElementById('lxc-wolfnet-ip');
            if (el) { el.value = data.ip; checkWolfnetIpReuse(el); }
            showToast('Next available: ' + data.ip + (data.previously_used ? ' (previously used)' : ''), data.previously_used ? 'warning' : 'success');
        } else {
            showToast('No available WolfNet IPs (10.10.10.2-254 all used)', 'error');
        }
    } catch (e) {
        showToast('Failed to check available IPs: ' + e.message, 'error');
    }
}

// Warn — inline, non-blocking — when a manually-entered WolfNet IP has been
// used before or is currently held by a workload, so the operator sees the risk
// before saving (klasSponsor 2026-06-24: reusing a released IP black-holed
// because the old node's routing was stale). Wired to the WolfNet IP inputs'
// onchange.
async function checkWolfnetIpReuse(el) {
    if (!el) return;
    const noteId = el.id + '-reuse-note';
    const existing = document.getElementById(noteId);
    if (existing) existing.remove();
    const ip = (el.value || '').trim();
    if (!ip || ip.toLowerCase().startsWith('auto')) return;
    try {
        const r = await fetch(apiUrl('/api/wolfnet/ip-status?ip=' + encodeURIComponent(ip)));
        if (!r.ok) return;
        const d = await r.json();
        if (!d.active_holder && !d.previously_used) return;
        const msg = d.active_holder
            ? `⚠ ${escapeHtml(ip)} is currently in use (on ${escapeHtml(String(d.active_holder))}). Assigning it here will conflict — pick a different IP.`
            : `⚠ ${escapeHtml(ip)} has been used before. If its previous assignment isn't fully cleared it may be unreachable from other nodes — a never-used IP is safer.`;
        const note = document.createElement('div');
        note.id = noteId;
        note.style.cssText = 'margin-top:4px; font-size:11px; color:var(--warning); font-weight:500; line-height:1.4;';
        note.innerHTML = msg;
        el.insertAdjacentElement('afterend', note);
    } catch (_) { /* non-fatal */ }
}

async function openLxcSettings(name) {
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');

    title.textContent = `${name} — Settings`;
    body.innerHTML = renderBlockSkeleton({lines:3});
    modal.classList.add('active');
    _lxcSettingsTab = 1;

    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/parsed-config`));
        if (!resp.ok) throw new Error('Failed to load config');
        const cfg = await resp.json();
        _lxcParsedCfg = cfg;

        // Physical NICs for the vSwitch-uplink picker in the NIC editor.
        _lxcPhysicalNics = [];
        try {
            const ifr = await fetch(apiUrl('/api/networking/interfaces'));
            if (ifr.ok) {
                const ifs = await ifr.json();
                if (Array.isArray(ifs)) {
                    _lxcPhysicalNics = ifs
                        .filter(i => !i.is_vlan
                            && !i.name.startsWith('docker') && !i.name.startsWith('br-')
                            && !i.name.startsWith('veth') && !i.name.startsWith('wn')
                            && !i.name.startsWith('wolfnet') && !i.name.startsWith('lo')
                            && !i.name.startsWith('vmbr'))
                        .map(i => i.name);
                }
            }
        } catch (_) { /* picker falls back to "— none —" only */ }

        // Auto-generate MAC if missing or invalid
        var macRegex = /^([0-9A-Fa-f]{2}:){5}[0-9A-Fa-f]{2}$/;
        if (!cfg.net_hwaddr || !macRegex.test(cfg.net_hwaddr.trim())) {
            var hex = '0123456789ABCDEF';
            cfg.net_hwaddr = '02';
            for (var mi = 0; mi < 5; mi++) {
                cfg.net_hwaddr += ':' + hex[Math.floor(Math.random() * 16)] + hex[Math.floor(Math.random() * 16)];
            }
        }

        var ipv4Mode = cfg.net_ipv4 ? 'static' : 'dhcp';
        var ipv6Mode = cfg.net_ipv6 ? 'static' : (cfg.net_ipv6_gw ? 'static' : 'none');

        // Fetch mounts
        var mounts = [];
        try {
            const mr = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/mounts`));
            mounts = await mr.json();
        } catch (e) { }

        var mountRows = mounts.length > 0 ? mounts.map(m => `
            <div style="display:flex;align-items:center;gap:8px;padding:6px 8px;margin-bottom:4px;background:var(--bg-primary);border-radius:6px;border:1px solid var(--border);">
                <code style="flex:1;font-size:12px;color:var(--accent);">${escapeHtml(m.host_path)}</code>
                <span style="color:var(--text-muted);font-size:12px;">→</span>
                <code style="flex:1;font-size:12px;color:var(--text-primary);">${escapeHtml(m.container_path)}</code>
                ${m.read_only ? '<span class="badge" style="font-size:10px;">RO</span>' : ''}
                <button class="btn btn-sm" style="font-size:11px;padding:2px 6px;color:var(--danger);"
                    onclick="removeLxcMount('${name}','${m.host_path.replace(/'/g, "\\'")}')" title="Remove"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
            </div>
        `).join('') : '<div style="color:var(--text-muted);font-size:12px;padding:8px;">No bind mounts configured</div>';

        var tabBtnStyle = 'flex:1;padding:10px 12px;border:none;background:none;font-size:13px;font-weight:600;cursor:pointer;transition:all .2s;';

        body.innerHTML = `
            <!-- Tab Bar -->
            <div style="display:flex;border-bottom:1px solid var(--border);background:var(--bg-secondary);margin:-24px -24px 16px -24px;">
                <button class="lxc-tab-btn" data-ltab="1" onclick="switchLxcTab(1)"
                    style="${tabBtnStyle}border-bottom:2px solid var(--accent);color:var(--text-primary);">
                    General
                </button>
                <button class="lxc-tab-btn" data-ltab="2" onclick="switchLxcTab(2)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Network
                </button>
                <button class="lxc-tab-btn" data-ltab="3" onclick="switchLxcTab(3)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Resources
                </button>
                <button class="lxc-tab-btn" data-ltab="4" onclick="switchLxcTab(4)"
                    style="${tabBtnStyle}border-bottom:2px solid transparent;color:var(--text-muted);">
                    Features
                </button>
            </div>

            <!-- ═══ Tab 1: General ═══ -->
            <div class="lxc-tab-page" id="lxc-tab-1">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div class="form-group">
                        <label>Container Name</label>
                        <input type="text" class="form-control" value="${escapeHtml(name)}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                    <div class="form-group">
                        <label>Hostname</label>
                        <input type="text" id="lxc-hostname" class="form-control" value="${escapeHtml(cfg.hostname)}"
                            placeholder="Same as container name">
                    </div>
                    <div class="form-group">
                        <label>Architecture</label>
                        <input type="text" class="form-control" value="${escapeHtml(cfg.arch || 'auto')}" readonly
                            style="opacity:0.7;cursor:not-allowed;">
                    </div>
                    ${cfg.storage_path ? `<div class="form-group">
                        <label>Storage</label>
                        <input type="text" class="form-control" value="${escapeHtml(cfg.storage_path)}" readonly
                            style="opacity:0.7;cursor:not-allowed;font-size:12px;">
                    </div>` : ''}
                    <div class="form-group">
                        <label>Privilege Mode</label>
                        <select id="lxc-unprivileged" class="form-control">
                            <option value="false" ${cfg.unprivileged ? '' : 'selected'}>Privileged</option>
                            <option value="true" ${cfg.unprivileged ? 'selected' : ''}>Unprivileged</option>
                        </select>
                    </div>
                </div>
                <div style="margin-top:12px;padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <h4 style="margin:0 0 8px 0;font-size:13px;color:var(--text-primary);">Boot Options</h4>
                    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;">
                        <div class="form-group" style="margin:0;">
                            <label style="display:flex;align-items:center;gap:8px;cursor:pointer;">
                                <input type="checkbox" id="lxc-autostart" ${cfg.autostart ? 'checked' : ''}>
                                Autostart on Boot
                            </label>
                        </div>
                        <div class="form-group" style="margin:0;">
                            <label>Start Delay (s)</label>
                            <input type="number" id="lxc-start-delay" class="form-control" value="${cfg.start_delay}" min="0">
                        </div>
                        <div class="form-group" style="margin:0;">
                            <label>Start Order</label>
                            <input type="number" id="lxc-start-order" class="form-control" value="${cfg.start_order}" min="0"
                                placeholder="Higher = starts first">
                        </div>
                    </div>
                </div>
                <div class="form-group" style="margin-top:12px;">
                    <label for="lxc-notes">Notes / Description <small style="color:var(--text-muted);">(optional)</small></label>
                    <textarea id="lxc-notes" class="form-control" rows="3" maxlength="4096"
                        placeholder="Free-text notes about this container (purpose, owner, maintenance window…)"
                        style="resize:vertical;">${escapeHtml(cfg.notes || '')}</textarea>
                </div>
            </div>

            <!-- ═══ Tab 2: Network ═══ -->
            <div class="lxc-tab-page" id="lxc-tab-2" style="display:none;">
                <div id="lxc-nic-list">
                ${((cfg.network_interfaces || []).length > 0 ? cfg.network_interfaces : [{ index: 0, net_type: 'veth', name: 'eth0', link: '', hwaddr: '', ipv4: '', ipv4_gw: '', ipv6: '', ipv6_gw: '', mtu: '', vlan: '' }]).map(nic => `
                    <div class="lxc-nic-item" data-nic-index="${nic.index}" style="margin-bottom:8px;border:1px solid var(--border);border-radius:8px;overflow:hidden;">
                        <div class="lxc-nic-summary" onclick="toggleNicEditor(${nic.index})" style="display:flex;align-items:center;gap:12px;padding:10px 14px;cursor:pointer;background:var(--bg-tertiary);transition:background .15s;"
                             onmouseenter="this.style.background='var(--bg-secondary)'" onmouseleave="this.style.background='var(--bg-tertiary)'">
                            <span style="font-size:16px;"></span>
                            <div style="flex:1;min-width:0;">
                                <div style="font-weight:600;font-size:13px;">net${nic.index} — ${escapeHtml(nic.name || 'eth' + nic.index)}</div>
                                <div style="font-size:11px;color:var(--text-muted);font-family:monospace;display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:2px 12px;">
                                    <span>IP: ${escapeHtml(nic.ipv4) || 'DHCP'}</span>
                                    <span>GW: ${escapeHtml(nic.ipv4_gw) || '-'}</span>
                                    <span>MAC: ${escapeHtml(nic.hwaddr) || '-'}</span>
                                    <span>Bridge: ${escapeHtml(nic.link) || '-'}</span>
                                    <span>Type: ${escapeHtml(nic.net_type) || 'veth'}</span>
                                    ${nic.mtu ? `<span>MTU: ${escapeHtml(nic.mtu)}</span>` : ''}
                                    ${nic.vlan ? `<span>VLAN: ${escapeHtml(nic.vlan)}</span>` : ''}
                                    ${nic.ipv6 ? `<span>IPv6: ${escapeHtml(nic.ipv6)}</span>` : ''}
                                    ${nic.ipv6_gw ? `<span>IPv6 GW: ${escapeHtml(nic.ipv6_gw)}</span>` : ''}
                                </div>
                            </div>
                            <button class="btn btn-sm" onclick="event.stopPropagation(); removeLxcNic(${nic.index})" title="Remove interface" style="padding:2px 8px;line-height:1;color:#ef4444;"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                            <span class="lxc-nic-arrow" id="lxc-nic-arrow-${nic.index}" style="font-size:12px;color:var(--text-muted);transition:transform .2s;">▶</span>
                        </div>
                        <div class="lxc-nic-editor" id="lxc-nic-editor-${nic.index}" style="display:none;padding:14px;border-top:1px solid var(--border);background:var(--bg-primary);">
                            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;">
                                <h4 style="margin:0;font-size:14px;">Edit net${nic.index} — ${escapeHtml(nic.name || 'eth' + nic.index)}</h4>
                                <button class="btn btn-sm" onclick="closeNicEditor()" style="font-size:16px;padding:2px 8px;line-height:1;" title="Close"><span class="ws-icon-clean-wrap" data-icon="close"></span></button>
                            </div>
                            <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">Interface Name</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="name" value="${escapeHtml(nic.name || 'eth' + nic.index)}" placeholder="eth${nic.index}">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">Type</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="net_type" value="${escapeHtml(nic.net_type || 'veth')}" placeholder="veth">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">Bridge / Link</label>
                                    <input type="text" id="lxc-nic-link-${nic.index}" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="link" value="${escapeHtml(nic.link)}" placeholder="e.g. lxcbr0, vmbr0">
                                    <div style="margin-top:5px;">
                                        <button type="button" class="btn btn-sm" onclick="openCreateLanBridge('lxc-nic-link-${nic.index}','')" style="font-size:11px; padding:3px 8px;">+ Create LAN bridge</button>
                                        <span style="font-size:10px; color:var(--text-muted); margin-left:6px;">Builds a real LAN bridge and fills this field with its name.</span>
                                    </div>
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">MAC Address</label>
                                    <div style="display:flex;gap:4px;">
                                        <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="hwaddr" value="${escapeHtml(nic.hwaddr)}" placeholder="AA:BB:CC:DD:EE:FF" style="flex:1;">
                                        <button class="btn btn-sm" onclick="generateMacFor(${nic.index})" title="Generate MAC" style="padding:4px 6px;font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="refresh"></span></button>
                                    </div>
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">IPv4 Address / CIDR</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="ipv4" value="${escapeHtml(nic.ipv4)}" placeholder="192.168.1.100/24 or blank for DHCP">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">IPv4 Gateway</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="ipv4_gw" value="${escapeHtml(nic.ipv4_gw)}" placeholder="192.168.1.1">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">IPv6 Address / CIDR</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="ipv6" value="${escapeHtml(nic.ipv6)}" placeholder="fd00::100/64 or blank">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">IPv6 Gateway</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="ipv6_gw" value="${escapeHtml(nic.ipv6_gw)}" placeholder="fd00::1">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">MTU</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="mtu" value="${escapeHtml(nic.mtu)}" placeholder="Default">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">VLAN Tag</label>
                                    <input type="text" class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="vlan" value="${escapeHtml(nic.vlan)}" placeholder="e.g. 4000">
                                </div>
                                <div class="form-group" style="margin:0;">
                                    <label style="font-size:11px;">vSwitch uplink NIC</label>
                                    <select class="form-control lxc-nic-field" data-nic="${nic.index}" data-field="vsw_uplink" onchange="vswUplinkChanged(${nic.index})">${lxcUplinkOptions(nic.vsw_uplink)}</select>
                                </div>
                            </div>
                            <div style="font-size:11px;color:var(--text-muted);margin-top:8px;line-height:1.5;">
                                <strong>vSwitch VLAN:</strong> pick a <em>vSwitch uplink NIC</em> and set the
                                <em>VLAN Tag</em> — the VLAN ID your provider assigned (Hetzner: Robot → vSwitches,
                                4000–4091; OVH: your vRack VLAN number). Leave <em>Bridge / Link</em> blank — on Save,
                                WolfStack auto-creates the tagged sub-interface and bridge
                                (<code>vmbr&lt;vlan&gt;</code>) and attaches this NIC.
                            </div>
                            <div style="display:flex;justify-content:flex-end;margin-top:10px;">
                                <button class="btn btn-sm btn-primary" onclick="saveLxcSettings('${name}')">Save Settings</button>
                            </div>
                        </div>
                    </div>
                `).join('')}
                </div>

                <button class="btn btn-sm" onclick="addLxcNic('${name}')" style="margin-top:4px;font-size:11px;padding:6px 12px;">+ Add Interface</button>
                <button class="btn btn-sm" onclick="openCreateLanBridge('','')" style="margin-top:4px;margin-left:6px;font-size:11px;padding:6px 12px;">+ Create LAN bridge</button>
                <div style="font-size:11px;color:var(--text-muted);margin-top:6px;">Click a NIC above to set its <strong>Bridge / Link</strong> (e.g. a LAN bridge for direct LAN access). Use <strong>+ Create LAN bridge</strong> to build one first.</div>

                <div style="margin-top:12px;padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <h4 style="margin:0 0 8px 0;font-size:13px;">WolfNet</h4>
                    <div style="display:grid;grid-template-columns:1fr auto;gap:8px;align-items:end;">
                        <div class="form-group" style="margin:0;">
                            <label>WolfNet IP</label>
                            <input type="text" id="lxc-wolfnet-ip" class="form-control" value="${escapeHtml(cfg.wolfnet_ip || '')}" onchange="checkWolfnetIpReuse(this)"
                                placeholder="e.g. 10.10.10.50 (leave blank for none)">
                        </div>
                        <div style="display:flex;gap:4px;padding-bottom:2px;">
                            <button class="btn btn-sm" onclick="findNextWolfnetIp()" title="Find next available WolfNet IP"
                                style="padding:6px 10px;font-size:11px;">Next Available</button>
                        </div>
                    </div>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:6px;">Gateway is handled automatically by WolfNet — no need to configure it here.</div>
                    <div id="wolfnet-ip-warning" style="display:none;font-size:11px;color:var(--warning);margin-top:4px;"></div>
                </div>
            </div>

            <!-- ═══ Tab 3: Resources ═══ -->
            <div class="lxc-tab-page" id="lxc-tab-3" style="display:none;">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div class="form-group">
                        <label>Memory Limit (MB)</label>
                        <input type="text" id="lxc-memory" class="form-control" value="${escapeHtml(cfg.memory_limit)}"
                            placeholder="e.g. 2048 (leave blank for unlimited)">
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">Enter value in MB. Leave blank for unlimited.</small>
                    </div>
                    <div class="form-group">
                        <label>Swap Limit (MB)</label>
                        <input type="text" id="lxc-swap" class="form-control" value="${escapeHtml(cfg.swap_limit)}"
                            placeholder="e.g. 512 (0 to disable, blank for unlimited)">
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">Enter value in MB. 0 to disable, blank for unlimited.</small>
                    </div>
                    <div class="form-group">
                        <label>CPU Cores</label>
                        <input type="text" id="lxc-cpus" class="form-control" value="${escapeHtml(cfg.cpus)}"
                            placeholder="${cfg.proxmox ? 'e.g. 4' : 'e.g. 4   —  or 0-3 / 0,2 to pin'}"
                            ${cfg.proxmox ? '' : `oninput="updateLxcCpuSummary(this.value)"`}>
                        <small style="color:var(--text-muted);margin-top:4px;display:block;">${cfg.proxmox
                            ? 'Number of cores. Leave blank for unlimited. Restart the container to apply.'
                            : 'Plain number = soft CPU limit (e.g. <b>4</b> caps the container at 4 cores\' worth of CPU time, but the kernel can schedule it on <i>any</i> host CPU). A cpuset list <i>pins</i> the container to specific CPUs: <b>0-3</b> is the range 0,1,2,3 (4 CPUs, pinned); <b>0,3</b> is the list CPU 0 and CPU 3 only (2 CPUs, pinned). Pinning is rarely what you want — prefer a plain number unless you specifically need affinity. Blank = unlimited. Restart the container to apply.'}</small>
                        ${cfg.proxmox ? '' : `<small id="lxc-cpu-summary" style="color:var(--accent-color,#7c3aed);margin-top:4px;display:block;font-weight:500;"></small>`}
                    </div>
                </div>

                <div style="margin-top:16px;padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);">
                    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
                        <h4 style="margin:0;font-size:13px;">Bind Mounts (${mounts.length})</h4>
                        <div style="display:flex;gap:4px;">
                            <button class="btn btn-sm" onclick="addMountPoint('${name}')"
                                style="font-size:11px;padding:4px 8px;">+ Mount</button>
                            <button class="btn btn-sm" onclick="addWolfDiskMount('${name}')"
                                style="font-size:11px;padding:4px 8px;">WolfDisk</button>
                        </div>
                    </div>
                    ${mountRows}
                </div>
            </div>

            <!-- ═══ Tab 4: Features & Advanced ═══ -->
            <div class="lxc-tab-page" id="lxc-tab-4" style="display:none;">
                <div style="padding:12px;background:var(--bg-tertiary);border-radius:8px;border:1px solid var(--border);margin-bottom:12px;">
                    <h4 style="margin:0 0 12px 0;font-size:13px;color:var(--text-primary);">Device & Feature Toggles</h4>
                    <div style="display:grid;gap:10px;">
                        <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;padding:8px;border-radius:6px;background:var(--bg-primary);border:1px solid var(--border);">
                            <input type="checkbox" id="lxc-feat-tun" ${cfg.tun_enabled ? 'checked' : ''} style="margin-top:2px;">
                            <div>
                                <strong style="font-size:13px;">TUN/TAP Device</strong>
                                <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">
                                    Required for Tailscale, WireGuard, OpenVPN, and other VPN software.
                                    Enables <code>/dev/net/tun</code> inside the container.
                                </div>
                            </div>
                        </label>
                        <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;padding:8px;border-radius:6px;background:var(--bg-primary);border:1px solid var(--border);">
                            <input type="checkbox" id="lxc-feat-fuse" ${cfg.fuse_enabled ? 'checked' : ''} style="margin-top:2px;">
                            <div>
                                <strong style="font-size:13px;">FUSE</strong>
                                <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">
                                    Required for AppImage, sshfs, rclone mount, and other FUSE-based filesystems.
                                </div>
                            </div>
                        </label>
                        <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;padding:8px;border-radius:6px;background:var(--bg-primary);border:1px solid var(--border);">
                            <input type="checkbox" id="lxc-feat-nesting" ${cfg.nesting_enabled ? 'checked' : ''} style="margin-top:2px;">
                            <div>
                                <strong style="font-size:13px;">Nesting (LXC/Docker inside container)</strong>
                                <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">
                                    Allows running Docker or LXC containers inside this container.
                                    Required for Docker-in-LXC setups.
                                </div>
                            </div>
                        </label>
                        <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;padding:8px;border-radius:6px;background:var(--bg-primary);border:1px solid var(--border);">
                            <input type="checkbox" id="lxc-feat-nfs" ${cfg.nfs_enabled ? 'checked' : ''} style="margin-top:2px;">
                            <div>
                                <strong style="font-size:13px;">NFS</strong>
                                <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">
                                    Allow mounting NFS shares inside the container.
                                </div>
                            </div>
                        </label>
                        <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;padding:8px;border-radius:6px;background:var(--bg-primary);border:1px solid var(--border);">
                            <input type="checkbox" id="lxc-feat-keyctl" ${cfg.keyctl_enabled ? 'checked' : ''} style="margin-top:2px;">
                            <div>
                                <strong style="font-size:13px;">Keyctl (systemd support)</strong>
                                <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">
                                    Required for full systemd functionality in unprivileged containers.
                                    Enables proc and sys read-write mounts.
                                </div>
                            </div>
                        </label>
                    </div>
                </div>

                <details>
                    <summary style="cursor:pointer;color:var(--accent);font-size:12px;margin-bottom:8px;">
                        Raw Config Editor
                    </summary>
                    <div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;">
                        Advanced: Edit the raw LXC config. Changes here override the structured settings above.
                        A backup is created automatically before saving.
                    </div>
                    <textarea id="lxc-config-editor" style="width:100%;height:250px;background:var(--bg-primary);color:var(--text-primary);
                        border:1px solid var(--border);border-radius:8px;padding:12px;font-family:'JetBrains Mono',monospace;
                        font-size:12px;resize:vertical;line-height:1.5;">${escapeHtml(cfg.raw_config)}</textarea>
                </details>
            </div>

            <!-- Save/Cancel Bar — sticky at the bottom so it's always
                 visible even when a NIC editor or raw-config textarea
                 pushes the page way past the fold. Users were missing
                 the button entirely because expanding the Network tab's
                 NIC editor scrolled it off-screen with no hint that
                 "scroll further down to save" was needed. -->
            <div style="position:sticky;bottom:0;display:flex;justify-content:flex-end;gap:8px;padding:12px 0;border-top:1px solid var(--border);background:var(--bg-primary,#1e1e2e);z-index:10;">
                <button class="btn btn-sm" onclick="closeContainerDetail()">Cancel</button>
                <button class="btn btn-sm btn-primary" onclick="saveLxcSettings('${name}')">Save Settings</button>
            </div>
        `;

        // A vSwitch NIC comes back with a recovered uplink. vswUplinkChanged
        // only fires on user input, so run it once per such NIC to grey out
        // the auto-managed Bridge/Link field — matching how the NIC looks
        // right after the vSwitch is first configured.
        (cfg.network_interfaces || []).forEach(function (nic) {
            if (nic.vsw_uplink) vswUplinkChanged(nic.index);
        });

        // Paint the CPU summary line ("= N CPUs") from the loaded value.
        if (!cfg.proxmox) updateLxcCpuSummary(cfg.cpus || '');
    } catch (e) {
        body.innerHTML = `<p style="color:#ef4444;">Failed to load config: ${e.message}</p>`;
    }
}

// Resolve a CPU Cores field value to a human-readable summary. A bare
// number is a soft CFS-quota limit ("cap at N cores' worth of CPU
// time"). A cpuset list/range is hard pinning ("only run on these
// specific host CPUs"). Spelled out so "0-26" isn't read as "CPU 0 and
// CPU 26", and so the operator sees pin-vs-quota explicitly in the UI.
function updateLxcCpuSummary(raw) {
    var el = document.getElementById('lxc-cpu-summary');
    if (!el) return;
    var s = (raw || '').trim();
    if (s === '') { el.textContent = '= unlimited (no CPU cap)'; return; }
    // Bare count: soft CFS-quota limit; not pinning.
    if (/^\d+$/.test(s)) {
        var n = parseInt(s, 10);
        if (n === 0) { el.textContent = '= unlimited (no CPU cap)'; return; }
        var label = n === 1 ? '1 core' : (n + ' cores');
        el.textContent = '= soft limit: up to ' + label + ' of CPU time (scheduler may use any host CPU)';
        return;
    }
    // Cpuset list/range — hard pinning. Validate, then count distinct CPUs.
    var parts = s.split(',');
    var cpus = new Set();
    for (var i = 0; i < parts.length; i++) {
        var p = parts[i].trim();
        var m = p.match(/^(\d+)-(\d+)$/);
        if (m) {
            var lo = parseInt(m[1], 10), hi = parseInt(m[2], 10);
            if (hi < lo) { el.textContent = 'Invalid cpuset (range ' + p + ' is reversed)'; return; }
            for (var c = lo; c <= hi; c++) cpus.add(c);
        } else if (/^\d+$/.test(p)) {
            cpus.add(parseInt(p, 10));
        } else {
            el.textContent = 'Invalid cpuset — use a number, range (0-3), or list (0,2,4)';
            return;
        }
    }
    var count = cpus.size;
    var list = Array.from(cpus).sort(function (a, b) { return a - b; });
    var shown = list.length <= 12
        ? list.join(', ')
        : (list.slice(0, 6).join(', ') + ', …, ' + list.slice(-2).join(', '));
    if (count === 1) {
        el.textContent = '= pinned to 1 CPU (CPU ' + list[0] + ' only) — hard affinity, not a quota';
        return;
    }
    el.textContent = '= pinned to ' + count + ' specific CPUs (' + shown + ') — hard affinity, not a quota';
}

// Ensure a vSwitch VLAN's L2 plumbing exists; returns { name, mtu } for
// its bridge. Reuses an existing VLAN attachment for (uplink, vlanId)
// if there is one; otherwise creates an L2-only attachment — empty
// subnet/self_ip, so the bridge is pure L2 and the guests carry the
// addresses. Idempotent: a second call for the same VLAN reuses it.
async function ensureVswitchBridge(uplink, vlanId, mtuStr) {
    const mtu = parseInt(mtuStr, 10) || 1400;  // Hetzner vSwitch default
    // Reuse an existing attachment for this (uplink, VLAN) pair.
    try {
        const listResp = await fetch(apiUrl('/api/networking/vlan'));
        if (listResp.ok) {
            const data = await listResp.json();
            const existing = (data.vlans || []).find(v =>
                v.parent_iface === uplink && v.vlan_id === vlanId);
            if (existing) return { name: existing.bridge_name, mtu: existing.mtu };
        }
    } catch (_) { /* fall through and create */ }
    // None — create an L2-only attachment. provider 'custom' accepts any
    // VLAN ID; empty subnet/self_ip means no host IP on the bridge.
    const bridge = 'vmbr' + vlanId;
    const body = {
        id: '', name: 'vswitch-vlan-' + vlanId, provider: 'custom',
        parent_iface: uplink, vlan_id: vlanId, mtu: mtu,
        bridge_name: bridge, subnet: '', self_ip: '', routes: [],
        notes: 'Auto-created for a container vSwitch attachment.',
    };
    const resp = await fetch(apiUrl('/api/networking/vlan/attachments?ack_critical=true'), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
    });
    const out = await resp.json().catch(() => ({}));
    if (!resp.ok) {
        throw new Error(out.error || ('VLAN attachment create failed (HTTP ' + resp.status + ')'));
    }
    return { name: bridge, mtu: mtu };
}

async function saveLxcSettings(name) {
    // Re-entrancy guard: the vSwitch auto-wire makes a save several
    // round-trips long, and an un-disabled button invites a second
    // click that would POST the container settings twice. Block
    // re-entry and disable the Save buttons while a save is in flight.
    if (_lxcSaving) return;
    _lxcSaving = true;
    var _saveBtns = document.querySelectorAll('button[onclick*="saveLxcSettings"]');
    _saveBtns.forEach(function (b) { b.disabled = true; });
    try {
        await _saveLxcSettingsImpl(name);
    } finally {
        _lxcSaving = false;
        _saveBtns.forEach(function (b) { b.disabled = false; });
    }
}

async function _saveLxcSettingsImpl(name) {
    // A NIC editor open as a popup has its fields detached into the
    // backdrop overlay, not inside its .lxc-nic-item — so collecting
    // NICs below would read that interface as empty and silently drop
    // the operator's input. Fold any open editor back into its item
    // first so every field is collected.
    closeNicEditor();
    // Check if raw config editor was used (tab 4, details open)
    var rawEditor = document.getElementById('lxc-config-editor');
    var rawDetails = rawEditor ? rawEditor.closest('details') : null;
    var useRaw = rawDetails && rawDetails.open && rawEditor.value !== _lxcParsedCfg?.raw_config;

    if (useRaw) {
        try {
            const resp = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/config`), {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content: rawEditor.value })
            });
            if (!resp.ok) throw new Error('Failed to save raw config');
            showToast('Raw config saved (restart container to apply)', 'success');
            closeContainerDetail();
            return;
        } catch (e) {
            showToast('Error: ' + e.message, 'error');
            return;
        }
    }

    // Collect all network interfaces from NIC editors
    var networkInterfaces = [];
    var nicItems = document.querySelectorAll('.lxc-nic-item');
    nicItems.forEach(function (item) {
        var idx = parseInt(item.getAttribute('data-nic-index'));
        var getField = function (field) {
            var el = item.querySelector(`.lxc-nic-field[data-field="${field}"]`);
            return el ? el.value.trim() : '';
        };
        networkInterfaces.push({
            index: idx,
            net_type: getField('net_type') || 'veth',
            name: getField('name') || ('eth' + idx),
            link: getField('link'),
            hwaddr: getField('hwaddr'),
            ipv4: getField('ipv4'),
            ipv4_gw: getField('ipv4_gw'),
            ipv6: getField('ipv6'),
            ipv6_gw: getField('ipv6_gw'),
            mtu: getField('mtu'),
            vlan: getField('vlan'),
            vsw_uplink: getField('vsw_uplink'),
            firewall: false,
            flags: 'up'
        });
    });

    // vSwitch VLAN auto-wire — a NIC with a VLAN Tag + a vSwitch uplink
    // NIC gets its L2 plumbing (tagged sub-interface + bridge) created
    // on demand, then is attached to that bridge with no tag of its own
    // (the tag rides on the sub-interface). vsw_uplink is a frontend-
    // only helper field and must never reach the backend.
    for (const nic of networkInterfaces) {
        const uplink = (nic.vsw_uplink || '').trim();
        delete nic.vsw_uplink;
        if (!uplink) continue;  // not a vSwitch NIC — plain bridge / plain VLAN tag
        // A vSwitch uplink with no VLAN Tag can't be wired up — tell the
        // operator instead of silently saving a half-configured NIC.
        if (!nic.vlan) {
            showToast(`Interface ${nic.name}: a vSwitch uplink NIC is selected but the VLAN Tag is empty — enter the VLAN ID too, or set the uplink back to "— none —".`, 'error', 8000);
            return;
        }
        const vlanId = parseInt(nic.vlan, 10);
        if (!Number.isInteger(vlanId) || vlanId < 1 || vlanId > 4094) {
            showToast(`vSwitch: VLAN tag "${nic.vlan}" is invalid (must be 1-4094)`, 'error');
            return;
        }
        try {
            const bridge = await ensureVswitchBridge(uplink, vlanId, nic.mtu);
            nic.link = bridge.name;
            if (!nic.mtu) nic.mtu = String(bridge.mtu);
            nic.vlan = '';  // bridge-per-VLAN: the bridge IS the VLAN — no tag on the NIC
        } catch (e) {
            showToast('vSwitch setup failed: ' + (e.message || e), 'error');
            return;
        }
    }

    var settings = {
        hostname: (document.getElementById('lxc-hostname') || {}).value || '',
        autostart: (document.getElementById('lxc-autostart') || {}).checked || false,
        start_delay: parseInt((document.getElementById('lxc-start-delay') || {}).value) || 0,
        start_order: parseInt((document.getElementById('lxc-start-order') || {}).value) || 0,
        unprivileged: (document.getElementById('lxc-unprivileged') || {}).value === 'true',
        network_interfaces: networkInterfaces,
        memory_limit: (document.getElementById('lxc-memory') || {}).value || '',
        swap_limit: (document.getElementById('lxc-swap') || {}).value || '',
        cpus: (document.getElementById('lxc-cpus') || {}).value || '',
        tun_enabled: (document.getElementById('lxc-feat-tun') || {}).checked || false,
        fuse_enabled: (document.getElementById('lxc-feat-fuse') || {}).checked || false,
        nesting_enabled: (document.getElementById('lxc-feat-nesting') || {}).checked || false,
        nfs_enabled: (document.getElementById('lxc-feat-nfs') || {}).checked || false,
        keyctl_enabled: (document.getElementById('lxc-feat-keyctl') || {}).checked || false,
        wolfnet_ip: (document.getElementById('lxc-wolfnet-ip') || {}).value || '',
        // Notes: send the raw value (empty string clears it). The field always
        // exists in the General tab, so a missing element is unexpected — fall
        // back to '' rather than undefined so a clear isn't silently dropped.
        notes: (document.getElementById('lxc-notes') || {}).value ?? '',
    };

    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/settings`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(settings)
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast('Settings saved — restart container to apply changes', 'success');
            closeContainerDetail();
            // Refresh the container list
            if (typeof loadLxcContainers === 'function') loadLxcContainers();
            // Check for network conflicts
            try {
                var cr = await fetch(apiUrl('/api/network/conflicts'));
                var conflicts = await cr.json();
                conflicts.forEach(function (c) {
                    if (c.severity === 'error') {
                        showToast('Duplicate MAC ' + c.value + ' on: ' + c.containers.join(', '), 'error');
                    } else {
                        showToast('Duplicate IP ' + c.value + ' on: ' + c.containers.join(', '), 'warning');
                    }
                });
            } catch (e) { /* ignore conflict check errors */ }
        } else {
            showToast(data.error || 'Failed to save settings', 'error');
        }
    } catch (e) {
        showToast('Error saving settings: ' + e.message, 'error');
    }
}

// LXC bind-mount add. Opens a proper modal (replacing the old
// blocking prompt() chain) and includes the PVE-only options — shared,
// backup, quota, size — in a collapsed advanced section when the
// container is Proxmox-managed. The backend silently ignores those
// flags on native containers, so turning them on for a non-PVE CT is
// harmless but we hide them to keep the form uncluttered.
function openLxcMountModal(name, opts) {
    opts = opts || {};
    const isProxmox = !!(opts.proxmox ?? (window._lxcParsedCfg && window._lxcParsedCfg.proxmox));
    const defaults = opts.defaults || {};

    // Remove any lingering modal before appending a fresh one.
    document.getElementById('lxc-mount-modal')?.remove();

    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.id = 'lxc-mount-modal';
    overlay.style.zIndex = '10001';
    overlay.innerHTML = `
        <div class="modal" style="max-width:560px;">
            <div class="modal-header">
                <h3>Add Bind Mount — ${escapeHtml(name)}</h3>
                <button class="modal-close" onclick="document.getElementById('lxc-mount-modal')?.remove()">×</button>
            </div>
            <div class="modal-body" style="font-size:13px;">
                <div style="display:flex; flex-direction:column; gap:10px;">
                    <label style="display:flex; flex-direction:column; gap:4px;">
                        <span style="font-weight:600;">Source <span style="font-weight:400;color:var(--text-muted);font-size:11px;">${isProxmox ? '— host path or PVE storage id' : '— host directory'}</span></span>
                        <input id="lxc-mount-host" class="form-control" type="text"
                            placeholder="${isProxmox ? '/mnt/pve/cephfs/cs  or  local:4' : '/mnt/data'}"
                            value="${escapeHtml(defaults.host_path || '')}">
                    </label>
                    <label style="display:flex; flex-direction:column; gap:4px;">
                        <span style="font-weight:600;">Container path</span>
                        <input id="lxc-mount-container" class="form-control" type="text"
                            placeholder="/mnt/shared"
                            value="${escapeHtml(defaults.container_path || '')}">
                    </label>
                    <label style="display:flex; align-items:center; gap:6px;">
                        <input id="lxc-mount-ro" type="checkbox" ${defaults.read_only ? 'checked' : ''}>
                        <span>Read-only</span>
                    </label>
                    ${isProxmox ? `
                    <details style="background:var(--bg-tertiary); border:1px solid var(--border); border-radius:6px; padding:8px 10px;">
                        <summary style="cursor:pointer; font-weight:600; font-size:12px;">Proxmox options</summary>
                        <div style="display:flex; flex-direction:column; gap:8px; margin-top:10px;">
                            <label style="display:flex; align-items:center; gap:6px;">
                                <input id="lxc-mount-shared" type="checkbox" ${defaults.shared ? 'checked' : ''}>
                                <span>Shared <span style="color:var(--text-muted); font-size:11px;">— same content across cluster nodes (CephFS, NFS, etc). Lets pct migrate run without copying the volume.</span></span>
                            </label>
                            <label style="display:flex; align-items:center; gap:6px;">
                                <input id="lxc-mount-backup" type="checkbox" ${defaults.backup ? 'checked' : ''}>
                                <span>Include in vzdump backups</span>
                            </label>
                            <label style="display:flex; align-items:center; gap:6px;">
                                <input id="lxc-mount-quota" type="checkbox" ${defaults.quota ? 'checked' : ''}>
                                <span>Enable filesystem quotas <span style="color:var(--text-muted); font-size:11px;">(privileged CTs only)</span></span>
                            </label>
                            <label style="display:flex; flex-direction:column; gap:4px;">
                                <span>Size (GB) <span style="font-weight:400;color:var(--text-muted);font-size:11px;">— PVE storage sources only; leave blank for host-path binds</span></span>
                                <input id="lxc-mount-size" class="form-control" type="number" min="1" step="1"
                                    placeholder="e.g. 50" value="${defaults.size_gb != null ? defaults.size_gb : ''}">
                            </label>
                        </div>
                    </details>` : ''}
                    <details style="background:var(--bg-tertiary); border:1px solid var(--border); border-radius:6px; padding:8px 10px;">
                        <summary style="cursor:pointer; font-weight:600; font-size:12px;">Paste a Proxmox mp string</summary>
                        <div style="margin-top:8px; display:flex; flex-direction:column; gap:6px;">
                            <input id="lxc-mount-raw" class="form-control" type="text"
                                placeholder="/mnt/pve/cephfs/cs,mp=/mnt/shared,shared=1">
                            <button class="btn btn-sm" style="align-self:flex-start;" onclick="lxcMountParseRaw()">Parse into fields</button>
                            <div style="font-size:11px; color:var(--text-muted);">Accepts either the options part (<code>/src,mp=/dst,shared=1</code>) or a full config line (<code>mp0: /src,mp=/dst,…</code>).</div>
                        </div>
                    </details>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn" onclick="document.getElementById('lxc-mount-modal')?.remove()">Cancel</button>
                <button class="btn btn-primary" onclick="lxcMountSubmit('${escapeHtml(name)}')">Add Mount</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
    document.getElementById('lxc-mount-host').focus();
}

// Parse a PVE-style "src,mp=/dst,flag=1" string (optionally prefixed
// with "mpN: ") into the modal fields so a user can paste the line
// straight out of a pct config.
function lxcMountParseRaw() {
    const raw = document.getElementById('lxc-mount-raw')?.value?.trim();
    if (!raw) return;
    // Strip a leading "mp0: " / "mp12: " prefix if present.
    const cleaned = raw.replace(/^mp\d+\s*:\s*/, '');
    const parts = cleaned.split(',');
    const host = (parts.shift() || '').trim();
    if (host) document.getElementById('lxc-mount-host').value = host;
    let container = '';
    let sizeGb = '';
    const flags = { ro: false, shared: false, backup: false, quota: false };
    for (const p of parts) {
        const [k, v] = p.split('=').map(s => (s || '').trim());
        if (k === 'mp') container = v;
        else if (k === 'ro' && v === '1') flags.ro = true;
        else if (k === 'shared' && v === '1') flags.shared = true;
        else if (k === 'backup' && v === '1') flags.backup = true;
        else if (k === 'quota' && v === '1') flags.quota = true;
        else if (k === 'size') {
            const m = v.match(/^(\d+)\s*([TGMKtgmk])?/);
            if (m) {
                const n = parseInt(m[1], 10);
                const u = (m[2] || 'G').toUpperCase();
                sizeGb = u === 'T' ? n * 1024 : u === 'G' ? n : u === 'M' ? Math.max(1, Math.round(n / 1024)) : n;
            }
        }
    }
    if (container) document.getElementById('lxc-mount-container').value = container;
    const set = (id, v) => { const el = document.getElementById(id); if (el) el.checked = v; };
    set('lxc-mount-ro', flags.ro);
    set('lxc-mount-shared', flags.shared);
    set('lxc-mount-backup', flags.backup);
    set('lxc-mount-quota', flags.quota);
    const sz = document.getElementById('lxc-mount-size');
    if (sz && sizeGb !== '') sz.value = sizeGb;
}

async function lxcMountSubmit(name) {
    const host = document.getElementById('lxc-mount-host')?.value?.trim();
    const container = document.getElementById('lxc-mount-container')?.value?.trim();
    if (!host || !container) { showToast('Source and container path are required', 'error'); return; }
    const body = {
        host_path: host,
        container_path: container,
        read_only: document.getElementById('lxc-mount-ro')?.checked || false,
    };
    const sharedEl = document.getElementById('lxc-mount-shared');
    const backupEl = document.getElementById('lxc-mount-backup');
    const quotaEl = document.getElementById('lxc-mount-quota');
    const sizeEl = document.getElementById('lxc-mount-size');
    if (sharedEl) body.shared = sharedEl.checked;
    if (backupEl) body.backup = backupEl.checked;
    if (quotaEl) body.quota = quotaEl.checked;
    if (sizeEl && sizeEl.value) {
        const n = parseInt(sizeEl.value, 10);
        if (n > 0) body.size_gb = n;
    }
    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/mounts`), {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || 'Mount added', 'success');
            document.getElementById('lxc-mount-modal')?.remove();
            openLxcSettings(name);
        } else {
            showToast(data.error || 'Failed', 'error');
        }
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

function addMountPoint(name) {
    openLxcMountModal(name, {});
}

function addWolfDiskMount(name) {
    // WolfDisk is just a host path on the local node — pre-fill the
    // common defaults and let the user tweak in the modal.
    openLxcMountModal(name, {
        defaults: { host_path: '/mnt/wolfdisk', container_path: '/mnt/shared' },
    });
}

async function removeLxcMount(name, hostPath) {
    if (!(await showConfirm(`Remove mount ${hostPath}?`))) return;
    try {
        var resp = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/mounts`), {
            method: 'DELETE', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ host_path: hostPath }),
        });
        var data = await resp.json();
        if (resp.ok) { showToast(data.message || 'Mount removed', 'success'); openLxcSettings(name); }
        else { showToast(data.error || 'Failed', 'error'); }
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

function escapeHtml(text) {
    if (text == null) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ─── Clone & Migrate Functions ───

async function cloneDockerContainer(name) {
    const newName = await showPrompt(`Clone Docker container '${name}' — enter a name for the clone:`, 'Clone container', name + '-clone');
    if (!newName) return;

    showToast(`Cloning ${name}...`, 'info');
    try {
        const resp = await fetch(apiUrl(`/api/containers/docker/${name}/clone`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ new_name: newName }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || `Cloned as '${newName}'`, 'success');
            setTimeout(loadDockerContainers, 500);
        } else {
            showToast(data.error || 'Clone failed', 'error');
        }
    } catch (e) {
        showToast(`Clone failed: ${e.message}`, 'error');
    }
}

async function migrateDockerContainer(name) {
    // Show a modal with node selection
    const modal = document.getElementById('container-detail-modal');
    const title = document.getElementById('container-detail-title');
    const body = document.getElementById('container-detail-body');

    title.textContent = `Migrate Container: ${name}`;
    body.innerHTML = renderBlockSkeleton({lines:3});
    modal.classList.add('active');

    try {
        const resp = await fetch('/api/nodes');
        const data = await resp.json();
        const nodes = Array.isArray(data) ? data : (data.nodes || []);

        // Filter to the container's OWN cluster, excluding its current
        // host. `currentNodeId` is the node the user is browsing — i.e.
        // the host of this container — regardless of which cluster the
        // browser is connected to.
        const containerHost = nodes.find(n => n.id === currentNodeId)
                           || allNodes.find(n => n.id === currentNodeId)
                           || nodes.find(n => n.is_self);
        const containerCluster = containerHost?.cluster_name || 'WolfStack';
        const clusterNodes = nodes.filter(n => n.id !== currentNodeId && n.online && (n.cluster_name || 'WolfStack') === containerCluster);

        let nodeOpts = '';
        if (clusterNodes.length > 0) {
            nodeOpts = clusterNodes
                .sort((a, b) => (a.name || a.address).localeCompare(b.name || b.address))
                .map(n => `<option value="${n.url || 'https://' + n.address + ':8553'}">${n.name || n.address} (${n.address})</option>`).join('');
        }

        body.innerHTML = `
            <div style="padding: 1rem;">
                <p style="margin-bottom: 1rem; color: var(--text-secondary);">
                    This will export the container, transfer it to the target WolfStack node, and import it there.
                    The source container will keep running. The destination will be imported but not started.
                </p>
                <div style="background:var(--warning-bg);border:1px solid var(--warning);border-radius:8px;padding:10px 12px;margin-bottom:1rem;color:var(--warning);font-size:0.85em;">
                    Note: After migration you may need to update the container's network settings (IP address, gateway, DNS) on the destination node to match the new network.
                </div>
                <div style="margin-bottom: 1rem;">
                    <label style="display:block; margin-bottom:4px; font-weight:600;">Target Node</label>
                    ${nodeOpts ? `<select id="migrate-target" style="width:100%; padding:8px; border-radius:6px; border:1px solid var(--border); background:var(--bg-primary); color:var(--text-primary);">
                        ${nodeOpts}
                    </select>` : `<input id="migrate-target" type="text" placeholder="https://target-host.example.com" style="width:100%; padding:8px; border-radius:6px; border:1px solid var(--border); background:var(--bg-primary); color:var(--text-primary);">`}
                </div>
                <div style="margin-bottom: 1rem;">
                    <label style="display:block; margin-bottom:4px; font-weight:600;">Target Storage</label>
                    <select id="docker-migrate-storage" style="width:100%; padding:8px; border-radius:6px; border:1px solid var(--border); background:var(--bg-primary); color:var(--text-primary);">
                        <option value="">Auto (default)</option>
                    </select>
                </div>
                <div style="background:var(--info-bg,#1a2332);border:1px solid var(--info,#3b82f6);border-radius:8px;padding:10px 12px;margin-bottom:1rem;color:var(--info,#3b82f6);font-size:0.82em;">
                    The source container will keep running. The destination will be imported but not started — start it manually when ready.
                </div>
                <div style="display:flex; gap:8px;">
                    <button class="btn btn-primary" onclick="doMigrate('${name}')">Migrate</button>
                    <button class="btn" onclick="closeContainerDetail()">Cancel</button>
                </div>
            </div>
        `;
    } catch (e) {
        body.innerHTML = `
            <div style="padding: 1rem;">
                <p style="margin-bottom: 1rem; color: var(--text-secondary);">
                    Enter the URL of the target WolfStack node.
                </p>
                <div style="margin-bottom: 1rem;">
                    <label style="display:block; margin-bottom:4px; font-weight:600;">Target URL</label>
                    <input id="migrate-target" type="text" placeholder="https://target-host.example.com" style="width:100%; padding:8px; border-radius:6px; border:1px solid var(--border); background:var(--bg-primary); color:var(--text-primary);">
                </div>
                <div style="margin-bottom: 1rem;">
                    <label style="display:block; margin-bottom:4px; font-weight:600;">Target Storage</label>
                    <select id="docker-migrate-storage" style="width:100%; padding:8px; border-radius:6px; border:1px solid var(--border); background:var(--bg-primary); color:var(--text-primary);">
                        <option value="">Auto (default)</option>
                    </select>
                </div>
                <div style="background:var(--info-bg,#1a2332);border:1px solid var(--info,#3b82f6);border-radius:8px;padding:10px 12px;margin-bottom:1rem;color:var(--info,#3b82f6);font-size:0.82em;">
                    The source container will keep running. The destination will be imported but not started — start it manually when ready.
                </div>
                <div style="display:flex; gap:8px;">
                    <button class="btn btn-primary" onclick="doMigrate('${name}')">Migrate</button>
                    <button class="btn" onclick="closeContainerDetail()">Cancel</button>
                </div>
            </div>
        `;
    }
}

async function doMigrate(name) {
    const targetEl = document.getElementById('migrate-target');
    const targetUrl = normalizeWolfStackUrl(targetEl.value.trim());
    const storageVal = document.getElementById('docker-migrate-storage')?.value || '';

    if (!targetUrl) {
        showToast('Please enter a target URL', 'error');
        return;
    }

    closeContainerDetail();
    showToast(`Migrating ${name} to ${targetUrl}... This may take a while.`, 'info');

    const dockerTargetLabel = targetUrl.replace(/https?:\/\//, '').split('/')[0];
    const dockerTaskId = taskLogStart(`Migrating Docker '${name}' to ${dockerTargetLabel}`);

    try {
        const migrateBody = { target_url: targetUrl };
        if (storageVal) migrateBody.storage = storageVal;
        const resp = await fetch(apiUrl(`/api/containers/docker/${name}/migrate`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(migrateBody),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || 'Migration complete', 'success');
            updateTaskLogEntry(dockerTaskId, { status: 'completed', description: `Migrated Docker '${name}' to ${dockerTargetLabel}` });
            setTimeout(loadDockerContainers, 500);
        } else {
            showToast(data.error || 'Migration failed', 'error');
            updateTaskLogEntry(dockerTaskId, { status: 'failed', description: `Migrate Docker '${name}': ${data.error || 'Migration failed'}` });
        }
    } catch (e) {
        showToast(`Migration failed: ${e.message}`, 'error');
        updateTaskLogEntry(dockerTaskId, { status: 'failed', description: `Migrate Docker '${name}': ${e.message}` });
    }
}

async function cloneLxcContainer(name) {
    // Fetch cluster nodes from LOCAL server (not proxied) for the target selector
    let nodes = [];
    try {
        const resp = await fetch('/api/nodes');
        if (resp.ok) {
            const data = await resp.json();
            nodes = Array.isArray(data) ? data : (data.nodes || []);
        }
    } catch (e) { }

    const modal = document.createElement('div');
    modal.id = 'lxc-clone-modal';
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:400px;max-width:500px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <h3 style="margin:0 0 16px;color:var(--text,#fff);">Clone Container</h3>
            <p style="margin:0 0 16px;color:var(--text-muted,#aaa);font-size:0.9em;">Clone <strong>${name}</strong> to a new container.</p>
            <div style="display:flex;flex-direction:column;gap:12px;">
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">New Name</label>
                    <input id="clone-new-name" type="text" value="${name}-clone" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;"></div>
                <div id="clone-vmid-row" style="display:none;"><label style="font-size:13px;color:var(--text-muted,#aaa);">New VMID</label>
                    <input id="clone-vmid" type="number" min="100" placeholder="leave blank for the next free id" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                    <span style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">Exact copy, created stopped — change its IP / WolfNet address before starting it alongside the original.</span></div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Target Node</label>
                    <select id="clone-target-node" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">This node (local clone)</option>
                        ${nodes.filter(n => !n.is_self && n.online).sort((a, b) => (a.hostname || a.address).localeCompare(b.hostname || b.address)).map(n => `<option value="${n.id}">${n.hostname} (${n.address})</option>`).join('')}
                    </select></div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Storage</label>
                    <select id="clone-storage" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">Auto (default)</option>
                    </select></div>
                <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:8px;">
                    <button class="btn" onclick="document.getElementById('lxc-clone-modal')?.remove()">Cancel</button>
                    <button class="btn" style="background:var(--primary,#3b82f6);color:#fff;" onclick="doCloneLxc('${name}')">Clone</button>
                </div>
            </div>
        </div>
    `;
    document.body.appendChild(modal);

    // Populate storage dropdown from /api/storage/list (proxied to the target node)
    try {
        const storageResp = await fetch(apiUrl('/api/storage/list'));
        if (storageResp.ok) {
            const storageData = await storageResp.json();
            const sel = document.getElementById('clone-storage');
            if (storageData.proxmox) {
                const stores = storageData.storages.filter(s =>
                    s.content && s.content.some(c => c === 'rootdir' || c === 'images')
                );
                (stores.length ? stores : storageData.storages.filter(s => s.status === 'active')).forEach(s => {
                    const free = formatBytes(s.available_bytes);
                    sel.insertAdjacentHTML('beforeend', `<option value="${s.id}">${s.id} (${s.storage_type}, ${free} free)</option>`);
                });
                // Proxmox: let the operator choose the new VMID. Only for a
                // local (same-node) clone — a remote clone goes through
                // export/import and assigns its own id on the target.
                const vmidRow = document.getElementById('clone-vmid-row');
                const tgtSel = document.getElementById('clone-target-node');
                if (vmidRow && tgtSel) {
                    const syncVmidRow = () => { vmidRow.style.display = tgtSel.value ? 'none' : 'block'; };
                    syncVmidRow();
                    tgtSel.addEventListener('change', syncVmidRow);
                }
            } else if (storageData.paths) {
                storageData.paths.forEach(p => {
                    sel.insertAdjacentHTML('beforeend', `<option value="${p.path}">${p.path} (${formatBytes(p.free_bytes)} free)</option>`);
                });
            }
        }
    } catch (e) { }
}

async function doCloneLxc(name) {
    const newName = document.getElementById('clone-new-name').value.trim();
    const targetNode = document.getElementById('clone-target-node').value;
    const storage = document.getElementById('clone-storage').value.trim();
    // Proxmox local clone only — the field is hidden otherwise.
    const vmidRaw = document.getElementById('clone-vmid')?.value.trim() || '';
    const vmidRowVisible = document.getElementById('clone-vmid-row')?.style.display !== 'none';
    if (!newName) { showToast('Enter a name for the clone', 'error'); return; }
    if (vmidRowVisible && vmidRaw && (!/^\d+$/.test(vmidRaw) || parseInt(vmidRaw, 10) < 100)) {
        showToast('VMID must be a number ≥ 100 (or blank for the next free id)', 'error');
        return;
    }

    document.getElementById('lxc-clone-modal')?.remove();

    // Show progress modal
    const modal = document.createElement('div');
    modal.id = 'lxc-op-modal';
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:400px;max-width:500px;box-shadow:0 20px 60px rgba(0,0,0,0.5);text-align:center;">
            <div style="width:48px;height:48px;border:4px solid var(--border,#555);border-top:4px solid var(--primary,#3b82f6);border-radius:50%;animation:spin 1s linear infinite;margin:0 auto 16px;"></div>
            <h3 style="margin:0 0 8px;color:var(--text,#fff);">Cloning Container</h3>
            <p id="lxc-op-status" style="margin:0;color:var(--text-muted,#aaa);font-size:0.9em;">Cloning <strong>${name}</strong> → <strong>${newName}</strong>${targetNode ? ' (remote)' : ''}...</p>
            <div id="lxc-op-result" style="display:none;margin-top:16px;padding:12px;border-radius:8px;text-align:left;font-size:0.9em;"></div>
            <button id="lxc-op-close" style="display:none;margin-top:12px;" class="btn" onclick="document.getElementById('lxc-op-modal')?.remove()">Close</button>
        </div>
    `;
    if (!document.getElementById('lxc-spin-style')) {
        const s = document.createElement('style'); s.id = 'lxc-spin-style';
        s.textContent = '@keyframes spin { to { transform: rotate(360deg); } }';
        document.head.appendChild(s);
    }
    document.body.appendChild(modal);

    try {
        const body = { new_name: newName };
        if (targetNode) body.target_node = targetNode;
        if (storage) body.storage = storage;
        if (vmidRowVisible && vmidRaw) body.vmid = parseInt(vmidRaw, 10);

        const resp = await fetch(apiUrl(`/api/containers/lxc/${name}/clone`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        let data;
        try { data = await resp.json(); } catch { data = {}; }

        const resultEl = document.getElementById('lxc-op-result');
        const statusEl = document.getElementById('lxc-op-status');
        const spinner = modal.querySelector('div > div:first-child');
        if (spinner) spinner.style.display = 'none';
        document.getElementById('lxc-op-close').style.display = '';

        if (resp.ok) {
            // Success: dismiss the blocking blur overlay and confirm via
            // toast. Leaving the modal up forces the operator to click
            // Close before the page is usable — they often don't, and
            // the page sits behind backdrop-filter:blur(4px) until they
            // notice. Match the Docker clone's toast-only behaviour.
            document.getElementById('lxc-op-modal')?.remove();
            showToast(data.message || `Cloned as '${newName}'`, 'success');
            setTimeout(loadLxcContainers, 500);
        } else {
            // Failure: keep the modal open so the error message is
            // readable — the user needs to see what went wrong.
            statusEl.textContent = 'Clone failed';
            resultEl.style.display = 'block';
            resultEl.style.background = 'rgba(239,68,68,0.15)';
            resultEl.style.color = '#ef4444';
            resultEl.textContent = data.error || 'Unknown error';
        }
    } catch (e) {
        const resultEl = document.getElementById('lxc-op-result');
        const statusEl = document.getElementById('lxc-op-status');
        statusEl.textContent = 'Clone failed';
        resultEl.style.display = 'block';
        resultEl.style.background = 'rgba(239,68,68,0.15)';
        resultEl.style.color = '#ef4444';
        resultEl.textContent = e.message;
        document.getElementById('lxc-op-close').style.display = '';
    }
}

async function migrateLxcContainer(name) {
    // Fetch cluster nodes from LOCAL server (not proxied) — remote nodes don't have cluster info
    let nodes = [];
    try {
        const resp = await fetch('/api/nodes');
        if (resp.ok) {
            const data = await resp.json();
            nodes = Array.isArray(data) ? data : (data.nodes || []);
        }
    } catch (e) { }
    // Filter to the container's OWN cluster (not the cluster the
    // browser is connected to). When the user is browsing a container
    // on a remote node via the cluster browser, `is_self` points at
    // the local WolfStack host, which is often a different cluster.
    // The container's host is `currentNodeId`.
    const containerHost = nodes.find(n => n.id === currentNodeId)
                       || allNodes.find(n => n.id === currentNodeId)
                       || nodes.find(n => n.is_self);
    const containerCluster = containerHost?.cluster_name || 'WolfStack';
    const remoteNodes = nodes
        .filter(n => n.id !== currentNodeId && n.online && (n.cluster_name || 'WolfStack') === containerCluster)
        .sort((a, b) => (a.hostname || a.address).localeCompare(b.hostname || b.address));

    const modal = document.createElement('div');
    modal.id = 'lxc-migrate-modal';
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:420px;max-width:520px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <h3 style="margin:0 0 16px;color:var(--text,#fff);">Migrate Container</h3>
            <p style="margin:0 0 12px;color:var(--text-muted,#aaa);font-size:0.9em;">Move <strong>${name}</strong> to another node in this cluster: the source is stopped, copied across, and started on the destination — the source is kept (stopped) on the old node as a rollback. <em>Migrating to an external cluster instead copies it and leaves the source running.</em></p>
            <div style="background:var(--danger-bg);border:1px solid var(--danger);border-radius:8px;padding:10px 12px;margin-bottom:10px;color:var(--danger);font-size:0.85em;">
                The container will experience downtime during migration.
            </div>
            <div style="background:var(--warning-bg);border:1px solid var(--warning);border-radius:8px;padding:10px 12px;margin-bottom:16px;color:var(--warning);font-size:0.85em;">
                In-cluster moves keep the container exactly as-is — same IP, MAC and WolfNet address. Only a cross-cluster (external) migration lands on a different network, where you may need to update IP / gateway / DNS afterwards.
            </div>
            <div style="display:flex;flex-direction:column;gap:12px;">
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Migrate to</label>
                    <select id="migrate-target" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">— Select a cluster node —</option>
                        ${remoteNodes.map(n => {
                            const memGb = n.total_memory ? (n.total_memory / 1073741824).toFixed(1) + ' GB RAM' : '';
                            return `<option value="${n.id}">${n.hostname || n.id} — ${n.address}${memGb ? ' · ' + memGb : ''}</option>`;
                        }).join('')}
                        ${!remoteNodes.length ? '<option value="" disabled>(no other online nodes in this cluster)</option>' : ''}
                        <option value="__external__">↗ External cluster...</option>
                    </select>
                    <div id="migrate-target-info" style="font-size:11px;color:var(--text-muted,#666);margin-top:4px;"></div>
                </div>
                <div id="migrate-external-fields" style="display:none;">
                    <div style="background:var(--info-bg);border:1px solid var(--info);border-radius:8px;padding:10px 12px;margin-bottom:12px;color:var(--info);font-size:0.82em;line-height:1.5;">
                        <strong>Cross-cluster migration</strong> lets you move a container to a WolfStack instance on a different network.
                        On the <em>destination</em> cluster, go to <strong>LXC Containers → Generate Transfer Token</strong> to create a one-time token.
                        The token is valid for 30 minutes and authorises this node to push the container to that cluster.
                    </div>
                    <label style="font-size:13px;color:var(--text-muted,#aaa);">Target URL</label>
                    <input id="migrate-ext-url" type="text" placeholder="https://target.example.com" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;margin-bottom:8px;">
                    <label style="font-size:13px;color:var(--text-muted,#aaa);">Transfer Token</label>
                    <input id="migrate-ext-token" type="text" placeholder="wst_..." style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                </div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Target Storage</label>
                    <select id="migrate-storage" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">Auto (default)</option>
                    </select>
                    <span id="migrate-storage-hint" style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">Select a target node to load available storages</span></div>
                <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:8px;">
                    <button class="btn" onclick="document.getElementById('lxc-migrate-modal')?.remove()">Cancel</button>
                    <button class="btn" style="background:#ef4444;color:#fff;" onclick="doMigrateLxc('${name}')">Migrate</button>
                </div>
            </div>
        </div>
    `;
    document.body.appendChild(modal);

    // Helper: populate storage dropdown from a storage list response.
    // Also detects shared storage (Ceph, NFS, CIFS) and surfaces a
    // helpful badge so users know "this migration won't need a data
    // copy if you pick a shared backend".
    function lxcPopulateStorages(data) {
        const sel = document.getElementById('migrate-storage');
        const hint = document.getElementById('migrate-storage-hint');
        const info = document.getElementById('migrate-target-info');
        sel.innerHTML = '<option value="">Auto (default)</option>';
        const storages = data.storages || [];
        const suitable = storages.filter(s => s.content && s.content.some(c => c === 'rootdir' || c === 'images'));
        const display = suitable.length ? suitable : storages.filter(s => s.status === 'active');
        const sharedTypes = ['cephfs', 'rbd', 'ceph', 'nfs', 'cifs', 'glusterfs', 'zfs-over-iscsi'];
        let hasShared = false;
        display.forEach(s => {
            const free = typeof formatBytes === 'function' ? formatBytes(s.available_bytes) : Math.round(s.available_bytes / 1073741824) + ' GB';
            const isShared = sharedTypes.some(t => (s.type || '').toLowerCase().includes(t));
            if (isShared) hasShared = true;
            const badge = isShared ? ' shared' : '';
            sel.insertAdjacentHTML('beforeend', `<option value="${s.id}">${s.id} (${s.type || ''}, ${free} free${badge})</option>`);
        });
        if (hasShared && info) {
            info.innerHTML = '<span style="color:#22c55e;">Shared storage (Ceph/NFS) detected on the target — if you pick it, migration is config-only and takes seconds instead of copying gigabytes.</span>';
        } else if (info) {
            info.innerHTML = display.length ? '<span style="color:var(--text-muted);">No shared storage with this node — container data will be copied over the network.</span>' : '';
        }
        hint.textContent = storages.length ? '' : 'No storages found on the target node';
    }

    // Show/hide external fields + fetch storages from selected target node
    document.getElementById('migrate-target').addEventListener('change', async (e) => {
        const val = e.target.value;
        document.getElementById('migrate-external-fields').style.display = val === '__external__' ? 'block' : 'none';

        const sel = document.getElementById('migrate-storage');
        const hint = document.getElementById('migrate-storage-hint');
        sel.innerHTML = '<option value="">Auto (default)</option>';
        if (!val || val === '__external__') {
            hint.textContent = val === '__external__' ? 'Enter a target URL to load available storages' : 'Select a target node to load available storages';
            return;
        }
        hint.textContent = 'Loading storages...';
        try {
            const resp = await fetch(`/api/nodes/${val}/proxy/storage/list`);
            if (resp.ok) { lxcPopulateStorages(await resp.json()); }
            else { hint.textContent = 'Could not load storages from target node'; }
        } catch (err) { hint.textContent = 'Could not reach target node for storage list'; }
    });

    // Fetch storages from external URL via backend proxy (handles auth + port detection)
    let lxcExtUrlTimer = null;
    document.getElementById('migrate-ext-url')?.addEventListener('input', (e) => {
        clearTimeout(lxcExtUrlTimer);
        lxcExtUrlTimer = setTimeout(async () => {
            const url = e.target.value.trim();
            const sel = document.getElementById('migrate-storage');
            const hint = document.getElementById('migrate-storage-hint');
            sel.innerHTML = '<option value="">Auto (default)</option>';
            if (!url) { hint.textContent = 'Enter a target URL to load available storages'; return; }
            hint.textContent = 'Connecting to remote cluster...';
            try {
                const resp = await fetch(`/api/storage/remote-list?url=${encodeURIComponent(url)}`);
                if (resp.ok) { lxcPopulateStorages(await resp.json()); }
                else { const d = await resp.json().catch(() => ({})); hint.textContent = d.error || 'Could not reach remote cluster'; }
            } catch { hint.textContent = 'Could not reach remote cluster'; }
        }, 800);
    });
}

async function doMigrateLxc(name) {
    const target = document.getElementById('migrate-target').value;
    if (!target) { showToast('Select a target node', 'error'); return; }

    const rawExtUrl = document.getElementById('migrate-ext-url')?.value.trim() || '';
    const extToken = document.getElementById('migrate-ext-token')?.value.trim() || '';
    const migrateStorage = document.getElementById('migrate-storage')?.value || '';
    document.getElementById('lxc-migrate-modal')?.remove();

    const isExternal = target === '__external__';
    if (isExternal && (!rawExtUrl || !extToken)) { showToast('Enter URL and token', 'error'); return; }
    const extUrl = isExternal ? normalizeWolfStackUrl(rawExtUrl) : '';
    const lxcTargetLabel = isExternal ? extUrl.replace(/https?:\/\//, '').split('/')[0] : target;

    if (isExternal) {
        // Background task with live task log updates
        const taskId = taskLogStart(`Migrate LXC '${name}' → ${lxcTargetLabel}: starting...`);

        try {
            const startResp = await fetch(`/api/containers/lxc/${name}/migrate-external`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ target_url: extUrl, target_token: extToken, ...(migrateStorage && { storage: migrateStorage }) }),
            });
            const startData = await startResp.json().catch(() => ({}));
            if (!startResp.ok || !startData.task_id) {
                updateTaskLogEntry(taskId, { status: 'failed', description: `Migrate LXC '${name}': ${startData.error || 'Failed to start'}` });
                return;
            }

            // Poll backend for real status, update task log as each stage happens
            const migTaskId = startData.task_id;
            let lastStage = '';
            const poll = setInterval(async () => {
                try {
                    const sr = await fetch(`/api/migration/${migTaskId}/status`);
                    if (!sr.ok) return;
                    const s = await sr.json();
                    if (s.stage !== lastStage || s.completed) {
                        lastStage = s.stage;
                        if (s.completed && s.error) {
                            updateTaskLogEntry(taskId, { status: 'failed', description: `Migrate LXC '${name}': ${s.message}` });
                            clearInterval(poll);
                        } else if (s.completed) {
                            updateTaskLogEntry(taskId, { status: 'completed', description: `Migrate LXC '${name}' → ${lxcTargetLabel}: ${s.message}` });
                            clearInterval(poll);
                            setTimeout(loadLxcContainers, 500);
                        } else {
                            updateTaskLogEntry(taskId, { description: `Migrate LXC '${name}' → ${lxcTargetLabel}: ${s.message}` });
                        }
                    }
                } catch {}
            }, 1500);
        } catch (e) {
            updateTaskLogEntry(taskId, { status: 'failed', description: `Migrate LXC '${name}': ${e.message}` });
        }
    } else {
        // Intra-cluster: background task with a live stepped progress box.
        const logTaskId = taskLogStart(`Migrate LXC '${name}' → ${lxcTargetLabel}`);
        const steps = [
            { id: 'export', label: 'Stop & export source', icon: '', stages: ['preflight', 'stop_source', 'export'] },
            { id: 'upload', label: `Transfer to ${lxcTargetLabel}`, icon: '', stages: ['upload'] },
            { id: 'start',  label: `Import & start on ${lxcTargetLabel}`, icon: '', stages: ['import', 'start'] },
        ];
        showVmMigrateProgressModal(name, steps, 'Container');
        const startTime = Date.now();
        const elapsedEl = document.getElementById('vm-migrate-elapsed');
        const elapsedTimer = setInterval(() => {
            const secs = Math.floor((Date.now() - startTime) / 1000);
            const mins = Math.floor(secs / 60);
            if (elapsedEl) elapsedEl.textContent = mins > 0 ? `Elapsed: ${mins}m ${secs % 60}s` : `Elapsed: ${secs}s`;
        }, 1000);
        try {
            const targetNode = allNodes.find(n => n.id === target);
            const migrateBody = { target_node: target };
            if (targetNode) { migrateBody.target_address = targetNode.address; migrateBody.target_port = targetNode.port || 8553; }
            if (migrateStorage) migrateBody.storage = migrateStorage;
            const resp = await fetch(apiUrl(`/api/containers/lxc/${name}/migrate`), {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(migrateBody),
            });
            const kickoff = await resp.json().catch(() => ({}));
            if (!resp.ok || !kickoff.task_id) {
                clearInterval(elapsedTimer);
                const msg = kickoff.error || 'Failed to start migration';
                vmMigrateProgressFinish(steps, false, msg, 'export');
                updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate LXC '${name}': ${msg}` });
                return;
            }
            const result = await pollVmMigrationProgress(kickoff.task_id, steps);
            clearInterval(elapsedTimer);
            const finishMsg = result.ok ? (result.message || 'Migration complete') : (result.error || 'Migration failed');
            vmMigrateProgressFinish(steps, result.ok, finishMsg, result.failedStage);
            if (result.ok) {
                updateTaskLogEntry(logTaskId, { status: 'completed', description: `Migrate LXC '${name}' → ${lxcTargetLabel}: ${result.message || 'Done'}` });
                setTimeout(loadLxcContainers, 500);
            } else {
                updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate LXC '${name}': ${result.error || 'Failed'}` });
            }
        } catch (e) {
            clearInterval(elapsedTimer);
            vmMigrateProgressFinish(steps, false, `Migration failed: ${e.message}`, 'export');
            updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate LXC '${name}': ${e.message}` });
        }
    }
}

// ─── VM Backup (per-VM quick backup) ───
//
// Stage F: a one-click "back up this VM now" action wired straight to
// the per-VM row. Calls POST /api/backups with a Local-storage default
// at /var/lib/wolfstack/backups — the operator picks fancier storage
// (S3 / NFS / PBS) from the Backups page. The backend dispatches by
// platform (native / Proxmox / libvirt) and produces a portable
// WolfStack-format archive that restores cleanly anywhere.
async function backupSingleVm(vmName) {
    await refreshBackupLocalDir();
    if (!await wolfConfirm(
        `Back up VM "${vmName}" now to local storage (${_backupLocalDir})?\n\n` +
        `The backup is a portable tar.gz archive: VM config + every disk as qcow2. ` +
        `It restores cleanly on this host (native KVM, Proxmox, or libvirt) AND on ` +
        `any other WolfStack node — the file is platform-independent.\n\n` +
        `For S3 / NFS / PBS destinations, use the Backups page directly.`,
        'Backup VM', { okText: 'Backup now' }
    )) return;
    const storage = { type: 'local', path: _backupLocalDir };
    const target = { target_type: 'vm', name: vmName, hostname: null, state: null, specs: null };
    // The /api/backups endpoint is synchronous (it returns once the
    // tarball is written). On a stopped Proxmox VM with multi-GB
    // disks this can run for minutes, and previously the button just
    // sat there with no feedback. Show an in-flight toast so the
    // user knows it's running.
    showToast(`Backing up "${vmName}" — this may take a few minutes for large disks…`, 'info');
    try {
        const r = await fetch(apiUrl('/api/backups'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ target, storage }),
        });
        const data = await r.json();
        if (!r.ok) {
            const errMsg = (data && data.error) || ('HTTP ' + r.status);
            showToast(`Backup failed for "${vmName}": ${errMsg}`, 'error');
            return;
        }
        // Response contains entries with status / size / file path —
        // surface the real result instead of saying "queued" (the
        // /api/backups endpoint is synchronous, the backup is DONE
        // by the time this fires).
        const entry = (data && data.entries && data.entries[0]) || {};
        // S4 fix: backend field is `size_bytes`, not `size`. Pre-fix the
        // toast always showed "0 MB" because `entry.size` was undefined.
        const sizeMb = entry.size_bytes ? Math.round(entry.size_bytes / (1024 * 1024)) : null;
        const sizeNote = sizeMb !== null ? ` — ${sizeMb} MB` : '';
        if (entry.status === 'failed') {
            showToast(
                `Backup failed for "${vmName}": ${entry.error || 'unknown error'}`,
                'error'
            );
        } else {
            showToast(
                `Backup completed for "${vmName}"${sizeNote}. See the Backups page for the archive.`,
                'success'
            );
        }
    } catch (e) {
        showToast(`Backup failed: ${e.message || e}`, 'error');
    }
}
window.backupSingleVm = backupSingleVm;

// Clone a VM on this host. Always a full clone — full copies are safe
// to start/stop/delete independently; linked clones (Proxmox thin-overlay,
// available via `qm clone --full 0`) tie the child to the source and
// break if the source is removed. Defer that toggle until there's a real
// ask for it. Backend dispatches by platform: qm clone / virt-clone /
// native file-copy. Long operation — handler is wrapped in web::block.
async function cloneVm(vmName) {
    const suggested = `${vmName}-clone`;
    const newName = await wolfPrompt(
        `New name for the clone of "${vmName}":\n\n` +
        `Allowed: A-Z a-z 0-9 _ . - + :  (no spaces, no slashes). ` +
        `On Proxmox this runs \`qm clone\`; on libvirt \`virt-clone --auto-clone\`; ` +
        `on native KVM the OS disk + extra disks are file-copied and the MAC ` +
        `addresses are regenerated so both VMs can run side-by-side.\n\n` +
        `Full clone — the new VM is independent of the source.`,
        suggested, 'Clone VM', { okText: 'Clone', placeholder: suggested }
    );
    if (!newName) return;
    const trimmed = newName.trim();
    if (!trimmed) return;
    // Client-side mirror of the backend validator so the user sees the
    // error before we hit the API. The backend re-validates regardless.
    // `-` is escaped explicitly so a future `/u` flag (which makes
    // unescaped `-` adjacency a SyntaxError) doesn't surprise us.
    // Leading `-` is also forbidden so a name can't be argv-injected
    // into `qm clone … --name <name>` on the backend.
    if (!/^[A-Za-z0-9_.+:\-]+$/.test(trimmed)
        || trimmed.startsWith('.') || trimmed.startsWith('-')
        || trimmed.includes('..'))
    {
        showToast(
            `Invalid name "${trimmed}" — use A-Z a-z 0-9 _ . - + : (no leading dot or dash, no '..').`,
            'error'
        );
        return;
    }
    if (trimmed === vmName) {
        showToast('Clone name must differ from the source.', 'error');
        return;
    }
    showToast(`Cloning "${vmName}" → "${trimmed}" — this may take a few minutes for large disks…`, 'info');
    try {
        const r = await fetch(apiUrl(`/api/vms/${encodeURIComponent(vmName)}/clone`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include',
            body: JSON.stringify({ new_name: trimmed, full: true }),
        });
        const data = await r.json().catch(() => ({}));
        if (!r.ok) {
            const errMsg = (data && data.error) || ('HTTP ' + r.status);
            showToast(`Clone failed: ${errMsg}`, 'error');
            return;
        }
        showToast(`Cloned "${vmName}" → "${trimmed}". The new VM is stopped — start it from the VM list.`, 'success');
        // Refresh the VM list so the new clone appears without a
        // manual reload. Both the datacenter table and the per-server
        // card view ultimately come from loadVms() → renderVmCards().
        if (typeof loadVms === 'function') { try { loadVms(); } catch (_) {} }
    } catch (e) {
        showToast(`Clone failed: ${e.message || e}`, 'error');
    }
}
window.cloneVm = cloneVm;

// ─── VM Migration ───

async function migrateVm(name) {
    let nodes = [];
    try {
        const resp = await fetch('/api/nodes');
        if (resp.ok) {
            const data = await resp.json();
            nodes = Array.isArray(data) ? data : (data.nodes || []);
        }
    } catch (e) { }
    // Filter to the VM's OWN cluster (excluding its current host).
    // Uses `currentNodeId` — the node being browsed — not the self-node,
    // so cross-cluster browsing lists the right destinations.
    const vmHost = nodes.find(n => n.id === currentNodeId)
                || allNodes.find(n => n.id === currentNodeId)
                || nodes.find(n => n.is_self);
    const vmCluster = vmHost?.cluster_name || 'WolfStack';
    const remoteNodes = nodes.filter(n => n.id !== currentNodeId && n.online && (n.cluster_name || 'WolfStack') === vmCluster)
        .sort((a, b) => (a.hostname || a.address).localeCompare(b.hostname || b.address));

    const modal = document.createElement('div');
    modal.id = 'vm-migrate-modal';
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:420px;max-width:520px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <h3 style="margin:0 0 16px;color:var(--text,#fff);">Migrate VM</h3>
            <p style="margin:0 0 12px;color:var(--text-muted,#aaa);font-size:0.9em;">Copy <strong>${name}</strong> to another node. The source VM stays running — the destination will be imported but not started.</p>
            <div style="background:var(--danger-bg);border:1px solid var(--danger);border-radius:8px;padding:10px 12px;margin-bottom:10px;color:var(--danger);font-size:0.85em;">
                Warning: The VM will experience downtime during migration. Large disks may take a long time to transfer.
            </div>
            <div style="background:var(--warning-bg);border:1px solid var(--warning);border-radius:8px;padding:10px 12px;margin-bottom:16px;color:var(--warning);font-size:0.85em;">
                Note: After migration you will likely need to update the VM's network settings (IP address, gateway, DNS) on the destination node to match the new network.
            </div>
            <div style="display:flex;flex-direction:column;gap:12px;">
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Migrate to</label>
                    <select id="vm-migrate-target" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">-- Select a cluster node --</option>
                        ${remoteNodes.map(n => `<option value="${n.id}">${n.hostname} (${n.address})</option>`).join('')}
                        <option value="__external__">External cluster...</option>
                    </select></div>
                <div id="vm-migrate-external-fields" style="display:none;">
                    <div style="background:var(--info-bg);border:1px solid var(--info);border-radius:8px;padding:10px 12px;margin-bottom:12px;color:var(--info);font-size:0.82em;line-height:1.5;">
                        <strong>Cross-cluster migration</strong>: On the destination cluster, go to <strong>LXC Containers</strong> and click <strong>Generate Transfer Token</strong>. The same token works for VM transfers.
                    </div>
                    <label style="font-size:13px;color:var(--text-muted,#aaa);">Target URL</label>
                    <input id="vm-migrate-ext-url" type="text" placeholder="https://target.example.com" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;margin-bottom:8px;">
                    <label style="font-size:13px;color:var(--text-muted,#aaa);">Transfer Token</label>
                    <input id="vm-migrate-ext-token" type="text" placeholder="wst_..." style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                </div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Destination Storage</label>
                    <select id="vm-migrate-storage" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                        <option value="">Default</option>
                    </select>
                    <span id="vm-migrate-storage-hint" style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">Select a target node to load available storages</span></div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Source Staging Directory <span style="color:var(--text-muted,#666);font-weight:normal;">(optional)</span></label>
                    <input id="vm-migrate-staging" type="text" placeholder="/tmp  (default — pick somewhere larger if VM disk &gt; /tmp size)" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                    <span style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">Where the export tarball is staged on THIS node before upload. Needs ~2× the VM disk size free. Leave blank for /tmp / $TMPDIR.</span></div>
                <div><label style="font-size:13px;color:var(--text-muted,#aaa);">Target Staging Directory <span style="color:var(--text-muted,#666);font-weight:normal;">(optional)</span></label>
                    <input id="vm-migrate-target-staging" type="text" placeholder="/tmp on the target  (default)" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                    <span style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">Where the incoming archive is staged on the target node. Needs ~1× VM disk size free. Leave blank for the target's /tmp / $TMPDIR.</span></div>
                <label id="vm-migrate-pve-row" style="font-size:13px;color:var(--text-muted,#aaa);display:none;align-items:center;gap:8px;cursor:pointer;">
                    <input type="checkbox" id="vm-migrate-pve"/>
                    <span>Import as <strong>Proxmox-managed VM</strong> on the target (uses <code>qm create</code> + <code>qm importdisk</code>; destination storage above must be a PVE storage ID like <code>local-lvm</code>)</span>
                </label>
                <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:8px;">
                    <button class="btn" onclick="document.getElementById('vm-migrate-modal')?.remove()">Cancel</button>
                    <button class="btn" style="background:#ef4444;color:#fff;" onclick="doMigrateVm('${name}')">Migrate</button>
                </div>
            </div>
        </div>
    `;
    document.body.appendChild(modal);

    // Helper: populate VM storage dropdown
    function vmPopulateStorages(data) {
        const sel = document.getElementById('vm-migrate-storage');
        const hint = document.getElementById('vm-migrate-storage-hint');
        sel.innerHTML = '<option value="">Default</option>';
        const storages = data.storages || [];
        const suitable = storages.filter(s => s.content && s.content.some(c => c === 'rootdir' || c === 'images'));
        (suitable.length ? suitable : storages.filter(s => s.status === 'active')).forEach(s => {
            const free = typeof formatBytes === 'function' ? formatBytes(s.available_bytes) : Math.round(s.available_bytes / 1073741824) + ' GB';
            sel.insertAdjacentHTML('beforeend', `<option value="${s.id}">${s.id} (${s.type || ''}, ${free} free)</option>`);
        });
        hint.textContent = storages.length ? '' : 'No storages found';
    }

    document.getElementById('vm-migrate-target').addEventListener('change', async (e) => {
        const val = e.target.value;
        document.getElementById('vm-migrate-external-fields').style.display = val === '__external__' ? 'block' : 'none';

        // Reveal the "Import as Proxmox VM" checkbox only when the
        // chosen target is actually a Proxmox node — for WolfStack-
        // to-WolfStack moves the option is misleading.
        const pveRow = document.getElementById('vm-migrate-pve-row');
        const pveCb = document.getElementById('vm-migrate-pve');
        if (pveRow && pveCb) {
            const targetNode = (nodes || []).find(n => n.id === val);
            const isPve = !!targetNode && targetNode.node_type === 'proxmox';
            pveRow.style.display = isPve ? 'flex' : 'none';
            if (!isPve) pveCb.checked = false;
        }

        const sel = document.getElementById('vm-migrate-storage');
        const hint = document.getElementById('vm-migrate-storage-hint');
        sel.innerHTML = '<option value="">Default</option>';
        if (!val || val === '__external__') {
            hint.textContent = val === '__external__' ? 'Enter a target URL to load available storages' : 'Select a target node to load available storages';
            return;
        }
        hint.textContent = 'Loading storages...';
        try {
            const resp = await fetch(`/api/nodes/${val}/proxy/storage/list`);
            if (resp.ok) { vmPopulateStorages(await resp.json()); }
            else { hint.textContent = 'Could not load storages from target node'; }
        } catch (err) { hint.textContent = 'Could not reach target node for storage list'; }
    });

    // Fetch storages from external URL via backend proxy (handles auth + port detection)
    let vmExtUrlTimer = null;
    document.getElementById('vm-migrate-ext-url')?.addEventListener('input', (e) => {
        clearTimeout(vmExtUrlTimer);
        vmExtUrlTimer = setTimeout(async () => {
            const url = e.target.value.trim();
            const sel = document.getElementById('vm-migrate-storage');
            const hint = document.getElementById('vm-migrate-storage-hint');
            sel.innerHTML = '<option value="">Default</option>';
            if (!url) { hint.textContent = 'Enter a target URL to load available storages'; return; }
            hint.textContent = 'Connecting to remote cluster...';
            try {
                const resp = await fetch(`/api/storage/remote-list?url=${encodeURIComponent(url)}`);
                if (resp.ok) { vmPopulateStorages(await resp.json()); }
                else { const d = await resp.json().catch(() => ({})); hint.textContent = d.error || 'Could not reach remote cluster'; }
            } catch { hint.textContent = 'Could not reach remote cluster'; }
        }, 800);
    });
}

async function doMigrateVm(name) {
    const target = document.getElementById('vm-migrate-target').value;
    if (!target) { showToast('Select a target node', 'error'); return; }

    const rawExtUrl = document.getElementById('vm-migrate-ext-url')?.value.trim() || '';
    const extToken = document.getElementById('vm-migrate-ext-token')?.value.trim() || '';
    const migrateStorage = document.getElementById('vm-migrate-storage')?.value || '';
    const stagingDir = (document.getElementById('vm-migrate-staging')?.value || '').trim();
    const targetStagingDir = (document.getElementById('vm-migrate-target-staging')?.value || '').trim();
    const importAsProxmox = !!document.getElementById('vm-migrate-pve')?.checked;

    const isExternal = target === '__external__';
    if (isExternal && (!rawExtUrl || !extToken)) { showToast('Enter URL and token', 'error'); return; }
    const extUrl = isExternal ? normalizeWolfStackUrl(rawExtUrl) : '';

    document.getElementById('vm-migrate-modal')?.remove();

    const targetLabel = isExternal ? extUrl.replace(/https?:\/\//, '').split('/')[0] : target;
    const logTaskId = taskLogStart(`Migrating VM '${name}' to ${targetLabel}`);

    // Stage → step mapping. The backend emits these stage strings in
    // order; we promote each step to done/active based on the current
    // stage. preflight & stopping count as "before export" (spinner on
    // the export step; it's the first real long step anyway).
    const steps = [
        { id: 'export', label: 'Creating disk archive', icon: '', stages: ['preflight', 'stopping', 'export'] },
        { id: 'upload', label: isExternal ? `Uploading to ${targetLabel}` : 'Transferring to target node', icon: '', stages: ['upload'] },
        { id: 'import', label: 'Importing on target node (stopped)', icon: '', stages: ['import'] },
    ];

    showVmMigrateProgressModal(name, steps);
    const startTime = Date.now();
    const elapsedEl = document.getElementById('vm-migrate-elapsed');
    const elapsedTimer = setInterval(() => {
        const secs = Math.floor((Date.now() - startTime) / 1000);
        const mins = Math.floor(secs / 60);
        elapsedEl.textContent = mins > 0 ? `Elapsed: ${mins}m ${secs % 60}s` : `Elapsed: ${secs}s`;
    }, 1000);

    try {
        let resp;
        if (isExternal) {
            const extBody = { target_url: extUrl, target_token: extToken };
            if (migrateStorage) extBody.storage = migrateStorage;
            if (stagingDir) extBody.staging_dir = stagingDir;
            if (targetStagingDir) extBody.target_staging_dir = targetStagingDir;
            if (importAsProxmox) extBody.proxmox = true;
            resp = await fetch(`/api/vms/${name}/migrate-external`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(extBody),
            });
        } else {
            const targetNode = allNodes.find(n => n.id === target);
            const migrateBody = { target_node: target };
            if (targetNode) { migrateBody.target_address = targetNode.address; migrateBody.target_port = targetNode.port || 8553; }
            if (migrateStorage) migrateBody.storage = migrateStorage;
            if (stagingDir) migrateBody.staging_dir = stagingDir;
            if (targetStagingDir) migrateBody.target_staging_dir = targetStagingDir;
            if (importAsProxmox) migrateBody.proxmox = true;
            resp = await fetch(apiUrl(`/api/vms/${name}/migrate`), {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(migrateBody),
            });
        }

        const kickoff = await resp.json().catch(() => ({}));
        if (!resp.ok || !kickoff.task_id) {
            clearInterval(elapsedTimer);
            vmMigrateProgressFinish(null, false, kickoff.error || 'Failed to start migration');
            updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate VM '${name}': ${kickoff.error || 'start failed'}` });
            return;
        }

        const final = await pollVmMigrationProgress(kickoff.task_id, steps, isExternal);
        clearInterval(elapsedTimer);
        const totalSecs = Math.floor((Date.now() - startTime) / 1000);
        const totalMins = Math.floor(totalSecs / 60);
        if (elapsedEl) {
            elapsedEl.textContent = totalMins > 0 ? `Completed in ${totalMins}m ${totalSecs % 60}s` : `Completed in ${totalSecs}s`;
        }
        if (final.ok) {
            vmMigrateProgressFinish(steps, true, final.message || 'VM migrated successfully');
            updateTaskLogEntry(logTaskId, { status: 'completed', description: `Migrated VM '${name}' to ${targetLabel}` });
            setTimeout(loadVms, 500);
        } else {
            vmMigrateProgressFinish(steps, false, final.error || 'Unknown error', final.failedStage);
            updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate VM '${name}': ${final.error || 'Unknown error'}` });
        }
    } catch (e) {
        clearInterval(elapsedTimer);
        vmMigrateProgressFinish(steps, false, e.message);
        updateTaskLogEntry(logTaskId, { status: 'failed', description: `Migrate VM '${name}': ${e.message}` });
    }
}

/// Renders the progress dialog. Called by both doMigrateVm and
/// doMigrateVmDiskStorage. Inserts the modal into the DOM, wires up
/// the elapsed timer display, and ensures the spin keyframes style is
/// present. Steps array shape: { id, label, icon, stages: [string] }.
function showVmMigrateProgressModal(name, steps, noun = 'VM') {
    // Drop any stale modal so the elapsed-timer/progress lookups below bind
    // to this run's elements, not a leftover one from an aborted migration.
    document.getElementById('vm-op-modal')?.remove();
    const modal = document.createElement('div');
    modal.id = 'vm-op-modal';
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:480px;max-width:580px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <h3 style="margin:0 0 6px;color:var(--text,#fff);">Migrating ${escapeHtml(noun)}</h3>
            <p style="margin:0 0 16px;color:var(--text-muted,#aaa);font-size:0.85em;">Moving <strong>${escapeHtml(name)}</strong> — progress is polled live from the server.</p>
            <div id="vm-migrate-steps" style="display:flex;flex-direction:column;gap:6px;margin-bottom:14px;">
                ${steps.map(s => `
                    <div id="vmstep-${s.id}" style="display:flex;align-items:center;gap:10px;padding:8px 12px;border-radius:8px;background:var(--bg-secondary,#161622);transition:all 0.3s;">
                        <span class="mstep-icon" style="width:24px;text-align:center;font-size:14px;color:var(--text-muted,#555);">${s.icon}</span>
                        <span style="flex:1;font-size:0.88em;color:var(--text-muted,#666);">${s.label}</span>
                        <span class="mstep-status" style="font-size:12px;color:var(--text-muted,#555);min-width:20px;text-align:center;"></span>
                    </div>
                `).join('')}
            </div>
            <div id="vm-migrate-bar-wrap" style="margin-bottom:8px;">
                <div style="display:flex;justify-content:space-between;font-size:12px;color:var(--text-muted,#888);margin-bottom:4px;">
                    <span id="vm-migrate-msg">Starting…</span>
                    <span id="vm-migrate-bytes"></span>
                </div>
                <div style="height:8px;background:var(--bg-secondary,#161622);border-radius:6px;overflow:hidden;border:1px solid var(--border,#333);">
                    <div id="vm-migrate-bar" style="height:100%;width:0%;background:linear-gradient(90deg,#3b82f6,#60a5fa);transition:width 400ms ease-out;"></div>
                </div>
            </div>
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;">
                <div id="vm-migrate-spinner" style="width:20px;height:20px;border:3px solid var(--border,#555);border-top:3px solid #3b82f6;border-radius:50%;animation:spin 1s linear infinite;flex-shrink:0;"></div>
                <span id="vm-migrate-elapsed" style="font-size:0.82em;color:var(--text-muted,#888);">Elapsed: 0s</span>
            </div>
            <div id="vm-op-result" style="display:none;margin-top:12px;padding:12px;border-radius:8px;text-align:left;font-size:0.9em;"></div>
            <button id="vm-op-close" style="display:none;margin-top:12px;" class="btn" onclick="document.getElementById('vm-op-modal')?.remove()">Close</button>
        </div>
    `;
    if (!document.getElementById('lxc-spin-style')) {
        const s = document.createElement('style'); s.id = 'lxc-spin-style';
        s.textContent = '@keyframes spin { to { transform: rotate(360deg); } }';
        document.head.appendChild(s);
    }
    document.body.appendChild(modal);
}

function vmMigrateStepActive(stepId) {
    const el = document.getElementById('vmstep-' + stepId);
    if (!el) return;
    el.style.background = 'rgba(59,130,246,0.15)';
    el.style.border = '1px solid rgba(59,130,246,0.3)';
    el.querySelector('.mstep-status').innerHTML = '<div style="width:14px;height:14px;border:2px solid var(--border,#555);border-top:2px solid #3b82f6;border-radius:50%;animation:spin 1s linear infinite;display:inline-block;"></div>';
    el.querySelector('span:nth-child(2)').style.color = 'var(--text,#fff)';
}
function vmMigrateStepDone(stepId) {
    const el = document.getElementById('vmstep-' + stepId);
    if (!el) return;
    el.style.background = 'rgba(16,185,129,0.08)';
    el.style.border = '1px solid rgba(16,185,129,0.2)';
    el.querySelector('.mstep-status').textContent = '';
    el.querySelector('span:nth-child(2)').style.color = '#10b981';
}
function vmMigrateStepFailed(stepId) {
    const el = document.getElementById('vmstep-' + stepId);
    if (!el) return;
    el.style.background = 'rgba(239,68,68,0.1)';
    el.style.border = '1px solid rgba(239,68,68,0.2)';
    el.querySelector('.mstep-status').textContent = '';
    el.querySelector('span:nth-child(2)').style.color = '#ef4444';
}

function formatMigrateBytes(done, total) {
    if (done == null) return '';
    const fmt = (n) => {
        if (n < 1024) return n + ' B';
        if (n < 1024 * 1024) return (n / 1024).toFixed(1) + ' KB';
        if (n < 1024 * 1024 * 1024) return (n / (1024 * 1024)).toFixed(1) + ' MB';
        return (n / (1024 * 1024 * 1024)).toFixed(2) + ' GB';
    };
    if (total != null && total > 0) return `${fmt(done)} / ${fmt(total)}`;
    return fmt(done);
}

/// Poll /api/migration/{id}/status every second and update the modal's
/// steps + progress bar. Resolves with `{ok, message?, error?, failedStage?}`
/// once the task reaches `done` or `failed`. Any network hiccup during
/// polling keeps retrying — the migration runs server-side so a
/// transient fetch failure shouldn't abort the UI.
async function pollVmMigrationProgress(taskId, steps) {
    const barEl = document.getElementById('vm-migrate-bar');
    const msgEl = document.getElementById('vm-migrate-msg');
    const bytesEl = document.getElementById('vm-migrate-bytes');
    const stageToStep = {};
    steps.forEach(s => (s.stages || [s.id]).forEach(stg => { stageToStep[stg] = s.id; }));
    let lastStage = null;
    let failedStage = null;
    // Bail out if the status endpoint is unreachable for too long (server
    // restarted, task evicted) rather than polling forever.
    let consecutiveFailures = 0;
    const maxFailures = 30;

    while (true) {
        await new Promise(r => setTimeout(r, 1000));
        let data;
        try {
            const r = await fetch(apiUrl(`/api/migration/${taskId}/status`));
            if (!r.ok) {
                if (++consecutiveFailures >= maxFailures) {
                    return { ok: false, error: 'Lost contact with the server while polling migration status. Check the destination node before starting either copy.', failedStage: failedStage || (steps[steps.length - 1] && steps[steps.length - 1].id) };
                }
                continue;
            }
            data = await r.json();
            consecutiveFailures = 0;
        } catch {
            if (++consecutiveFailures >= maxFailures) {
                return { ok: false, error: 'Lost contact with the server while polling migration status. Check the destination node before starting either copy.', failedStage: failedStage || (steps[steps.length - 1] && steps[steps.length - 1].id) };
            }
            continue;
        }

        const stage = data.stage || '';
        const msg = data.message || '';
        const pct = typeof data.percent === 'number' ? data.percent : null;
        const done = typeof data.bytes_done === 'number' ? data.bytes_done : null;
        const total = typeof data.bytes_total === 'number' ? data.bytes_total : null;

        if (msgEl) msgEl.textContent = msg || '…';
        if (bytesEl) bytesEl.textContent = formatMigrateBytes(done, total);
        if (barEl) {
            if (pct != null) {
                barEl.style.width = Math.max(0, Math.min(100, pct)).toFixed(1) + '%';
                barEl.style.background = 'linear-gradient(90deg,#3b82f6,#60a5fa)';
            } else {
                barEl.style.width = '100%';
                barEl.style.background = 'repeating-linear-gradient(45deg,rgba(59,130,246,0.4) 0 10px,rgba(59,130,246,0.15) 10px 20px)';
            }
        }

        // Promote steps as the stage advances
        if (stage && stage !== lastStage) {
            const currentStepId = stageToStep[stage];
            if (currentStepId) {
                // Mark every previous step done
                for (const s of steps) {
                    if (s.id === currentStepId) break;
                    vmMigrateStepDone(s.id);
                }
                vmMigrateStepActive(currentStepId);
            }
            lastStage = stage;
        }

        if (data.completed) {
            if (stage === 'done') {
                for (const s of steps) vmMigrateStepDone(s.id);
                return { ok: true, message: msg };
            } else {
                failedStage = stageToStep[lastStage] || (steps[steps.length - 1] && steps[steps.length - 1].id);
                return { ok: false, error: data.error || msg || 'Unknown error', failedStage };
            }
        }
    }
}

function vmMigrateProgressFinish(steps, ok, message, failedStepId) {
    const resultEl = document.getElementById('vm-op-result');
    const spinner = document.getElementById('vm-migrate-spinner');
    const barWrap = document.getElementById('vm-migrate-bar-wrap');
    if (spinner) spinner.style.display = 'none';
    const closeBtn = document.getElementById('vm-op-close');
    if (closeBtn) closeBtn.style.display = '';
    if (ok) {
        if (steps) for (const s of steps) vmMigrateStepDone(s.id);
        if (barWrap) {
            const bar = document.getElementById('vm-migrate-bar');
            if (bar) { bar.style.width = '100%'; bar.style.background = 'linear-gradient(90deg,#10b981,#34d399)'; }
        }
        if (resultEl) {
            resultEl.style.display = 'block';
            resultEl.style.background = 'rgba(16,185,129,0.15)';
            resultEl.style.color = '#10b981';
            resultEl.textContent = message;
        }
    } else {
        if (steps && failedStepId) vmMigrateStepFailed(failedStepId);
        if (barWrap) {
            const bar = document.getElementById('vm-migrate-bar');
            if (bar) { bar.style.background = 'linear-gradient(90deg,#ef4444,#f87171)'; }
        }
        if (resultEl) {
            resultEl.style.display = 'block';
            resultEl.style.background = 'rgba(239,68,68,0.15)';
            resultEl.style.color = '#ef4444';
            resultEl.textContent = message;
        }
    }
}

// Move a stopped VM's disks to a different storage pool on the SAME
// node. Mirrors the LXC disk-migrate dialog — same shape (target +
// remove-source checkbox), different endpoint. Intended for shifting
// a VM from /var/lib/wolfstack/vms onto a bigger ZFS pool without
// crossing the cluster.
async function migrateVmDiskStorage(name) {
    // Fetch storage candidates from this node's /api/storage/list so
    // the operator picks from real mount points / PVE storage IDs,
    // not a free-form path (which worked too, but typos → silent fail).
    let storages = [];
    let isProxmoxHost = false;
    try {
        const r = await fetch(apiUrl('/api/storage/list'));
        if (r.ok) {
            const d = await r.json();
            storages = (d.storages || d || []).filter(s =>
                !s.content || s.content.includes('images') || s.content.includes('rootdir')
            );
            // PVE storages have a `type` field like "lvmthin" / "dir"
            // AND usually an `id` column that differs from `path`.
            // Detect so we can show the right hint text.
            isProxmoxHost = storages.some(s => s.type && s.type !== 'native');
        }
    } catch {}

    const opts = storages.map(s => {
        const free = typeof formatBytes === 'function'
            ? formatBytes((s.available_bytes || s.available_gb * 1073741824) || 0)
            : (s.available_gb ? s.available_gb + ' GB' : '—') + ' free';
        // On Proxmox hosts the "target" the backend calls `qm move_disk`
        // with is the PVE storage ID, not a path. Prefer s.id for PVE
        // rows so the operator picks the correct token.
        const val = isProxmoxHost ? (s.id || s.path) : (s.path || s.id);
        const label = isProxmoxHost ? `${s.id}${s.type ? ' ('+s.type+')' : ''}` : (s.path || s.id);
        return `<option value="${escapeAttr(val)}">${escapeHtml(label)} (${free})</option>`;
    }).join('');

    const modal = document.createElement('div');
    modal.className = 'modal-overlay';
    // .modal-overlay defaults to opacity:0; pointer-events:none — override
    // inline so the modal is interactive immediately on append.
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);opacity:1;pointer-events:all;';
    modal.innerHTML = `
        <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:440px;max-width:560px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <h3 style="margin:0 0 10px;color:var(--text,#fff);">Migrate VM Disk Storage</h3>
            <p style="margin:0 0 14px;color:var(--text-muted,#aaa);font-size:0.9em;">Move <strong>${escapeHtml(name)}</strong>'s disks to a different storage pool on <em>this</em> node. VM must be stopped; the config is updated to point at the new pool after copy.</p>
            ${isProxmoxHost ? '<div style="background:rgba(59,130,246,0.08);border:1px solid rgba(59,130,246,0.25);border-radius:6px;padding:8px 12px;margin-bottom:8px;font-size:12px;color:var(--text,#fff);">Proxmox host detected — target is a PVE <strong>storage ID</strong> (e.g. <code>local-lvm</code>, <code>wolfpool</code>). The server will call <code>qm move_disk</code> for every disk slot.</div>' : ''}
            <div style="display:flex;flex-direction:column;gap:12px;">
                <div>
                    <label style="font-size:13px;color:var(--text-muted,#aaa);">${isProxmoxHost ? 'Target PVE storage ID' : 'Target storage path'}</label>
                    <input id="vm-disk-migrate-target" list="vm-disk-migrate-options" placeholder="${isProxmoxHost ? 'local-lvm' : '/wolfpool/vms'}" style="width:100%;padding:8px 12px;background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:6px;color:var(--text,#fff);margin-top:4px;">
                    <datalist id="vm-disk-migrate-options">${opts}</datalist>
                    <span style="font-size:11px;color:var(--text-muted,#666);margin-top:2px;display:block;">${isProxmoxHost ? 'Pick from the PVE storage IDs above, or type one. PVE handles the copy and config update atomically.' : 'Pick from known mounts or type a path. Target directory must exist; free-space is pre-flighted before any copy.'}</span>
                </div>
                <label style="font-size:13px;color:var(--text-muted,#aaa);display:flex;align-items:center;gap:8px;cursor:pointer;">
                    <input type="checkbox" id="vm-disk-migrate-remove-source"/>
                    <span>Remove source files after successful copy</span>
                </label>
                <span style="font-size:11px;color:var(--text-muted,#666);">Default OFF — keep the source until you've confirmed the new copy boots. Turn on only if you need the space back immediately.</span>
                <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:8px;">
                    <button class="btn" onclick="this.closest('.modal-overlay').remove()">Cancel</button>
                    <button class="btn" style="background:#3b82f6;color:#fff;" onclick="doMigrateVmDiskStorage('${escapeAttr(name)}', this)">Migrate Disk</button>
                </div>
            </div>
        </div>`;
    document.body.appendChild(modal);
}

async function doMigrateVmDiskStorage(name, btn) {
    const overlay = btn?.closest?.('.modal-overlay') || document;
    const target = (overlay.querySelector('#vm-disk-migrate-target')?.value || '').trim();
    const removeSource = !!overlay.querySelector('#vm-disk-migrate-remove-source')?.checked;
    if (!target) { showToast('Pick or enter a target storage path', 'error'); return; }
    if (!(await showConfirm(`Migrate ${name}'s disks to ${target}? ${removeSource ? '(source will be removed after successful copy)' : '(source will be kept)'}`))) return;
    overlay.remove?.();

    const logTaskId = taskLogStart(`Migrating VM '${name}' disks to ${target}`);
    const steps = [
        { id: 'disk_copy', label: `Copying disks → ${target}`, icon: '', stages: ['preflight', 'disk_copy'] },
    ];
    showVmMigrateProgressModal(name, steps);
    const startTime = Date.now();
    const elapsedEl = document.getElementById('vm-migrate-elapsed');
    const elapsedTimer = setInterval(() => {
        const secs = Math.floor((Date.now() - startTime) / 1000);
        const mins = Math.floor(secs / 60);
        elapsedEl.textContent = mins > 0 ? `Elapsed: ${mins}m ${secs % 60}s` : `Elapsed: ${secs}s`;
    }, 1000);

    try {
        const r = await fetch(apiUrl(`/api/vms/${encodeURIComponent(name)}/disk/migrate`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ target, remove_source: removeSource }),
        });
        const kickoff = await r.json().catch(() => ({}));
        if (!r.ok || !kickoff.task_id) {
            clearInterval(elapsedTimer);
            vmMigrateProgressFinish(steps, false, kickoff.error || ('HTTP ' + r.status));
            updateTaskLogEntry(logTaskId, { status: 'failed', description: `VM '${name}' disk migrate: ${kickoff.error || r.status}` });
            return;
        }
        const final = await pollVmMigrationProgress(kickoff.task_id, steps);
        clearInterval(elapsedTimer);
        if (final.ok) {
            vmMigrateProgressFinish(steps, true, final.message || 'Disk migration complete');
            updateTaskLogEntry(logTaskId, { status: 'completed', description: final.message || `Migrated '${name}' disks to ${target}` });
            if (typeof loadVms === 'function') loadVms();
        } else {
            vmMigrateProgressFinish(steps, false, final.error || 'Unknown error', final.failedStage);
            updateTaskLogEntry(logTaskId, { status: 'failed', description: `VM '${name}' disk migrate: ${final.error || 'Unknown error'}` });
        }
    } catch (e) {
        clearInterval(elapsedTimer);
        vmMigrateProgressFinish(steps, false, e.message);
        updateTaskLogEntry(logTaskId, { status: 'failed', description: `VM '${name}' disk migrate: ${e.message}` });
    }
}

// Open the LXC storage panel: shows current backend + size + used,
// lets the user grow the volume or migrate it to another storage.
// Same UI works for native LXC (rsync-based migrate, ZFS/LVM/btrfs
// resize) and Proxmox-managed LXC (PVE move-volume / resize API).
async function openLxcStorage(name) {
    const apiBase = apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/disk`);
    let info;
    try {
        const r = await fetch(apiBase);
        if (!r.ok) {
            const err = await r.json().catch(() => ({}));
            showToast(`Couldn't read storage info: ${err.error || r.status}`, 'error');
            return;
        }
        info = await r.json();
    } catch (e) {
        showToast('Network error: ' + e.message, 'error');
        return;
    }
    const fmtBytes = (b) => {
        if (b == null) return '—';
        if (b > 1024**4) return (b / 1024**4).toFixed(2) + ' TB';
        if (b > 1024**3) return (b / 1024**3).toFixed(2) + ' GB';
        if (b > 1024**2) return (b / 1024**2).toFixed(1) + ' MB';
        return b + ' B';
    };
    const currentGb = info.size_bytes != null ? Math.ceil(info.size_bytes / 1024 / 1024 / 1024) : 8;
    const usedPct = (info.size_bytes && info.used_bytes)
        ? Math.round(100 * info.used_bytes / info.size_bytes) : 0;
    // Storage targets — use the same /api/storage/list that the LXC
    // create flow uses, filtered to sensible LXC-rootfs targets. That
    // call goes through apiUrl() so when the user is viewing a remote
    // node's containers, the storage list also comes from that node
    // (not the browser's local host). Filter out the current storage
    // so a user can't accidentally "migrate" into the same place.
    let targetOptions = '';
    try {
        // PVE containers use move-volume and need a PVE storage id —
        // fetch those from /api/storage/list. Native LXC uses rsync to
        // a filesystem path, which means we need *real mount points*
        // on the host, not PVE storage definitions that may have no
        // directly-cd-able path (rbd, zfs pools referenced by id, …).
        // /api/storage/filesystems walks the node's live metrics disk
        // list and returns only writable on-disk filesystems.
        let opts = '';
        if (info.proxmox) {
            const r = await fetch(apiUrl('/api/storage/list'));
            const list = r.ok ? await r.json() : {};
            const storages = Array.isArray(list.storages) ? list.storages : [];
            const usable = storages.filter(s =>
                s.content && s.content.some(c => c === 'rootdir' || c === 'images')
                && s.id !== info.storage
            );
            if (usable.length) {
                opts = usable.map(s => {
                    const free = formatBytes(s.available_bytes);
                    return `<option value="${escapeHtml(s.id)}">${escapeHtml(s.id)} (${escapeHtml(s.type)}, ${free} free)</option>`;
                }).join('');
            }
        } else {
            const r = await fetch(apiUrl('/api/storage/filesystems'));
            const list = r.ok ? await r.json() : {};
            const mounts = Array.isArray(list.filesystems) ? list.filesystems : [];
            // Always offer the default /var/lib/lxc unless the container
            // is already there — matches the create-modal default.
            const defaultPath = '/var/lib/lxc';
            if (info.storage !== defaultPath) {
                opts += `<option value="${defaultPath}">${defaultPath} (default)</option>`;
            }
            // For every real mount, offer <mount>/lxc as the target so
            // containers land in a predictable subdir. Skip the mount
            // the container is already on and /var/lib/lxc's parent
            // mount (already covered by the default option above).
            for (const m of mounts) {
                if (!m.mount_point) continue;
                const candidate = m.mount_point === '/'
                    ? defaultPath
                    : `${m.mount_point.replace(/\/+$/, '')}/lxc`;
                if (candidate === info.storage) continue;
                if (candidate === defaultPath && info.storage === defaultPath) continue;
                // Dedupe — /var/lib/lxc as default plus a filesystem
                // mounted at / would both produce /var/lib/lxc.
                if (opts.includes(`value="${escapeHtml(candidate)}"`)) continue;
                const free = formatBytes(m.available_bytes);
                opts += `<option value="${escapeHtml(candidate)}">${escapeHtml(candidate)} (${escapeHtml(m.fs_type)}, ${free} free)</option>`;
            }
        }
        if (opts) {
            targetOptions = `<select id="lxc-storage-target" class="form-control">${opts}</select>`;
        } else {
            // Nothing else to migrate to — fall back to a text input so
            // the user can still type a path/storage id if they have one.
            targetOptions = `<input id="lxc-storage-target" class="form-control" placeholder="${info.proxmox ? 'e.g. local-zfs, ceph-pool' : 'filesystem path'}"/>`;
        }
    } catch (e) {
        targetOptions = '<input id="lxc-storage-target" class="form-control" placeholder="storage path or PVE storage id"/>';
    }
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.style.zIndex = '10000';
    overlay.innerHTML = `
        <div class="modal" style="max-width:560px;">
            <div class="modal-header">
                <h3>Storage — ${escapeHtml(name)}</h3>
                <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">×</button>
            </div>
            <div class="modal-body" style="font-size:13px;">
                <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-bottom:14px; padding:10px; background:var(--bg-card); border-radius:6px;">
                    <div><div style="color:var(--text-muted); font-size:11px;">Backend</div><strong>${escapeHtml(info.backend || '?')}</strong>${info.proxmox ? ' <span class="badge" style="background:rgba(6, 182, 212,0.15); color:#06b6d4; font-size:10px; padding:1px 6px;">PVE</span>' : ''}</div>
                    <div><div style="color:var(--text-muted); font-size:11px;">Filesystem</div><strong>${escapeHtml(info.fs_type || '?')}</strong></div>
                    <div><div style="color:var(--text-muted); font-size:11px;">Storage</div><code style="font-size:11px;">${escapeHtml(info.storage || '—')}</code></div>
                    <div><div style="color:var(--text-muted); font-size:11px;">Rootfs</div><code style="font-size:11px;">${escapeHtml(info.rootfs || '—')}</code></div>
                    <div style="grid-column:1/-1;"><div style="color:var(--text-muted); font-size:11px;">Used / Size</div>
                        <strong>${fmtBytes(info.used_bytes)} of ${fmtBytes(info.size_bytes)}</strong>
                        <div style="background:var(--bg-secondary); height:6px; border-radius:3px; margin-top:4px;">
                            <div style="background:${usedPct > 80 ? '#ef4444' : usedPct > 60 ? '#fbbf24' : '#22c55e'}; height:6px; width:${usedPct}%; border-radius:3px;"></div>
                        </div>
                    </div>
                </div>

                <h4 style="font-size:13px; margin:12px 0 6px;">Grow disk</h4>
                <div style="display:flex; gap:8px; align-items:end;">
                    <label style="flex:1;">New size (GB)
                        <input id="lxc-storage-size" type="number" class="form-control" value="${currentGb + 4}" min="${currentGb}"/>
                    </label>
                    <button class="btn btn-primary" onclick="lxcStorageResize(this, '${escapeHtml(name)}')" style="height:34px;">Resize</button>
                </div>
                <div style="font-size:11px; color:var(--text-muted); margin-top:4px;">
                    ${info.backend === 'directory' ? 'Directory backend has no per-container quota — grow the host filesystem instead.' :
                      info.proxmox ? 'Proxmox routes via the PVE resize API; absolute size only (no shrink).' :
                      info.backend === 'zfs' ? 'ZFS quota change is online and instant.' :
                      info.backend === 'lvm' ? 'LVM grow is online for ext4/xfs/btrfs.' :
                      'Resize behaviour depends on the backend.'}
                </div>

                <h4 style="font-size:13px; margin:18px 0 6px;">Move to different storage</h4>
                <div style="display:flex; gap:8px; align-items:end;">
                    <div style="flex:1;">
                        <div style="font-size:11px; color:var(--text-muted); margin-bottom:2px;">Target ${info.proxmox ? 'PVE storage id' : 'LXC storage path'}</div>
                        ${targetOptions}
                    </div>
                    <label style="display:flex; align-items:center; gap:4px; font-size:12px;">
                        <input type="checkbox" id="lxc-storage-remove"/> remove source
                    </label>
                    <button class="btn" onclick="lxcStorageMigrate(this, '${escapeHtml(name)}')" style="height:34px;">Migrate</button>
                </div>
                <div style="font-size:11px; color:var(--text-muted); margin-top:4px;">
                    ${info.proxmox ? 'PVE move-volume copies the volume between storage pools (zfs send/recv, dd, etc).' : 'rsync -aHAX preserves perms/xattrs. Container should be stopped for a clean move.'}
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn" onclick="this.closest('.modal-overlay').remove()">Close</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
}

async function lxcStorageResize(btn, name) {
    // Scope field lookups to the modal this button lives in — the same
    // ID may exist elsewhere in the DOM (e.g. a storage modal for a
    // different container still open) and document.getElementById would
    // pick the first one, not the one the user is actually looking at.
    const overlay = btn?.closest?.('.modal-overlay') || document;
    const sizeEl = overlay.querySelector('#lxc-storage-size');
    const sizeGb = parseInt(sizeEl?.value, 10);
    if (!sizeGb || sizeGb < 1) { showToast('Enter a size in GB', 'warning'); return; }
    if (!(await showConfirm(`Resize ${name}'s disk to ${sizeGb} GB?`))) return;
    try {
        const r = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/disk/resize`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ size_gb: sizeGb }),
        });
        const data = await r.json();
        if (!r.ok) {
            showToast('Resize failed: ' + (data.error || r.status), 'error');
            return;
        }
        showToast(data.message || 'Resized', 'success');
        overlay.remove?.();
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
}

async function lxcStorageMigrate(btn, name) {
    // Scope field lookups to this modal — see lxcStorageResize for why.
    // The previous code used document.getElementById which picks the
    // first match anywhere on the page, so a lingering overlay could
    // feed us the wrong storage target / checkbox state and produce
    // confirms like "Migrate 106 to local? (source will be kept)"
    // when the user had picked wolfpool with remove-source ticked.
    const overlay = btn?.closest?.('.modal-overlay') || document;
    const targetEl = overlay.querySelector('#lxc-storage-target');
    const removeEl = overlay.querySelector('#lxc-storage-remove');
    const target = (targetEl?.value || '').trim();
    const removeSource = !!removeEl?.checked;
    if (!target) { showToast('Pick or enter a target storage', 'warning'); return; }
    if (!(await showConfirm(`Migrate ${name} to ${target}? ${removeSource ? '(source will be removed after copy)' : '(source will be kept)'}`))) return;
    try {
        const r = await fetch(apiUrl(`/api/containers/lxc/${encodeURIComponent(name)}/disk/migrate`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ target, remove_source: removeSource }),
        });
        const data = await r.json();
        if (!r.ok) {
            showToast('Migrate failed: ' + (data.error || r.status), 'error');
            return;
        }
        showToast(data.message || 'Migrate started', 'success', 8000);
        overlay.remove?.();
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
}

async function exportLxcContainer(name) {
    if (!(await showConfirm(`Export container '${name}'? The container will be briefly stopped.`))) return;
    showToast(`Exporting ${name}...`, 'info');

    try {
        const resp = await fetch(apiUrl(`/api/containers/lxc/${name}/export`), { method: 'POST' });
        if (!resp.ok) {
            let data;
            try { data = await resp.json(); } catch { data = {}; }
            showToast(data.error || 'Export failed', 'error');
            return;
        }
        const blob = await resp.blob();
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${name}-export.tar.gz`;
        a.click();
        URL.revokeObjectURL(url);
        showToast(`Exported ${name} — downloading...`, 'success');
    } catch (e) {
        showToast(`Export failed: ${e.message}`, 'error');
    }
}

async function generateTransferToken() {
    try {
        const resp = await fetch(apiUrl('/api/containers/transfer-token'), { method: 'POST' });
        const data = await resp.json();
        if (!resp.ok) { showToast(data.error || 'Failed', 'error'); return; }

        const modal = document.createElement('div');
        modal.id = 'transfer-token-modal';
        modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:10000;backdrop-filter:blur(4px);';
        modal.innerHTML = `
            <div style="background:var(--card-bg,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:28px 36px;min-width:400px;max-width:500px;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
                <h3 style="margin:0 0 12px;color:var(--text,#fff);">Transfer Token Generated</h3>
                <p style="color:var(--text-muted,#aaa);font-size:0.9em;margin-bottom:16px;">
                    Share this token with the source cluster admin. It expires in 30 minutes and can only be used once.
                </p>
                <div style="background:var(--bg-primary,#111);border:1px solid var(--border,#444);border-radius:8px;padding:12px;font-family:monospace;font-size:13px;color:var(--text,#fff);word-break:break-all;margin-bottom:12px;">${data.token}</div>
                <div style="display:flex;gap:8px;justify-content:flex-end;">
                    <button class="btn" onclick="navigator.clipboard.writeText('${data.token}');showToast('Token copied','success')">Copy</button>
                    <button class="btn" onclick="document.getElementById('transfer-token-modal')?.remove()">Close</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);
    } catch (e) {
        showToast(`Error: ${e.message}`, 'error');
    }
}

