// ─── Storage Providers ───

let _currentProviderName = null;

async function loadStorageProviders() {
    try {
        const resp = await fetch(apiUrl('/api/storage/providers'));
        if (!resp.ok) return;
        const providers = await resp.json();
        const grid = document.getElementById('storage-providers-grid');
        grid.innerHTML = providers.map(p => {
            const statusColor = p.status === 'running' ? '#10b981' : p.status === 'stopped' ? '#ef4444' : p.status === 'failed' ? '#ef4444' : '#6b7280';
            const statusLabel = p.status === 'running' ? 'Running' : p.status === 'stopped' ? 'Stopped' : p.status === 'failed' ? 'Failed' : p.status === 'no-service' ? 'Installed' : '⭕ Not Installed';
            const hasService = p.service && p.status !== 'not-installed' && p.status !== 'no-service';
            const wd = p.wolfdisk_info;
            let wdHtml = '';
            if (wd) {
                const roleLabels = { leader: 'Server (Leader)', follower: 'Server (Follower)', client: 'Client Only', auto: 'Auto' };
                const roleColors = { leader: '#f59e0b', follower: '#3b82f6', client: '#06b6d4', auto: '#6b7280' };
                const modeLabel = wd.replication_mode === 'replicated'
                    ? `Replicated (${wd.replication_factor}x)` : 'Shared';
                const features = [];
                if (wd.role !== 'client') features.push(`${modeLabel}`);
                if (wd.peers.length > 0) features.push(`${wd.peers.length} peer${wd.peers.length !== 1 ? 's' : ''}`);
                if (wd.s3_enabled) features.push(`S3 API on ${wd.s3_bind || ':9878'}`);
                wdHtml = `
                <div style="background:var(--bg-tertiary, rgba(0,0,0,0.15)); border-radius:6px; padding:8px 10px; margin-bottom:10px; font-size:12px;">
                    <div style="display:flex; align-items:center; gap:8px; margin-bottom:4px;">
                        <span style="background:${roleColors[wd.role] || '#6b7280'}; color:#fff; padding:1px 8px; border-radius:10px; font-size:11px; font-weight:600;">${roleLabels[wd.role] || wd.role}</span>
                        <span style="color:var(--text-muted);">Node: <strong style="color:var(--text-primary)">${wd.node_id}</strong></span>
                    </div>
                    <div style="display:flex; flex-wrap:wrap; gap:6px 16px; color:var(--text-muted); font-size:11px; margin-top:4px;">
                        ${features.length ? `<span>${features.join(' · ')}</span>` : ''}
                        <span>Mount: <strong style="color:var(--text-primary)">${wd.mount_path}</strong></span>
                        <span>Data: <strong style="color:var(--text-primary)">${wd.data_dir}</strong></span>
                        <span>Bind: <strong style="color:var(--text-primary)">${wd.bind}</strong></span>
                    </div>
                </div>`;
            }
            return `
            <div style="background:var(--bg-secondary); border:1px solid var(--border); border-radius:8px; padding:14px;">
                <div style="display:flex; align-items:center; gap:12px; margin-bottom:10px;">
                    <span style="font-size:24px;">${p.icon}</span>
                    <div style="flex:1; min-width:0;">
                        <div style="font-weight:600; font-size:14px;">${p.label}</div>
                        <div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${p.description}</div>
                    </div>
                </div>
                ${wdHtml}
                <div style="display:flex; align-items:center; justify-content:space-between; gap:8px; flex-wrap:wrap;">
                    <span style="font-size:12px; font-weight:600; color:${statusColor};">${statusLabel}</span>
                    <div style="display:flex; gap:4px; flex-wrap:wrap;">
                        ${!p.installed ? `<button class="btn btn-sm btn-primary" style="font-size:11px;" onclick="installProvider('${p.name}')">Install</button>` : ''}
                        ${hasService && p.status !== 'running' ? `<button class="btn btn-sm" style="font-size:11px; color:#10b981;" onclick="providerAction('${p.name}','start')">▶ Start</button>` : ''}
                        ${hasService && p.status === 'running' ? `<button class="btn btn-sm" style="font-size:11px; color:#ef4444;" onclick="providerAction('${p.name}','stop')">Stop</button>` : ''}
                        ${hasService && p.status === 'running' ? `<button class="btn btn-sm" style="font-size:11px; color:#3b82f6;" onclick="providerAction('${p.name}','restart')">Restart</button>` : ''}
                        ${p.installed ? `<button class="btn btn-sm" style="font-size:11px; color:#60a5fa;" onclick="openProviderSettings('${p.name}','${p.icon}','${p.label}','${p.config_path || ''}')">Settings</button>` : ''}
                    </div>
                </div>
            </div>`;
        }).join('');
    } catch (e) {
        console.error('Failed to load providers:', e);
    }
}

async function installProvider(name) {
    if (!(await showConfirm(`Install storage provider "${name}"? This may take a moment.`))) return;
    showToast(`Installing ${name}...`, 'info');
    try {
        const resp = await fetch(apiUrl(`/api/storage/providers/${name}/install`), { method: 'POST' });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || `${name} installed`, 'success');
            await loadStorageProviders();
            if (name === 'wolfdisk') {
                openProviderSettings('wolfdisk', '', 'WolfDisk', '/etc/wolfdisk/config.toml');
            }
        } else {
            showToast(data.error || 'Install failed', 'error');
            loadStorageProviders();
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

async function providerAction(name, action) {
    showToast(`${action}ing ${name}...`, 'info');
    try {
        const resp = await fetch(apiUrl(`/api/storage/providers/${name}/action`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || `${action} successful`, 'success');
        } else {
            showToast(data.error || `${action} failed`, 'error');
        }
        loadStorageProviders();
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

async function openProviderSettings(name, icon, label, configPath) {
    _currentProviderName = name;
    document.getElementById('provider-settings-icon').textContent = icon;
    document.getElementById('provider-settings-label').textContent = label;
    document.getElementById('provider-config-path').textContent = configPath || 'N/A';

    // Load config
    const editor = document.getElementById('provider-config-editor');
    editor.value = 'Loading...';
    document.getElementById('provider-settings-modal').classList.add('active');

    try {
        const resp = await fetch(apiUrl(`/api/storage/providers/${name}/config`));
        const data = await resp.json();
        editor.value = data.content || '';
        if (data.error) {
            editor.value = `# ${data.error}\n# You can create this file by entering content below and saving.`;
        }
    } catch (e) {
        editor.value = `# Error loading config: ${e.message}`;
    }
}

function closeProviderSettings() {
    document.getElementById('provider-settings-modal').classList.remove('active');
    _currentProviderName = null;
}

async function saveProviderConfig() {
    if (!_currentProviderName) return;
    const content = document.getElementById('provider-config-editor').value;
    try {
        const resp = await fetch(apiUrl(`/api/storage/providers/${_currentProviderName}/config`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ content }),
        });
        const data = await resp.json();
        if (resp.ok) {
            showToast(data.message || 'Config saved', 'success');
        } else {
            showToast(data.error || 'Save failed', 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

// ─── WolfDisk Cluster Management ───

let wdCurrentCluster = '';
let wdClusterData = [];
let wdExpandedNodes = new Set();
let wdConfigNodeId = null;
let wdInstallMode = null; // set when install button was clicked — config saves then launches terminal
let wdLatestVersion = null; // latest version from GitHub

// Encode a unique member ID: "nodeId" for hosts, "nodeId:runtime:containerName" for containers
function wdMemberId(n) {
    if (n.memberType && n.memberType !== 'host' && n.containerName) {
        return n.nodeId + ':' + n.memberType + ':' + n.containerName;
    }
    return n.nodeId;
}

// Parse a member ID back to {nodeId, runtime, container}
function wdParseMemberId(mid) {
    var parts = mid.split(':');
    if (parts.length >= 3) {
        return { nodeId: parts[0], runtime: parts[1], container: parts.slice(2).join(':') };
    }
    return { nodeId: mid, runtime: null, container: null };
}

// Find a member entry in wdClusterData by member ID
function wdFindMember(mid) {
    return wdClusterData.find(function(n) { return wdMemberId(n) === mid; });
}

// Build API URL with optional container targeting query params
function wdApiUrl(mid, path) {
    var p = wdParseMemberId(mid);
    var url = nodeApiUrl(p.nodeId, path);
    if (p.runtime && p.container) {
        var sep = url.indexOf('?') >= 0 ? '&' : '?';
        url += sep + 'runtime=' + encodeURIComponent(p.runtime) + '&target=' + encodeURIComponent(p.container);
    }
    return url;
}

function wdTypeBadge(memberType) {
    var labels = { host: 'Host', docker: 'Docker', lxc: 'LXC' };
    var l = labels[memberType] || memberType || 'Host';
    return '<span style="border:1px solid var(--border); color:var(--text-secondary); padding:1px 6px; border-radius:8px; font-size:10px; font-weight:600;">' + l + '</span>';
}

function showWolfDiskPage(clusterName) {
    closeSidebarMobile();
    wdCurrentCluster = clusterName;
    currentPage = 'wolfdisk-cluster';
    currentNodeId = null;
    wdExpandedNodes.clear();

    document.querySelectorAll('.page-view').forEach(p => p.style.display = 'none');
    const el = document.getElementById('page-wolfdisk-cluster');
    if (el) el.style.display = 'block';
    document.getElementById('page-title').textContent = 'WolfDisk \u2014 ' + clusterName;

    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const item = document.querySelector('.wolfdisk-cluster-item[data-cluster="' + CSS.escape(clusterName) + '"]');
    if (item) item.classList.add('active');

    loadWolfDiskCluster();
}

// Cluster sync healthcheck (klasSponsor 2026-06): fan /api/storage/wolfdisk/status
// out across the cluster's online nodes and report how in-sync they are. WolfDisk
// rewrites cluster_status.json every second with its index_version (the
// replication marker — nodes sharing a version are in sync), file_count and peer
// last-seen. We compare index_version across running nodes: all-equal = in sync;
// any difference = a node is catching up (lag). A stale status file (the daemon
// stopped) is flagged distinctly from a genuine out-of-sync.
async function loadWolfDiskSyncHealth() {
    const el = document.getElementById('wd-sync-health');
    if (!el) return;
    const nodes = (typeof getClusterNodes === 'function' ? getClusterNodes(wdCurrentCluster) : []).filter(n => n.online);
    if (nodes.length === 0) { el.innerHTML = ''; return; }

    const rows = await Promise.all(nodes.map(async (node) => {
        try {
            const resp = await fetch(nodeApiUrl(node.id, '/api/storage/wolfdisk/status'));
            const s = resp.ok ? await resp.json() : { running: false };
            return { node, status: s };
        } catch (_) {
            return { node, status: { running: false } };
        }
    }));

    // Only nodes actually running WolfDisk with a fresh status file count toward sync.
    const live = rows.filter(r => r.status && r.status.node_id && (r.status.status_age_secs == null || r.status.status_age_secs <= 10));
    if (live.length === 0) { el.innerHTML = ''; return; } // no WolfDisk here — hide the card

    const versions = [...new Set(live.map(r => Number(r.status.index_version || 0)))];
    const stale = rows.filter(r => r.status && r.status.node_id && r.status.status_age_secs != null && r.status.status_age_secs > 10);
    const inSync = versions.length <= 1 && stale.length === 0;
    const maxVer = Math.max(...live.map(r => Number(r.status.index_version || 0)), 0);

    const banner = inSync
        ? `<span style="color:#10b981; font-weight:700;">✓ In sync</span> <span style="color:var(--text-muted); font-size:12px;">— all ${live.length} node(s) at index version ${maxVer}</span>`
        : stale.length > 0
            ? `<span style="color:#f59e0b; font-weight:700;">⚠ ${stale.length} node(s) not reporting</span> <span style="color:var(--text-muted); font-size:12px;">— WolfDisk may be stopped there</span>`
            : `<span style="color:#f59e0b; font-weight:700;">⟳ Syncing</span> <span style="color:var(--text-muted); font-size:12px;">— index versions differ (a node is catching up)</span>`;

    const fmtBytes = (b) => (typeof formatStorageBytes === 'function') ? formatStorageBytes(b) : (b + ' B');
    const rowHtml = rows.map(r => {
        const s = r.status || {};
        const name = escapeHtml(r.node.hostname || r.node.name || r.node.id);
        if (!s.node_id) {
            return `<tr><td style="padding:6px 10px;">${name}</td><td colspan="5" style="padding:6px 10px; color:var(--text-muted);">WolfDisk not running</td></tr>`;
        }
        const ver = Number(s.index_version || 0);
        const isStale = s.status_age_secs != null && s.status_age_secs > 10;
        const behind = !isStale && ver < maxVer;
        const verCell = isStale
            ? `<span style="color:#f59e0b;">stale (${s.status_age_secs}s)</span>`
            : behind
                ? `<span style="color:#f59e0b;">v${ver} — ${maxVer - ver} behind</span>`
                : `<span style="color:#10b981;">v${ver}</span>`;
        return `<tr>
            <td style="padding:6px 10px;">${name}</td>
            <td style="padding:6px 10px;">${escapeHtml(s.role || '—')}</td>
            <td style="padding:6px 10px;">${verCell}</td>
            <td style="padding:6px 10px;">${Number(s.file_count || 0).toLocaleString()}</td>
            <td style="padding:6px 10px;">${escapeHtml(fmtBytes(Number(s.total_size || 0)))}</td>
            <td style="padding:6px 10px;">${Array.isArray(s.peers) ? s.peers.filter(p => Number(p.last_seen_secs_ago) < 5).length + '/' + s.peers.length : '—'}</td>
        </tr>`;
    }).join('');

    el.innerHTML = `
        <div style="background:var(--bg-card); border:1px solid var(--border); border-radius:10px; padding:14px 16px;">
            <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:8px;">
                <div style="font-weight:600; font-size:14px;">WolfDisk Cluster Health</div>
                <div>${banner}</div>
            </div>
            <table style="width:100%; border-collapse:collapse; font-size:13px;">
                <thead><tr style="color:var(--text-muted); font-size:11px; text-align:left;">
                    <th style="padding:4px 10px;">Node</th><th style="padding:4px 10px;">Role</th>
                    <th style="padding:4px 10px;">Index Version</th><th style="padding:4px 10px;">Files</th>
                    <th style="padding:4px 10px;">Size</th><th style="padding:4px 10px;">Peers up</th>
                </tr></thead>
                <tbody>${rowHtml}</tbody>
            </table>
        </div>`;
}

// ─── Dedicate a disk to WolfDisk (klasSponsor 2026-06) ───
// Pick an online node + an unused whole disk; the backend wipes it, migrates this
// node's WolfDisk data onto it, mounts it at the data_dir (+ fstab), and restarts
// WolfDisk. DESTRUCTIVE — gated behind an explicit confirmation checkbox.
function wdOpenDedicateDiskModal() {
    const nodes = (typeof getClusterNodes === 'function' ? getClusterNodes(wdCurrentCluster) : []).filter(n => n.online);
    if (nodes.length === 0) { showToast('No online nodes in this cluster', 'error'); return; }
    const nodeOpts = nodes.map(n => `<option value="${escapeAttr(n.id)}">${escapeHtml(n.hostname || n.name || n.id)}</option>`).join('');
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.style.cssText = 'display:flex; z-index:10001;';
    overlay.innerHTML = `
      <div style="background:var(--bg-card); border:1px solid var(--border); border-radius:14px; padding:26px; max-width:520px; width:92%; max-height:90vh; display:flex; flex-direction:column; overflow-y:auto;">
        <h3 style="margin:0 0 6px; font-size:17px; color:var(--text-primary);">Dedicate a Disk to WolfDisk</h3>
        <p style="color:var(--text-secondary); font-size:13px; margin:0 0 14px;">Wipe an unused disk and move a node's WolfDisk data onto it. The disk is formatted, mounted at WolfDisk's data directory, added to <code>/etc/fstab</code> (mounts on boot), and WolfDisk is restarted.</p>
        <div class="form-group"><label>Node</label>
          <select id="wd-dd-node" class="form-control" onchange="wdDedicateLoadDisks()">${nodeOpts}</select></div>
        <div class="form-group"><label>Unused disk</label>
          <select id="wd-dd-disk" class="form-control"><option value="">Loading…</option></select>
          <small style="color:var(--text-muted); font-size:11px;">Only whole disks with nothing mounted on them are listed.</small></div>
        <div class="form-group"><label>Filesystem</label>
          <select id="wd-dd-fs" class="form-control"><option value="ext4">ext4 (recommended)</option><option value="xfs">xfs</option><option value="btrfs">btrfs</option></select></div>
        <div style="background:rgba(239,68,68,0.08); border:1px solid rgba(239,68,68,0.35); border-radius:8px; padding:10px 12px; margin:6px 0 12px; font-size:12px; color:#fca5a5;">
          ⚠ This <b>erases the selected disk completely</b>. WolfDisk is stopped, the disk is formatted, existing WolfDisk data is copied onto it, then WolfDisk restarts. Make sure the disk holds nothing you need.</div>
        <label style="display:flex; gap:8px; align-items:center; font-size:13px; margin-bottom:12px; cursor:pointer;">
          <input type="checkbox" id="wd-dd-confirm"> I understand the selected disk will be erased.</label>
        <div id="wd-dd-status" style="font-size:12px; margin-bottom:10px;"></div>
        <div style="display:flex; gap:8px; justify-content:flex-end;">
          <button class="btn btn-sm" onclick="this.closest('.modal-overlay').remove()">Cancel</button>
          <button class="btn btn-primary btn-sm" id="wd-dd-go" onclick="wdDedicateDiskGo(this)">Erase &amp; Dedicate</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    wdDedicateLoadDisks();
}

async function wdDedicateLoadDisks() {
    const nodeId = document.getElementById('wd-dd-node') && document.getElementById('wd-dd-node').value;
    const sel = document.getElementById('wd-dd-disk');
    if (!nodeId || !sel) return;
    sel.innerHTML = '<option value="">Loading…</option>';
    try {
        const resp = await fetch(nodeApiUrl(nodeId, '/api/storage/disk-info'));
        const data = await resp.json();
        const devs = Array.isArray(data) ? data : (data.devices || []);
        // Group every entry under its parent disk so we can require the WHOLE disk
        // (and all its partitions) to be unmounted before offering it.
        const byDisk = {};
        devs.forEach(d => { if (d.disk) (byDisk[d.disk] = byDisk[d.disk] || []).push(d); });
        const CLAIMED = ['LVM2_member', 'linux_raid_member', 'crypto_LUKS', 'swap', 'zfs_member', 'bcache', 'ceph_bluestore'];
        const usable = devs
            .filter(d => d.type === 'disk' && !String(d.device || '').startsWith('/dev/loop'))
            // Require the WHOLE disk + every partition to be unmounted AND not an
            // LVM/RAID/LUKS/swap member (those hold data without a mountpoint).
            .filter(d => (byDisk[d.device] || [d]).every(x =>
                (!Array.isArray(x.mountpoints) || x.mountpoints.length === 0) &&
                !CLAIMED.includes(x.fstype)));
        if (usable.length === 0) { sel.innerHTML = '<option value="">No unused whole disks found</option>'; return; }
        sel.innerHTML = usable.map(d =>
            `<option value="${escapeAttr(d.device)}">${escapeHtml(d.device + ' — ' + (d.size || '') + (d.model ? ' ' + d.model : ''))}</option>`
        ).join('');
    } catch (e) { sel.innerHTML = '<option value="">Could not load disks</option>'; }
}

async function wdDedicateDiskGo(btn) {
    const nodeId = document.getElementById('wd-dd-node').value;
    const device = document.getElementById('wd-dd-disk').value;
    const fstype = document.getElementById('wd-dd-fs').value;
    const confirmed = document.getElementById('wd-dd-confirm').checked;
    const statusEl = document.getElementById('wd-dd-status');
    if (!device) { statusEl.innerHTML = '<span style="color:var(--danger)">Pick a disk.</span>'; return; }
    if (!confirmed) { statusEl.innerHTML = '<span style="color:var(--danger)">Tick the confirmation box first.</span>'; return; }
    btn.disabled = true; btn.textContent = 'Working…';
    statusEl.innerHTML = '<span style="color:var(--text-muted)">Formatting &amp; migrating — this can take a moment…</span>';
    try {
        const resp = await fetch(nodeApiUrl(nodeId, '/api/storage/wolfdisk/dedicate-disk'), {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ device, fstype }),
        });
        const data = await resp.json();
        if (resp.ok && data.ok) {
            // Destructive op — leave the result on screen (don't auto-dismiss) so
            // the operator can read/copy it; turn the action button into Close.
            statusEl.innerHTML = '<span style="color:#10b981">' + escapeHtml(data.message || 'Done') + '</span>';
            showToast('WolfDisk dedicated disk set up', 'success');
            btn.disabled = false;
            btn.textContent = 'Close';
            btn.onclick = () => { const o = document.querySelector('.modal-overlay'); if (o) o.remove(); loadWolfDiskCluster(); };
        } else {
            statusEl.innerHTML = '<span style="color:var(--danger)">' + escapeHtml(data.error || 'Failed') + '</span>';
            btn.disabled = false; btn.textContent = 'Erase & Dedicate';
        }
    } catch (e) {
        statusEl.innerHTML = '<span style="color:var(--danger)">' + escapeHtml(e.message) + '</span>';
        btn.disabled = false; btn.textContent = 'Erase & Dedicate';
    }
}

async function loadWolfDiskCluster() {
    const loading = document.getElementById('wd-loading');
    const container = document.getElementById('wd-clusters-container');
    const statsEl = document.getElementById('wd-summary-stats');
    if (loading) loading.style.display = 'block';
    if (container) container.innerHTML = '';
    if (statsEl) statsEl.innerHTML = '';
    // Refresh the node list FIRST. On first navigation to this tab, allNodes can
    // still be stale/partial (or a node's online flag not yet set), so the scan
    // below missed nodes — that's why the tab "didn't show all nodes until you
    // clicked refresh" (klasSponsor 2026-06). Awaiting a fresh fetchNodes() makes
    // getClusterNodes() see the current, complete fleet before we filter on it.
    try { await fetchNodes(); } catch (_) {}
    // Live sync-health card (independent of the heavier node scan below).
    loadWolfDiskSyncHealth();

    // Fetch latest WolfDisk version from GitHub (in parallel with node scans)
    if (!wdLatestVersion) {
        fetch('https://raw.githubusercontent.com/wolfsoftwaresystemsltd/WolfScale/main/wolfdisk/Cargo.toml')
            .then(r => r.ok ? r.text() : '')
            .then(text => {
                var m = text.match(/^version\s*=\s*"([^"]+)"/m);
                if (m) wdLatestVersion = m[1];
            })
            .catch(() => {});
    }

    const nodes = getClusterNodes(wdCurrentCluster);
    const results = await Promise.allSettled(
        nodes.filter(n => n.online).map(async (node) => {
            const [provResp, mountsResp, dockerResp, lxcResp, wnResp] = await Promise.all([
                fetch(nodeApiUrl(node.id, '/api/storage/providers')),
                fetch(nodeApiUrl(node.id, '/api/storage/mounts')),
                fetch(nodeApiUrl(node.id, '/api/containers/docker')).catch(() => ({ json: () => [] })),
                fetch(nodeApiUrl(node.id, '/api/containers/lxc')).catch(() => ({ json: () => [] })),
                fetch(nodeApiUrl(node.id, '/api/networking/wolfnet/local-info')).catch(() => ({ ok: false })),
            ]);
            const providers = provResp.ok ? await provResp.json() : [];
            var wnInfo = null;
            try { wnInfo = wnResp.ok ? await wnResp.json() : null; } catch(_) {}
            const wdProvider = (Array.isArray(providers) ? providers : []).find(p => p.name === 'wolfdisk');
            const allMounts = mountsResp.ok ? await mountsResp.json() : [];
            const wdMounts = (Array.isArray(allMounts) ? allMounts : []).filter(m => m.mount_type === 'wolfdisk');
            let docker = [], lxc = [];
            try { docker = dockerResp.ok ? await dockerResp.json() : []; } catch(_) {}
            try { lxc = lxcResp.ok ? await lxcResp.json() : []; } catch(_) {}
            if (!Array.isArray(docker)) docker = [];
            if (!Array.isArray(lxc)) lxc = [];
            // Detect containers with wolfdisk
            var hasWd = function(c) { return c.services && c.services.some(function(s) { return (typeof s === 'string' ? s : s.name) === 'wolfdisk'; }); };
            var wdSvc = function(c) { var s = (c.services || []).find(function(s) { return (typeof s === 'string' ? s : s.name) === 'wolfdisk'; }); return s ? (typeof s === 'string' ? 'running' : s.status) : 'unknown'; };
            const wdContainers = [
                ...docker.filter(hasWd).map(c => Object.assign({}, c, { _type: 'docker' })),
                ...lxc.filter(hasWd).map(c => Object.assign({}, c, { _type: 'lxc' })),
            ];

            // All containers (for showing installable ones)
            const allContainers = [
                ...docker.filter(c => c.state === 'running' || c.status === 'running').map(c => Object.assign({}, c, { _type: 'docker' })),
                ...lxc.filter(c => c.state === 'running' || c.status === 'RUNNING').map(c => Object.assign({}, c, { _type: 'lxc' })),
            ];

            // Fetch WolfDisk config from each container that has it
            var containerEntries = [];
            for (var ci = 0; ci < wdContainers.length; ci++) {
                var ct = wdContainers[ci];
                var ctName = ct.name || ct.names || '';
                var ctRuntime = ct._type;
                try {
                    var [cfgResp, verResp] = await Promise.all([
                        fetch(nodeApiUrl(node.id, '/api/configurator/toml/wolfdisk/structured?runtime=' + ctRuntime + '&target=' + encodeURIComponent(ctName))),
                        fetch(nodeApiUrl(node.id, '/api/containers/component-version?runtime=' + ctRuntime + '&target=' + encodeURIComponent(ctName) + '&component=wolfdisk')).catch(function() { return { ok: false }; }),
                    ]);
                    var ctConfig = cfgResp.ok ? await cfgResp.json() : {};
                    var ctVer = null;
                    try { var vd = verResp.ok ? await verResp.json() : {}; ctVer = vd.version || null; } catch(_) {}
                    containerEntries.push({
                        nodeId: node.id,
                        nodeName: ctName,
                        hostName: node.hostname || node.name || node.id,
                        online: true,
                        installed: true,
                        status: wdSvc(ct),
                        version: ctVer,
                        memberType: ctRuntime,
                        containerName: ctName,
                        info: ctConfig.node ? {
                            cluster_name: ctConfig.cluster ? (ctConfig.cluster.name || 'default') : 'default',
                            node_id: ctConfig.node.id || ctName,
                            role: ctConfig.node.role || 'auto',
                            replication_mode: ctConfig.replication ? (ctConfig.replication.mode || 'shared') : 'shared',
                            replication_factor: ctConfig.replication ? (ctConfig.replication.factor || 3) : 3,
                            data_dir: ctConfig.node.data_dir || '/var/lib/wolfdisk',
                            mount_path: ctConfig.mount ? (ctConfig.mount.path || '/mnt/wolfdisk') : '/mnt/wolfdisk',
                            bind: ctConfig.node.bind || '0.0.0.0:8550',
                            peers: ctConfig.cluster ? (ctConfig.cluster.peers || []) : [],
                            s3_enabled: ctConfig.s3 ? (ctConfig.s3.enabled || false) : false,
                            s3_bind: ctConfig.s3 ? ctConfig.s3.bind : null,
                        } : null,
                        wdClusterName: ctConfig.cluster ? (ctConfig.cluster.name || null) : null,
                        mounts: [],
                        containers: [],
                    });
                } catch (_) {
                    containerEntries.push({
                        nodeId: node.id, nodeName: ctName, hostName: node.hostname || node.name || node.id,
                        online: true, installed: true, status: wdSvc(ct), version: null,
                        memberType: ctRuntime, containerName: ctName,
                        info: null, wdClusterName: null, mounts: [], containers: [],
                    });
                }
            }

            // Containers without wolfdisk (installable)
            var installableContainers = allContainers.filter(function(c) { return !hasWd(c); }).map(function(c) {
                return {
                    nodeId: node.id, nodeName: c.name || c.names || '', hostName: node.hostname || node.name || node.id,
                    online: true, installed: false, status: 'not-installed',
                    memberType: c._type, containerName: c.name || c.names || '',
                    info: null, wdClusterName: null, mounts: [], containers: [],
                };
            });

            return {
                hostEntry: {
                    nodeId: node.id,
                    nodeName: node.hostname || node.name || node.id,
                    online: true,
                    installed: wdProvider ? wdProvider.installed : false,
                    status: wdProvider ? wdProvider.status : 'not-installed',
                    info: wdProvider ? wdProvider.wolfdisk_info : null,
                    wdClusterName: wdProvider && wdProvider.wolfdisk_info ? wdProvider.wolfdisk_info.cluster_name : null,
                    memberType: 'host',
                    wolfnetIp: wnInfo ? (wnInfo.address || null) : null,
                    version: wdProvider ? (wdProvider.version || null) : null,
                    nodeAddress: node.address || null,
                    mounts: wdMounts,
                    containers: wdContainers,
                },
                containerEntries: containerEntries,
                installableContainers: installableContainers,
            };
        })
    );

    const onlineNodes = nodes.filter(n => n.online);
    const offlineNodes = nodes.filter(n => !n.online).map(n => ({
        nodeId: n.id, nodeName: n.hostname || n.name || n.id, online: false,
        installed: false, status: 'offline', info: null, wdClusterName: null, memberType: 'host', mounts: [], containers: [],
    }));
    const erroredNodes = results
        .map((r, i) => r.status === 'rejected' ? onlineNodes[i] : null)
        .filter(Boolean)
        .map(n => ({
            nodeId: n.id, nodeName: n.hostname || n.name || n.id, online: true,
            installed: false, status: 'error', info: null, wdClusterName: null, memberType: 'host', mounts: [], containers: [],
        }));

    // Flatten host entries + container entries from successful results
    var fulfilled = results.filter(r => r.status === 'fulfilled').map(r => r.value);
    var allEntries = [];
    for (var fi = 0; fi < fulfilled.length; fi++) {
        allEntries.push(fulfilled[fi].hostEntry);
        allEntries.push.apply(allEntries, fulfilled[fi].containerEntries);
        allEntries.push.apply(allEntries, fulfilled[fi].installableContainers);
    }

    wdClusterData = [
        ...allEntries,
        ...erroredNodes,
        ...offlineNodes,
    ];

    if (loading) loading.style.display = 'none';
    renderWolfDiskPage(wdClusterData);
}

function renderWolfDiskPage(data) {
    const statsEl = document.getElementById('wd-summary-stats');
    const container = document.getElementById('wd-clusters-container');

    // Group by WolfDisk cluster name
    const groups = {};
    const unassigned = [];
    for (const node of data) {
        if (node.wdClusterName && node.wdClusterName !== 'default' && node.installed) {
            if (!groups[node.wdClusterName]) groups[node.wdClusterName] = [];
            groups[node.wdClusterName].push(node);
        } else if (node.wdClusterName === 'default' && node.installed) {
            if (!groups['default']) groups['default'] = [];
            groups['default'].push(node);
        } else {
            unassigned.push(node);
        }
    }

    // Summary stats
    const totalNodes = data.length;
    const installedNodes = data.filter(n => n.installed).length;
    const runningNodes = data.filter(n => n.status === 'running').length;
    const clusterCount = Object.keys(groups).length;
    const totalMounts = data.reduce((s, n) => s + n.mounts.filter(m => m.status === 'mounted').length, 0);

    statsEl.innerHTML =
        wdStatCard('Installed', installedNodes + '/' + totalNodes, installedNodes === totalNodes ? 'var(--success)' : 'var(--warning)') +
        wdStatCard('Running', runningNodes + '/' + installedNodes, installedNodes > 0 && runningNodes === installedNodes ? 'var(--success)' : installedNodes === 0 ? 'var(--text-muted)' : 'var(--danger)') +
        wdStatCard('Clusters', '' + clusterCount, 'var(--accent)') +
        wdStatCard('Mounts', '' + totalMounts, 'var(--accent)');

    // Render cluster sections
    var html = '';
    var clusterNames = Object.keys(groups).sort();
    for (var i = 0; i < clusterNames.length; i++) {
        html += renderWolfDiskClusterSection(clusterNames[i], groups[clusterNames[i]]);
    }
    if (unassigned.length > 0) {
        html += renderWolfDiskUnassignedSection(unassigned);
    }
    if (data.length === 0) {
        html += '<div class="card" style="padding:40px; text-align:center; color:var(--text-muted);">' +
            '<div style="font-size:48px; margin-bottom:12px;"></div>' +
            '<div style="font-size:15px; font-weight:600; margin-bottom:4px;">No nodes in this cluster</div>' +
            '<div style="font-size:12px;">Add nodes to your WolfStack cluster to get started with WolfDisk.</div></div>';
    }
    container.innerHTML = html;
}

function wdStatCard(label, value, color) {
    return '<div style="background:var(--bg-secondary); border:1px solid var(--border); border-radius:8px; padding:14px 16px; text-align:center;">' +
        '<div style="font-size:22px; font-weight:700; color:' + color + ';">' + value + '</div>' +
        '<div style="font-size:11px; color:var(--text-muted); margin-top:2px;">' + label + '</div></div>';
}

function renderWolfDiskClusterSection(name, nodes) {
    // Find leader and compute topology info
    var leader = nodes.find(n => n.info && n.info.role === 'leader');
    var followers = nodes.filter(n => n.info && n.info.role === 'follower');
    var clients = nodes.filter(n => n.info && n.info.role === 'client');
    var repMode = leader ? leader.info.replication_mode : (nodes[0] && nodes[0].info ? nodes[0].info.replication_mode : 'shared');
    var repFactor = leader ? leader.info.replication_factor : (nodes[0] && nodes[0].info ? nodes[0].info.replication_factor : 0);
    var s3Nodes = nodes.filter(n => n.info && n.info.s3_enabled);

    var topoParts = [];
    topoParts.push(nodes.length + ' node' + (nodes.length !== 1 ? 's' : ''));
    if (repMode === 'replicated') topoParts.push('Replicated ' + repFactor + 'x');
    else topoParts.push('Shared');
    if (s3Nodes.length > 0) topoParts.push('S3 on ' + s3Nodes.map(n => n.nodeName + ' (' + (n.info.s3_bind || ':9878') + ')').join(', '));

    var html = '<div class="card" style="margin-bottom:16px;">';
    // Section header
    html += '<div style="padding:16px 20px; border-bottom:1px solid var(--border); display:flex; align-items:center; gap:12px; flex-wrap:wrap;">';
    html += '<span style="font-size:18px;"></span>';
    html += '<span style="font-size:16px; font-weight:700; color:var(--text-primary);">' + (name === 'default' ? 'Default Cluster' : name) + '</span>';
    html += '<span style="font-size:12px; color:var(--text-muted); margin-left:4px;">' + topoParts.join(' \u00b7 ') + '</span>';
    html += '</div>';

    // Topology bar
    html += '<div style="padding:10px 20px; background:var(--bg-tertiary, rgba(0,0,0,0.1)); font-size:11px; color:var(--text-muted); display:flex; flex-wrap:wrap; gap:12px;">';
    if (leader) html += '<span>Leader: <strong style="color:var(--text-primary);">' + leader.nodeName + '</strong> (' + (leader.wolfnetIp || leader.info.bind) + (leader.wolfnetIp ? ' via WolfNet' : '') + ')</span>';
    if (followers.length) html += '<span>Followers: <strong style="color:var(--text-primary);">' + followers.map(f => f.nodeName).join(', ') + '</strong></span>';
    if (clients.length) html += '<span>Clients: <strong style="color:var(--text-primary);">' + clients.map(c => c.nodeName).join(', ') + '</strong></span>';
    html += '</div>';

    // Node table
    html += '<div style="overflow-x:auto;">';
    html += '<table style="width:100%; border-collapse:collapse; font-size:13px;">';
    html += '<thead><tr style="border-bottom:1px solid var(--border); color:var(--text-muted); font-size:11px; text-transform:uppercase; letter-spacing:0.5px;">';
    html += '<th style="padding:10px 16px; text-align:left;">Member</th>';
    html += '<th style="padding:10px 12px; text-align:left;">Type</th>';
    html += '<th style="padding:10px 12px; text-align:left;">Status</th>';
    html += '<th style="padding:10px 12px; text-align:left;">Role</th>';
    html += '<th style="padding:10px 16px; text-align:right;">Actions</th>';
    html += '</tr></thead><tbody>';
    for (var i = 0; i < nodes.length; i++) {
        html += renderWolfDiskNodeRow(nodes[i]);
    }
    html += '</tbody></table></div></div>';
    return html;
}

function renderWolfDiskUnassignedSection(nodes) {
    // Collect existing WolfDisk cluster names + their peer addresses for quick-join
    var existingClusters = {};
    for (var i = 0; i < wdClusterData.length; i++) {
        var nd = wdClusterData[i];
        if (nd.wdClusterName && nd.installed && nd.info) {
            if (!existingClusters[nd.wdClusterName]) existingClusters[nd.wdClusterName] = [];
            existingClusters[nd.wdClusterName].push(nd.info.bind);
        }
    }
    var clusterNames = Object.keys(existingClusters);

    var html = '<div class="card" style="margin-bottom:16px;">';
    html += '<div style="padding:16px 20px; border-bottom:1px solid var(--border); display:flex; align-items:center; gap:12px;">';
    html += '<span style="font-size:18px;"></span>';
    html += '<span style="font-size:16px; font-weight:700; color:var(--text-primary);">Not in a WolfDisk cluster</span>';
    html += '<span style="font-size:12px; color:var(--text-muted);">' + nodes.length + ' member' + (nodes.length !== 1 ? 's' : '') + '</span>';
    html += '</div>';

    html += '<div style="overflow-x:auto;">';
    html += '<table style="width:100%; border-collapse:collapse; font-size:13px;">';
    html += '<thead><tr style="border-bottom:1px solid var(--border); color:var(--text-muted); font-size:11px; text-transform:uppercase; letter-spacing:0.5px;">';
    html += '<th style="padding:10px 16px; text-align:left;">Name</th>';
    html += '<th style="padding:10px 12px; text-align:left;">Type</th>';
    html += '<th style="padding:10px 12px; text-align:left;">Status</th>';
    html += '<th style="padding:10px 16px; text-align:right;">Actions</th>';
    html += '</tr></thead><tbody>';
    for (var i = 0; i < nodes.length; i++) {
        var n = nodes[i];
        var statusLabel = !n.online ? '<span style="color:var(--text-muted);">\u25CF Offline</span>' : n.status === 'error' ? '<span style="color:var(--warning);">\u25CF Unreachable</span>' : !n.installed ? '<span style="color:var(--text-muted);">\u25CB Not Installed</span>' : '<span style="color:var(--success);">\u25CF Installed</span>';
        var typeBadge = wdTypeBadge(n.memberType);
        var hostLabel = n.hostName ? ' <span style="font-size:10px; color:var(--text-muted);">on ' + n.hostName + '</span>' : '';
        html += '<tr style="border-bottom:1px solid var(--border);">';
        html += '<td style="padding:10px 16px; font-weight:600;">' + n.nodeName + hostLabel + '</td>';
        html += '<td style="padding:10px 12px;">' + typeBadge + '</td>';
        html += '<td style="padding:10px 12px;">' + statusLabel + '</td>';
        html += '<td style="padding:10px 16px; text-align:right; display:flex; flex-wrap:wrap; gap:4px; justify-content:flex-end;">';
        if (n.online && !n.installed) {
            if (n.memberType === 'host') {
                html += '<button class="btn btn-sm btn-primary" style="font-size:11px;" onclick="wdInstall(\'' + n.nodeId + '\')">Install</button>';
            } else {
                html += '<button class="btn btn-sm btn-primary" style="font-size:11px;" onclick="wdInstallContainer(\'' + n.nodeId + '\',\'' + n.memberType + '\',\'' + (n.containerName || '').replace(/'/g, "\\'") + '\')">Install</button>';
            }
        } else if (n.online && n.installed) {
            // Quick-join buttons for each existing cluster
            for (var ci = 0; ci < clusterNames.length; ci++) {
                var cn = clusterNames[ci];
                var cnLabel = cn === 'default' ? 'Default Cluster' : cn;
                html += '<button class="btn btn-sm btn-success" style="font-size:11px;" onclick="wdJoinCluster(\'' + wdMemberId(n) + '\',\'' + cn.replace(/'/g, "\\'") + '\')">Join ' + cnLabel + '</button>';
            }
            html += '<button class="btn btn-sm" style="font-size:11px;" onclick="wdOpenConfig(\'' + wdMemberId(n) + '\')">Configure</button>';
        }
        html += '</td></tr>';
    }
    html += '</tbody></table></div></div>';
    return html;
}

function renderWolfDiskNodeRow(node) {
    var n = node;
    var roleColors = { leader: 'var(--warning)', follower: 'var(--accent)', client: 'var(--text-muted)', auto: 'var(--text-muted)' };
    var roleLabels = { leader: 'Leader', follower: 'Follower', client: 'Client', auto: 'Auto' };
    var role = n.info ? n.info.role : 'unknown';
    var statusDot = n.status === 'running' ? '<span style="color:var(--success);">\u25CF</span>' : n.status === 'stopped' ? '<span style="color:var(--danger);">\u25CF</span>' : n.status === 'failed' ? '<span style="color:var(--warning);">\u25CF</span>' : '<span style="color:var(--text-muted);">\u25CF</span>';
    var statusLabel = n.status === 'running' ? 'Running' : n.status === 'stopped' ? 'Stopped' : n.status === 'failed' ? 'Failed' : n.online ? 'Unknown' : 'Offline';
    var mid = wdMemberId(n);
    var hostLabel = n.hostName ? ' <span style="font-size:10px; color:var(--text-muted);">on ' + n.hostName + '</span>' : '';

    var isExpanded = wdExpandedNodes.has(mid);
    var html = '<tr style="border-bottom:1px solid var(--border); cursor:pointer;" onclick="toggleWolfDiskNode(\'' + mid + '\')">';
    html += '<td style="padding:10px 16px; font-weight:600;"><span style="font-size:10px; margin-right:4px; color:var(--text-muted);">' + (isExpanded ? '\u25BC' : '\u25B6') + '</span> ' + n.nodeName + hostLabel + '</td>';
    html += '<td style="padding:10px 12px;">' + wdTypeBadge(n.memberType) + '</td>';
    var verTag = n.version ? ' <span style="font-size:10px; color:var(--text-muted);">v' + n.version + '</span>' : '';
    var upgradeTag = (n.version && wdLatestVersion && n.version !== wdLatestVersion) ? ' <span style="font-size:9px; color:var(--warning);" title="Latest: ' + wdLatestVersion + '">update</span>' : '';
    html += '<td style="padding:10px 12px;">' + statusDot + ' ' + statusLabel + verTag + upgradeTag + '</td>';
    html += '<td style="padding:10px 12px;"><span style="background:' + (roleColors[role] || '#6b7280') + '; color:#fff; padding:1px 8px; border-radius:10px; font-size:11px; font-weight:600;">' + (roleLabels[role] || role) + '</span></td>';
    html += '<td style="padding:10px 16px; text-align:right;" onclick="event.stopPropagation();">';
    if (n.status === 'running') {
        html += '<button class="btn btn-sm btn-danger" style="font-size:10px; padding:2px 8px;" onclick="wdAction(\'' + mid + '\',\'stop\')" title="Stop">\u23f9</button> ';
        html += '<button class="btn btn-sm" style="font-size:10px; padding:2px 8px;" onclick="wdAction(\'' + mid + '\',\'restart\')" title="Restart">\ud83d\udd04</button> ';
    } else if (n.status === 'stopped') {
        html += '<button class="btn btn-sm btn-primary" style="font-size:10px; padding:2px 8px;" onclick="wdAction(\'' + mid + '\',\'start\')" title="Start">\u25b6</button> ';
    }
    html += '<button class="btn btn-sm" style="font-size:10px; padding:2px 8px;" onclick="wdOpenConfig(\'' + mid + '\')" title="Configure">\u2699\ufe0f</button>';
    html += '</td></tr>';

    // Expandable detail row
    if (isExpanded) {
        html += renderWolfDiskNodeDetail(n);
    }
    return html;
}

function toggleWolfDiskNode(mid) {
    if (wdExpandedNodes.has(mid)) wdExpandedNodes.delete(mid);
    else wdExpandedNodes.add(mid);
    renderWolfDiskPage(wdClusterData);
}

function renderWolfDiskNodeDetail(n) {
    var info = n.info;
    var html = '<tr><td colspan="5" style="padding:0; background:var(--bg-tertiary, rgba(0,0,0,0.08));">';
    html += '<div style="padding:16px 24px; font-size:12px;">';

    if (info) {
        // Config summary grid
        html += '<div style="display:grid; grid-template-columns:repeat(auto-fill, minmax(200px,1fr)); gap:8px 20px; margin-bottom:14px;">';
        if (n.version) {
            var needsUpgrade = wdLatestVersion && n.version !== wdLatestVersion;
            html += wdDetailItem('Version', n.version + (needsUpgrade ? ' (latest: ' + wdLatestVersion + ')' : ''));
        }
        html += wdDetailItem('Data Directory', info.data_dir);
        html += wdDetailItem('Mount Path', info.mount_path);
        html += wdDetailItem('Bind Address', info.bind);
        if (n.wolfnetIp) html += wdDetailItem('WolfNet', n.wolfnetIp);
        html += wdDetailItem('Replication', info.replication_mode === 'replicated' ? 'Replicated ' + info.replication_factor + 'x' : 'Shared');
        if (info.peers && info.peers.length) html += wdDetailItem('Peers', info.peers.join(', '));
        if (info.s3_enabled) html += wdDetailItem('S3 API', 'Enabled on ' + (info.s3_bind || ':9878'));
        html += '</div>';
        // Upgrade button if version mismatch
        if (n.version && wdLatestVersion && n.version !== wdLatestVersion) {
            html += '<div style="margin-bottom:10px;"><button class="btn btn-sm btn-primary" style="font-size:11px;" onclick="event.stopPropagation(); wdUpgrade(\'' + wdMemberId(n) + '\')">Upgrade to ' + wdLatestVersion + '</button></div>';
        }
    }

    // Mounts section
    if (n.mounts.length > 0) {
        html += '<div style="margin-bottom:10px;"><strong style="color:var(--text-primary); font-size:11px; text-transform:uppercase; letter-spacing:0.5px;">Mounts</strong></div>';
        for (var i = 0; i < n.mounts.length; i++) {
            var m = n.mounts[i];
            var mIcon = m.status === 'mounted' ? '\u2705' : '\u26ab';
            html += '<div style="display:flex; align-items:center; gap:8px; margin-bottom:4px; padding:4px 8px; background:var(--bg-secondary); border-radius:4px;">';
            html += '<span>' + mIcon + '</span>';
            html += '<span style="flex:1; color:var(--text-primary);">' + (m.mount_point || m.name) + '</span>';
            html += '<span style="color:var(--text-muted); font-size:11px;">' + m.status + '</span>';
            if (m.status === 'mounted') {
                html += ' <button class="btn btn-sm btn-danger" style="font-size:10px; padding:1px 6px;" onclick="wdMountAction(\'' + n.nodeId + '\',\'' + m.id + '\',\'unmount\')">Unmount</button>';
            } else {
                html += ' <button class="btn btn-sm btn-primary" style="font-size:10px; padding:1px 6px;" onclick="wdMountAction(\'' + n.nodeId + '\',\'' + m.id + '\',\'mount\')">Mount</button>';
            }
            html += '</div>';
        }
    }

    // Containers section (only show for host-type members)
    if (n.memberType === 'host' && n.containers && n.containers.length > 0) {
        html += '<div style="margin-top:10px; margin-bottom:6px;"><strong style="color:var(--text-primary); font-size:11px; text-transform:uppercase; letter-spacing:0.5px;">Containers with WolfDisk</strong></div>';
        for (var i = 0; i < n.containers.length; i++) {
            var c = n.containers[i];
            var cStatus = c.state || c.status || 'unknown';
            html += '<div style="display:flex; align-items:center; gap:8px; margin-bottom:4px; padding:4px 8px; background:var(--bg-secondary); border-radius:4px;">';
            html += '<span style="font-size:11px; border:1px solid var(--border); color:var(--text-secondary); padding:1px 6px; border-radius:8px;">' + c._type.toUpperCase() + '</span>';
            html += '<span style="color:var(--text-primary);">' + (c.name || c.names || 'unnamed') + '</span>';
            html += '<span style="color:var(--text-muted); font-size:11px; margin-left:auto;">' + cStatus + '</span>';
            html += '</div>';
        }
    }

    if (!info && n.installed) {
        html += '<div style="color:var(--text-muted); font-style:italic;">Configuration not available \u2014 config file may be missing.</div>';
    }

    html += '</div></td></tr>';
    return html;
}

// Diagnose WolfDisk config for common issues
async function wdDiagnose() {
    if (!wdConfigNodeId) return;
    var mid = wdConfigNodeId;
    var bodyEl = document.getElementById('wd-config-modal-body');

    // Read current form values
    var bind = (document.getElementById('wd-cfg-node-bind') || {}).value || '';
    var dataDir = (document.getElementById('wd-cfg-node-data_dir') || {}).value || '';
    var mountPath = (document.getElementById('wd-cfg-mount-path') || {}).value || '';
    var nodeId = (document.getElementById('wd-cfg-node-id') || {}).value || '';
    var discovery = (document.getElementById('wd-cfg-cluster-discovery') || {}).value || '';
    var peers = wdCollectPeers();
    var allowOther = document.getElementById('wd-cfg-mount-allow_other');

    var issues = [];
    var warnings = [];
    var ok = [];

    // Check node ID
    if (!nodeId) issues.push('Node ID is empty — each node needs a unique ID');
    else ok.push('Node ID: ' + nodeId);

    // Check bind address format
    if (!bind) {
        issues.push('Bind address is empty — WolfDisk needs an address:port to listen on');
    } else if (bind.indexOf(':') < 0) {
        issues.push('Bind address "' + bind + '" is missing the port — use format like 0.0.0.0:8550');
    } else {
        var port = parseInt(bind.split(':').pop());
        if (isNaN(port) || port < 1 || port > 65535) issues.push('Bind port is invalid: ' + bind);
        else ok.push('Bind address: ' + bind);
    }

    // Check data dir
    if (!dataDir) issues.push('Data directory is empty');
    else ok.push('Data directory: ' + dataDir);

    // Check mount path
    if (!mountPath) issues.push('Mount path is empty');
    else ok.push('Mount path: ' + mountPath);

    // Check peers format
    for (var i = 0; i < peers.length; i++) {
        var p = peers[i];
        if (p.indexOf(':') < 0) {
            issues.push('Peer "' + p + '" is missing the port — should be host:8550');
        }
    }
    if (peers.length > 0) ok.push(peers.length + ' peer(s) configured');
    else warnings.push('No peers configured — this node will run standalone unless discovery finds others');

    // Check allow_other
    if (allowOther && !allowOther.checked) {
        warnings.push('Allow Other Users is off — containers and non-root apps won\'t be able to access the mount');
    }

    // Remote checks — try to query the target node for runtime issues
    try {
        var statusResp = await fetch(wdApiUrl(mid, '/api/storage/providers'));
        if (statusResp.ok) {
            var providers = await statusResp.json();
            var wd = (Array.isArray(providers) ? providers : []).find(function(p) { return p.name === 'wolfdisk'; });
            if (wd) {
                if (!wd.installed) warnings.push('WolfDisk binary is not installed on this node');
                else ok.push('WolfDisk binary: installed');
                if (wd.status === 'running') ok.push('Service: running');
                else if (wd.status === 'stopped') warnings.push('Service is stopped');
                else if (wd.status === 'failed') issues.push('Service has failed — check journal: journalctl -u wolfdisk -n 20');
            }
        }
    } catch (_) {
        warnings.push('Could not reach node to check service status');
    }

    // Check if bind port conflicts with known services
    if (bind) {
        var bPort = parseInt(bind.split(':').pop());
        if (bPort === 9500 || bPort === 9501) issues.push('Port ' + bPort + ' conflicts with MinIO — use 8550/8551 instead');
        if (bPort === 8553) issues.push('Port 8553 is used by WolfStack — pick a different port');
    }

    // Check discovery port conflicts
    if (discovery) {
        var dPort = discovery.match(/:(\d+)$/);
        if (dPort) {
            var dp = parseInt(dPort[1]);
            if (dp === 9501) issues.push('Discovery port 9501 conflicts with MinIO — use 8551 instead');
        }
    }

    // Note: FUSE and stale mounts are now handled automatically by the backend
    // on start/restart, so we don't need to warn about them here

    // Render report
    var html = '<div style="border:1px solid var(--border); border-radius:8px; padding:16px; margin-bottom:16px; background:var(--bg-secondary);">';
    html += '<div style="font-size:14px; font-weight:600; color:var(--text-primary); margin-bottom:12px;">Diagnosis Report</div>';

    if (issues.length > 0) {
        html += '<div style="margin-bottom:10px;"><span style="font-weight:600; color:var(--danger);">Issues (' + issues.length + ')</span></div>';
        for (var i = 0; i < issues.length; i++) {
            html += '<div style="padding:4px 8px; margin-bottom:4px; border-radius:4px; font-size:12px; background:rgba(239,68,68,0.1); color:var(--danger);">\u2716 ' + issues[i] + '</div>';
        }
    }
    if (warnings.length > 0) {
        html += '<div style="margin-bottom:10px; margin-top:8px;"><span style="font-weight:600; color:var(--warning);">Warnings (' + warnings.length + ')</span></div>';
        for (var i = 0; i < warnings.length; i++) {
            html += '<div style="padding:4px 8px; margin-bottom:4px; border-radius:4px; font-size:12px; background:rgba(245,158,11,0.1); color:var(--warning);">\u26a0 ' + warnings[i] + '</div>';
        }
    }
    if (ok.length > 0) {
        html += '<div style="margin-bottom:10px; margin-top:8px;"><span style="font-weight:600; color:var(--success);">OK (' + ok.length + ')</span></div>';
        for (var i = 0; i < ok.length; i++) {
            html += '<div style="padding:4px 8px; margin-bottom:4px; border-radius:4px; font-size:12px; color:var(--success);">\u2714 ' + ok[i] + '</div>';
        }
    }
    if (issues.length === 0 && warnings.length === 0) {
        html += '<div style="font-size:13px; color:var(--success); font-weight:600;">Everything looks good!</div>';
    }
    html += '<div style="margin-top:10px; text-align:right;"><button class="btn btn-sm" onclick="document.getElementById(\'wd-diagnose-area\').innerHTML=\'\'">Dismiss</button></div>';
    html += '</div>';

    var diagArea = document.getElementById('wd-diagnose-area');
    if (diagArea) diagArea.innerHTML = html;
}

// Collect peers from the picker (checkboxes + manual textarea)
function wdCollectPeers() {
    var peers = [];
    var checks = document.querySelectorAll('.wd-peer-checkbox:checked');
    for (var i = 0; i < checks.length; i++) {
        peers.push(checks[i].getAttribute('data-addr'));
    }
    var manual = document.getElementById('wd-cfg-cluster-peers-manual');
    if (manual && manual.value.trim()) {
        var lines = manual.value.split('\n');
        for (var i = 0; i < lines.length; i++) {
            var line = lines[i].trim();
            if (line) {
                // Auto-add default port if missing
                if (line.indexOf(':') < 0) line += ':8550';
                peers.push(line);
            }
        }
    }
    // Filter out 0.0.0.0 entries — these are useless as peer addresses
    return peers.filter(function(p) { return !p.startsWith('0.0.0.0'); });
}

function wdDetailItem(label, value) {
    return '<div><span style="color:var(--text-muted);">' + label + ':</span> <strong style="color:var(--text-primary);">' + value + '</strong></div>';
}

async function wdUpgrade(mid) {
    var node = wdFindMember(mid);
    var name = node ? node.nodeName : mid;
    if (!await showConfirm('Upgrade WolfDisk on ' + name + ' to v' + (wdLatestVersion || 'latest') + '?\n\nThe install script will run in upgrade mode (config preserved).', 'Upgrade WolfDisk')) return;
    var p = wdParseMemberId(mid);
    var consoleName = 'wolfdisk';
    if (p.runtime && p.container) consoleName = 'wolfdisk@' + p.runtime + ':' + p.container;
    wdOpenConsole(p.nodeId, 'install', consoleName);
    showToast('Upgrade terminal opened for ' + name, 'success');
}

function wdOpenConsole(nodeId, type, consoleName) {
    var url = '/console.html?type=' + encodeURIComponent(type) + '&name=' + encodeURIComponent(consoleName);
    var node = allNodes.find(n => n.id === nodeId);
    if (node && !node.is_self) {
        url += '&node_id=' + encodeURIComponent(nodeId);
    }
    window.open(url, 'wd_install_' + consoleName, 'width=960,height=600,menubar=no,toolbar=no,scrollbars=yes,resizable=yes');
    // Auto-refresh the WolfDisk page when the user returns to this window
    var refreshOnFocus = function() {
        window.removeEventListener('focus', refreshOnFocus);
        if (currentPage === 'wolfdisk-cluster') loadWolfDiskCluster();
    };
    window.addEventListener('focus', refreshOnFocus);
}

async function wdInstall(nodeId) {
    // Open config dialog first — user sets up cluster/peers/settings, then we install
    wdInstallMode = { nodeId: nodeId, memberType: 'host' };
    var existingClusters = {};
    for (var i = 0; i < wdClusterData.length; i++) {
        var nd = wdClusterData[i];
        if (nd.wdClusterName && nd.installed && nd.info) existingClusters[nd.wdClusterName] = true;
    }
    var cNames = Object.keys(existingClusters);
    if (cNames.length === 1) {
        await wdJoinCluster(nodeId, cNames[0]);
    } else {
        await wdOpenConfig(nodeId);
    }
}

async function wdAction(mid, action) {
    var node = wdFindMember(mid);
    var name = node ? node.nodeName : mid;
    showToast(action.charAt(0).toUpperCase() + action.slice(1) + 'ing WolfDisk on ' + name + '...', 'info');
    try {
        var resp = await fetch(wdApiUrl(mid, '/api/storage/providers/wolfdisk/action'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: action }),
        });
        var data = await resp.json();
        if (resp.ok) {
            showToast('WolfDisk ' + action + ' on ' + name + ' \u2014 ' + (data.message || 'OK'), 'success');
        } else {
            showToast(data.error || action + ' failed', 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
    loadWolfDiskCluster();
}

async function wdInstallContainer(hostNodeId, runtime, containerName) {
    // Open config dialog first — user sets up cluster/peers/settings, then we install
    var mid = hostNodeId + ':' + runtime + ':' + containerName;
    wdInstallMode = { nodeId: hostNodeId, memberType: runtime, containerName: containerName, mid: mid };
    var existingClusters = {};
    for (var i = 0; i < wdClusterData.length; i++) {
        var nd = wdClusterData[i];
        if (nd.wdClusterName && nd.installed && nd.info) existingClusters[nd.wdClusterName] = true;
    }
    var cNames = Object.keys(existingClusters);
    if (cNames.length === 1) {
        await wdJoinCluster(mid, cNames[0]);
    } else {
        await wdOpenConfig(mid);
    }
}

async function wdJoinCluster(mid, clusterName) {
    // Collect peer addresses — prefer WolfNet IPs for mesh connectivity, fall back to bind address
    var peers = [];
    for (var i = 0; i < wdClusterData.length; i++) {
        var nd = wdClusterData[i];
        if (nd.wdClusterName === clusterName && nd.installed && nd.info && nd.info.bind) {
            var bindPort = nd.info.bind.split(':').pop() || '8550';
            var peerAddr = null;
            if (nd.wolfnetIp) {
                peerAddr = nd.wolfnetIp + ':' + bindPort;
            } else if (nd.nodeAddress && nd.nodeAddress !== '0.0.0.0') {
                peerAddr = nd.nodeAddress + ':' + bindPort;
            } else if (!nd.info.bind.startsWith('0.0.0.0')) {
                peerAddr = nd.info.bind;
            }
            if (peerAddr) peers.push(peerAddr);
        }
    }
    // Get replication settings from the first node in the cluster
    var templateNode = wdClusterData.find(n => n.wdClusterName === clusterName && n.info);
    var repMode = templateNode ? templateNode.info.replication_mode : 'shared';
    var repFactor = templateNode ? templateNode.info.replication_factor : 3;

    // Open config editor pre-populated with cluster settings
    await wdOpenConfig(mid);

    // Pre-fill cluster name
    var nameEl = document.getElementById('wd-cfg-cluster-name');
    if (nameEl) nameEl.value = clusterName;
    // Pre-fill peers — check matching checkboxes and put rest in manual field
    var checkboxes = document.querySelectorAll('.wd-peer-checkbox');
    var checkedAddrs = [];
    for (var ci = 0; ci < checkboxes.length; ci++) {
        var cbAddr = checkboxes[ci].getAttribute('data-addr');
        if (peers.indexOf(cbAddr) >= 0) {
            checkboxes[ci].checked = true;
            checkedAddrs.push(cbAddr);
        }
    }
    var manualPeers = peers.filter(function(p) { return checkedAddrs.indexOf(p) < 0; });
    var manualEl = document.getElementById('wd-cfg-cluster-peers-manual');
    if (manualEl && manualPeers.length > 0) manualEl.value = manualPeers.join('\n');
    // Pre-fill replication to match
    var modeEl = document.getElementById('wd-cfg-replication-mode');
    if (modeEl) modeEl.value = repMode;
    var factorEl = document.getElementById('wd-cfg-replication-factor');
    if (factorEl) factorEl.value = repFactor;
}

async function wdMountAction(nodeId, mountId, action) {
    showToast(action.charAt(0).toUpperCase() + action.slice(1) + 'ing...', 'info');
    try {
        var resp = await fetch(nodeApiUrl(nodeId, '/api/storage/mounts/' + mountId + '/' + action), { method: 'POST' });
        var data = await resp.json();
        if (resp.ok) {
            showToast(action + ' successful', 'success');
        } else {
            showToast(data.error || action + ' failed', 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
    loadWolfDiskCluster();
}

async function wdOpenConfig(mid) {
    wdConfigNodeId = mid;
    var node = wdFindMember(mid);
    var name = node ? node.nodeName : mid;
    var titleEl = document.getElementById('wd-config-modal-title');
    var bodyEl = document.getElementById('wd-config-modal-body');
    var modal = document.getElementById('wd-config-modal');
    var p = wdParseMemberId(mid);
    var typeLabel = p.runtime ? ' (' + p.runtime.toUpperCase() + ')' : '';
    var isInstall = !!wdInstallMode;
    titleEl.textContent = (isInstall ? 'Install WolfDisk \u2014 ' : 'WolfDisk Configuration \u2014 ') + name + typeLabel;
    bodyEl.innerHTML = renderBlockSkeleton({lines:3});
    var diagArea = document.getElementById('wd-diagnose-area');
    if (diagArea) diagArea.innerHTML = '';
    modal.style.display = 'flex';

    // Update modal buttons based on mode
    var btnContainer = modal.querySelector('[style*="justify-content:flex-end"]');
    if (btnContainer) {
        if (isInstall) {
            btnContainer.innerHTML = '<button class="btn btn-sm" onclick="wdCloseConfig()">Cancel</button>' +
                '<button class="btn btn-sm btn-primary" onclick="wdSaveAndInstall()">Save & Install</button>';
        } else {
            btnContainer.innerHTML = '<button class="btn btn-sm" onclick="wdDiagnose()" style="margin-right:auto;">Diagnose</button>' +
                '<button class="btn btn-sm" onclick="wdCloseConfig()">Cancel</button>' +
                '<button class="btn btn-sm" onclick="wdSaveConfig(false)" style="border-color:var(--accent); color:var(--accent);">Save Only</button>' +
                '<button class="btn btn-sm btn-primary" onclick="wdSaveConfig(true)">Save & Start</button>';
        }
    }

    try {
        var resp = await fetch(wdApiUrl(mid, '/api/configurator/toml/wolfdisk/structured'));
        var config = resp.ok ? await resp.json() : {};

        var schema = getTomlSchema('wolfdisk');
        var html = '';
        for (var si = 0; si < schema.length; si++) {
            var section = schema[si];
            html += '<div style="margin-bottom:16px;">';
            html += '<div style="font-size:13px; font-weight:600; color:var(--text-primary); margin-bottom:4px;">' + section.label + '</div>';
            if (section.description) html += '<div style="font-size:11px; color:var(--text-muted); margin-bottom:10px;">' + section.description + '</div>';
            html += '<div style="display:grid; grid-template-columns:repeat(auto-fill, minmax(220px, 1fr)); gap:10px 16px;">';
            for (var fi = 0; fi < section.fields.length; fi++) {
                var f = section.fields[fi];
                var raw = config[section.key] ? config[section.key][f.key] : undefined;
                // For strings/selects, treat empty string same as missing — use default
                var val = (raw !== undefined && raw !== null && (f.type === 'boolean' || f.type === 'number' || raw !== ''))
                    ? raw : (f.default !== undefined ? f.default : '');
                var inputId = 'wd-cfg-' + section.key + '-' + f.key;
                html += '<div' + (f.type === 'array' || f.type === 'map' ? ' style="grid-column:span 2;"' : '') + '>';
                html += '<label style="font-size:11px; color:var(--text-muted); display:block; margin-bottom:3px;">' + f.label + '</label>';
                if (f.type === 'map') {
                    // Bucket→folder map editor — same widget as the standalone
                    // configurator, so the inline install/config modal can edit
                    // [s3.buckets] too (not just render it as [object Object]).
                    html += tomlMapFieldHtml(inputId, f, val);
                } else if (f.type === 'select') {
                    html += '<select id="' + inputId + '" class="form-control" style="font-size:12px;">';
                    for (var oi = 0; oi < f.options.length; oi++) {
                        html += '<option value="' + f.options[oi] + '"' + (val === f.options[oi] ? ' selected' : '') + '>' + f.options[oi] + '</option>';
                    }
                    html += '</select>';
                } else if (f.type === 'boolean') {
                    html += '<label style="display:flex; align-items:center; gap:6px; cursor:pointer;"><input type="checkbox" id="' + inputId + '"' + (val ? ' checked' : '') + '> <span style="font-size:12px; color:var(--text-primary);">Enabled</span></label>';
                } else if (f.type === 'array' && f.key === 'peers') {
                    // Peer picker: show known cluster nodes as checkboxes + manual entry
                    var currentPeers = Array.isArray(val) ? val : (val ? val.split('\n').filter(function(s){return s.trim();}) : []);
                    html += '<div id="' + inputId + '-picker" style="border:1px solid var(--border); border-radius:6px; padding:8px; max-height:160px; overflow-y:auto; background:var(--bg-input);">';
                    // Gather all known nodes with their addresses
                    var knownNodes = [];
                    for (var ki = 0; ki < wdClusterData.length; ki++) {
                        var kn = wdClusterData[ki];
                        if (!kn.online) continue;
                        // Build peer address: prefer WolfNet IP, then node's real IP, never use 0.0.0.0
                        var bindPort = kn.info ? (kn.info.bind || '').split(':').pop() || '8550' : '8550';
                        var addr;
                        if (kn.wolfnetIp) {
                            addr = kn.wolfnetIp + ':' + bindPort;
                        } else if (kn.nodeAddress && kn.nodeAddress !== '0.0.0.0') {
                            addr = kn.nodeAddress + ':' + bindPort;
                        } else if (kn.info && kn.info.bind && !kn.info.bind.startsWith('0.0.0.0')) {
                            addr = kn.info.bind;
                        } else {
                            addr = null; // skip — can't determine a real address
                        }
                        if (!addr) continue;
                        // Don't show self in peer list
                        if (kn.nodeId === wdParseMemberId(mid).nodeId && kn.memberType === 'host') continue;
                        knownNodes.push({ name: kn.nodeName, addr: addr, wolfnet: !!kn.wolfnetIp, type: kn.memberType || 'host' });
                    }
                    if (knownNodes.length > 0) {
                        for (var ki = 0; ki < knownNodes.length; ki++) {
                            var kn = knownNodes[ki];
                            var checked = currentPeers.some(function(p){ return p.trim() === kn.addr; }) ? ' checked' : '';
                            var wnTag = kn.wolfnet ? ' <span style="font-size:9px; color:var(--success);">WolfNet</span>' : '';
                            html += '<label style="display:flex; align-items:center; gap:6px; padding:3px 4px; cursor:pointer; font-size:12px;">';
                            html += '<input type="checkbox" class="wd-peer-checkbox" data-addr="' + kn.addr + '"' + checked + '>';
                            html += '<span style="color:var(--text-primary);">' + kn.name + '</span>';
                            html += '<span style="color:var(--text-muted); font-family:monospace; font-size:11px;">' + kn.addr + '</span>' + wnTag;
                            html += '</label>';
                        }
                    } else {
                        html += '<div style="font-size:11px; color:var(--text-muted); padding:4px;">No other online nodes found in this cluster.</div>';
                    }
                    // Manual entry for external peers
                    html += '<div style="margin-top:6px; border-top:1px solid var(--border); padding-top:6px;">';
                    html += '<label style="font-size:10px; color:var(--text-muted); display:block; margin-bottom:2px;">Additional peers (one per line, host:port)</label>';
                    // Filter out known addresses from manual field
                    var knownAddrs = knownNodes.map(function(k){ return k.addr; });
                    var manualPeers = currentPeers.filter(function(p){ return p.trim() && knownAddrs.indexOf(p.trim()) < 0; });
                    html += '<textarea id="' + inputId + '-manual" class="form-control" rows="2" style="font-size:11px; font-family:monospace;" placeholder="e.g. 192.168.1.10:8550">' + manualPeers.join('\n') + '</textarea>';
                    html += '</div></div>';
                    // Hidden field to collect final value
                    html += '<input type="hidden" id="' + inputId + '">';
                } else if (f.type === 'array') {
                    html += '<textarea id="' + inputId + '" class="form-control" rows="3" style="font-size:12px; font-family:monospace;" placeholder="One per line">' + (Array.isArray(val) ? val.join('\n') : (val || '')) + '</textarea>';
                } else if (f.type === 'number') {
                    html += '<input type="number" id="' + inputId + '" class="form-control" value="' + (val || f.default || '') + '" style="font-size:12px;">';
                } else {
                    html += '<input type="text" id="' + inputId + '" class="form-control" value="' + (val || '') + '" placeholder="' + (f.placeholder || '') + '" style="font-size:12px;">';
                }
                if (f.help) html += '<div style="font-size:10px; color:var(--text-muted); margin-top:2px;">' + f.help + '</div>';
                html += '</div>';
            }
            html += '</div></div>';
        }
        bodyEl.innerHTML = html;

        // Auto-suggest hostname as node ID if still set to default
        var nodeIdEl = document.getElementById('wd-cfg-node-id');
        if (nodeIdEl && (!nodeIdEl.value || nodeIdEl.value === 'node-1')) {
            nodeIdEl.value = name;
        }
    } catch (e) {
        bodyEl.innerHTML = '<div style="color:var(--danger);">Failed to load config: ' + e.message + '</div>';
    }
}

function wdCloseConfig() {
    document.getElementById('wd-config-modal').style.display = 'none';
    wdConfigNodeId = null;
    wdInstallMode = null;
    // Always refresh after closing config modal (install/save may have changed state)
    if (currentPage === 'wolfdisk-cluster') loadWolfDiskCluster();
}

async function wdSaveAndInstall() {
    // Save the config first (creates /etc/wolfdisk/config.toml), then run the install terminal
    // The install script will skip interactive prompts since config already exists
    if (!wdConfigNodeId || !wdInstallMode) return;
    var savedMid = wdConfigNodeId;
    var mode = wdInstallMode;

    // Collect config from form
    var schema = getTomlSchema('wolfdisk');
    var config = {};
    for (var si = 0; si < schema.length; si++) {
        var section = schema[si];
        config[section.key] = {};
        for (var fi = 0; fi < section.fields.length; fi++) {
            var f = section.fields[fi];
            var el = document.getElementById('wd-cfg-' + section.key + '-' + f.key);
            if (!el) continue;
            if (f.type === 'boolean') config[section.key][f.key] = el.checked;
            else if (f.type === 'number') config[section.key][f.key] = el.value ? Number(el.value) : (f.default || 0);
            else if (f.type === 'array' && f.key === 'peers') config[section.key][f.key] = wdCollectPeers();
            else if (f.type === 'array') config[section.key][f.key] = el.value.split('\n').map(s => s.trim()).filter(s => s);
            else if (f.type === 'map') config[section.key][f.key] = collectMapRows(el);
            else config[section.key][f.key] = el.value || f.default || '';
        }
    }

    // First bootstrap the config directory on the target, then save config
    try {
        await fetch(wdApiUrl(savedMid, '/api/configurator/toml/wolfdisk/bootstrap'), { method: 'POST' });
    } catch (_) {}
    try {
        var resp = await fetch(wdApiUrl(savedMid, '/api/configurator/toml/wolfdisk/structured'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(config),
        });
        if (!resp.ok) {
            var data = await resp.json();
            showToast(data.error || 'Failed to save config', 'error');
            return;
        }
    } catch (e) {
        showToast('Failed to save config: ' + e.message, 'error');
        return;
    }

    // Close modal
    document.getElementById('wd-config-modal').style.display = 'none';
    wdConfigNodeId = null;
    wdInstallMode = null;

    // Open install terminal
    var consoleName = 'wolfdisk';
    if (mode.memberType && mode.memberType !== 'host' && mode.containerName) {
        consoleName = 'wolfdisk@' + mode.memberType + ':' + mode.containerName;
    }
    wdOpenConsole(mode.nodeId, 'install', consoleName);
    showToast('Config saved. Installation terminal opened — refresh this page when complete.', 'success');
}

async function wdSaveConfig(startAfter) {
    if (!wdConfigNodeId) return;
    var savedMid = wdConfigNodeId;
    var schema = getTomlSchema('wolfdisk');
    var config = {};
    for (var si = 0; si < schema.length; si++) {
        var section = schema[si];
        config[section.key] = {};
        for (var fi = 0; fi < section.fields.length; fi++) {
            var f = section.fields[fi];
            var el = document.getElementById('wd-cfg-' + section.key + '-' + f.key);
            if (!el) continue;
            if (f.type === 'boolean') config[section.key][f.key] = el.checked;
            else if (f.type === 'number') config[section.key][f.key] = el.value ? Number(el.value) : (f.default || 0);
            else if (f.type === 'array' && f.key === 'peers') config[section.key][f.key] = wdCollectPeers();
            else if (f.type === 'array') {
                config[section.key][f.key] = el.value.split('\n').map(s => s.trim()).filter(s => s);
            } else if (f.type === 'map') {
                config[section.key][f.key] = collectMapRows(el);
            } else {
                config[section.key][f.key] = el.value || f.default || '';
            }
        }
    }

    try {
        var resp = await fetch(wdApiUrl(savedMid, '/api/configurator/toml/wolfdisk/structured'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(config),
        });
        var data = await resp.json();
        if (resp.ok) {
            if (startAfter) {
                showToast('Configuration saved. Starting WolfDisk...', 'success');
                try {
                    await fetch(wdApiUrl(savedMid, '/api/storage/providers/wolfdisk/action'), {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ action: 'restart' }),
                    });
                    showToast('WolfDisk started successfully', 'success');
                } catch (_) {
                    showToast('Config saved but failed to start service', 'error');
                }
            } else {
                showToast('Configuration saved. Restart WolfDisk to apply changes.', 'success');
            }
            wdCloseConfig();
        } else {
            showToast(data.error || 'Save failed', 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}

// ─── System Logs ───

async function loadSystemLogs() {
    const viewer = document.getElementById('syslog-viewer');
    const countEl = document.getElementById('syslog-count');
    const search = document.getElementById('syslog-search').value.trim();
    const unit = document.getElementById('syslog-unit').value;
    const lines = document.getElementById('syslog-lines').value;

    viewer.innerHTML = renderBlockSkeleton({lines:3});

    try {
        const params = new URLSearchParams({ lines });
        if (search) params.set('search', search);
        if (unit) params.set('unit', unit);

        const resp = await fetch(apiUrl(`/api/system/logs?${params}`));
        if (!resp.ok) throw new Error('Failed to fetch logs');
        const data = await resp.json();

        if (data.lines && data.lines.length > 0) {
            // Color-code log lines
            viewer.innerHTML = data.lines.map(line => {
                let color = 'var(--text-primary)';
                const lower = line.toLowerCase();
                if (lower.includes('error') || lower.includes('failed') || lower.includes('fatal')) color = '#ef4444';
                else if (lower.includes('warning') || lower.includes('warn')) color = '#f59e0b';
                else if (lower.includes('notice') || lower.includes('info:')) color = '#3b82f6';
                return `<div style="color:${color}; border-bottom:1px solid var(--bg-tertiary); padding:1px 0;">${escapeHtml(line)}</div>`;
            }).join('');
            countEl.textContent = `${data.lines.length} lines`;
            viewer.scrollTop = viewer.scrollHeight;
        } else {
            viewer.innerHTML = '<span style="color:var(--text-muted);">No log entries found.</span>';
            countEl.textContent = '0 lines';
        }
    } catch (e) {
        viewer.innerHTML = `<span style="color:#ef4444;">Error: ${e.message}</span>`;
    }
}

function copySystemLogs() {
    const viewer = document.getElementById('syslog-viewer');
    const text = viewer.innerText;
    navigator.clipboard.writeText(text).then(() => {
        showToast('Logs copied to clipboard', 'success');
    }).catch(() => {
        showToast('Failed to copy logs', 'error');
    });
}

// ═══════════════════════════════════════════════
// ─── Status Page Admin ───
// ═══════════════════════════════════════════════

let spConfig = { monitors: [], pages: [] };
let spMonitorsEnriched = [];
let spCurrentCluster = null;
let spRefreshTimer = null;

// Determine if the current cluster is local (this server) or remote.
// Returns the API base path: '' for local, '/api/nodes/{id}/proxy' for remote.
// Find the first online node in a remote cluster (shared by proxy + public URL)
function spFindRemoteNode(clusterName) {
    return allNodes.find(n =>
        n.online &&
        (n.cluster_name || 'WolfStack') === clusterName
    ) || null;
}

function spApiBase() {
    if (!spCurrentCluster) return '';
    const selfNode = allNodes.find(n => n.is_self);
    const selfCluster = selfNode?.cluster_name || 'WolfStack';
    if (spCurrentCluster === selfCluster) return '';
    const remoteNode = spFindRemoteNode(spCurrentCluster);
    if (!remoteNode) return '';
    return `/api/nodes/${remoteNode.id}/proxy`;
}

function spUrl(path) {
    const base = spApiBase();
    return base ? `${base}/${path}` : `/api/${path}`;
}

// Build the public URL for a status page. Same-cluster uses the page's
// current origin so it inherits whatever scheme/host/port the admin is
// already using — including a reverse-proxy domain (Cloudflare tunnel,
// nginx, etc.), since /status/{slug} is also served on the main port.
// Remote clusters fall back to the node's IP on the dedicated 8550
// listener because we don't know the remote cluster's public URL.
function spPublicUrl(slug, cluster) {
    const selfNode = allNodes.find(n => n.is_self);
    const selfCluster = selfNode?.cluster_name || 'WolfStack';
    const resolvedCluster = cluster || spCurrentCluster || selfCluster;
    // Admin-configured override (Settings → 🌐 Reverse Proxy) wins over
    // the auto-detected origin for the local cluster. Needed when the
    // admin UI and public status pages live on different URLs, or when
    // the proxy is mounted on a subpath.
    const localBase = (_reverseProxyBase || window.location.origin).replace(/\/+$/, '');
    if (resolvedCluster === selfCluster) {
        return `${localBase}/status/${slug}`;
    }
    const remoteNode = spFindRemoteNode(resolvedCluster);
    if (remoteNode) {
        const host = remoteNode.address || remoteNode.hostname;
        return `http://${host}:8550/status/${slug}`;
    }
    return `${localBase}/status/${slug}`;
}

function showStatusPagesForCluster(clusterName) {
    closeSidebarMobile();
    spCurrentCluster = clusterName;
    currentPage = 'statuspage';
    currentNodeId = null;
    currentComponent = null;

    // Switch to status page view
    document.querySelectorAll('.page-view').forEach(p => p.style.display = 'none');
    const el = document.getElementById('page-statuspage');
    if (el) el.style.display = 'block';

    // Highlight sidebar item
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const item = document.querySelector(`.statuspage-cluster-item[data-cluster="${clusterName}"]`);
    if (item) item.classList.add('active');

    // Update page title
    document.getElementById('page-title').textContent = `Status Pages — ${clusterName}`;

    // Hide forms
    const spPageForm = document.getElementById('sp-page-form');
    const spMonForm = document.getElementById('sp-monitor-form');
    const spIncForm = document.getElementById('sp-incident-form');
    if (spPageForm) spPageForm.style.display = 'none';
    if (spMonForm) spMonForm.style.display = 'none';
    if (spIncForm) spIncForm.style.display = 'none';

    spInitialLoad = true;
    loadStatusPageData();

    // Auto-refresh status data every 30s while viewing this page
    if (spRefreshTimer) clearInterval(spRefreshTimer);
    spRefreshTimer = setInterval(() => {
        if (currentPage !== 'statuspage') {
            clearInterval(spRefreshTimer);
            spRefreshTimer = null;
            return;
        }
        loadStatusPageData();
    }, 30000);
}

function switchStatusTab(tab) {
    document.getElementById('sp-panel-pages').style.display = tab === 'pages' ? '' : 'none';
    document.getElementById('sp-panel-monitors').style.display = tab === 'monitors' ? '' : 'none';
    document.getElementById('sp-panel-incidents').style.display = tab === 'incidents' ? '' : 'none';
    document.getElementById('sp-tab-pages').classList.toggle('btn-primary', tab === 'pages');
    document.getElementById('sp-tab-monitors').classList.toggle('btn-primary', tab === 'monitors');
    document.getElementById('sp-tab-incidents').classList.toggle('btn-primary', tab === 'incidents');

    if (tab === 'incidents') {
        renderIncidentsList();
    }
}

let spInitialLoad = true;

async function loadStatusPageData() {
    let pages = [];
    let monitors = [];

    try {
        const cfgRes = await fetch(spUrl('statuspage/config'));
        if (cfgRes.ok) {
            spConfig = await cfgRes.json();
            if (!spConfig.monitors) spConfig.monitors = [];
            if (!spConfig.pages) spConfig.pages = [];
            if (!spConfig.incidents) spConfig.incidents = [];
        } else {
            spConfig = { monitors: [], pages: [], incidents: [] };
        }
    } catch (e) {
        console.warn('Status page config load failed, using defaults:', e);
        spConfig = { monitors: [], pages: [], incidents: [] };
    }

    try {
        const pagesRes = await fetch(spUrl('statuspage/pages'));
        if (pagesRes.ok) {
            const pagesData = await pagesRes.json();
            pages = pagesData.pages || [];
        }
    } catch (e) {
        console.warn('Status pages list load failed:', e);
    }

    try {
        const monsRes = await fetch(spUrl('statuspage/monitors'));
        if (monsRes.ok) {
            const monsData = await monsRes.json();
            monitors = monsData.monitors || [];
        }
    } catch (e) {
        console.warn('Status monitors list load failed:', e);
    }

    spMonitorsEnriched = monitors;
    renderStatusPages(pages);
    renderStatusMonitors(monitors);
    renderIncidentsList();
    // Only switch to pages tab on initial load, not on auto-refresh
    if (spInitialLoad) {
        switchStatusTab('pages');
        spInitialLoad = false;
    }
}

function renderStatusPages(pages) {
    const el = document.getElementById('sp-pages-list');
    if (!el) return;
    // Filter pages by current cluster
    if (spCurrentCluster) {
        pages = pages.filter(p => p.page && p.page.cluster === spCurrentCluster);
    }
    if (!pages || !pages.length) {
        el.innerHTML = `<div style="text-align:center; padding:50px; color:var(--text-muted);">
            <div style="font-size:48px; margin-bottom:16px;"></div>
            <div style="font-size:16px; font-weight:600; margin-bottom:8px;">No Status Pages Yet</div>
            <div style="font-size:13px; margin-bottom:20px;">Create a public status page to monitor your services and share uptime with your users.</div>
            <button class="btn btn-primary" onclick="showStatusPageForm()" style="font-size:13px;">+ Create Your First Status Page</button>
        </div>`;
        return;
    }
    el.innerHTML = pages.map(p => {
        const st = p.overall_status || 'unknown';
        const colors = { up: '#22c55e', degraded: '#eab308', down: '#ef4444', unknown: '#6b7280' };
        const labels = { up: 'Operational', degraded: 'Degraded', down: 'Major Outage', unknown: 'Unknown' };
        const svcCount = (p.page?.services || []).length;

        const activeIncidents = (p.page?.incidents || []).filter(i => i.status !== 'resolved');
        const incidentBadge = activeIncidents.length > 0
            ? `<span style="font-size:10px; padding:2px 8px; background:#ef4444; color:#fff; border-radius:10px; margin-left:8px;">${activeIncidents.length} active</span>`
            : '';

        const uptime = p.uptime_30d != null ? `${p.uptime_30d.toFixed(2)}%` : '—';
        const pageUrl = spPublicUrl(p.page.slug, p.page.cluster);

        return `<div style="background:var(--bg-input); border:1px solid var(--border); border-radius:12px; padding:20px;">
            <div style="display:flex; align-items:flex-start; justify-content:space-between; margin-bottom:12px;">
                <div>
                    <div style="display:flex; align-items:center; gap:8px;">
                        <span style="width:10px; height:10px; border-radius:50%; background:${colors[st]}; box-shadow:0 0 8px ${colors[st]}50;"></span>
                        <span style="font-weight:600; font-size:16px;">${escapeHtml(p.page.title)}</span>
                        ${p.page.enabled ? '' : '<span style="font-size:10px; padding:2px 8px; background:rgba(107,114,128,0.2); border-radius:4px; color:#9ca3af;">Disabled</span>'}
                        ${incidentBadge}
                    </div>
                    <div style="font-size:12px; color:var(--text-muted); margin-top:6px; margin-left:18px;">
                        <a href="${pageUrl}" target="_blank" style="color:var(--accent-light);">${pageUrl}</a>
                    </div>
                </div>
                <div style="text-align:right;">
                    <div style="font-size:20px; font-weight:700; color:${colors[st]};">${labels[st]}</div>
                    <div style="font-size:11px; color:var(--text-muted);">${uptime} uptime (30d)</div>
                </div>
            </div>
            <div style="display:flex; justify-content:space-between; align-items:center; padding-top:12px; border-top:1px solid var(--border);">
                <div style="font-size:12px; color:var(--text-muted);">
                    ${(p.page?.monitor_ids || []).length} monitor(s) &bull; ${(p.page?.incident_ids || []).length} incident(s) assigned
                </div>
                <div style="display:flex; gap:6px;">
                    <button class="btn btn-sm" onclick="showIncidentForm(null, '${p.page.id}')" style="font-size:11px;">Report Incident</button>
                    <button class="btn btn-sm" onclick="editStatusPage('${p.page.id}')" style="font-size:11px;">Edit</button>
                    <button class="btn btn-sm" onclick="window.open('${pageUrl}', '_blank')" style="font-size:11px;">View</button>
                    <button class="btn btn-sm" onclick="deleteStatusPage('${p.page.id}')" style="font-size:11px; color:#ef4444;"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                </div>
            </div>
        </div>`;
    }).join('');
}

function renderStatusMonitors(monitors) {
    const el = document.getElementById('sp-monitors-list');
    if (!el) return;
    // Filter monitors by current cluster
    if (spCurrentCluster) {
        monitors = monitors.filter(m => m.monitor && m.monitor.cluster === spCurrentCluster);
    }
    if (!monitors || !monitors.length) {
        el.innerHTML = `<div style="text-align:center; padding:50px; color:var(--text-muted);">
            <div style="font-size:48px; margin-bottom:16px;"></div>
            <div style="font-size:16px; font-weight:600; margin-bottom:8px;">No Monitors Yet</div>
            <div style="font-size:13px; margin-bottom:20px;">Create monitors to check the health of your services, containers, and endpoints.</div>
            <button class="btn btn-primary" onclick="showMonitorForm()" style="font-size:13px;">+ Create Your First Monitor</button>
        </div>`;
        return;
    }
    el.innerHTML = monitors.map(m => {
        const mon = m.monitor;
        const colors = { up: '#22c55e', degraded: '#eab308', down: '#ef4444', unknown: '#6b7280' };
        const st = m.status || 'unknown';
        const latencyStr = m.latest ? `${m.latest.latency_ms}ms` : '—';
        const typeLabel = mon.check?.type || '?';
        const uptime = (m.uptime_percent || 100).toFixed(2);

        const uptimeHistory = renderUptimeBar(m.history || [], 30);

        return `<div style="background:var(--bg-input); border:1px solid var(--border); border-radius:10px; padding:16px;">
            <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;">
                <div style="display:flex; align-items:center; gap:12px;">
                    <span style="width:12px; height:12px; border-radius:50%; background:${colors[st]}; display:inline-block; box-shadow:0 0 8px ${colors[st]}50;"></span>
                    <div>
                        <div style="font-weight:600; font-size:14px;">${escapeHtml(mon.name)}
                            <span style="font-size:10px; padding:2px 8px; background:var(--bg-tertiary); border-radius:4px; color:var(--text-muted); margin-left:8px; text-transform:uppercase;">${typeLabel}</span>
                        </div>
                        <div style="font-size:12px; color:var(--text-muted); margin-top:2px;">${m.status_label} &bull; ${latencyStr} response</div>
                    </div>
                </div>
                <div style="display:flex; align-items:center; gap:8px;">
                    <div style="text-align:right;">
                        <div style="font-size:18px; font-weight:700; color:${colors[st]};">${uptime}%</div>
                        <div style="font-size:10px; color:var(--text-muted);">30-day uptime</div>
                    </div>
                    <div style="display:flex; gap:4px; margin-left:12px;">
                        <button class="btn btn-sm" onclick="showMonitorDetails('${mon.id}')" style="font-size:11px;" title="View Details"><span class="ws-icon-clean-wrap" data-icon="eye"></span></button>
                        <button class="btn btn-sm" onclick="editMonitor('${mon.id}')" style="font-size:11px;" title="Edit"><span class="ws-icon-clean-wrap" data-icon="edit"></span></button>
                        <button class="btn btn-sm" onclick="deleteMonitor('${mon.id}')" style="font-size:11px; color:#ef4444;" title="Delete"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                    </div>
                </div>
            </div>
            <div style="display:flex; gap:1px; height:24px; background:var(--bg-tertiary); border-radius:4px; overflow:hidden;" title="30-day uptime history">
                ${uptimeHistory}
            </div>
            <div style="display:flex; justify-content:space-between; margin-top:4px; font-size:10px; color:var(--text-muted);">
                <span>30 days ago</span>
                <span>Today</span>
            </div>
        </div>`;
    }).join('');
}

function renderUptimeBar(history, days) {
    const bars = [];
    const colors = { up: '#22c55e', degraded: '#eab308', down: '#ef4444', unknown: '#374151' };

    for (let i = 0; i < days; i++) {
        const dayData = history[i];
        let color = colors.unknown;
        let tooltip = 'No data';

        if (dayData) {
            const pct = dayData.uptime_percent || 0;
            if (pct >= 99.5) {
                color = colors.up;
            } else if (pct >= 95) {
                color = colors.degraded;
            } else if (pct > 0) {
                color = colors.down;
            }
            tooltip = `${pct.toFixed(2)}% uptime`;
        }

        bars.push(`<div style="flex:1; background:${color}; transition:background 0.2s;" title="${tooltip}"></div>`);
    }

    return bars.join('');
}

async function showMonitorDetails(monitorId) {
    const m = spMonitorsEnriched.find(x => x.monitor.id === monitorId);
    if (!m) return;

    const mon = m.monitor;
    const colors = { up: '#22c55e', degraded: '#eab308', down: '#ef4444', unknown: '#6b7280' };
    const st = m.status || 'unknown';

    let checkDetails = '';
    const c = mon.check || {};
    if (c.type === 'http') {
        checkDetails = `URL: <code>${escapeHtml(c.url)}</code><br>Expected: ${c.expected_status || 200}`;
    } else if (c.type === 'tcp') {
        checkDetails = `Host: <code>${escapeHtml(c.host)}:${c.port}</code>`;
    } else if (c.type === 'ping') {
        checkDetails = `Host: <code>${escapeHtml(c.host)}</code>`;
    } else if (c.type === 'container') {
        checkDetails = `Container: <code>${escapeHtml(c.name)}</code> (${c.runtime})`;
    } else if (c.type === 'wolfrun') {
        checkDetails = `Service: <code>${escapeHtml(c.service_name)}</code><br>Min healthy: ${c.min_healthy}`;
    }

    const recentChecks = (m.recent_checks || []).slice(0, 10).map(chk => {
        const time = new Date(chk.timestamp).toLocaleString();
        const statusColor = chk.success ? colors.up : colors.down;
        return `<div style="display:flex; justify-content:space-between; padding:6px 0; border-bottom:1px solid var(--border);">
            <span style="color:${statusColor};">${chk.success ? '' : ''}</span>
            <span style="font-size:11px; color:var(--text-muted);">${time}</span>
            <span style="font-size:11px;">${chk.latency_ms}ms</span>
        </div>`;
    }).join('') || '<div style="color:var(--text-muted); padding:12px;">No recent checks</div>';

    // CSS exposes `.modal-overlay` (fixed-position centering layer)
    // and `.modal` (inner card). Earlier this code set `class="modal
    // active"` on the outer div and `class="modal-content"` on the
    // inner — neither of which is a positioning class — so the dialog
    // flowed inline and rendered left-aligned under the sidebar.
    const modal = document.createElement('div');
    modal.className = 'modal-overlay active';
    modal.id = 'sp-monitor-details-modal';
    modal.innerHTML = `
        <div class="modal" style="max-width:600px;">
            <div class="modal-header">
                <h3 style="display:flex; align-items:center; gap:10px;">
                    <span style="width:12px; height:12px; border-radius:50%; background:${colors[st]};"></span>
                    ${escapeHtml(mon.name)}
                </h3>
                <button class="modal-close" onclick="document.getElementById('sp-monitor-details-modal').remove()">&times;</button>
            </div>
            <div class="modal-body" style="padding:20px;">
                <div style="display:grid; grid-template-columns:1fr 1fr; gap:20px; margin-bottom:20px;">
                    <div>
                        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Status</div>
                        <div style="font-size:16px; font-weight:600; color:${colors[st]};">${m.status_label}</div>
                    </div>
                    <div>
                        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Uptime (30 days)</div>
                        <div style="font-size:16px; font-weight:600;">${(m.uptime_percent || 100).toFixed(2)}%</div>
                    </div>
                    <div>
                        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Check Interval</div>
                        <div style="font-size:14px;">${mon.interval_secs}s</div>
                    </div>
                    <div>
                        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Timeout</div>
                        <div style="font-size:14px;">${mon.timeout_secs}s</div>
                    </div>
                </div>
                <div style="margin-bottom:20px;">
                    <div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">Check Configuration</div>
                    <div style="background:var(--bg-tertiary); padding:12px; border-radius:8px; font-size:13px;">
                        <span style="text-transform:uppercase; font-size:10px; padding:2px 6px; background:var(--primary-color); color:#fff; border-radius:4px; margin-right:8px;">${c.type}</span>
                        ${checkDetails}
                    </div>
                </div>
                <div>
                    <div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">Recent Checks</div>
                    <div style="background:var(--bg-tertiary); padding:12px; border-radius:8px; max-height:200px; overflow-y:auto;">
                        ${recentChecks}
                    </div>
                </div>
            </div>
        </div>
    `;
    document.body.appendChild(modal);
}

// ─── Monitor Form ───
function showMonitorForm(existing) {
    const form = document.getElementById('sp-monitor-form');
    document.getElementById('sp-page-form').style.display = 'none';
    form.style.display = '';
    document.getElementById('sp-monitor-form-title').textContent = existing ? 'Edit Monitor' : 'New Monitor';
    document.getElementById('sp-mon-id').value = existing?.id || (crypto.randomUUID?.() || ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c => (c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> c / 4).toString(16)));
    document.getElementById('sp-mon-name').value = existing?.name || '';
    document.getElementById('sp-mon-interval').value = existing?.interval_secs || 60;
    document.getElementById('sp-mon-timeout').value = existing?.timeout_secs || 10;
    document.getElementById('sp-mon-enabled').checked = existing?.enabled !== false;
    document.getElementById('sp-mon-type').value = existing?.check?.type || 'http';
    updateMonitorFormFields(existing?.check);
    form.scrollIntoView({ behavior: 'smooth' });
}

function editMonitor(id) {
    const mon = spConfig.monitors.find(m => m.id === id);
    if (mon) showMonitorForm(mon);
}

async function updateMonitorFormFields(existingCheck) {
    const type = document.getElementById('sp-mon-type').value;
    const el = document.getElementById('sp-mon-fields');
    const c = existingCheck || {};

    if (type === 'http') {
        el.innerHTML = `<div style="display:grid; grid-template-columns:3fr 1fr; gap:16px; margin-bottom:16px;">
            <div class="form-group"><label>URL</label><input type="text" id="sp-mon-url" class="form-control" placeholder="https://example.com" value="${escapeHtml(c.url || '')}"></div>
            <div class="form-group"><label>Expected Status</label><input type="number" id="sp-mon-status" class="form-control" value="${c.expected_status || 200}"></div>
        </div>`;
    } else if (type === 'tcp') {
        el.innerHTML = `<div style="display:grid; grid-template-columns:3fr 1fr; gap:16px; margin-bottom:16px;">
            <div class="form-group"><label>Host</label><input type="text" id="sp-mon-host" class="form-control" placeholder="192.168.1.10" value="${escapeHtml(c.host || '')}"></div>
            <div class="form-group"><label>Port</label><input type="number" id="sp-mon-port" class="form-control" value="${c.port || 80}"></div>
        </div>`;
    } else if (type === 'ping') {
        el.innerHTML = `<div class="form-group" style="margin-bottom:16px;"><label>Host</label><input type="text" id="sp-mon-host" class="form-control" placeholder="192.168.1.10" value="${escapeHtml(c.host || '')}"></div>`;
    } else if (type === 'container') {
        el.innerHTML = renderBlockSkeleton({lines:3});
        await loadContainersForMonitor();
        el.innerHTML = renderContainerPicker(c);
    } else if (type === 'wolfrun') {
        el.innerHTML = renderBlockSkeleton({lines:3});
        await loadWolfrunServicesForMonitor();
        el.innerHTML = renderWolfrunServicePicker(c);
    }
}

async function saveMonitor() {
    const type = document.getElementById('sp-mon-type').value;
    let check;
    if (type === 'http') {
        check = { type: 'http', url: document.getElementById('sp-mon-url').value, expected_status: parseInt(document.getElementById('sp-mon-status').value) || 200 };
    } else if (type === 'tcp') {
        check = { type: 'tcp', host: document.getElementById('sp-mon-host').value, port: parseInt(document.getElementById('sp-mon-port').value) || 80 };
    } else if (type === 'ping') {
        check = { type: 'ping', host: document.getElementById('sp-mon-host').value };
    } else if (type === 'container') {
        const nodeId = document.getElementById('sp-mon-container-node')?.value || null;
        check = {
            type: 'container',
            runtime: document.getElementById('sp-mon-runtime').value,
            name: document.getElementById('sp-mon-container').value,
            node_id: nodeId || undefined
        };
    } else if (type === 'wolfrun') {
        const svcSelect = document.getElementById('sp-mon-wolfrun-svc');
        const svcId = svcSelect?.value;
        if (!svcId) {
            showToast('Please select a WolfRun service', 'error');
            return;
        }
        const svc = spAvailableWolfrunServices.find(s => s.id === svcId);
        check = {
            type: 'wolfrun',
            service_id: svcId,
            service_name: svc?.name || '',
            min_healthy: parseInt(document.getElementById('sp-mon-wolfrun-min')?.value) || 1,
            health_check: document.getElementById('sp-mon-wolfrun-check')?.value || 'running'
        };
    }
    const monitor = {
        id: document.getElementById('sp-mon-id').value,
        name: document.getElementById('sp-mon-name').value,
        check,
        interval_secs: parseInt(document.getElementById('sp-mon-interval').value) || 60,
        timeout_secs: parseInt(document.getElementById('sp-mon-timeout').value) || 10,
        enabled: document.getElementById('sp-mon-enabled').checked,
        cluster: spCurrentCluster,
    };
    try {
        const res = await fetch(spUrl('statuspage/monitors'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(monitor),
        });
        if (!res.ok) throw new Error(await res.text());
        showToast('Monitor saved', 'success');
        document.getElementById('sp-monitor-form').style.display = 'none';
        loadStatusPageData();
    } catch (e) { showToast('Failed to save monitor: ' + e.message, 'error'); }
}

async function deleteMonitor(id) {
    if (!(await showConfirm('Delete this monitor?'))) return;
    try {
        await fetch(spUrl(`statuspage/monitors/${id}`), { method: 'DELETE' });
        showToast('Monitor deleted', 'success');
        loadStatusPageData();
    } catch (e) { showToast('Failed to delete monitor', 'error'); }
}

// ─── Page Form ───
function showStatusPageForm(existing) {
    const form = document.getElementById('sp-page-form');
    document.getElementById('sp-monitor-form').style.display = 'none';
    document.getElementById('sp-incident-form').style.display = 'none';
    form.style.display = '';
    document.getElementById('sp-page-form-title').textContent = existing ? 'Edit Status Page' : 'New Status Page';
    document.getElementById('sp-page-id').value = existing?.id || (crypto.randomUUID?.() || ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c => (c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> c / 4).toString(16)));
    document.getElementById('sp-page-title').value = existing?.title || '';
    document.getElementById('sp-page-slug').value = existing?.slug || '';
    document.getElementById('sp-page-logo').value = existing?.logo_url || '';
    document.getElementById('sp-page-footer').value = existing?.footer_text || '';
    document.getElementById('sp-page-enabled').checked = existing?.enabled !== false;
    document.getElementById('sp-page-theme').value = existing?.theme || 'dark';

    const container = document.getElementById('sp-page-services');
    container.innerHTML = '';

    const monitors = (spConfig?.monitors || []).filter(m => m.cluster === spCurrentCluster);
    const incidents = (spConfig?.incidents || []).filter(i => i.cluster === spCurrentCluster);
    if (monitors.length === 0 && !existing) {
        container.innerHTML = `<div style="background:var(--bg-tertiary); border:1px dashed var(--border); border-radius:8px; padding:20px; text-align:center; color:var(--text-muted);">
            <div style="font-size:24px; margin-bottom:8px;"></div>
            <div style="font-size:13px; margin-bottom:12px;">You need to create monitors in this cluster before adding them to a status page.</div>
            <button class="btn btn-sm btn-primary" onclick="switchStatusTab('monitors'); showMonitorForm();" style="font-size:12px;">+ Create Your First Monitor</button>
        </div>`;
    } else {
        const monHtml = monitors.map(m => `
            <label style="display:block; margin-bottom:4px; font-size:13px;">
                <input type="checkbox" class="sp-checkbox-monitor" value="${m.id}" ${(existing?.monitor_ids || []).includes(m.id) ? 'checked' : ''}>
                ${escapeHtml(m.name)}
            </label>
        `).join('');

        const incHtml = incidents.length ? incidents.map(i => `
            <label style="display:block; margin-bottom:4px; font-size:13px;">
                <input type="checkbox" class="sp-checkbox-incident" value="${i.id}" ${(existing?.incident_ids || []).includes(i.id) ? 'checked' : ''}>
                ${escapeHtml(i.title)} (${i.status})
            </label>
        `).join('') : '<div style="font-size:12px; color:var(--text-muted);">No incidents in this cluster.</div>';

        container.innerHTML = `
            <div style="background:var(--bg-tertiary); border:1px solid var(--border); border-radius:8px; padding:16px;">
                <h4 style="margin:0 0 12px 0; font-size:14px;">Assign Monitors</h4>
                <div style="max-height:150px; overflow-y:auto; border-bottom:1px solid var(--border); padding-bottom:12px; margin-bottom:12px;">
                    ${monHtml || '<div style="font-size:12px; color:var(--text-muted);">No monitors.</div>'}
                </div>
                <h4 style="margin:0 0 12px 0; font-size:14px;">Assign Incidents</h4>
                <div style="max-height:150px; overflow-y:auto;">
                    ${incHtml}
                </div>
            </div>
        `;
    }

    form.scrollIntoView({ behavior: 'smooth' });
}

function editStatusPage(id) {
    const page = spConfig.pages.find(p => p.id === id);
    if (page) showStatusPageForm(page);
}

// Service row functions removed — page form now uses checkbox-based monitor/incident assignment

async function saveStatusPage() {
    const monitor_ids = Array.from(document.querySelectorAll('.sp-checkbox-monitor:checked')).map(cb => cb.value);
    const incident_ids = Array.from(document.querySelectorAll('.sp-checkbox-incident:checked')).map(cb => cb.value);

    const page = {
        id: document.getElementById('sp-page-id').value,
        slug: document.getElementById('sp-page-slug').value.toLowerCase().replace(/[^a-z0-9-]/g, ''),
        title: document.getElementById('sp-page-title').value,
        logo_url: document.getElementById('sp-page-logo').value || null,
        footer_text: document.getElementById('sp-page-footer').value || null,
        theme: document.getElementById('sp-page-theme').value || null,
        enabled: document.getElementById('sp-page-enabled').checked,
        cluster: spCurrentCluster,
        monitor_ids,
        incident_ids,
    };

    try {
        const res = await fetch(spUrl('statuspage/pages'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(page),
        });
        if (!res.ok) { const d = await res.json(); throw new Error(d.error || 'Failed'); }
        showToast('Status page saved', 'success');
        document.getElementById('sp-page-form').style.display = 'none';
        loadStatusPageData();
    } catch (e) { showToast('Failed to save page: ' + e.message, 'error'); }
}

async function deleteStatusPage(id) {
    if (!(await showConfirm('Delete this status page? This cannot be undone.'))) return;
    try {
        await fetch(spUrl(`statuspage/pages/${id}`), { method: 'DELETE' });
        showToast('Status page deleted', 'success');
        loadStatusPageData();
    } catch (e) { showToast('Failed to delete page', 'error'); }
}

// ═══════════════════════════════════════════════
// ─── Status Page Incident Management ───
// ═══════════════════════════════════════════════

let spAllIncidents = [];
let spIncidentPage = 0;
const SP_INCIDENTS_PER_PAGE = 10;

function renderIncidentsList() {
    const el = document.getElementById('sp-incidents-list');

    spAllIncidents = (spConfig.incidents || []).filter(i => i.cluster === spCurrentCluster);
    spAllIncidents.sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));

    if (!spAllIncidents.length) {
        el.innerHTML = `<div style="text-align:center; padding:40px; color:var(--text-muted);">
            <div style="font-size:32px; margin-bottom:12px;"></div>
            <div style="font-size:14px;">No incidents reported</div>
            <div style="font-size:12px; margin-top:4px;">All systems operational</div>
        </div>`;
        return;
    }

    const totalPages = Math.ceil(spAllIncidents.length / SP_INCIDENTS_PER_PAGE);
    if (spIncidentPage >= totalPages) spIncidentPage = totalPages - 1;
    if (spIncidentPage < 0) spIncidentPage = 0;
    const start = spIncidentPage * SP_INCIDENTS_PER_PAGE;
    const pageIncidents = spAllIncidents.slice(start, start + SP_INCIDENTS_PER_PAGE);

    const impactColors = { none: '#6b7280', minor: '#eab308', major: '#f97316', critical: '#ef4444' };
    const statusIcons = { investigating: '', identified: '', monitoring: '', resolved: '' };

    const cardsHtml = pageIncidents.map(inc => {
        const impact = inc.impact || 'none';
        const status = inc.status || 'investigating';
        const created = inc.created_at ? new Date(inc.created_at).toLocaleString() : 'Unknown';
        const resolved = inc.resolved_at ? new Date(inc.resolved_at).toLocaleString() : null;
        const updates = inc.updates || [];
        const lastUpdate = updates.length ? updates[updates.length - 1] : null;

        const updatesHtml = updates.slice(-3).map(u => {
            const time = u.timestamp ? new Date(u.timestamp).toLocaleString() : '';
            return `<div style="padding:8px 0; border-bottom:1px solid var(--border);">
                <div style="font-size:11px; color:var(--text-muted);">${time} — ${statusIcons[u.status] || ''} ${u.status}</div>
                <div style="font-size:12px; margin-top:4px;">${escapeHtml(u.message)}</div>
            </div>`;
        }).join('');

        return `<div style="background:var(--bg-input); border:1px solid var(--border); border-left:4px solid ${impactColors[impact]}; border-radius:10px; padding:16px;">
            <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:12px;">
                <div>
                    <div style="font-weight:600; font-size:15px;">${statusIcons[status]} ${escapeHtml(inc.title)}</div>
                    <div style="font-size:12px; color:var(--text-muted); margin-top:4px;">
                        <span style="padding:2px 8px; background:${impactColors[impact]}22; color:${impactColors[impact]}; border-radius:4px; text-transform:uppercase; font-size:10px; font-weight:600;">${impact}</span>
                        &bull; Started: ${created}
                        ${resolved ? `&bull; Resolved: ${resolved}` : ''}
                    </div>
                </div>
                <div style="display:flex; gap:6px;">
                    ${status !== 'resolved' ? `<button class="btn btn-sm" onclick="updateIncident('${inc.id}')" style="font-size:11px;">Update</button>` : ''}
                    <button class="btn btn-sm" onclick="editIncident('${inc.id}')" style="font-size:11px;"><span class="ws-icon-clean-wrap" data-icon="edit"></span></button>
                    <button class="btn btn-sm" onclick="deleteIncident('${inc.id}')" style="font-size:11px; color:#ef4444;"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                </div>
            </div>
            ${updates.length > 0 ? `
                <div style="background:var(--bg-tertiary); border-radius:8px; padding:12px; margin-top:12px;">
                    <div style="font-size:11px; font-weight:600; color:var(--text-muted); margin-bottom:8px;">RECENT UPDATES</div>
                    ${updatesHtml}
                </div>
            ` : ''}
        </div>`;
    }).join('');

    let paginationHtml = '';
    if (totalPages > 1) {
        paginationHtml = `<div style="display:flex; justify-content:center; align-items:center; gap:8px; margin-top:16px;">
            <button class="btn btn-sm" onclick="spIncidentPage=0; renderIncidentsList();" ${spIncidentPage === 0 ? 'disabled' : ''} style="font-size:11px;">First</button>
            <button class="btn btn-sm" onclick="spIncidentPage--; renderIncidentsList();" ${spIncidentPage === 0 ? 'disabled' : ''} style="font-size:11px;">Prev</button>
            <span style="font-size:12px; color:var(--text-muted);">Page ${spIncidentPage + 1} of ${totalPages} (${spAllIncidents.length} total)</span>
            <button class="btn btn-sm" onclick="spIncidentPage++; renderIncidentsList();" ${spIncidentPage >= totalPages - 1 ? 'disabled' : ''} style="font-size:11px;">Next</button>
            <button class="btn btn-sm" onclick="spIncidentPage=${totalPages - 1}; renderIncidentsList();" ${spIncidentPage >= totalPages - 1 ? 'disabled' : ''} style="font-size:11px;">Last</button>
        </div>`;
    }

    el.innerHTML = cardsHtml + paginationHtml;
}

function showIncidentForm(existing, forPageId) {
    const form = document.getElementById('sp-incident-form');
    document.getElementById('sp-page-form').style.display = 'none';
    document.getElementById('sp-monitor-form').style.display = 'none';
    form.style.display = '';

    document.getElementById('sp-incident-form-title').textContent = existing ? 'Edit Incident' : 'Report Incident';
    document.getElementById('sp-incident-id').value = existing?.id || (crypto.randomUUID?.() || ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c => (c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> c / 4).toString(16)));
    document.getElementById('sp-incident-title').value = existing?.title || '';
    document.getElementById('sp-incident-status').value = existing?.status || 'investigating';
    document.getElementById('sp-incident-impact').value = existing?.impact || 'minor';
    document.getElementById('sp-incident-message').value = '';

    // Populate the affected monitors/services multi-select
    const servicesSelect = document.getElementById('sp-incident-services');
    if (servicesSelect) {
        const monitors = (spConfig?.monitors || []).filter(m => m.cluster === spCurrentCluster);
        servicesSelect.disabled = false;
        servicesSelect.innerHTML = monitors.map(m =>
            `<option value="${m.id}" ${(existing?.service_ids || []).includes(m.id) ? 'selected' : ''}>${escapeHtml(m.name)}</option>`
        ).join('');
        if (monitors.length === 0) {
            servicesSelect.innerHTML = '<option value="" disabled>No monitors in this cluster</option>';
        }
    }

    // Populate the page selector so user can link incident to a page
    const pageSelect = document.getElementById('sp-incident-page');
    if (pageSelect) {
        const pages = (spConfig?.pages || []).filter(p => p.cluster === spCurrentCluster);
        pageSelect.disabled = false;
        pageSelect.innerHTML = '<option value="">-- None (standalone incident) --</option>' +
            pages.map(p => {
                const selected = (forPageId && forPageId === p.id) ? 'selected' : '';
                return `<option value="${p.id}" ${selected}>${escapeHtml(p.title)}</option>`;
            }).join('');
    }

    // Store the page ID for save
    document.getElementById('sp-incident-page-id').value = forPageId || '';

    form.scrollIntoView({ behavior: 'smooth' });
}

function editIncident(incidentId) {
    const incident = (spConfig.incidents || []).find(i => i.id === incidentId);
    if (incident) showIncidentForm(incident);
}

function updateIncident(incidentId) {
    const incident = (spConfig.incidents || []).find(i => i.id === incidentId);
    if (!incident) return;

    showIncidentForm(incident);
    document.getElementById('sp-incident-form-title').textContent = 'Add Update to Incident';
}

async function saveIncident() {
    const title = document.getElementById('sp-incident-title').value.trim();
    if (!title) {
        showToast('Please enter an incident title', 'error');
        return;
    }

    const incidentId = document.getElementById('sp-incident-id').value;
    const status = document.getElementById('sp-incident-status').value;
    const impact = document.getElementById('sp-incident-impact').value;
    const message = document.getElementById('sp-incident-message').value.trim();
    const selectedPageId = document.getElementById('sp-incident-page-id')?.value || document.getElementById('sp-incident-page')?.value || '';

    // Collect selected affected services
    const servicesSelect = document.getElementById('sp-incident-services');
    const selectedServiceIds = servicesSelect ? Array.from(servicesSelect.selectedOptions).map(o => o.value).filter(v => v) : [];

    const existingIncident = (spConfig.incidents || []).find(i => i.id === incidentId);

    const incident = {
        id: incidentId,
        title,
        status,
        impact,
        cluster: spCurrentCluster,
        service_ids: selectedServiceIds.length > 0 ? selectedServiceIds : (existingIncident?.service_ids || []),
        created_at: existingIncident?.created_at || new Date().toISOString(),
        resolved_at: status === 'resolved' ? (existingIncident?.resolved_at || new Date().toISOString()) : null,
        updates: existingIncident?.updates || [],
        auto_created: existingIncident?.auto_created || false,
    };

    if (message) {
        incident.updates.push({
            timestamp: new Date().toISOString(),
            status,
            message
        });
    }

    try {
        const res = await fetch(spUrl('statuspage/incidents'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(incident),
        });
        if (!res.ok) throw new Error(await res.text());

        // If a page was selected, link the incident to that page
        if (selectedPageId) {
            const page = spConfig.pages.find(p => p.id === selectedPageId);
            if (page && !page.incident_ids.includes(incidentId)) {
                page.incident_ids.push(incidentId);
                await fetch(spUrl('statuspage/pages'), {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(page),
                });
            }
        }

        showToast('Incident saved', 'success');
        document.getElementById('sp-incident-form').style.display = 'none';
        loadStatusPageData();
    } catch (e) {
        showToast('Failed to save incident: ' + e.message, 'error');
    }
}

async function deleteIncident(incidentId) {
    if (!(await showConfirm('Delete this incident?'))) return;

    try {
        const res = await fetch(spUrl(`statuspage/incidents/${incidentId}`), {
            method: 'DELETE',
        });
        if (!res.ok) throw new Error(await res.text());
        showToast('Incident deleted', 'success');
        loadStatusPageData();
    } catch (e) {
        showToast('Failed to delete incident: ' + e.message, 'error');
    }
}

// ═══════════════════════════════════════════════
// ─── Status Page Container/Service Picker ───
// ═══════════════════════════════════════════════

let spAvailableContainers = [];
let spAvailableWolfrunServices = [];

async function loadContainersForMonitor() {
    spAvailableContainers = [];
    // /api/containers/cluster fans out across the cluster on the
    // backend. spUrl() targets the cluster the operator is creating
    // a status page for — local cluster goes direct, remote/federated
    // clusters are reached via spApiBase() through their gateway
    // node. This single call replaces a brittle frontend fan-out
    // that:
    //   (a) skipped the local node because the node-proxy rejects
    //       self-targeted calls with HTTP 400, and
    //   (b) returned nothing on remote clusters because the local
    //       allNodes list doesn't carry remote-cluster peers.
    try {
        const resp = await fetch(spUrl('containers/cluster'));
        if (!resp.ok) return;
        const data = await resp.json();
        const list = Array.isArray(data) ? data : (data.containers || []);
        for (const c of list) {
            spAvailableContainers.push({
                // ContainerInfo is lowercase (name, state, runtime).
                // No Docker-API-shape fallback: the cluster endpoint
                // always returns ContainerInfo, so claiming to handle
                // a different shape would just hide future regressions.
                name: c.name,
                runtime: c.runtime,
                node: c.node_hostname || '',
                node_id: c.node_id || '',
                state: c.state,
            });
        }
    } catch (e) { /* best-effort — picker falls back to manual entry */ }
}

async function loadWolfrunServicesForMonitor() {
    spAvailableWolfrunServices = [];
    // Use spUrl() — the status-page form's cluster context — instead
    // of wolfrunApiUrl() which keys off `wolfrunCurrentCluster`
    // (the WolfRun page's own selected cluster, often unrelated to
    // the status page being edited). When the two diverged the
    // picker silently fetched the wrong cluster's services.
    try {
        const resp = await fetch(spUrl('wolfrun/services'));
        if (resp.ok) {
            const services = await resp.json();
            spAvailableWolfrunServices = services.filter(s => {
                const svcCluster = s.cluster_name || 'WolfStack';
                return svcCluster === spCurrentCluster;
            });
        }
    } catch (e) { }
}

function renderContainerPicker(existingCheck) {
    const c = existingCheck || {};
    const containerOptions = spAvailableContainers.map(ct => {
        const selected = c.name === ct.name && c.runtime === ct.runtime ? 'selected' : '';
        const stateIcon = ct.state === 'running' ? '' : '';
        return `<option value="${ct.runtime}:${escapeHtml(ct.name)}:${ct.node_id}" ${selected}>${stateIcon} ${escapeHtml(ct.name)} (${ct.runtime} @ ${escapeHtml(ct.node)})</option>`;
    }).join('');

    return `<div class="form-group" style="margin-bottom:16px;">
        <label>Select Container</label>
        <select id="sp-mon-container-select" class="form-control" onchange="onContainerSelect()">
            <option value="">-- Select a container --</option>
            ${containerOptions}
        </select>
        <div style="margin-top:8px; font-size:11px; color:var(--text-muted);">
            Or manually specify:
        </div>
        <div style="display:grid; grid-template-columns:1fr 2fr 1fr; gap:8px; margin-top:6px;">
            <select id="sp-mon-runtime" class="form-control" style="font-size:12px;">
                <option value="docker" ${c.runtime === 'docker' || !c.runtime ? 'selected' : ''}>Docker</option>
                <option value="lxc" ${c.runtime === 'lxc' ? 'selected' : ''}>LXC</option>
            </select>
            <input type="text" id="sp-mon-container" class="form-control" placeholder="container-name" value="${escapeHtml(c.name || '')}" style="font-size:12px;">
            <input type="text" id="sp-mon-container-node" class="form-control" placeholder="node-id (optional)" value="${escapeHtml(c.node_id || '')}" style="font-size:12px;">
        </div>
    </div>`;
}

function onContainerSelect() {
    const select = document.getElementById('sp-mon-container-select');
    if (!select.value) return;
    const [runtime, name, nodeId] = select.value.split(':');
    document.getElementById('sp-mon-runtime').value = runtime;
    document.getElementById('sp-mon-container').value = name;
    document.getElementById('sp-mon-container-node').value = nodeId || '';
}

function renderWolfrunServicePicker(existingCheck) {
    const c = existingCheck || {};
    const svcOptions = spAvailableWolfrunServices.map(svc => {
        const selected = c.service_id === svc.id ? 'selected' : '';
        const running = svc.instances?.filter(i => i.status === 'running').length || 0;
        const total = svc.instances?.length || 0;
        const statusIcon = running === total && total > 0 ? '' : running > 0 ? '' : '';
        return `<option value="${svc.id}" ${selected}>${statusIcon} ${escapeHtml(svc.name)} (${running}/${total} running)</option>`;
    }).join('');

    return `<div class="form-group" style="margin-bottom:16px;">
        <label>WolfRun Service</label>
        <select id="sp-mon-wolfrun-svc" class="form-control">
            <option value="">-- Select a WolfRun service --</option>
            ${svcOptions}
        </select>
        <div style="margin-top:8px; font-size:11px; color:var(--text-muted);">
            Monitors all instances of this service and reports UP if minimum replicas are healthy.
        </div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:16px; margin-top:12px;">
            <div class="form-group" style="margin:0;">
                <label style="font-size:11px;">Min Healthy Instances</label>
                <input type="number" id="sp-mon-wolfrun-min" class="form-control" value="${c.min_healthy || 1}" min="1" style="font-size:12px;">
            </div>
            <div class="form-group" style="margin:0;">
                <label style="font-size:11px;">Health Check Type</label>
                <select id="sp-mon-wolfrun-check" class="form-control" style="font-size:12px;">
                    <option value="running" ${c.health_check === 'running' || !c.health_check ? 'selected' : ''}>Container Running</option>
                    <option value="http" ${c.health_check === 'http' ? 'selected' : ''}>HTTP Health Endpoint</option>
                </select>
            </div>
        </div>
    </div>`;
}

// ═══════════════════════════════════════════════════════════════════════════════
// ─── WolfKube — Kubernetes Management ───
// ═══════════════════════════════════════════════════════════════════════════════

let k8sClusters = [];
let k8sPodCountsByNode = {};   // { nodeId: podCount } for sidebar badges
let k8sCurrentCluster = null;  // selected K8sCluster id
let k8sCurrentView = 'overview'; // overview, pods, deployments, services, namespaces, nodes
let k8sCurrentNamespace = '';    // '' = all namespaces
let k8sRefreshTimer = null;
let k8sDetailOpen = false;       // true when viewing pod/deployment detail — suppresses auto-refresh
let k8sWolfStackCluster = '';    // WolfStack cluster name context

// Route K8s cluster API calls through node proxy for remote clusters
function k8sClusterUrl(clusterId, subpath) {
    const cluster = k8sClusters.find(c => c.id === clusterId);
    if (cluster && cluster.owner_node_id) {
        const node = allNodes.find(n => n.id === cluster.owner_node_id);
        if (node && !node.is_self) {
            return `/api/nodes/${cluster.owner_node_id}/proxy/kubernetes/clusters/${encodeURIComponent(clusterId)}${subpath || ''}`;
        }
    }
    return `/api/kubernetes/clusters/${encodeURIComponent(clusterId)}${subpath || ''}`;
}

// Transparent fetch interceptor: rewrite K8s cluster URLs to proxy through owner node
const _origFetch = window.fetch;
window.fetch = function(url, options) {
    if (typeof url === 'string') {
        const m = url.match(/^\/api\/kubernetes\/clusters\/([^\/\?]+)(.*)/);
        if (m) {
            const rawId = m[1];
            const clusterId = decodeURIComponent(rawId);
            const cluster = k8sClusters.find(c => c.id === clusterId);
            if (cluster && cluster.owner_node_id) {
                const node = allNodes.find(n => n.id === cluster.owner_node_id);
                if (node && !node.is_self) {
                    url = `/api/nodes/${cluster.owner_node_id}/proxy/kubernetes/clusters/${rawId}${m[2]}`;
                }
            }
        }
    }
    return _origFetch.call(this, url, options);
};

function updateK8sPodBadges() {
    // Count pods per node from cluster status data
    const counts = {};
    for (const c of k8sClusters) {
        if (c.status && c.status.nodes) {
            for (const kn of c.status.nodes) {
                // Match k8s node name to WolfStack node by hostname or address
                const nodeName = (kn.name || '').toLowerCase();
                for (const n of allNodes) {
                    const hn = (n.hostname || '').toLowerCase();
                    const addr = (n.address || '').toLowerCase();
                    if (nodeName === hn || nodeName === hn.split('.')[0] || nodeName === addr) {
                        counts[n.id] = (counts[n.id] || 0);
                        // Mark this node as having k8s — actual pod count will come from status totals
                        counts[n.id] = -1; // placeholder, replaced below
                    }
                }
            }
        }
    }

    // Get actual pod counts per node from status pods data
    // For now, use the total pods from cluster status divided across nodes,
    // or if we have the per-node data from loadNodeK8sPods, use k8sPodCountsByNode
    // The k8sPodCountsByNode is populated asynchronously by loadNodeK8sPods

    // Update all WolfKube badges
    document.querySelectorAll('.k8s-pod-badge').forEach(badge => {
        const nodeId = badge.getAttribute('data-node');
        const count = k8sPodCountsByNode[nodeId];
        if (count && count > 0) {
            badge.textContent = count;
            badge.style.display = '';
        } else if (counts[nodeId] !== undefined) {
            // Node is part of a k8s cluster but no pod count yet — show cluster indicator
            badge.textContent = '';
            badge.style.display = '';
        } else {
            badge.style.display = 'none';
        }
    });
}

// Fetch pod counts for all k8s nodes to populate sidebar badges
async function refreshK8sPodBadgeCounts() {
    if (k8sClusters.length === 0) return;
    const nodeCounts = {};
    const fetches = k8sClusters.map(async (c) => {
        try {
            const resp = await fetch(`/api/kubernetes/clusters/${encodeURIComponent(c.id)}/pods`);
            if (!resp.ok) return;
            const pods = await resp.json();
            for (const p of pods) {
                if (!p.node) continue;
                const podNode = p.node.toLowerCase();
                for (const n of allNodes) {
                    const hn = (n.hostname || '').toLowerCase();
                    const addr = (n.address || '').toLowerCase();
                    if (podNode === hn || podNode === hn.split('.')[0] || podNode === addr) {
                        nodeCounts[n.id] = (nodeCounts[n.id] || 0) + 1;
                    }
                }
            }
        } catch (e) {}
    });
    await Promise.all(fetches);
    k8sPodCountsByNode = nodeCounts;
    updateK8sPodBadges();
}

function showK8sClusterPage(clusterName) {
    k8sWolfStackCluster = clusterName;
    selectView('kubernetes');
}

async function loadKubernetesClusters() {
    const el = document.getElementById('kubernetes-content');
    if (!el) return;

    try {
        const resp = await fetch('/api/kubernetes/clusters');
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        k8sClusters = await resp.json();
    } catch (e) {
        k8sClusters = [];
    }

    renderKubernetesPage();
    refreshK8sPodBadgeCounts();
}

function renderKubernetesPage() {
    const el = document.getElementById('kubernetes-content');
    if (!el) return;

    // Filter k8s clusters to only those belonging to the active WolfStack cluster
    let visibleK8s = k8sClusters;
    if (k8sWolfStackCluster) {
        const wsClusterNodes = new Set(
            allNodes.filter(n => (n.cluster_name || 'WolfStack') === k8sWolfStackCluster).map(n => n.id)
        );
        visibleK8s = k8sClusters.filter(c => !c.owner_node_id || wsClusterNodes.has(c.owner_node_id));
    }

    const clusterLabel = k8sWolfStackCluster ? ` — ${escapeHtml(k8sWolfStackCluster)}` : '';

    let html = `
    <div class="card" style="margin-bottom:20px; background:linear-gradient(135deg, rgba(50,108,229,0.12), rgba(50,108,229,0.04)); border-color:rgba(50,108,229,0.25);">
        <div class="card-body" style="display:flex; align-items:center; justify-content:space-between; padding:28px 32px;">
            <div style="display:flex; align-items:center; gap:20px;">
                <div style="width:64px; height:64px; background:linear-gradient(135deg,#326ce5,#54a3ff); border-radius:16px; display:flex; align-items:center; justify-content:center; font-size:32px; box-shadow:0 4px 20px rgba(50,108,229,0.3);">&#9784;</div>
                <div>
                    <h2 style="font-size:24px; margin-bottom:4px; color:var(--text-primary); font-weight:700;">WolfKube${clusterLabel}</h2>
                    <p style="color:var(--text-secondary); font-size:13px; margin:0;">Provision and manage Kubernetes clusters across your nodes with WolfNet overlay networking.</p>
                </div>
            </div>
            <div style="display:flex; gap:8px;">
                <button class="btn btn-primary" onclick="showK8sProvisionModal()" style="background:#326ce5; border-color:#326ce5;">+ Provision Cluster</button>
                <button class="btn btn-secondary" onclick="showK8sImportModal()">Import Cluster</button>
            </div>
        </div>
    </div>`;

    // Auto-detect banner
    html += `<div id="k8s-detect-banner"></div>`;

    if (visibleK8s.length === 0) {
        html += `<div class="card"><div class="card-body" style="padding:60px; text-align:center;">
            <div style="font-size:48px; margin-bottom:16px;">&#9784;</div>
            <h3 style="margin-bottom:8px; color:var(--text-primary);">No Clusters Configured</h3>
            <p style="color:var(--text-muted); margin-bottom:20px;">Provision a new cluster (k3s, MicroK8s, or kubeadm) or import an existing kubeconfig.</p>
            <div style="display:flex; gap:8px; justify-content:center;">
                <button class="btn btn-primary" onclick="showK8sProvisionModal()" style="background:#326ce5; border-color:#326ce5;">Provision Cluster</button>
                <button class="btn btn-secondary" onclick="showK8sImportModal()">Import Cluster</button>
            </div>
        </div></div>`;
    } else {
        // Cluster list
        html += `<div class="card"><div class="card-body" style="padding:0;">
        <table class="data-table" style="width:100%;"><thead><tr>
            <th>Cluster</th><th>Type</th><th>Nodes</th><th>Status</th><th>API Server</th><th style="text-align:right;">Actions</th>
        </tr></thead><tbody>`;

        visibleK8s.forEach(c => {
            const typeBadge = `<span style="padding:2px 8px;border-radius:6px;font-size:11px;background:rgba(50,108,229,0.12);color:#326ce5;border:1px solid rgba(50,108,229,0.3);">${escapeHtml(c.cluster_type || 'k8s')}</span>`;
            const nodeCount = (c.nodes || []).length;
            html += `<tr style="cursor:pointer;" onclick="openK8sCluster('${escapeHtml(c.id)}')">
                <td><strong>${escapeHtml(c.name)}</strong></td>
                <td>${typeBadge}</td>
                <td>${nodeCount} node${nodeCount !== 1 ? 's' : ''}</td>
                <td><span id="k8s-status-${c.id}" style="color:var(--text-muted);">checking...</span></td>
                <td><code style="font-size:11px;">${escapeHtml(c.api_url || '')}</code></td>
                <td style="text-align:right;">
                    <button class="btn btn-sm btn-secondary" onclick="event.stopPropagation(); openK8sCluster('${escapeHtml(c.id)}')" style="font-size:11px;">Manage</button>
                    <button class="btn btn-sm btn-danger" onclick="event.stopPropagation(); deleteK8sCluster('${escapeHtml(c.id)}', '${escapeHtml(c.name)}')" style="font-size:11px;">Remove</button>
                </td>
            </tr>`;
        });

        html += `</tbody></table></div></div>`;

        // Check cluster statuses async
        visibleK8s.forEach(c => checkK8sClusterStatus(c.id));
    }

    // Detail panel (shown when a cluster is selected)
    html += `<div id="k8s-detail-panel" style="display:none; margin-top:20px;"></div>`;

    el.innerHTML = html;

    // Auto-detect existing k8s installations
    k8sDetectExisting();
}

async function k8sDetectExisting() {
    const banner = document.getElementById('k8s-detect-banner');
    if (!banner) return;
    try {
        const resp = await fetch('/api/kubernetes/detect');
        if (!resp.ok) return;
        const detected = await resp.json();
        if (detected.length === 0) { banner.innerHTML = ''; return; }
        banner.innerHTML = `<div class="card" style="margin-bottom:16px; border-color:rgba(50,108,229,0.4); background:rgba(50,108,229,0.06);">
            <div class="card-body" style="padding:16px 24px;">
                <div style="display:flex; align-items:center; gap:12px; margin-bottom:12px;">
                    <span style="font-size:20px;">&#128269;</span>
                    <strong style="font-size:14px;">Existing Kubernetes installations detected</strong>
                </div>
                ${detected.map(d => `<div style="display:flex; align-items:center; gap:12px; padding:8px 0; border-top:1px solid var(--border);">
                    <div style="flex:1;">
                        <strong>${escapeHtml(d.name)}</strong>
                        <span style="font-size:12px; color:var(--text-muted); margin-left:8px;">${escapeHtml(d.cluster_type)} &mdash; ${escapeHtml(d.kubeconfig_path)}</span>
                    </div>
                    <button class="btn btn-sm btn-primary" onclick="k8sImportDetected('${escapeHtml(d.name)}', '${escapeHtml(d.kubeconfig_path)}', '${escapeHtml(d.cluster_type)}')" style="background:#326ce5; border-color:#326ce5; font-size:11px;">Import</button>
                </div>`).join('')}
            </div>
        </div>`;
    } catch (e) { /* ignore */ }
}

async function k8sImportDetected(name, kubeconfigPath, clusterType) {
    try {
        const resp = await fetch('/api/kubernetes/clusters', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, kubeconfig_path: kubeconfigPath, cluster_type: clusterType }),
        });
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok) throw new Error(data.error || 'Import failed');
        showToast(`Imported "${name}" cluster!`, 'success');
        loadKubernetesClusters();
    } catch (e) { showToast('Import failed: ' + e.message, 'error'); }
}

async function checkK8sClusterStatus(clusterId) {
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${clusterId}/status`);
        const el = document.getElementById(`k8s-status-${clusterId}`);
        if (!el) return;
        if (!resp.ok) {
            el.innerHTML = '<span style="color:#ef4444;">Unreachable</span>';
            return;
        }
        const status = await resp.json();
        if (status.healthy) {
            el.innerHTML = `<span style="display:inline-flex;align-items:center;gap:4px;"><span style="width:6px;height:6px;border-radius:50%;background:#10b981;display:inline-block;"></span> Healthy (${status.nodes_ready}/${status.nodes_total} nodes)</span>`;
        } else {
            el.innerHTML = `<span style="display:inline-flex;align-items:center;gap:4px;"><span style="width:6px;height:6px;border-radius:50%;background:#ef4444;display:inline-block;"></span> Unhealthy</span>`;
        }
        // Update the node count cell with live data
        const row = el.closest('tr');
        if (row && status.nodes_total != null) {
            const nodeCell = row.children[2];
            if (nodeCell) nodeCell.textContent = `${status.nodes_total} node${status.nodes_total !== 1 ? 's' : ''}`;
        }
    } catch (e) {
        const el = document.getElementById(`k8s-status-${clusterId}`);
        if (el) el.innerHTML = '<span style="color:var(--text-muted);">Unknown</span>';
    }
}

async function openK8sCluster(clusterId) {
    k8sCurrentCluster = clusterId;
    k8sCurrentView = 'overview';
    k8sCurrentNamespace = '';
    await renderK8sClusterDetail();

    // Auto-refresh — only update the active tab content, not the entire page
    if (k8sRefreshTimer) clearInterval(k8sRefreshTimer);
    k8sRefreshTimer = setInterval(() => {
        if (currentPage === 'kubernetes' && k8sCurrentCluster) {
            // Don't refresh when user is viewing pod/deployment detail
            if (k8sDetailOpen) return;
            // Only refresh data tabs, not settings/wolfnet/detail views
            const autoRefreshTabs = ['overview', 'nodes', 'namespaces', 'deployments', 'pods', 'services', 'storage'];
            if (autoRefreshTabs.includes(k8sCurrentView)) {
                switchK8sTab(k8sCurrentView, true);
            }
        } else {
            clearInterval(k8sRefreshTimer);
        }
    }, 30000);
}

async function renderK8sClusterDetail() {
    const panel = document.getElementById('k8s-detail-panel');
    if (!panel || !k8sCurrentCluster) return;
    panel.style.display = '';

    const cluster = k8sClusters.find(c => c.id === k8sCurrentCluster);
    const clusterName = cluster ? cluster.name : k8sCurrentCluster;

    // Tab bar
    const tabs = [
        { key: 'overview', label: 'Overview' },
        { key: 'nodes', label: 'Nodes' },
        { key: 'namespaces', label: 'Namespaces' },
        { key: 'deployments', label: 'Deployments' },
        { key: 'pods', label: 'Pods' },
        { key: 'services', label: 'Services' },
        { key: 'storage', label: 'Storage' },
        { key: 'wolfnet', label: 'WolfNet' },
        { key: 'settings', label: 'Settings' },
    ];

    let html = `<div class="card"><div class="card-body" style="padding:16px 24px;">
        <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:16px;">
            <div style="display:flex; align-items:center; gap:12px;">
                <button class="btn btn-sm btn-secondary" onclick="k8sDetailOpen=false; k8sCurrentCluster=null; document.getElementById('k8s-detail-panel').style.display='none'; clearInterval(k8sRefreshTimer);" style="font-size:11px;">&larr; Back</button>
                <h3 style="margin:0; font-size:18px; font-weight:700;">${escapeHtml(clusterName)}</h3>
            </div>
            <div style="display:flex; gap:8px;">
                <select id="k8s-ns-filter" class="form-control" style="width:200px; font-size:12px;" onchange="k8sCurrentNamespace=this.value; switchK8sTab(k8sCurrentView);">
                    <option value="">All Namespaces</option>
                </select>
                <button class="btn btn-sm btn-primary" onclick="showK8sApplyYamlModal()" style="background:#326ce5; border-color:#326ce5; font-size:11px;">Apply YAML</button>
            </div>
        </div>
        <div style="display:flex; gap:4px; margin-bottom:16px; border-bottom:1px solid var(--border); padding-bottom:8px;">`;

    tabs.forEach(t => {
        const active = t.key === k8sCurrentView ? 'background:rgba(50,108,229,0.15); color:#326ce5; font-weight:600;' : '';
        html += `<button class="btn btn-sm" data-k8s-tab="${t.key}" onclick="switchK8sTab('${t.key}')" style="font-size:12px; border:none; padding:6px 14px; border-radius:6px; ${active}">${t.label}</button>`;
    });

    html += `</div><div id="k8s-tab-content">Loading...</div></div></div>`;
    panel.innerHTML = html;

    // Load namespaces for filter
    loadK8sNamespaceFilter();

    // Load current tab
    switchK8sTab(k8sCurrentView);
}

async function loadK8sNamespaceFilter() {
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/namespaces`);
        if (!resp.ok) return;
        const namespaces = await resp.json();
        const sel = document.getElementById('k8s-ns-filter');
        if (!sel) return;
        let opts = '<option value="">All Namespaces</option>';
        namespaces.forEach(ns => {
            const selected = ns.name === k8sCurrentNamespace ? ' selected' : '';
            opts += `<option value="${escapeHtml(ns.name)}"${selected}>${escapeHtml(ns.name)}</option>`;
        });
        sel.innerHTML = opts;
    } catch (e) { /* ignore */ }
}

async function switchK8sTab(tab, silent) {
    if (!silent) k8sDetailOpen = false;
    k8sCurrentView = tab;
    const content = document.getElementById('k8s-tab-content');
    if (!content) return;
    if (!silent) {
        content.innerHTML = renderBlockSkeleton({lines:3});
        // Update tab button active states
        document.querySelectorAll('[data-k8s-tab]').forEach(btn => {
            btn.style.background = btn.dataset.k8sTab === tab ? 'rgba(50,108,229,0.15)' : '';
            btn.style.color = btn.dataset.k8sTab === tab ? '#326ce5' : '';
            btn.style.fontWeight = btn.dataset.k8sTab === tab ? '600' : '';
        });
    }

    const nsParam = k8sCurrentNamespace ? `?namespace=${encodeURIComponent(k8sCurrentNamespace)}` : '';

    try {
        if (tab === 'overview') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/status`);
            if (!resp.ok) throw new Error('Failed to get status');
            const status = await resp.json();
            content.innerHTML = renderK8sOverview(status);
        } else if (tab === 'nodes') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/nodes`);
            if (!resp.ok) throw new Error('Failed');
            const nodes = await resp.json();
            content.innerHTML = renderK8sNodes(nodes);
        } else if (tab === 'namespaces') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/namespaces`);
            if (!resp.ok) throw new Error('Failed');
            const namespaces = await resp.json();
            content.innerHTML = renderK8sNamespaces(namespaces);
        } else if (tab === 'deployments') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/deployments${nsParam}`);
            if (!resp.ok) throw new Error('Failed');
            const deps = await resp.json();
            content.innerHTML = renderK8sDeployments(deps);
        } else if (tab === 'pods') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods${nsParam}`);
            if (!resp.ok) throw new Error('Failed');
            const pods = await resp.json();
            content.innerHTML = renderK8sPods(pods);
        } else if (tab === 'services') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/services${nsParam}`);
            if (!resp.ok) throw new Error('Failed');
            const svcs = await resp.json();
            content.innerHTML = renderK8sServices(svcs);
        } else if (tab === 'storage') {
            const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/storage${nsParam}`);
            if (!resp.ok) throw new Error('Failed');
            const storageData = await resp.json();
            content.innerHTML = renderK8sStorage(storageData);
        } else if (tab === 'wolfnet') {
            const [wnResp, depResp] = await Promise.all([
                fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/wolfnet`),
                fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/deployments`),
            ]);
            if (!wnResp.ok) throw new Error('Failed');
            const status = await wnResp.json();
            const deployments = depResp.ok ? await depResp.json() : [];
            const cluster = k8sClusters.find(c => c.id === k8sCurrentCluster);
            content.innerHTML = renderK8sWolfNet(status, cluster, deployments);
        } else if (tab === 'settings') {
            const cluster = k8sClusters.find(c => c.id === k8sCurrentCluster);
            content.innerHTML = renderK8sSettings(cluster);
        }
    } catch (e) {
        content.innerHTML = `<div style="padding:20px; text-align:center; color:#ef4444;">Failed to load ${tab}: ${e.message}</div>`;
    }
}

function renderK8sOverview(status) {
    const healthColor = status.healthy ? '#10b981' : '#ef4444';
    const healthLabel = status.healthy ? 'Healthy' : 'Unhealthy';
    return `
    <div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(160px, 1fr)); gap:16px; margin-bottom:20px;">
        <div class="card" style="text-align:center; padding:20px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">Status</div>
            <div style="font-size:20px; font-weight:700; color:${healthColor}; margin-top:4px; display:flex; align-items:center; justify-content:center; gap:6px;">
                <span style="width:8px;height:8px;border-radius:50%;background:${healthColor};display:inline-block;"></span> ${healthLabel}
            </div>
        </div>
        <div class="card" style="text-align:center; padding:20px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">Nodes</div>
            <div style="font-size:24px; font-weight:700; color:var(--text-primary); margin-top:4px;">${status.nodes_ready}/${status.nodes_total}</div>
        </div>
        <div class="card" style="text-align:center; padding:20px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">Pods</div>
            <div style="font-size:24px; font-weight:700; color:var(--text-primary); margin-top:4px;">${status.pods_running}/${status.pods_total}</div>
        </div>
        <div class="card" style="text-align:center; padding:20px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">Namespaces</div>
            <div style="font-size:24px; font-weight:700; color:var(--text-primary); margin-top:4px;">${status.namespaces}</div>
        </div>
        <div class="card" style="text-align:center; padding:20px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">API Version</div>
            <div style="font-size:14px; font-weight:600; color:var(--text-primary); margin-top:8px;">${escapeHtml(status.api_version || 'N/A')}</div>
        </div>
    </div>`;
}

function renderK8sNodes(nodes) {
    if (nodes.length === 0) return '<div style="padding:20px; text-align:center; color:var(--text-muted);">No nodes found.</div>';
    let html = '<table class="data-table" style="width:100%;"><thead><tr><th>Name</th><th>Status</th><th>Roles</th><th>Version</th><th>CPU</th><th>Memory</th><th>Age</th></tr></thead><tbody>';
    nodes.forEach(n => {
        const statusColor = n.status === 'Ready' ? '#10b981' : '#ef4444';
        html += `<tr>
            <td><strong>${escapeHtml(n.name)}</strong></td>
            <td><span style="color:${statusColor}; font-weight:600;">${escapeHtml(n.status)}</span></td>
            <td>${escapeHtml(n.roles || '')}</td>
            <td><code style="font-size:11px;">${escapeHtml(n.version || '')}</code></td>
            <td>${escapeHtml(n.cpu_capacity || '')}</td>
            <td>${escapeHtml(n.memory_capacity || '')}</td>
            <td>${escapeHtml(n.age || '')}</td>
        </tr>`;
    });
    return html + '</tbody></table>';
}

function renderK8sNamespaces(namespaces) {
    let html = `<div style="margin-bottom:12px;"><button class="btn btn-sm btn-primary" onclick="showK8sCreateNamespaceModal()" style="background:#326ce5; border-color:#326ce5; font-size:11px;">+ Create Namespace</button></div>`;
    html += '<table class="data-table" style="width:100%;"><thead><tr><th>Name</th><th>Status</th><th>Age</th><th style="text-align:right;">Actions</th></tr></thead><tbody>';
    namespaces.forEach(ns => {
        const isSystem = ['kube-system', 'kube-public', 'kube-node-lease', 'default'].includes(ns.name);
        html += `<tr>
            <td><strong>${escapeHtml(ns.name)}</strong>${isSystem ? ' <span style="font-size:10px;color:var(--text-muted);">(system)</span>' : ''}</td>
            <td>${escapeHtml(ns.status || '')}</td>
            <td>${escapeHtml(ns.age || '')}</td>
            <td style="text-align:right;">${isSystem ? '' : `<button class="btn btn-sm btn-danger" onclick="deleteK8sNamespace('${escapeHtml(ns.name)}')" style="font-size:11px;">Delete</button>`}</td>
        </tr>`;
    });
    return html + '</tbody></table>';
}

function renderK8sDeployments(deps) {
    if (deps.length === 0) return '<div style="padding:20px; text-align:center; color:var(--text-muted);">No deployments found.</div>';
    // Look up WolfNet routes from cluster data
    const cluster = k8sClusters.find(c => c.id === k8sCurrentCluster);
    const routes = cluster?.wolfnet_routes || [];
    let html = '<table class="data-table" style="width:100%;"><thead><tr><th>Name</th><th>Namespace</th><th>Ready</th><th>WolfNet IP</th><th>Image</th><th>Age</th><th style="text-align:right;">Actions</th></tr></thead><tbody>';
    deps.forEach(d => {
        const ready = `${d.ready_replicas || 0}/${d.desired_replicas || 0}`;
        const allReady = (d.ready_replicas || 0) >= (d.desired_replicas || 0) && (d.desired_replicas || 0) > 0;
        const readyColor = allReady ? '#10b981' : '#eab308';
        const route = routes.find(r => r.deployment_name === d.name && r.namespace === (d.namespace || 'default'));
        const wolfnetCell = route
            ? `<code style="color:#10b981; font-weight:600; font-size:11px;">${escapeHtml(route.wolfnet_ip)}</code>`
            : '<span style="color:var(--text-muted); font-size:11px;">-</span>';
        html += `<tr>
            <td><strong><a href="#" onclick="event.preventDefault(); showK8sDeploymentDetail('${escapeHtml(d.name)}', '${escapeHtml(d.namespace || 'default')}')" style="color:var(--text-primary); text-decoration:none;">${escapeHtml(d.name)}</a></strong></td>
            <td><code style="font-size:11px;">${escapeHtml(d.namespace || '')}</code></td>
            <td><span style="color:${readyColor}; font-weight:600;">${ready}</span></td>
            <td>${wolfnetCell}</td>
            <td><code style="font-size:11px; max-width:250px; overflow:hidden; text-overflow:ellipsis; display:inline-block;">${escapeHtml(d.image || '')}</code></td>
            <td>${escapeHtml(d.age || '')}</td>
            <td style="text-align:right; white-space:nowrap;">
                <button class="btn btn-sm btn-secondary" onclick="showK8sDeploymentDetail('${escapeHtml(d.name)}', '${escapeHtml(d.namespace || 'default')}')" style="font-size:11px;">Manage</button>
                <button class="btn btn-sm btn-secondary" onclick="showK8sScaleModal('${escapeHtml(d.name)}', '${escapeHtml(d.namespace || 'default')}', ${d.desired_replicas || 1})" style="font-size:11px;">Scale</button>
                <button class="btn btn-sm btn-secondary" onclick="openK8sYamlEditor('deployment', '${escapeHtml(d.name)}', '${escapeHtml(d.namespace || 'default')}')" style="font-size:11px;">YAML</button>
                <button class="btn btn-sm btn-danger" onclick="k8sDeleteDeploymentFull('${escapeHtml(d.name)}', '${escapeHtml(d.namespace || 'default')}')" style="font-size:11px;">Remove</button>
            </td>
        </tr>`;
    });
    return html + '</tbody></table>';
}

function renderK8sPods(pods) {
    if (pods.length === 0) return '<div style="padding:20px; text-align:center; color:var(--text-muted);">No pods found.</div>';
    let html = '<table class="data-table" style="width:100%;"><thead><tr><th>Name</th><th>Namespace</th><th>Status</th><th>Ready</th><th>Restarts</th><th>Node</th><th>IP</th><th>Age</th><th style="text-align:right;">Actions</th></tr></thead><tbody>';
    pods.forEach(p => {
        const statusColors = { Running: '#10b981', Pending: '#eab308', Succeeded: '#3b82f6', Failed: '#ef4444', Unknown: '#9ca3af' };
        const color = statusColors[p.status] || '#9ca3af';
        const ns = p.namespace || 'default';
        const isRunning = p.status === 'Running';
        html += `<tr>
            <td><strong><a href="#" onclick="event.preventDefault(); showK8sPodDetail('${escapeHtml(p.name)}', '${escapeHtml(ns)}')" style="color:var(--text-primary); text-decoration:none; font-size:12px;">${escapeHtml(p.name)}</a></strong></td>
            <td><code style="font-size:11px;">${escapeHtml(ns)}</code></td>
            <td><span style="color:${color}; font-weight:600; font-size:12px;">${escapeHtml(p.status || '')}</span></td>
            <td>${escapeHtml(p.ready || '')}</td>
            <td>${p.restarts || 0}</td>
            <td style="font-size:11px;">${escapeHtml(p.node || '')}</td>
            <td><code style="font-size:11px;">${escapeHtml(p.ip || '')}</code></td>
            <td>${escapeHtml(p.age || '')}</td>
            <td style="text-align:right; white-space:nowrap;">
                ${isRunning ? `<button class="btn btn-sm btn-secondary" onclick="openK8sPodConsole('${escapeHtml(p.name)}', '${escapeHtml(ns)}')" style="font-size:11px;" title="Terminal">Console</button>` : ''}
                <button class="btn btn-sm btn-secondary" onclick="showK8sPodDetail('${escapeHtml(p.name)}', '${escapeHtml(ns)}')" style="font-size:11px;">Manage</button>
                <button class="btn btn-sm btn-secondary" onclick="openK8sYamlEditor('pod', '${escapeHtml(p.name)}', '${escapeHtml(ns)}')" style="font-size:11px;">YAML</button>
                <button class="btn btn-sm btn-danger" onclick="k8sDeletePod('${escapeHtml(p.name)}', '${escapeHtml(ns)}')" style="font-size:11px;">Delete</button>
            </td>
        </tr>`;
    });
    return html + '</tbody></table>';
}

function renderK8sServices(svcs) {
    if (svcs.length === 0) return '<div style="padding:20px; text-align:center; color:var(--text-muted);">No services found.</div>';
    let html = '<table class="data-table" style="width:100%;"><thead><tr><th>Name</th><th>Namespace</th><th>Type</th><th>Cluster IP</th><th>External IP</th><th>Ports</th><th>Age</th><th style="text-align:right;">Actions</th></tr></thead><tbody>';
    svcs.forEach(s => {
        html += `<tr>
            <td><strong>${escapeHtml(s.name)}</strong></td>
            <td><code style="font-size:11px;">${escapeHtml(s.namespace || '')}</code></td>
            <td><span style="padding:2px 8px;border-radius:6px;font-size:11px;background:rgba(50,108,229,0.12);color:#326ce5;">${escapeHtml(s.service_type || '')}</span></td>
            <td><code style="font-size:11px;">${escapeHtml(s.cluster_ip || '')}</code></td>
            <td><code style="font-size:11px;">${escapeHtml(s.external_ip || 'None')}</code></td>
            <td style="font-size:11px;">${escapeHtml(s.ports || '')}</td>
            <td>${escapeHtml(s.age || '')}</td>
            <td style="text-align:right;">
                <button class="btn btn-sm btn-secondary" onclick="openK8sYamlEditor('service', '${escapeHtml(s.name)}', '${escapeHtml(s.namespace || 'default')}')" style="font-size:11px;">YAML</button>
                <button class="btn btn-sm btn-danger" onclick="k8sDeleteService('${escapeHtml(s.name)}', '${escapeHtml(s.namespace || 'default')}')" style="font-size:11px;">Delete</button>
            </td>
        </tr>`;
    });
    return html + '</tbody></table>';
}

// ─── K8s Actions ───

async function deleteK8sCluster(id, name) {
    if (!(await showConfirm(`Remove cluster "${name}" from WolfKube? This only removes tracking, not the actual cluster.`))) return;
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${id}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || `HTTP ${resp.status}`);
        showToast(`Cluster "${name}" removed`, 'success');
        loadKubernetesClusters();
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

async function deleteK8sNamespace(name) {
    if (!(await showConfirm(`Delete namespace "${name}"? All resources in it will be destroyed.`))) return;
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/namespaces/${name}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Namespace "${name}" deleted`, 'success');
        switchK8sTab('namespaces');
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

async function k8sDeletePod(name, namespace) {
    if (!(await showConfirm(`Delete pod "${name}" in ${namespace}?`))) return;
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${name}?namespace=${encodeURIComponent(namespace)}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Pod "${name}" deleted`, 'success');
        taskLog('K8s delete pod: ' + name);
        switchK8sTab('pods');
    } catch (e) { showToast('Failed: ' + e.message, 'error'); taskLog('K8s delete pod: ' + name, 'failed'); }
}

async function k8sDeleteDeployment(name, namespace) {
    if (!(await showConfirm(`Delete deployment "${name}" in ${namespace}?`))) return;
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/deployments/${name}?namespace=${encodeURIComponent(namespace)}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Deployment "${name}" deleted`, 'success');
        taskLog('K8s delete deployment: ' + name);
        switchK8sTab('deployments');
    } catch (e) { showToast('Failed: ' + e.message, 'error'); taskLog('K8s delete deployment: ' + name, 'failed'); }
}

async function k8sRestartDeployment(name, namespace) {
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/deployments/${name}/restart?namespace=${encodeURIComponent(namespace)}`, { method: 'POST' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Deployment "${name}" restarting`, 'success');
        taskLog('K8s restart deployment: ' + name);
        setTimeout(() => switchK8sTab('deployments'), 2000);
    } catch (e) { showToast('Failed: ' + e.message, 'error'); taskLog('K8s restart deployment: ' + name, 'failed'); }
}

async function k8sDeleteService(name, namespace) {
    if (!(await showConfirm(`Delete service "${name}" in ${namespace}?`))) return;
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/services/${name}?namespace=${encodeURIComponent(namespace)}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Service "${name}" deleted`, 'success');
        switchK8sTab('services');
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

// ─── K8s Modals ───

function showK8sScaleModal(name, namespace, currentReplicas) {
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.onclick = e => { if (e.target === overlay) closeModal(); };
    overlay.innerHTML = `
        <div class="modal" style="max-width:420px;">
            <div class="modal-header">
                <h3>Scale Deployment</h3>
                <button class="modal-close" onclick="closeModal()">&times;</button>
            </div>
            <div class="modal-body">
                <p style="color:var(--text-muted); font-size:12px; margin:0 0 16px 0;">Adjust replicas for <strong>${escapeHtml(name)}</strong> in <code>${escapeHtml(namespace)}</code></p>
                <div class="form-group">
                    <label style="font-weight:600; font-size:13px; margin-bottom:6px; display:block;">Replicas</label>
                    <input type="number" id="k8s-scale-replicas" class="form-control" value="${currentReplicas}" min="0" max="100" style="font-size:16px; padding:10px 12px; width:120px;">
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="closeModal()">Cancel</button>
                <button class="btn btn-primary" onclick="k8sScaleDeployment('${escapeHtml(name)}', '${escapeHtml(namespace)}')" style="background:#326ce5; border-color:#326ce5;">Scale</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
}

async function k8sScaleDeployment(name, namespace) {
    const replicas = parseInt(document.getElementById('k8s-scale-replicas').value);
    closeModal();
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/deployments/${name}/scale`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ namespace, replicas }),
        });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Scaled "${name}" to ${replicas} replicas`, 'success');
        taskLog('K8s scale deployment: ' + name + ' to ' + replicas);
        setTimeout(() => switchK8sTab('deployments'), 1000);
    } catch (e) { showToast('Failed: ' + e.message, 'error'); taskLog('K8s scale deployment: ' + name, 'failed'); }
}

function showK8sCreateNamespaceModal() {
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.onclick = e => { if (e.target === overlay) closeModal(); };
    overlay.innerHTML = `
        <div class="modal" style="max-width:420px;">
            <div class="modal-header">
                <h3>Create Namespace</h3>
                <button class="modal-close" onclick="closeModal()">&times;</button>
            </div>
            <div class="modal-body">
                <p style="color:var(--text-muted); font-size:12px; margin:0 0 16px 0;">Create a new Kubernetes namespace for isolating workloads.</p>
                <div class="form-group">
                    <label style="font-weight:600; font-size:13px; margin-bottom:6px; display:block;">Namespace Name</label>
                    <input type="text" id="k8s-ns-name" class="form-control" placeholder="my-namespace" style="font-size:14px; padding:10px 12px;">
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="closeModal()">Cancel</button>
                <button class="btn btn-primary" onclick="k8sCreateNamespace()" style="background:#326ce5; border-color:#326ce5;">Create</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
}

async function k8sCreateNamespace() {
    const name = document.getElementById('k8s-ns-name').value.trim();
    if (!name) return;
    closeModal();
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/namespaces`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name }),
        });
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        showToast(`Namespace "${name}" created`, 'success');
        switchK8sTab('namespaces');
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

async function showK8sPodLogs(pod, namespace) {
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.onclick = e => { if (e.target === overlay) closeModal(); };
    overlay.innerHTML = `
        <div class="modal" style="max-width:700px;">
            <div class="modal-header">
                <h3>Logs: ${escapeHtml(pod)}</h3>
                <button class="modal-close" onclick="closeModal()">&times;</button>
            </div>
            <div class="modal-body">
                <pre id="k8s-log-content" style="max-height:500px; overflow:auto; background:var(--bg-secondary); padding:12px; border-radius:8px; font-size:12px; white-space:pre-wrap;">Loading...</pre>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="closeModal()">Close</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/logs/${encodeURIComponent(pod)}?namespace=${encodeURIComponent(namespace)}&tail=200`);
        const el = document.getElementById('k8s-log-content');
        if (!resp.ok) { el.textContent = 'Failed to load logs'; return; }
        const data = await resp.json();
        el.textContent = data.logs || '(no logs)';
        el.scrollTop = el.scrollHeight;
    } catch (e) {
        document.getElementById('k8s-log-content').textContent = 'Error: ' + e.message;
    }
}

// ─── K8s Pod Detail View ───

let k8sPodDetailTab = 'overview';

function openK8sPodConsole(podName, namespace, container) {
    const target = `${k8sCurrentCluster}/${podName}/${namespace}${container ? '/' + container : ''}`;
    // K8s clusters may be on a different node — use the cluster's owner_node_id,
    // not currentNodeId. Funnel into the shared tabbed popup like every shell.
    const cluster = k8sClusters.find(c => c.id === k8sCurrentCluster);
    let nodeId = '';
    if (cluster && cluster.owner_node_id) {
        const node = allNodes.find(n => n.id === cluster.owner_node_id);
        if (node && !node.is_self) nodeId = cluster.owner_node_id;
    }
    _openShellTab('k8s', target, nodeId);
}

async function showK8sPodDetail(name, namespace) {
    k8sDetailOpen = true;
    const content = document.getElementById('k8s-tab-content');
    if (!content) return;
    content.innerHTML = renderBlockSkeleton({lines:3});
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(name)}/detail?namespace=${encodeURIComponent(namespace)}`);
        if (!resp.ok) throw new Error((await resp.json().catch(() => ({}))).error || 'Failed');
        const pod = await resp.json();

        let html = `<div style="margin-bottom:12px;"><button class="btn btn-sm btn-secondary" onclick="k8sDetailOpen=false; switchK8sTab('pods')" style="font-size:11px;">&larr; Back to Pods</button></div>`;

        // Header
        const statusColors = { Running: '#10b981', Pending: '#eab308', Succeeded: '#3b82f6', Failed: '#ef4444', Unknown: '#9ca3af' };
        const sColor = statusColors[pod.status] || '#9ca3af';
        const isRunning = pod.status === 'Running';
        html += `<div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:16px;">
            <div>
                <h3 style="margin:0; font-size:18px; font-weight:700;">${escapeHtml(pod.name)}</h3>
                <span style="font-size:12px; color:var(--text-muted);">Namespace: <code>${escapeHtml(pod.namespace)}</code> &bull;
                Node: <code>${escapeHtml(pod.node_name || 'N/A')}</code> &bull;
                IP: <code>${escapeHtml(pod.pod_ip || 'N/A')}</code> &bull;
                Status: <span style="color:${sColor}; font-weight:600;">${escapeHtml(pod.status || 'Unknown')}</span></span>
            </div>
            <div style="display:flex; gap:8px;">
                ${isRunning ? `<button class="btn btn-sm btn-secondary" onclick="openK8sPodConsole('${escapeHtml(name)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Console</button>` : ''}
                <button class="btn btn-sm btn-danger" onclick="k8sDeletePod('${escapeHtml(name)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Delete</button>
            </div>
        </div>`;

        // Tabs
        const podTabs = [
            { key: 'overview', label: 'Overview' },
            { key: 'logs', label: 'Logs' },
        ];
        if (isRunning) {
            podTabs.push({ key: 'terminal', label: 'Terminal' });
            podTabs.push({ key: 'processes', label: 'Processes' });
            podTabs.push({ key: 'disk', label: 'Disk Space' });
            podTabs.push({ key: 'resources', label: 'Resources' });
        }
        podTabs.push({ key: 'events', label: 'Events' });

        html += `<div style="display:flex; gap:4px; margin-bottom:16px; border-bottom:1px solid var(--border-color); padding-bottom:0;">`;
        podTabs.forEach(t => {
            const active = t.key === 'overview' ? 'border-bottom:2px solid #326ce5; color:#326ce5; font-weight:600;' : 'color:var(--text-muted);';
            html += `<button class="btn btn-sm" data-pod-tab="${t.key}" onclick="switchK8sPodTab('${t.key}', '${escapeHtml(name)}', '${escapeHtml(namespace)}')" style="font-size:12px; border:none; border-radius:0; padding:8px 14px; background:transparent; ${active}">${t.label}</button>`;
        });
        html += `</div>`;

        html += `<div id="k8s-pod-tab-content"></div>`;

        content.innerHTML = html;
        window._k8sPodDetail = pod;
        renderK8sPodOverview(pod);
    } catch (e) {
        content.innerHTML = `<div style="padding:20px; text-align:center; color:#ef4444;">Failed to load pod: ${e.message}</div>`;
    }
}

function switchK8sPodTab(tab, podName, namespace) {
    k8sPodDetailTab = tab;
    // Update tab button styles
    document.querySelectorAll('[data-pod-tab]').forEach(btn => {
        if (btn.dataset.podTab === tab) {
            btn.style.borderBottom = '2px solid #326ce5';
            btn.style.color = '#326ce5';
            btn.style.fontWeight = '600';
        } else {
            btn.style.borderBottom = 'none';
            btn.style.color = 'var(--text-muted)';
            btn.style.fontWeight = '400';
        }
    });

    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;
    const pod = window._k8sPodDetail;

    if (tab === 'overview') {
        renderK8sPodOverview(pod);
    } else if (tab === 'logs') {
        renderK8sPodLogsTab(podName, namespace, pod);
    } else if (tab === 'terminal') {
        renderK8sPodTerminalTab(podName, namespace, pod);
    } else if (tab === 'processes') {
        loadK8sPodProcesses(podName, namespace);
    } else if (tab === 'disk') {
        loadK8sPodDiskSpace(podName, namespace);
    } else if (tab === 'resources') {
        loadK8sPodResources(podName, namespace, pod);
    } else if (tab === 'events') {
        loadK8sPodEvents(podName, namespace);
    }
}

function renderK8sPodOverview(pod) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;

    let html = '';

    // Basic info card
    html += `<div class="card" style="margin-bottom:16px;"><div class="card-body" style="padding:20px;">
        <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Pod Information</h4>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px 24px; font-size:13px;">
            <div><span style="color:var(--text-muted);">QoS Class:</span> <strong>${escapeHtml(pod.qos_class || 'N/A')}</strong></div>
            <div><span style="color:var(--text-muted);">Restart Policy:</span> <strong>${escapeHtml(pod.restart_policy || 'N/A')}</strong></div>
            <div><span style="color:var(--text-muted);">Service Account:</span> <code>${escapeHtml(pod.service_account || 'default')}</code></div>
            <div><span style="color:var(--text-muted);">DNS Policy:</span> <strong>${escapeHtml(pod.dns_policy || 'N/A')}</strong></div>
            <div><span style="color:var(--text-muted);">Host IP:</span> <code>${escapeHtml(pod.host_ip || 'N/A')}</code></div>
            <div><span style="color:var(--text-muted);">Pod IP:</span> <code>${escapeHtml(pod.pod_ip || 'N/A')}</code></div>
            <div><span style="color:var(--text-muted);">Created:</span> ${escapeHtml(pod.creation_timestamp || 'N/A')}</div>
            <div><span style="color:var(--text-muted);">Node:</span> <code>${escapeHtml(pod.node_name || 'N/A')}</code></div>
        </div>
    </div></div>`;

    // Labels
    if (pod.labels && Object.keys(pod.labels).length > 0) {
        html += `<div class="card" style="margin-bottom:16px;"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Labels</h4>
            <div style="display:flex; flex-wrap:wrap; gap:6px;">`;
        Object.entries(pod.labels).forEach(([k, v]) => {
            html += `<span style="padding:3px 10px; border-radius:6px; font-size:11px; background:rgba(50,108,229,0.1); color:#326ce5; border:1px solid rgba(50,108,229,0.2);"><code>${escapeHtml(k)}</code>=<code>${escapeHtml(v)}</code></span>`;
        });
        html += `</div></div></div>`;
    }

    // Container statuses
    const statuses = pod.container_statuses || [];
    if (statuses.length > 0) {
        html += `<div class="card" style="margin-bottom:16px;"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Container Status</h4>
            <table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Name</th><th>Ready</th><th>State</th><th>Restarts</th><th>Image</th></tr></thead><tbody>`;
        statuses.forEach(cs => {
            const ready = cs.ready ? '<span style="color:#10b981; font-weight:600;">Yes</span>' : '<span style="color:#ef4444; font-weight:600;">No</span>';
            let state = 'unknown';
            if (cs.state) {
                if (cs.state.running) state = 'Running';
                else if (cs.state.waiting) state = 'Waiting: ' + (cs.state.waiting.reason || '');
                else if (cs.state.terminated) state = 'Terminated: ' + (cs.state.terminated.reason || '');
            }
            html += `<tr>
                <td><strong>${escapeHtml(cs.name)}</strong></td>
                <td>${ready}</td>
                <td>${escapeHtml(state)}</td>
                <td>${cs.restartCount || 0}</td>
                <td><code style="font-size:11px; max-width:250px; overflow:hidden; text-overflow:ellipsis; display:inline-block;">${escapeHtml(cs.image || '')}</code></td>
            </tr>`;
        });
        html += `</tbody></table></div></div>`;
    }

    // Containers spec
    (pod.containers || []).forEach(c => {
        html += `<div class="card" style="margin-bottom:16px;"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Container: ${escapeHtml(c.name)}</h4>
            <div style="background:var(--bg-secondary); border-radius:8px; padding:12px; margin-bottom:12px;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Image</div>
                <code style="font-size:13px; word-break:break-all;">${escapeHtml(c.image)}</code>
            </div>`;

        // Resources (requests/limits)
        if (c.resources && (c.resources.requests || c.resources.limits)) {
            html += `<div style="margin-bottom:12px;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Resource Limits</div>
                <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px;">`;
            if (c.resources.requests) {
                html += `<div style="padding:8px 12px; background:var(--bg-secondary); border-radius:6px; font-size:12px;"><strong>Requests:</strong> CPU: <code>${escapeHtml(c.resources.requests.cpu || 'none')}</code>, Memory: <code>${escapeHtml(c.resources.requests.memory || 'none')}</code></div>`;
            }
            if (c.resources.limits) {
                html += `<div style="padding:8px 12px; background:var(--bg-secondary); border-radius:6px; font-size:12px;"><strong>Limits:</strong> CPU: <code>${escapeHtml(c.resources.limits.cpu || 'none')}</code>, Memory: <code>${escapeHtml(c.resources.limits.memory || 'none')}</code></div>`;
            }
            html += `</div></div>`;
        }

        // Ports
        if (c.ports && c.ports.length > 0) {
            html += `<div style="margin-bottom:12px;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Ports</div>
                <div style="display:flex; gap:8px; flex-wrap:wrap;">`;
            c.ports.forEach(p => {
                html += `<span style="padding:3px 10px; border-radius:6px; font-size:12px; background:rgba(50,108,229,0.1); color:#326ce5; border:1px solid rgba(50,108,229,0.2);">${escapeHtml(String(p.containerPort || p.container_port || ''))}/${escapeHtml(p.protocol || 'TCP')}</span>`;
            });
            html += `</div></div>`;
        }

        // Env vars
        if (c.env && c.env.length > 0) {
            html += `<div style="margin-bottom:12px;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Environment Variables</div>
                <table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Name</th><th>Value</th></tr></thead><tbody>`;
            c.env.forEach(e => {
                const val = e.value || (e.valueFrom ? '(from ref)' : '');
                html += `<tr><td><code>${escapeHtml(e.name)}</code></td><td><code style="word-break:break-all;">${escapeHtml(val)}</code></td></tr>`;
            });
            html += `</tbody></table></div>`;
        }

        // Volume mounts
        if (c.volume_mounts && c.volume_mounts.length > 0) {
            html += `<div>
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Volume Mounts</div>
                <table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Name</th><th>Mount Path</th><th>Read Only</th></tr></thead><tbody>`;
            c.volume_mounts.forEach(vm => {
                html += `<tr><td>${escapeHtml(vm.name)}</td><td><code>${escapeHtml(vm.mountPath || vm.mount_path || '')}</code></td><td>${vm.readOnly || vm.read_only ? 'Yes' : 'No'}</td></tr>`;
            });
            html += `</tbody></table></div>`;
        }

        html += `</div></div>`;
    });

    // Conditions
    if (pod.conditions && pod.conditions.length > 0) {
        html += `<div class="card"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Conditions</h4>
            <table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Type</th><th>Status</th><th>Reason</th><th>Last Transition</th></tr></thead><tbody>`;
        pod.conditions.forEach(c => {
            const color = c.status === 'True' ? '#10b981' : '#ef4444';
            html += `<tr><td>${escapeHtml(c.type)}</td><td><span style="color:${color}; font-weight:600;">${escapeHtml(c.status)}</span></td><td>${escapeHtml(c.reason || '')}</td><td style="font-size:11px;">${escapeHtml(c.lastTransitionTime || '')}</td></tr>`;
        });
        html += `</tbody></table></div></div>`;
    }

    container.innerHTML = html;
}

async function renderK8sPodLogsTab(podName, namespace, pod) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;

    // If multi-container pod, show container selector
    const containers = pod.containers || [];
    let selectorHtml = '';
    if (containers.length > 1) {
        selectorHtml = `<div style="margin-bottom:12px; display:flex; gap:8px; align-items:center;">
            <label style="font-size:12px; color:var(--text-muted);">Container:</label>
            <select id="k8s-pod-log-container" class="form-control" style="font-size:12px; width:auto;" onchange="k8sPodRefreshLogs('${escapeHtml(podName)}', '${escapeHtml(namespace)}')">
                ${containers.map(c => `<option value="${escapeHtml(c.name)}">${escapeHtml(c.name)}</option>`).join('')}
            </select>
        </div>`;
    }

    container.innerHTML = `
        <div class="card"><div class="card-body" style="padding:20px;">
            <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;">
                <h4 style="margin:0; font-size:14px; font-weight:600;">Pod Logs</h4>
                <div style="display:flex; gap:8px;">
                    <select id="k8s-pod-log-lines" class="form-control" style="font-size:11px; width:auto; padding:4px 8px;" onchange="k8sPodRefreshLogs('${escapeHtml(podName)}', '${escapeHtml(namespace)}')">
                        <option value="100">Last 100 lines</option>
                        <option value="200">Last 200 lines</option>
                        <option value="500" selected>Last 500 lines</option>
                        <option value="1000">Last 1000 lines</option>
                        <option value="5000">Last 5000 lines</option>
                    </select>
                    <button class="btn btn-sm btn-secondary" onclick="k8sPodRefreshLogs('${escapeHtml(podName)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Refresh</button>
                </div>
            </div>
            ${selectorHtml}
            <pre id="k8s-pod-log-content" style="max-height:600px; overflow:auto; background:var(--bg-secondary); padding:12px; border-radius:8px; font-size:11px; line-height:1.5; white-space:pre-wrap; margin:0;">Loading...</pre>
        </div></div>`;
    k8sPodRefreshLogs(podName, namespace);
}

async function k8sPodRefreshLogs(podName, namespace) {
    const el = document.getElementById('k8s-pod-log-content');
    if (!el) return;
    const tail = document.getElementById('k8s-pod-log-lines')?.value || '500';
    const containerSel = document.getElementById('k8s-pod-log-container')?.value || '';
    const containerParam = containerSel ? `&container=${encodeURIComponent(containerSel)}` : '';
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/logs/${encodeURIComponent(podName)}?namespace=${encodeURIComponent(namespace)}&tail=${tail}${containerParam}`);
        if (!resp.ok) { el.textContent = 'Failed to load logs'; return; }
        const data = await resp.json();
        el.textContent = data.logs || '(no logs)';
        el.scrollTop = el.scrollHeight;
    } catch (e) {
        el.textContent = 'Error: ' + e.message;
    }
}

function renderK8sPodTerminalTab(podName, namespace, pod) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;

    const containers = pod.containers || [];
    let containerButtons = '';
    if (containers.length > 1) {
        containerButtons = `<div style="margin-bottom:16px;">
            <div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">This pod has multiple containers. Select one to open a terminal:</div>
            <div style="display:flex; gap:8px; flex-wrap:wrap;">
                ${containers.map(c => `<button class="btn btn-sm btn-primary" onclick="openK8sPodConsole('${escapeHtml(podName)}', '${escapeHtml(namespace)}', '${escapeHtml(c.name)}')" style="font-size:12px; background:#326ce5; border-color:#326ce5;">Terminal: ${escapeHtml(c.name)}</button>`).join('')}
            </div>
        </div>`;
    }

    container.innerHTML = `
        <div class="card"><div class="card-body" style="padding:20px; text-align:center;">
            <div style="font-size:48px; margin-bottom:16px;">&#128187;</div>
            <h4 style="margin:0 0 8px 0; font-size:16px; font-weight:600;">Pod Terminal</h4>
            <p style="color:var(--text-muted); font-size:13px; margin-bottom:20px;">Open an interactive shell session inside this pod. This uses <code>kubectl exec</code> to connect to a bash or sh shell.</p>
            ${containerButtons}
            ${containers.length <= 1 ? `<button class="btn btn-primary" onclick="openK8sPodConsole('${escapeHtml(podName)}', '${escapeHtml(namespace)}')" style="font-size:14px; padding:10px 28px; background:#326ce5; border-color:#326ce5;">Open Terminal</button>` : ''}
            <div style="margin-top:16px; padding:12px; background:var(--bg-secondary); border-radius:8px; font-size:12px; color:var(--text-muted); text-align:left;">
                <strong>Tip:</strong> The terminal opens in a new window. You can run any command inside the pod, just like SSH. Type <code>exit</code> to close the session.
            </div>
        </div></div>`;
}

async function loadK8sPodProcesses(podName, namespace) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;
    container.innerHTML = renderBlockSkeleton({lines:3});
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/exec`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ namespace, command: ['ps', 'aux'] }),
        });
        const data = await resp.json();
        let output = data.output || data.error || 'No output';
        // If ps aux failed, try ps -ef
        if (data.error && data.error.includes('not found')) {
            const resp2 = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/exec`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ namespace, command: ['ps', '-ef'] }),
            });
            const data2 = await resp2.json();
            output = data2.output || data2.error || 'No output';
        }

        container.innerHTML = `
            <div class="card"><div class="card-body" style="padding:20px;">
                <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;">
                    <h4 style="margin:0; font-size:14px; font-weight:600;">Running Processes</h4>
                    <button class="btn btn-sm btn-secondary" onclick="loadK8sPodProcesses('${escapeHtml(podName)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Refresh</button>
                </div>
                <pre style="max-height:500px; overflow:auto; background:var(--bg-secondary); padding:12px; border-radius:8px; font-size:11px; line-height:1.5; white-space:pre-wrap; margin:0;">${escapeHtml(output)}</pre>
            </div></div>`;
    } catch (e) {
        container.innerHTML = `<div class="card"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Running Processes</h4>
            <div style="padding:16px; background:var(--bg-secondary); border-radius:8px; color:var(--text-muted); font-size:13px;">
                Could not retrieve processes: ${escapeHtml(e.message)}<br>
                <span style="font-size:12px;">The <code>ps</code> command may not be available in this container image. Use the Terminal tab for interactive access.</span>
            </div>
        </div></div>`;
    }
}

async function loadK8sPodDiskSpace(podName, namespace) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;
    container.innerHTML = renderBlockSkeleton({lines:3});
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/exec`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ namespace, command: ['df', '-h'] }),
        });
        const data = await resp.json();
        const dfOutput = data.output || data.error || 'No output';

        // Parse df -h output into a table
        const lines = dfOutput.trim().split('\n');
        let tableHtml = '';
        if (lines.length > 1) {
            tableHtml = `<table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Filesystem</th><th>Size</th><th>Used</th><th>Available</th><th>Use%</th><th>Mounted On</th></tr></thead><tbody>`;
            for (let i = 1; i < lines.length; i++) {
                const parts = lines[i].split(/\s+/);
                if (parts.length >= 6) {
                    const usePct = parseInt(parts[4]) || 0;
                    const barColor = usePct > 90 ? '#ef4444' : usePct > 70 ? '#eab308' : '#10b981';
                    tableHtml += `<tr>
                        <td><code style="font-size:11px;">${escapeHtml(parts[0])}</code></td>
                        <td>${escapeHtml(parts[1])}</td>
                        <td>${escapeHtml(parts[2])}</td>
                        <td>${escapeHtml(parts[3])}</td>
                        <td>
                            <div style="display:flex; align-items:center; gap:6px;">
                                <div style="flex:1; height:6px; background:var(--bg-secondary); border-radius:3px; min-width:50px;">
                                    <div style="width:${usePct}%; height:100%; background:${barColor}; border-radius:3px;"></div>
                                </div>
                                <span style="font-size:11px; min-width:30px;">${escapeHtml(parts[4])}</span>
                            </div>
                        </td>
                        <td><code style="font-size:11px;">${escapeHtml(parts.slice(5).join(' '))}</code></td>
                    </tr>`;
                }
            }
            tableHtml += `</tbody></table>`;
        } else {
            tableHtml = `<pre style="background:var(--bg-secondary); padding:12px; border-radius:8px; font-size:11px; margin:0; white-space:pre-wrap;">${escapeHtml(dfOutput)}</pre>`;
        }

        container.innerHTML = `
            <div class="card"><div class="card-body" style="padding:20px;">
                <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;">
                    <h4 style="margin:0; font-size:14px; font-weight:600;">Disk Space</h4>
                    <button class="btn btn-sm btn-secondary" onclick="loadK8sPodDiskSpace('${escapeHtml(podName)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Refresh</button>
                </div>
                ${tableHtml}
            </div></div>`;
    } catch (e) {
        container.innerHTML = `<div class="card"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Disk Space</h4>
            <div style="padding:16px; background:var(--bg-secondary); border-radius:8px; color:var(--text-muted); font-size:13px;">
                Could not retrieve disk usage: ${escapeHtml(e.message)}<br>
                <span style="font-size:12px;">The <code>df</code> command may not be available in this container image.</span>
            </div>
        </div></div>`;
    }
}

async function loadK8sPodResources(podName, namespace, pod) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;
    container.innerHTML = renderBlockSkeleton({lines:3});

    // Fetch kubectl top and memory info in parallel
    let topData = { cpu: 'N/A', memory: 'N/A' };
    let memInfo = '';
    try {
        const [topResp, memResp] = await Promise.all([
            fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/top?namespace=${encodeURIComponent(namespace)}`),
            fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/exec`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ namespace, command: ['cat', '/proc/meminfo'] }),
            }),
        ]);
        if (topResp.ok) topData = await topResp.json();
        if (memResp.ok) {
            const memData = await memResp.json();
            memInfo = memData.output || '';
        }
    } catch (e) { /* ignore partial failures */ }

    // Parse meminfo
    let memTotal = '', memFree = '', memAvail = '', memUsed = '';
    if (memInfo) {
        const getVal = key => { const m = memInfo.match(new RegExp(key + ':\\s+([\\d]+)')); return m ? m[1] : ''; };
        const totalKb = parseInt(getVal('MemTotal')) || 0;
        const freeKb = parseInt(getVal('MemFree')) || 0;
        const availKb = parseInt(getVal('MemAvailable')) || 0;
        const usedKb = totalKb - availKb;
        const fmt = kb => kb >= 1048576 ? (kb / 1048576).toFixed(1) + ' GB' : kb >= 1024 ? (kb / 1024).toFixed(0) + ' MB' : kb + ' KB';
        memTotal = fmt(totalKb);
        memFree = fmt(freeKb);
        memAvail = fmt(availKb);
        memUsed = fmt(usedKb);
    }

    // Resource spec from pod detail
    const specs = (pod.containers || []).map(c => {
        const req = c.resources?.requests || {};
        const lim = c.resources?.limits || {};
        return { name: c.name, reqCpu: req.cpu || '-', reqMem: req.memory || '-', limCpu: lim.cpu || '-', limMem: lim.memory || '-' };
    });

    let html = `<div class="card" style="margin-bottom:16px;"><div class="card-body" style="padding:20px;">
        <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:16px;">
            <h4 style="margin:0; font-size:14px; font-weight:600;">Current Resource Usage</h4>
            <button class="btn btn-sm btn-secondary" onclick="loadK8sPodResources('${escapeHtml(podName)}', '${escapeHtml(namespace)}', window._k8sPodDetail)" style="font-size:11px;">Refresh</button>
        </div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:16px; margin-bottom:16px;">
            <div style="padding:16px; background:var(--bg-secondary); border-radius:8px; text-align:center;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">CPU Usage</div>
                <div style="font-size:24px; font-weight:700; color:#326ce5;">${escapeHtml(topData.cpu || 'N/A')}</div>
            </div>
            <div style="padding:16px; background:var(--bg-secondary); border-radius:8px; text-align:center;">
                <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Memory Usage</div>
                <div style="font-size:24px; font-weight:700; color:#3b82f6;">${escapeHtml(topData.memory || 'N/A')}</div>
            </div>
        </div>`;

    if (topData.error) {
        html += `<div style="padding:10px 14px; background:rgba(234,179,8,0.08); border-radius:6px; border-left:3px solid #eab308; font-size:12px; color:var(--text-secondary); margin-bottom:16px;">
            <strong>Note:</strong> ${escapeHtml(topData.error)}
        </div>`;
    }

    if (memInfo) {
        html += `<div style="margin-bottom:16px;">
            <div style="font-size:11px; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Memory Details (from /proc/meminfo)</div>
            <div style="display:grid; grid-template-columns:repeat(4, 1fr); gap:8px;">
                <div style="padding:10px; background:var(--bg-secondary); border-radius:6px; text-align:center; font-size:12px;"><div style="color:var(--text-muted); font-size:10px;">Total</div><strong>${escapeHtml(memTotal)}</strong></div>
                <div style="padding:10px; background:var(--bg-secondary); border-radius:6px; text-align:center; font-size:12px;"><div style="color:var(--text-muted); font-size:10px;">Used</div><strong>${escapeHtml(memUsed)}</strong></div>
                <div style="padding:10px; background:var(--bg-secondary); border-radius:6px; text-align:center; font-size:12px;"><div style="color:var(--text-muted); font-size:10px;">Available</div><strong>${escapeHtml(memAvail)}</strong></div>
                <div style="padding:10px; background:var(--bg-secondary); border-radius:6px; text-align:center; font-size:12px;"><div style="color:var(--text-muted); font-size:10px;">Free</div><strong>${escapeHtml(memFree)}</strong></div>
            </div>
        </div>`;
    }
    html += `</div></div>`;

    // Resource spec table
    if (specs.length > 0) {
        html += `<div class="card"><div class="card-body" style="padding:20px;">
            <h4 style="margin:0 0 12px 0; font-size:14px; font-weight:600;">Resource Requests &amp; Limits</h4>
            <table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Container</th><th>CPU Request</th><th>CPU Limit</th><th>Memory Request</th><th>Memory Limit</th></tr></thead><tbody>`;
        specs.forEach(s => {
            html += `<tr><td><strong>${escapeHtml(s.name)}</strong></td><td><code>${escapeHtml(s.reqCpu)}</code></td><td><code>${escapeHtml(s.limCpu)}</code></td><td><code>${escapeHtml(s.reqMem)}</code></td><td><code>${escapeHtml(s.limMem)}</code></td></tr>`;
        });
        html += `</tbody></table></div></div>`;
    }

    container.innerHTML = html;
}

async function loadK8sPodEvents(podName, namespace) {
    const container = document.getElementById('k8s-pod-tab-content');
    if (!container) return;
    container.innerHTML = renderBlockSkeleton({lines:3});
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/pods/${encodeURIComponent(podName)}/events?namespace=${encodeURIComponent(namespace)}`);
        if (!resp.ok) throw new Error('Failed to load events');
        const data = await resp.json();
        const events = data.events || [];

        let html = `<div class="card"><div class="card-body" style="padding:20px;">
            <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:12px;">
                <h4 style="margin:0; font-size:14px; font-weight:600;">Pod Events</h4>
                <button class="btn btn-sm btn-secondary" onclick="loadK8sPodEvents('${escapeHtml(podName)}', '${escapeHtml(namespace)}')" style="font-size:11px;">Refresh</button>
            </div>`;

        if (events.length === 0) {
            html += `<div style="padding:16px; text-align:center; color:var(--text-muted); font-size:13px; background:var(--bg-secondary); border-radius:8px;">No events found for this pod.</div>`;
        } else {
            html += `<table class="data-table" style="width:100%; font-size:12px;"><thead><tr><th>Type</th><th>Reason</th><th>Message</th><th>Count</th><th>Last Seen</th></tr></thead><tbody>`;
            events.forEach(ev => {
                const typeColor = ev.type === 'Normal' ? '#10b981' : '#eab308';
                html += `<tr>
                    <td><span style="color:${typeColor}; font-weight:600;">${escapeHtml(ev.type || '')}</span></td>
                    <td><strong>${escapeHtml(ev.reason || '')}</strong></td>
                    <td style="font-size:11px; max-width:400px; word-break:break-word;">${escapeHtml(ev.message || '')}</td>
                    <td>${ev.count || 1}</td>
                    <td style="font-size:11px;">${escapeHtml(ev.lastTimestamp || ev.eventTime || '')}</td>
                </tr>`;
            });
            html += `</tbody></table>`;
        }
        html += `</div></div>`;
        container.innerHTML = html;
    } catch (e) {
        container.innerHTML = `<div style="padding:20px; text-align:center; color:#ef4444;">Failed to load events: ${e.message}</div>`;
    }
}

function showK8sApplyYamlModal() {
    const overlay = document.createElement('div');
    overlay.className = 'modal-overlay active';
    overlay.onclick = e => { if (e.target === overlay) closeModal(); };
    overlay.innerHTML = `
        <div class="modal" style="max-width:640px;">
            <div class="modal-header">
                <h3>Apply YAML Manifest</h3>
                <button class="modal-close" onclick="closeModal()">&times;</button>
            </div>
            <div class="modal-body">
                <p style="color:var(--text-muted); font-size:12px; margin:0 0 16px 0;">Apply a Kubernetes YAML manifest to this cluster.</p>
                <div class="form-group" style="margin-bottom:16px;">
                    <label style="font-weight:600; font-size:13px; margin-bottom:6px; display:block;">Namespace <span style="font-weight:400; color:var(--text-muted);">(optional)</span></label>
                    <input type="text" id="k8s-apply-ns" class="form-control" placeholder="default" value="${escapeHtml(k8sCurrentNamespace || '')}" style="font-size:14px; padding:10px 12px;">
                </div>
                <div class="form-group">
                    <label style="font-weight:600; font-size:13px; margin-bottom:6px; display:block;">YAML</label>
                    <textarea id="k8s-apply-yaml" class="form-control" rows="15" style="font-family:monospace; font-size:12px; padding:12px;" placeholder="apiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: my-app\n..."></textarea>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="closeModal()">Cancel</button>
                <button class="btn btn-primary" onclick="k8sApplyYaml()" style="background:#326ce5; border-color:#326ce5;">Apply</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
}

async function k8sApplyYaml() {
    const yaml = document.getElementById('k8s-apply-yaml').value.trim();
    const namespace = document.getElementById('k8s-apply-ns').value.trim() || null;
    if (!yaml) return;
    closeModal();
    try {
        const resp = await fetch(`/api/kubernetes/clusters/${k8sCurrentCluster}/apply`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ yaml, namespace }),
        });
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok) throw new Error(data.error || 'Failed');
        showToast(data.message || 'Applied successfully', 'success');
        setTimeout(() => switchK8sTab(k8sCurrentView), 1000);
    } catch (e) { showToast('Failed: ' + e.message, 'error'); }
}

// ─── YAML Editor ───

async function openK8sYamlEditor(kind, name, namespace) {
    // Fetch current YAML from the cluster
    const url = `/api/kubernetes/clusters/${encodeURIComponent(k8sCurrentCluster)}/resource-yaml?kind=${encodeURIComponent(kind)}&name=${encodeURIComponent(name)}&namespace=${encodeURIComponent(namespace)}`;
    showToast('Loading YAML...', 'info', 2000);

    try {
        const resp = await fetch(url);
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok) throw new Error(data.error || 'Failed to fetch YAML');

        const yaml = data.yaml || '';

        // Use the system modal pattern
        closeModal();
        const overlay = document.getElementById('k8s-yaml-modal') || document.createElement('div');
        overlay.id = 'k8s-yaml-modal';
        overlay.className = 'modal-overlay';
        overlay.innerHTML = `
            <div class="modal" style="max-width:900px; width:95%; max-height:90vh; display:flex; flex-direction:column;">
                <div class="modal-header" style="flex-shrink:0;">
                    <h3>Edit ${kind.charAt(0).toUpperCase() + kind.slice(1)}: ${name}</h3>
                    <button class="modal-close" onclick="closeModal()">&times;</button>
                </div>
                <div class="modal-body" style="flex:1; overflow:hidden; padding:0;">
                    <textarea id="k8s-yaml-editor" style="width:100%; height:100%; min-height:400px; font-family:'JetBrains Mono',Consolas,monospace; font-size:12px; line-height:1.5; padding:12px; border:none; background:var(--bg-input); color:var(--text-primary); resize:none; outline:none; tab-size:2;">${escapeHtml(yaml)}</textarea>
                </div>
                <div class="modal-footer" style="flex-shrink:0; display:flex; justify-content:space-between; align-items:center;">
                    <span style="font-size:11px; color:var(--text-muted);">${kind}/${name} in ${namespace}</span>
                    <div style="display:flex; gap:8px;">
                        <button class="btn btn-secondary" onclick="closeModal()">Cancel</button>
                        <button class="btn btn-primary" id="k8s-yaml-apply-btn" onclick="applyK8sYamlEdit()" style="background:var(--accent); border-color:var(--accent);">Apply Changes</button>
                    </div>
                </div>
            </div>`;
        if (!overlay.parentNode) document.body.appendChild(overlay);
        requestAnimationFrame(() => overlay.classList.add('active'));

        // Allow Tab key in textarea
        const editor = document.getElementById('k8s-yaml-editor');
        if (editor) {
            editor.addEventListener('keydown', (e) => {
                if (e.key === 'Tab') {
                    e.preventDefault();
                    const start = editor.selectionStart;
                    const end = editor.selectionEnd;
                    editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
                    editor.selectionStart = editor.selectionEnd = start + 2;
                }
            });
        }
    } catch (e) {
        showToast('Failed to load YAML: ' + e.message, 'error');
    }
}

async function applyK8sYamlEdit() {
    const yaml = document.getElementById('k8s-yaml-editor')?.value?.trim();
    if (!yaml) return;
    const btn = document.getElementById('k8s-yaml-apply-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Applying...'; }

    try {
        const resp = await fetch(`/api/kubernetes/clusters/${encodeURIComponent(k8sCurrentCluster)}/apply`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ yaml }),
        });
        const data = await resp.json().catch(() => ({}));
        if (!resp.ok) throw new Error(data.error || 'Apply failed');

        showToast(data.message || 'Applied successfully', 'success');
        taskLog('K8s YAML applied');
        closeModal();
        setTimeout(() => switchK8sTab(k8sCurrentView), 1000);
    } catch (e) {
        showToast('Apply failed: ' + e.message, 'error');
        taskLog('K8s YAML apply failed', 'failed');
        if (btn) { btn.disabled = false; btn.textContent = 'Apply Changes'; }
    }
}

