async function dbMgrRenderServerTab(body) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    body.innerHTML = `
        <div style="display:grid; gap:14px;">
            <div id="db-srv-version">Loading version…</div>
            <div id="db-srv-vars">Loading variables…</div>
            <div id="db-srv-procs">Loading processes…</div>
        </div>
    `;
    dbSrvLoadVersion();
    dbSrvLoadVars();
    dbSrvLoadProcs();
}

async function dbSrvLoadVersion() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-srv-version');
    if (!el) return;
    try {
        const v = conn.kind === 'postgres'
            ? await dbMgrRunSql('SELECT version() AS version, current_database() AS db, current_user AS "user", inet_server_addr()::text AS host, inet_server_port() AS port')
            : await dbMgrRunSql("SELECT VERSION() AS version, DATABASE() AS db, USER() AS user, @@hostname AS host, @@port AS port");
        el.innerHTML = '<h4 style="margin:0 0 6px; font-size:13px; display:flex; gap:8px; align-items:center;"><span>Server</span> <button class="btn btn-sm" onclick="dbSrvLoadVersion()" style="padding:2px 8px; font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="refresh"></span></button></h4>' + renderKvTable(v);
    } catch (e) { el.innerHTML = `<div style="color:var(--danger);">Version: ${escapeHtml(e.message)}</div>`; }
}

async function dbSrvLoadVars() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-srv-vars');
    if (!el) return;
    try {
        const vars = conn.kind === 'postgres'
            ? await dbMgrRunSql("SELECT name, setting, unit, context FROM pg_settings WHERE name IN ('max_connections','shared_buffers','work_mem','effective_cache_size','max_wal_size','checkpoint_timeout','autovacuum','listen_addresses','server_version','server_encoding','timezone','log_statement','log_duration','statement_timeout','idle_in_transaction_session_timeout','tcp_keepalives_idle','ssl') ORDER BY name")
            : await dbMgrRunSql("SHOW VARIABLES WHERE Variable_name IN ('version','version_comment','max_connections','innodb_buffer_pool_size','character_set_server','collation_server','sql_mode','time_zone','datadir','socket','tmpdir','wait_timeout','max_allowed_packet','long_query_time','slow_query_log','general_log','connect_timeout','net_read_timeout','net_write_timeout','innodb_flush_log_at_trx_commit','sync_binlog')");
        // Custom row renderer so we can add an Edit button per variable.
        let html = `<h4 style="margin:0 0 6px; font-size:13px; display:flex; gap:8px; align-items:center;">
            <span>Key variables</span>
            <button class="btn btn-sm" onclick="dbSrvLoadVars()" style="padding:2px 8px; font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="refresh"></span></button>
            <span style="font-size:11px; color:var(--text-muted);">Click to change — requires Schema permission</span>
        </h4>`;
        html += '<div style="overflow:auto; border:1px solid var(--border); border-radius:6px;"><table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--bg-tertiary);">';
        for (const c of vars.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border); white-space:nowrap;">${escapeHtml(c)}</th>`;
        html += '<th style="padding:6px 8px; border-bottom:1px solid var(--border);"></th></tr></thead><tbody>';
        for (const row of vars.rows) {
            const name = String(row[0]);
            const value = row[1] == null ? '' : String(row[1]);
            // Postgres: skip rows whose context is 'internal' (read-only).
            const readOnly = conn.kind === 'postgres' && row[3] === 'internal';
            html += '<tr>';
            for (const v of row) html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border);">${v == null ? '<span style="color:var(--text-muted);">NULL</span>' : escapeHtml(String(v))}</td>`;
            html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); text-align:right;">
                ${readOnly ? '<span style="color:var(--text-muted); font-size:10px;">read-only</span>' : `<button class="btn btn-sm" onclick="dbSrvEditVar('${escapeHtml(name).replace(/'/g, "\\'")}', '${escapeHtml(value).replace(/'/g, "\\'")}')" title="Change this variable" style="padding:1px 8px; font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="edit"></span></button>`}
            </td></tr>`;
        }
        html += '</tbody></table></div>';
        el.innerHTML = html;
    } catch (e) { el.innerHTML = `<div style="color:var(--danger);">Variables: ${escapeHtml(e.message)}</div>`; }
}

async function dbSrvLoadProcs() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-srv-procs');
    if (!el) return;
    try {
        const procs = conn.kind === 'postgres'
            ? await dbMgrRunSql("SELECT pid, datname, usename, application_name, client_addr, state, query_start, LEFT(query, 80) AS query FROM pg_stat_activity ORDER BY query_start DESC NULLS LAST LIMIT 50")
            : await dbMgrRunSql("SHOW FULL PROCESSLIST");
        let html = `<h4 style="margin:0 0 6px; font-size:13px; display:flex; gap:8px; align-items:center;">
            <span>Active sessions (${procs.row_count})</span>
            <button class="btn btn-sm" onclick="dbSrvLoadProcs()" style="padding:2px 8px; font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="refresh"></span></button>
            <span style="font-size:11px; color:var(--text-muted);">Click to kill a session — requires Schema permission</span>
        </h4>`;
        html += '<div style="overflow:auto; border:1px solid var(--border); border-radius:6px;"><table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--bg-tertiary);">';
        for (const c of procs.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border); white-space:nowrap;">${escapeHtml(c)}</th>`;
        html += '<th style="padding:6px 8px; border-bottom:1px solid var(--border);"></th></tr></thead><tbody>';
        for (const row of procs.rows) {
            // PID/Id is the first column on both engines.
            const pid = row[0];
            html += '<tr>';
            for (const v of row) html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); max-width:360px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${v == null ? '' : escapeHtml(String(v))}">${v == null ? '<span style="color:var(--text-muted);">NULL</span>' : escapeHtml(String(v))}</td>`;
            html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); text-align:right;">
                <button class="btn btn-sm" onclick="dbSrvKillSession('${escapeHtml(String(pid))}')" title="Kill session ${pid}" style="padding:1px 8px; font-size:10px;"><span class="ws-icon-clean-wrap" data-icon="stop"></span></button>
            </td></tr>`;
        }
        html += '</tbody></table></div>';
        el.innerHTML = html;
    } catch (e) { el.innerHTML = `<div style="color:var(--danger);">Processes: ${escapeHtml(e.message)}</div>`; }
}

async function dbSrvEditVar(name, currentValue) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    // Proper modal for the input.
    const modal = document.createElement('div');
    modal.style.cssText = 'position:fixed; inset:0; background:rgba(0,0,0,0.6); z-index:10000; display:flex; align-items:center; justify-content:center;';
    const scopeOptions = conn.kind === 'postgres'
        ? `<option value="session" selected>Session only</option><option value="system">Cluster-wide (ALTER SYSTEM + reload)</option>`
        : `<option value="session" selected>Session only (SET SESSION)</option><option value="global">Cluster-wide (SET GLOBAL)</option>`;
    modal.innerHTML = `
        <div style="background:var(--bg-card); border:1px solid var(--border); border-radius:10px; padding:18px; width:520px; max-width:95vw;">
            <h3 style="margin:0 0 10px;">Change ${escapeHtml(name)}</h3>
            <label style="display:block; font-size:13px;">New value
                <input id="db-var-val" class="form-control" value="${escapeHtml(currentValue)}" autocomplete="off">
            </label>
            <label style="display:block; font-size:13px; margin-top:10px;">Scope
                <select id="db-var-scope" class="form-control">${scopeOptions}</select>
            </label>
            <div style="font-size:11px; color:var(--text-muted); margin-top:8px;">${conn.kind === 'postgres' ? 'ALTER SYSTEM persists across restarts and runs pg_reload_conf(). Session variant only affects this connection.' : 'GLOBAL persists for new connections (not existing ones). SESSION only affects this connection. Neither survives restart unless also set in my.cnf.'}</div>
            <div style="display:flex; gap:8px; justify-content:flex-end; margin-top:14px;">
                <button class="btn btn-sm" id="db-var-cancel">Cancel</button>
                <button class="btn btn-primary btn-sm" id="db-var-submit">Apply</button>
            </div>
        </div>
    `;
    dbModalHost().appendChild(modal);
    const close = () => modal.remove();
    modal.querySelector('#db-var-cancel').addEventListener('click', close);
    const submit = async () => {
        const newVal = modal.querySelector('#db-var-val').value;
        const scope = modal.querySelector('#db-var-scope').value;
        let sql;
        if (conn.kind === 'postgres') {
            // Quote non-numeric values. Be conservative — we wrap anything
            // that isn't a plain number in single quotes.
            const v = /^-?\d+(\.\d+)?$/.test(newVal) ? newVal : `'${newVal.replace(/'/g, "''")}'`;
            sql = scope === 'system' ? `ALTER SYSTEM SET ${name} = ${v}` : `SET ${name} = ${v}`;
        } else {
            const v = /^-?\d+(\.\d+)?$/.test(newVal) ? newVal : `'${newVal.replace(/'/g, "''")}'`;
            sql = scope === 'global' ? `SET GLOBAL ${name} = ${v}` : `SET SESSION ${name} = ${v}`;
        }
        const ok = await wolfConfirm(`Run this?\n\n${sql}${conn.kind === 'postgres' && scope === 'system' ? '\nSELECT pg_reload_conf();' : ''}`, 'Change variable', { okText: 'Apply', danger: true });
        if (!ok) return;
        try {
            // Use query-multi so we can pg_reload_conf in the same request.
            const statements = [sql];
            if (conn.kind === 'postgres' && scope === 'system') statements.push('SELECT pg_reload_conf()');
            const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/query-multi`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ statements, permission: 'schema', timeout_secs: 30, stop_on_error: true }),
            });
            const data = await resp.json();
            if (!resp.ok || (data.results || []).some(r => r.ok === false)) {
                const firstErr = (data.results || []).find(r => r.ok === false);
                showToast(firstErr ? firstErr.error : (data.error || 'Failed'), 'error');
                return;
            }
            close();
            showToast(`Applied ${name} = ${newVal}`, 'success');
            dbSrvLoadVars();
        } catch (e) { showToast('Apply failed: ' + e.message, 'error'); }
    };
    modal.querySelector('#db-var-submit').addEventListener('click', submit);
    modal.querySelector('#db-var-val').addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); submit(); } });
    setTimeout(() => modal.querySelector('#db-var-val').focus(), 0);
}

async function dbSrvKillSession(pid) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const sql = conn.kind === 'postgres'
        ? `SELECT pg_terminate_backend(${parseInt(pid, 10)})`
        : `KILL ${parseInt(pid, 10)}`;
    const ok = await wolfConfirm(`Kill session ${pid}?\n\n${sql}`, 'Kill session', { okText: 'Kill', danger: true });
    if (!ok) return;
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/query`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query: sql, permission: 'schema', timeout_secs: 10 }),
        });
        const data = await resp.json();
        if (!resp.ok) { showToast(data.error || 'Kill failed', 'error'); return; }
        showToast(`Session ${pid} killed`, 'success');
        dbSrvLoadProcs();
    } catch (e) { showToast('Kill failed: ' + e.message, 'error'); }
}

function renderResultTable(r) {
    if (!r || !r.columns || !r.rows.length) return '<div style="color:var(--text-muted); font-size:12px;">(no rows)</div>';
    let html = '<div style="overflow:auto; border:1px solid var(--border); border-radius:6px;"><table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--bg-tertiary);">';
    for (const c of r.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border); white-space:nowrap;">${escapeHtml(c)}</th>`;
    html += '</tr></thead><tbody>';
    for (const row of r.rows) {
        html += '<tr>';
        for (const v of row) html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); max-width:360px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${v == null ? '' : escapeHtml(String(v))}">${v == null ? '<span style="color:var(--text-muted);">NULL</span>' : escapeHtml(String(v))}</td>`;
        html += '</tr>';
    }
    return html + '</tbody></table></div>';
}

function renderKvTable(r) {
    if (!r || !r.rows.length) return '<div style="color:var(--text-muted);">no data</div>';
    const row = r.rows[0];
    let html = '<div style="display:grid; grid-template-columns:auto 1fr; gap:4px 12px; font-size:12px;">';
    for (let i = 0; i < r.columns.length; i++) {
        html += `<div style="color:var(--text-muted);">${escapeHtml(r.columns[i])}</div><div style="font-family:monospace; overflow:hidden; text-overflow:ellipsis;">${row[i] == null ? '—' : escapeHtml(String(row[i]))}</div>`;
    }
    return html + '</div>';
}

async function dbMgrRenderStructureTab(body) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    body.innerHTML = `
        <div style="display:flex; gap:6px; flex-wrap:wrap; margin-bottom:10px;">
            <button class="btn btn-sm" onclick="dbStructAddColumn()">Add column</button>
            <button class="btn btn-sm" onclick="dbStructAddIndex()">Add index</button>
            <button class="btn btn-sm" onclick="dbStructAddFk()">Add foreign key</button>
            <div style="flex:1;"></div>
            <span style="font-size:11px; color:var(--text-muted); align-self:center;">Structural changes require <strong>Schema</strong> permission — the operator who submits them is audit-logged.</span>
        </div>
        <div style="display:grid; grid-template-columns:1fr; gap:14px;">
            <div id="db-struct-columns"><div style="color:var(--text-muted);">Loading columns…</div></div>
            <div id="db-struct-indexes"><div style="color:var(--text-muted);">Loading indexes…</div></div>
            <div id="db-struct-fks"><div style="color:var(--text-muted);">Loading foreign keys…</div></div>
        </div>
    `;
    dbStructLoadColumns();
    dbStructLoadIndexes();
    dbStructLoadFks();
}

async function dbStructLoadColumns() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-struct-columns');
    if (!el) return;
    try {
        let data;
        if (conn.kind === 'postgres') {
            data = await dbMgrRunSql(
                `SELECT column_name, data_type, is_nullable, column_default
                 FROM information_schema.columns
                 WHERE table_schema = '${_dbMgrCurrentDb.replace(/'/g, "''")}'
                   AND table_name = '${_dbMgrCurrentTable.replace(/'/g, "''")}'
                 ORDER BY ordinal_position`
            );
        } else {
            const fq = `${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentDb)}.${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentTable)}`;
            data = await dbMgrRunSql(`DESCRIBE ${fq}`);
        }
        document.getElementById('db-mgr-info').textContent = `${data.row_count} columns`;
        // Render with a "Drop" button per row.
        let html = '<h4 style="margin:0 0 6px; font-size:13px;">Columns</h4><table style="width:100%; font-size:12px; border-collapse:collapse;">';
        html += '<thead><tr style="background:var(--bg-tertiary);">';
        for (const c of data.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border);">${escapeHtml(c)}</th>`;
        html += '<th style="padding:6px 8px; border-bottom:1px solid var(--border);"></th></tr></thead><tbody>';
        for (const row of data.rows) {
            const colName = String(row[0]);
            html += '<tr>';
            for (const v of row) {
                html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border);">${escapeHtml(v == null ? '' : String(v))}</td>`;
            }
            html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); text-align:right;">
                <button class="btn btn-sm" onclick="dbStructDropColumn('${escapeHtml(colName).replace(/'/g, "\\'")}')" style="padding:2px 8px; font-size:11px;">Drop</button>
            </td>`;
            html += '</tr>';
        }
        html += '</tbody></table>';
        el.innerHTML = html;
    } catch (e) {
        el.innerHTML = `<div style="color:var(--danger); padding:6px; font-size:12px;">${escapeHtml(e.message)}</div>`;
    }
}

async function dbStructLoadIndexes() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-struct-indexes');
    if (!el) return;
    try {
        let data;
        if (conn.kind === 'postgres') {
            data = await dbMgrRunSql(
                `SELECT indexname, indexdef FROM pg_indexes
                 WHERE schemaname = '${_dbMgrCurrentDb.replace(/'/g, "''")}'
                   AND tablename = '${_dbMgrCurrentTable.replace(/'/g, "''")}'
                 ORDER BY indexname`
            );
        } else {
            const fq = `${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentDb)}.${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentTable)}`;
            data = await dbMgrRunSql(`SHOW INDEX FROM ${fq}`);
        }
        let html = '<h4 style="margin:0 0 6px; font-size:13px;">Indexes</h4>';
        if (!data.rows.length) {
            html += '<div style="color:var(--text-muted); font-size:12px;">(no indexes)</div>';
        } else {
            html += '<table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--bg-tertiary);">';
            for (const c of data.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border);">${escapeHtml(c)}</th>`;
            html += '<th style="padding:6px 8px; border-bottom:1px solid var(--border);"></th></tr></thead><tbody>';
            // Dedupe by index name (MySQL SHOW INDEX returns one row per column).
            const seen = new Set();
            for (const row of data.rows) {
                const idxName = conn.kind === 'postgres' ? String(row[0]) : String(row[2]);
                const dropKey = idxName + '||' + (conn.kind === 'postgres' ? '' : String(row[0]));
                if (conn.kind !== 'postgres' && seen.has(idxName)) continue;
                seen.add(idxName);
                html += '<tr>';
                for (const v of row) {
                    html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border);">${escapeHtml(v == null ? '' : String(v))}</td>`;
                }
                html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); text-align:right;">
                    <button class="btn btn-sm" onclick="dbStructDropIndex('${escapeHtml(idxName).replace(/'/g, "\\'")}')" style="padding:2px 8px; font-size:11px;">Drop</button>
                </td>`;
                html += '</tr>';
            }
            html += '</tbody></table>';
        }
        el.innerHTML = html;
    } catch (e) {
        el.innerHTML = `<div style="color:var(--danger); padding:6px; font-size:12px;">Indexes: ${escapeHtml(e.message)}</div>`;
    }
}

async function dbStructLoadFks() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const el = document.getElementById('db-struct-fks');
    if (!el) return;
    try {
        let data;
        if (conn.kind === 'postgres') {
            data = await dbMgrRunSql(
                `SELECT tc.constraint_name, kcu.column_name,
                        ccu.table_schema || '.' || ccu.table_name AS references_table,
                        ccu.column_name AS references_column,
                        rc.update_rule, rc.delete_rule
                 FROM information_schema.table_constraints tc
                 JOIN information_schema.key_column_usage kcu
                     ON kcu.constraint_name = tc.constraint_name
                     AND kcu.table_schema = tc.table_schema
                 JOIN information_schema.referential_constraints rc
                     ON rc.constraint_name = tc.constraint_name
                 JOIN information_schema.constraint_column_usage ccu
                     ON ccu.constraint_name = tc.constraint_name
                 WHERE tc.constraint_type = 'FOREIGN KEY'
                   AND tc.table_schema = '${_dbMgrCurrentDb.replace(/'/g, "''")}'
                   AND tc.table_name = '${_dbMgrCurrentTable.replace(/'/g, "''")}'`
            );
        } else {
            data = await dbMgrRunSql(
                `SELECT constraint_name, column_name,
                        CONCAT(referenced_table_schema, '.', referenced_table_name) AS references_table,
                        referenced_column_name AS references_column
                 FROM information_schema.key_column_usage
                 WHERE table_schema = '${_dbMgrCurrentDb.replace(/'/g, "''")}'
                   AND table_name = '${_dbMgrCurrentTable.replace(/'/g, "''")}'
                   AND referenced_table_name IS NOT NULL`
            );
        }
        let html = '<h4 style="margin:0 0 6px; font-size:13px;">Foreign keys</h4>';
        if (!data.rows.length) {
            html += '<div style="color:var(--text-muted); font-size:12px;">(no foreign keys)</div>';
        } else {
            html += '<table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--bg-tertiary);">';
            for (const c of data.columns) html += `<th style="padding:6px 8px; text-align:left; border-bottom:1px solid var(--border);">${escapeHtml(c)}</th>`;
            html += '<th style="padding:6px 8px; border-bottom:1px solid var(--border);"></th></tr></thead><tbody>';
            for (const row of data.rows) {
                const fkName = String(row[0]);
                html += '<tr>';
                for (const v of row) {
                    html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border);">${escapeHtml(v == null ? '' : String(v))}</td>`;
                }
                html += `<td style="padding:5px 8px; border-bottom:1px solid var(--border); text-align:right;">
                    <button class="btn btn-sm" onclick="dbStructDropFk('${escapeHtml(fkName).replace(/'/g, "\\'")}')" style="padding:2px 8px; font-size:11px;">Drop</button>
                </td>`;
                html += '</tr>';
            }
            html += '</tbody></table>';
        }
        el.innerHTML = html;
    } catch (e) {
        el.innerHTML = `<div style="color:var(--danger); padding:6px; font-size:12px;">Foreign keys: ${escapeHtml(e.message)}</div>`;
    }
}

// ─── Schema-change helpers: build the ALTER SQL, confirm, execute, reload ───
async function dbStructExec(sql, opLabel) {
    const ok = await wolfConfirm(
        `Run this schema change?\n\n${sql}`,
        opLabel, { okText: 'Run', danger: true }
    );
    if (!ok) return false;
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/query`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query: sql, permission: 'schema', timeout_secs: 60 }),
        });
        const data = await resp.json();
        if (!resp.ok) { showToast(data.error || 'Schema change failed', 'error'); return false; }
        showToast(`${opLabel} succeeded`, 'success');
        return true;
    } catch (e) { showToast('Schema change failed: ' + e.message, 'error'); return false; }
}

function dbStructTableRef(conn) {
    return `${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentDb)}.${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentTable)}`;
}

async function dbStructAddColumn() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const name = await showPrompt('New column name:', 'Add column', '');
    if (!name) return;
    const type = await showPrompt('Column type (e.g. VARCHAR(255), INT, TIMESTAMP):', 'Add column — type', '');
    if (!type) return;
    const nullable = await showConfirm('Allow NULL values in this column?\n\nConfirm = NULL allowed (default).\nCancel = NOT NULL (every row must have a value).', 'Column nullability');
    const defaultVal = (await showPrompt('Default value (leave blank for none):', 'Add column — default', '')) || '';
    let sql = `ALTER TABLE ${dbStructTableRef(conn)} ADD COLUMN ${dbMgrEscapeIdent(conn.kind, name)} ${type}`;
    if (!nullable) sql += ' NOT NULL';
    if (defaultVal.trim()) sql += ` DEFAULT ${defaultVal}`;
    if (await dbStructExec(sql, 'Add column')) { dbStructLoadColumns(); }
}

async function dbStructDropColumn(colName) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const sql = `ALTER TABLE ${dbStructTableRef(conn)} DROP COLUMN ${dbMgrEscapeIdent(conn.kind, colName)}`;
    if (await dbStructExec(sql, `Drop column ${colName}`)) { dbStructLoadColumns(); }
}

async function dbStructAddIndex() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const name = await showPrompt('Index name:', 'Add index', '');
    if (!name) return;
    const cols = await showPrompt('Column(s), comma-separated:', 'Add index — columns', '');
    if (!cols) return;
    const unique = await showConfirm('Make this a UNIQUE index?\n\nConfirm = UNIQUE (each value must occur only once).\nCancel = normal index (duplicates allowed).', 'Index type');
    const escCols = cols.split(',').map(c => dbMgrEscapeIdent(conn.kind, c.trim())).join(', ');
    let sql;
    if (conn.kind === 'postgres') {
        sql = `CREATE ${unique ? 'UNIQUE ' : ''}INDEX ${dbMgrEscapeIdent(conn.kind, name)} ON ${dbStructTableRef(conn)} (${escCols})`;
    } else {
        sql = `CREATE ${unique ? 'UNIQUE ' : ''}INDEX ${dbMgrEscapeIdent(conn.kind, name)} ON ${dbStructTableRef(conn)} (${escCols})`;
    }
    if (await dbStructExec(sql, 'Add index')) { dbStructLoadIndexes(); }
}

async function dbStructDropIndex(idxName) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    let sql;
    if (conn.kind === 'postgres') {
        // Postgres indexes live in the schema, not scoped to a table.
        sql = `DROP INDEX ${dbMgrEscapeIdent(conn.kind, _dbMgrCurrentDb)}.${dbMgrEscapeIdent(conn.kind, idxName)}`;
    } else {
        sql = `DROP INDEX ${dbMgrEscapeIdent(conn.kind, idxName)} ON ${dbStructTableRef(conn)}`;
    }
    if (await dbStructExec(sql, `Drop index ${idxName}`)) { dbStructLoadIndexes(); }
}

async function dbStructAddFk() {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    const name = await showPrompt('Constraint name:', 'Add foreign key', '');
    if (!name) return;
    const col = await showPrompt('Column in this table that references another:', 'Foreign key — local column', '');
    if (!col) return;
    const refTable = await showPrompt('References which table? (schema.table or just table)', 'Foreign key — referenced table', '');
    if (!refTable) return;
    const refCol = await showPrompt('References which column?', 'Foreign key — referenced column', '');
    if (!refCol) return;
    const onDelete = (await showPrompt('ON DELETE action: NO ACTION / RESTRICT / CASCADE / SET NULL (blank = NO ACTION)', 'Foreign key — on delete', '')) || 'NO ACTION';
    const refParts = refTable.split('.').map(p => dbMgrEscapeIdent(conn.kind, p.trim())).join('.');
    const sql = `ALTER TABLE ${dbStructTableRef(conn)} ADD CONSTRAINT ${dbMgrEscapeIdent(conn.kind, name)} `
              + `FOREIGN KEY (${dbMgrEscapeIdent(conn.kind, col)}) `
              + `REFERENCES ${refParts} (${dbMgrEscapeIdent(conn.kind, refCol)}) `
              + `ON DELETE ${onDelete}`;
    if (await dbStructExec(sql, 'Add foreign key')) { dbStructLoadFks(); }
}

async function dbStructDropFk(fkName) {
    const conn = _dbConnsCache.find(c => c.id === _dbCurrentId);
    if (!conn) return;
    let sql;
    if (conn.kind === 'postgres') {
        sql = `ALTER TABLE ${dbStructTableRef(conn)} DROP CONSTRAINT ${dbMgrEscapeIdent(conn.kind, fkName)}`;
    } else {
        sql = `ALTER TABLE ${dbStructTableRef(conn)} DROP FOREIGN KEY ${dbMgrEscapeIdent(conn.kind, fkName)}`;
    }
    if (await dbStructExec(sql, `Drop FK ${fkName}`)) { dbStructLoadFks(); }
}

// When the Databases page is in fullscreen mode the browser isolates
// that element and paints everything else underneath. Modals
// appended to document.body therefore render BEHIND the fullscreen
// page. Attach to the fullscreen element instead so the modal sits
// on top where the operator can see + click it.
function dbModalHost() {
    return document.fullscreenElement || document.body;
}

// The shared wolfConfirm / wolfPrompt dialog lives as a static
// element in index.html, OUTSIDE #page-databases. Fullscreen hides
// it. Slide it in/out of the fullscreen element as the operator
// toggles so Confirm modals (delete row, change variable, etc.)
// still appear during fullscreen sessions.
document.addEventListener('fullscreenchange', () => {
    const dlg = document.getElementById('wolf-dialog-modal');
    if (!dlg) return;
    const fs = document.fullscreenElement;
    if (fs && !fs.contains(dlg)) fs.appendChild(dlg);
    else if (!fs && dlg.parentElement !== document.body) document.body.appendChild(dlg);
});

function dbToggleFullscreen() {
    // Use the Fullscreen API on the whole Databases page — hides the
    // main sidebar/topnav and gives operators the full browser
    // viewport for the Manager. The browser handles the Esc exit.
    const page = document.getElementById('page-databases');
    if (!page) return;
    if (!document.fullscreenElement) {
        page.requestFullscreen?.().catch(e => showToast('Fullscreen not available: ' + e.message, 'error'));
    } else {
        document.exitFullscreen?.();
    }
}

function dbCloseConnection() {
    _dbCurrentId = null;
    _dbLastResult = null;
    _dbMgrSchemas = null;
    _dbMgrTablesCache = {};
    _dbMgrExpanded = new Set();
    _dbMgrCurrentDb = null;
    _dbMgrCurrentTable = null;
    const layout = document.getElementById('db-layout');
    const panel = document.getElementById('db-conn-panel');
    if (layout) layout.style.gridTemplateColumns = '280px 1fr';
    if (panel) panel.style.display = '';
    const ws = document.getElementById('db-workspace');
    if (ws) ws.innerHTML = `
        <div style="color:var(--text-muted); text-align:center; padding:60px 20px;">
            <div style="font-size:36px; margin-bottom:8px;"></div>
            <div style="font-size:14px;">Pick a connection on the left to start querying.</div>
            <div style="font-size:12px; margin-top:4px;">Queries are executed on the node that owns the connection — cross-node access is proxied automatically.</div>
        </div>
    `;
    dbRenderConnections();
}

// ─── Saved queries + query history (server-side, per authenticated user) ───
// Cached in-memory for the current session; refreshed after every
// save/delete. History is pushed server-side automatically inside
// the /query handler, so we just re-fetch after running.
let _dbSavedCache = [];    // [{name, sql, created_at}]
let _dbHistoryCache = [];  // [{sql, created_at}]

async function dbLoadSaved() {
    if (!_dbCurrentId) { _dbSavedCache = []; return _dbSavedCache; }
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/saved-queries`);
        const data = await resp.json();
        _dbSavedCache = resp.ok ? (data.saved || []) : [];
    } catch { _dbSavedCache = []; }
    return _dbSavedCache;
}

async function dbLoadHistory() {
    if (!_dbCurrentId) { _dbHistoryCache = []; return _dbHistoryCache; }
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/history`);
        const data = await resp.json();
        _dbHistoryCache = resp.ok ? (data.history || []) : [];
    } catch { _dbHistoryCache = []; }
    return _dbHistoryCache;
}

// ─── Multi-tab query editor (per-connection) ───
// Each tab carries: {id, title, sql, dirty}. Active tab's SQL is
// always mirrored into the #db-query textarea; switching tabs
// swaps the buffer. Tabs live in memory for the session; survive
// Data/Structure/Diagram navigation but not page reload.
let _dbQueryTabs = [];
let _dbQueryActive = 0;
let _dbEditorHeight = 260;  // persisted height of the SQL editor (px)
let _dbTreeCollapsed = false;

function dbToggleTree() {
    _dbTreeCollapsed = !_dbTreeCollapsed;
    const ws = document.getElementById('db-workspace');
    if (ws && _dbCurrentId) {
        // Re-render the whole workspace so the grid-template-columns
        // flips. Cheaper than hunting down every style to toggle.
        dbOpenConnection(_dbCurrentId);
    }
}

function dbQueryEnsureTabs() {
    if (!_dbQueryTabs.length) {
        // First tab inherits whichever schema the tree currently has
        // selected, matching the "new tab snapshots current" rule.
        _dbQueryTabs.push({ id: 'q1', title: 'Query 1', sql: '', dirty: false, caret: 0, schema: _dbMgrCurrentDb || '' });
        _dbQueryActive = 0;
    }
}

function dbQueryNewTab() {
    dbQuerySyncActiveTab();
    const n = _dbQueryTabs.length + 1;
    // Navicat-style: a NEW tab snapshots the schema the tree is on
    // right now, but existing tabs keep whichever schema they were
    // created in — so clicking around the tree doesn't rewrite the
    // context of open work.
    _dbQueryTabs.push({ id: `q${n}${Date.now()}`, title: `Query ${n}`, sql: '', dirty: false, caret: 0, schema: _dbMgrCurrentDb || '' });
    _dbQueryActive = _dbQueryTabs.length - 1;
    dbMgrRenderQueryTab(document.getElementById('db-mgr-body'));
}

function dbQuerySyncActiveTab() {
    // Capture SQL and caret into the active tab so a re-render
    // (tab switch, rename, add/close) doesn't drop the cursor.
    const ta = document.getElementById('db-query');
    if (!ta || !_dbQueryTabs[_dbQueryActive]) return;
    _dbQueryTabs[_dbQueryActive].sql = ta.value;
    _dbQueryTabs[_dbQueryActive].caret = ta.selectionStart;
    _dbQueryTabs[_dbQueryActive].caretEnd = ta.selectionEnd;
}

function dbQuerySwitchTab(idx) {
    dbQuerySyncActiveTab();
    _dbQueryActive = idx;
    dbMgrRenderQueryTab(document.getElementById('db-mgr-body'));
}

function dbQueryCloseTab(idx, ev) {
    if (ev) ev.stopPropagation();
    dbQuerySyncActiveTab();
    if (_dbQueryTabs.length === 1) {
        _dbQueryTabs[0].sql = '';
        _dbQueryTabs[0].title = 'Query 1';
        _dbQueryTabs[0].caret = 0;
        dbMgrRenderQueryTab(document.getElementById('db-mgr-body'));
        return;
    }
    _dbQueryTabs.splice(idx, 1);
    if (_dbQueryActive >= _dbQueryTabs.length) _dbQueryActive = _dbQueryTabs.length - 1;
    dbMgrRenderQueryTab(document.getElementById('db-mgr-body'));
}

async function dbQueryRenameTab(idx) {
    const cur = _dbQueryTabs[idx];
    const name = await showPrompt('Tab name:', 'Rename tab', cur.title);
    if (!name) return;
    cur.title = name;
    dbMgrRenderQueryTab(document.getElementById('db-mgr-body'));
}

function dbMgrRenderQueryTab(body) {
    dbQueryEnsureTabs();
    const hint = _dbMgrCurrentTable
        ? `SELECT * FROM ${_dbMgrCurrentTable} LIMIT 100;`
        : 'SELECT 1;';
    const active = _dbQueryTabs[_dbQueryActive];
    // Tab strip
    let tabsHtml = '';
    for (let i = 0; i < _dbQueryTabs.length; i++) {
        const t = _dbQueryTabs[i];
        const isActive = i === _dbQueryActive;
        tabsHtml += `<div onclick="dbQuerySwitchTab(${i})" ondblclick="dbQueryRenameTab(${i})"
            style="padding:5px 10px; cursor:pointer; display:flex; align-items:center; gap:6px; border-right:1px solid var(--border); background:${isActive ? 'var(--bg-card)' : 'transparent'}; font-size:12px; ${isActive ? 'border-bottom:2px solid var(--accent, #06b6d4);' : ''}">
            <span>${escapeHtml(t.title)}</span>
            <span onclick="dbQueryCloseTab(${i}, event)" style="color:var(--text-muted); font-size:11px; padding:0 2px;"></span>
        </div>`;
    }
    tabsHtml += `<div onclick="dbQueryNewTab()" style="padding:5px 12px; cursor:pointer; font-size:12px; color:var(--accent, #06b6d4);" title="New query tab">+</div>`;

    body.innerHTML = `
        <div style="display:flex; border:1px solid var(--border); border-radius:6px 6px 0 0; overflow:auto; background:var(--bg-secondary); margin-bottom:0;">
            ${tabsHtml}
        </div>
        <div style="display:flex; gap:8px; align-items:center; margin-bottom:6px; flex-wrap:wrap; padding:8px; border:1px solid var(--border); border-top:none; background:var(--bg-card);">
            <label style="font-size:13px; margin:0;">Permission:
                <select id="db-perm" class="form-control" style="display:inline-block; width:auto; margin-left:6px;">
                    <option value="read">Read (SELECT / SHOW / EXPLAIN)</option>
                    <option value="update">Update (+ INSERT / UPDATE)</option>
                    <option value="delete">Delete (+ DELETE / TRUNCATE)</option>
                    <option value="schema">Schema (+ ALTER / CREATE / DROP)</option>
                </select>
            </label>
            <label style="font-size:13px; margin:0;">Timeout (s):
                <input id="db-timeout" type="number" min="1" max="300" value="30" class="form-control" style="display:inline-block; width:90px; margin-left:6px;">
            </label>
            <span id="db-schema-badge" title="This tab's working schema — snapshot when the tab was created. New tabs inherit the currently-selected tree schema; existing tabs stay with theirs so clicking around doesn't change their context. Click to rebind to the current tree selection." onclick="dbRebindTabSchema()" style="cursor:pointer; font-size:12px; padding:3px 8px; border-radius:5px; background:rgba(6, 182, 212,0.15); color:#c084fc; margin-left:auto;">${escapeHtml(active.schema || '(default)')}</span>
            <span id="db-validate" style="font-size:12px; padding:3px 8px; border-radius:5px; background:var(--bg-tertiary); color:var(--text-muted);">type to validate…</span>
        </div>
        <div id="db-editor-wrap" style="position:relative; width:100%; height:${_dbEditorHeight || 260}px; min-height:120px;">
            <pre id="db-query-hl" aria-hidden="true"
                style="position:absolute; inset:0; margin:0; padding:8px 10px; font-family:var(--font-mono, ui-monospace, monospace); font-size:13px; line-height:1.45; tab-size:4; white-space:pre-wrap; word-wrap:break-word; pointer-events:none; color:var(--text-primary); overflow:hidden; background:var(--bg-primary); border:1px solid var(--border); border-radius:4px; z-index:1; box-sizing:border-box;"></pre>
            <textarea id="db-query" class="form-control" placeholder="${escapeHtml(hint)}"
                style="position:absolute; inset:0; z-index:2; width:100%; height:100%; resize:none; font-family:var(--font-mono, ui-monospace, monospace); font-size:13px; line-height:1.45; tab-size:4; background:transparent; caret-color:var(--text-primary); color:transparent; text-shadow:0 0 0 transparent; box-sizing:border-box;"
                spellcheck="false">${escapeHtml(active.sql || '')}</textarea>
        </div>
        <div id="db-editor-resize" title="Drag to resize"
            style="height:8px; margin:4px 0; cursor:ns-resize; background:linear-gradient(var(--border), var(--border)) center/40px 2px no-repeat; border-radius:3px;"></div>
        <div style="display:flex; gap:6px; margin-top:8px; align-items:center; flex-wrap:wrap;">
            <button class="btn btn-primary btn-sm" onclick="dbRunQuery()">▶ Run</button>
            <button class="btn btn-sm" onclick="dbExplainQuery()" title="Prepend EXPLAIN and run">Explain</button>
            <button class="btn btn-sm" onclick="dbFormatQuery()" title="Pretty-print SQL keywords">Format</button>
            <button class="btn btn-sm" onclick="dbSaveCurrentQuery()">Save…</button>
            <select id="db-saved-select" onchange="dbLoadSavedSelected()" class="form-control" style="display:inline-block; width:auto; font-size:12px; padding:4px 8px;">
                <option value="">— Saved queries —</option>
            </select>
            <select id="db-hist-select" onchange="dbLoadHistSelected()" class="form-control" style="display:inline-block; width:auto; font-size:12px; padding:4px 8px;">
                <option value="">— Recent —</option>
            </select>
            <button class="btn btn-sm" onclick="dbUploadSqlFile()" title="Upload a .sql file and run every statement">Run SQL file…</button>
            <div style="flex:1;"></div>
            <button class="btn btn-sm" id="db-copy-csv" onclick="dbCopyCsv()" disabled>CSV</button>
            <button class="btn btn-sm" id="db-copy-md" onclick="dbCopyMarkdown()" disabled>Markdown</button>
        </div>
        <div style="font-size:11px; color:var(--text-muted); margin-top:4px;">Ctrl/Cmd + Enter runs. Tab indents. Double-click a tab name to rename.</div>
        <div id="db-result" style="margin-top:14px;"></div>
    `;
    dbRefreshSavedDropdown();
    dbRefreshHistoryDropdown();
    const ta = document.getElementById('db-query');
    if (ta) {
        ta.addEventListener('keydown', (e) => {
            if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
                e.preventDefault();
                dbRunQuery();
            }
            if (e.key === 'Tab') {
                e.preventDefault();
                const s = ta.selectionStart, e2 = ta.selectionEnd;
                ta.value = ta.value.slice(0, s) + '    ' + ta.value.slice(e2);
                ta.selectionStart = ta.selectionEnd = s + 4;
                dbScheduleValidate();
                dbHighlightSql();
            }
        });
        ta.addEventListener('input', () => {
            if (_dbQueryTabs[_dbQueryActive]) _dbQueryTabs[_dbQueryActive].sql = ta.value;
            dbScheduleValidate();
            dbHighlightSql();
            // Live autocomplete: after the user types ≥2 word chars,
            // show suggestions (keyword/table/column) without needing
            // Ctrl+Space. Debounced so every keystroke doesn't
            // rebuild the popup. Backspace/Delete also retrigger.
            dbScheduleAutocomplete();
        });
        ta.addEventListener('scroll', () => {
            const hl = document.getElementById('db-query-hl');
            if (hl) { hl.scrollTop = ta.scrollTop; hl.scrollLeft = ta.scrollLeft; }
        });
        // Persist caret into the tab on every selection change so Run
        // queries, tab switches, and autocomplete accepts all resume
        // exactly where the operator left off.
        ta.addEventListener('keyup', dbQuerySyncActiveTab);
        ta.addEventListener('mouseup', dbQuerySyncActiveTab);
    }
    // Wire the resize divider so operators can grow the result area
    // by dragging the editor shorter (or the reverse). Height is held
    // in memory so it persists across tab switches in this session.
    const resizer = document.getElementById('db-editor-resize');
    const wrap = document.getElementById('db-editor-wrap');
    if (resizer && wrap) {
        resizer.addEventListener('mousedown', (e) => {
            e.preventDefault();
            const startY = e.clientY;
            const startH = wrap.getBoundingClientRect().height;
            document.body.style.cursor = 'ns-resize';
            const onMove = (ev) => {
                const h = Math.max(80, Math.min(window.innerHeight - 200, startH + (ev.clientY - startY)));
                _dbEditorHeight = h;
                wrap.style.height = `${h}px`;
            };
            const onUp = () => {
                document.body.style.cursor = '';
                document.removeEventListener('mousemove', onMove);
                document.removeEventListener('mouseup', onUp);
            };
            document.addEventListener('mousemove', onMove);
            document.addEventListener('mouseup', onUp);
        });
    }
    // Restore caret from the active tab (see dbQuerySyncActiveTab).
    if (ta && active) {
        const pos = typeof active.caret === 'number' ? Math.min(active.caret, ta.value.length) : ta.value.length;
        const endPos = typeof active.caretEnd === 'number' ? Math.min(active.caretEnd, ta.value.length) : pos;
        try {
            ta.focus();
            ta.setSelectionRange(pos, endPos);
        } catch (_) { /* element not attached yet on some paths */ }
    }
    dbHighlightSql();
    dbScheduleValidate();
}

// ─── Lightweight SQL syntax highlighter (regex tokeniser overlay) ───
// We paint coloured spans in a <pre> element positioned behind a
// transparent-background <textarea>. The two share font metrics so
// the cursor and coloured text line up. It's not as nice as Monaco,
// but it's 50 lines of JS and requires zero external deps.
const SQL_KEYWORDS = new Set([
    'SELECT','FROM','WHERE','AND','OR','NOT','IN','IS','NULL','LIKE','BETWEEN',
    'GROUP','BY','ORDER','ASC','DESC','HAVING','LIMIT','OFFSET','DISTINCT','AS',
    'JOIN','LEFT','RIGHT','INNER','OUTER','FULL','CROSS','ON','USING','WITH',
    'UNION','ALL','INTERSECT','EXCEPT','CASE','WHEN','THEN','ELSE','END',
    'INSERT','INTO','VALUES','UPDATE','SET','DELETE','TRUNCATE','MERGE',
    'CREATE','ALTER','DROP','RENAME','TABLE','INDEX','VIEW','TRIGGER','FUNCTION','PROCEDURE',
    'DATABASE','SCHEMA','COLUMN','CONSTRAINT','PRIMARY','KEY','FOREIGN','REFERENCES',
    'UNIQUE','CHECK','DEFAULT','AUTO_INCREMENT','IF','EXISTS','CASCADE','RESTRICT',
    'SHOW','DESCRIBE','DESC','EXPLAIN','ANALYZE','USE','BEGIN','COMMIT','ROLLBACK','TRANSACTION',
    'VARCHAR','CHAR','TEXT','INT','INTEGER','BIGINT','SMALLINT','TINYINT','DECIMAL','NUMERIC',
    'FLOAT','DOUBLE','BOOLEAN','BOOL','DATE','DATETIME','TIMESTAMP','TIME','BLOB','JSON','UUID','SERIAL',
    'COUNT','SUM','AVG','MIN','MAX','NOW','CURRENT_TIMESTAMP','CURRENT_DATE','CONCAT','COALESCE','IFNULL',
]);
function dbHighlightSql() {
    const ta = document.getElementById('db-query');
    const hl = document.getElementById('db-query-hl');
    if (!ta || !hl) return;
    const src = ta.value;
    // Tokenise: strings, line comments, block comments, numbers, keywords, idents.
    // Replacement keeps characters 1:1 so metrics stay aligned.
    let html = '';
    let i = 0;
    while (i < src.length) {
        const c = src[i];
        // Line comment
        if (c === '-' && src[i + 1] === '-') {
            const end = src.indexOf('\n', i);
            const j = end === -1 ? src.length : end;
            html += `<span style="color:#71717a;">${escapeHtml(src.slice(i, j))}</span>`;
            i = j; continue;
        }
        // Block comment
        if (c === '/' && src[i + 1] === '*') {
            const end = src.indexOf('*/', i + 2);
            const j = end === -1 ? src.length : end + 2;
            html += `<span style="color:#71717a;">${escapeHtml(src.slice(i, j))}</span>`;
            i = j; continue;
        }
        // String literal (single or double quote)
        if (c === "'" || c === '"' || c === '`') {
            let j = i + 1;
            while (j < src.length) {
                if (src[j] === '\\') { j += 2; continue; }
                if (src[j] === c) { j++; break; }
                j++;
            }
            html += `<span style="color:#f59e0b;">${escapeHtml(src.slice(i, j))}</span>`;
            i = j; continue;
        }
        // Number
        if (/\d/.test(c)) {
            let j = i;
            while (j < src.length && /[\d.]/.test(src[j])) j++;
            html += `<span style="color:#22d3ee;">${escapeHtml(src.slice(i, j))}</span>`;
            i = j; continue;
        }
        // Identifier / keyword
        if (/[A-Za-z_]/.test(c)) {
            let j = i;
            while (j < src.length && /[A-Za-z0-9_]/.test(src[j])) j++;
            const word = src.slice(i, j);
            if (SQL_KEYWORDS.has(word.toUpperCase())) {
                html += `<span style="color:#06b6d4; font-weight:600;">${escapeHtml(word)}</span>`;
            } else {
                html += escapeHtml(word);
            }
            i = j; continue;
        }
        // Operators + punctuation
        if ('=<>!+-*/%(),;.'.includes(c)) {
            html += `<span style="color:#f472b6;">${escapeHtml(c)}</span>`;
            i++; continue;
        }
        html += escapeHtml(c);
        i++;
    }
    // Trailing newline ensures the <pre> matches the textarea's trailing empty line.
    hl.innerHTML = html + '\n';
}

let _dbValidateTimer = null;
function dbScheduleValidate() {
    if (_dbValidateTimer) clearTimeout(_dbValidateTimer);
    const badge = document.getElementById('db-validate');
    if (badge) {
        badge.style.background = 'var(--bg-tertiary)';
        badge.style.color = 'var(--text-muted)';
        badge.textContent = 'validating…';
    }
    _dbValidateTimer = setTimeout(dbRunValidate, 450);
}

async function dbRunValidate() {
    if (!_dbCurrentId) return;
    const ta = document.getElementById('db-query');
    const badge = document.getElementById('db-validate');
    if (!ta || !badge) return;
    const sql = ta.value.trim();
    if (!sql) {
        badge.style.background = 'var(--bg-tertiary)';
        badge.style.color = 'var(--text-muted)';
        badge.textContent = 'type to validate…';
        return;
    }
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/validate`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query: sql }),
        });
        const data = await resp.json();
        if (data.ok) {
            const tierColor = data.tier === 'schema' ? '#06b6d4'
                : data.tier === 'delete' ? '#ef4444'
                : data.tier === 'update' ? '#eab308' : '#22c55e';
            badge.style.background = `${tierColor}22`;
            badge.style.color = tierColor;
            badge.textContent = `${data.tier} tier`;
            // Auto-advance the permission selector up to the detected
            // tier — queries need the matching permission or higher or
            // the server rejects them even if the classifier accepted.
            // Never downgrade, respect operator choice.
            const perm = document.getElementById('db-perm');
            if (perm) {
                const order = { read: 0, update: 1, delete: 2, schema: 3 };
                if (order[data.tier] > order[perm.value]) perm.value = data.tier;
            }
        } else {
            badge.style.background = 'rgba(239,68,68,0.15)';
            badge.style.color = '#ef4444';
            badge.textContent = `${data.error}`;
        }
    } catch (e) {
        badge.style.background = 'var(--bg-tertiary)';
        badge.style.color = 'var(--text-muted)';
        badge.textContent = 'validate failed';
    }
}

function dbExplainQuery() {
    const ta = document.getElementById('db-query');
    if (!ta) return;
    const cur = ta.value.trim();
    if (!cur) return;
    // MariaDB/MySQL and Postgres both accept "EXPLAIN <stmt>".
    if (!/^\s*explain\b/i.test(cur)) {
        ta.value = 'EXPLAIN ' + cur;
    }
    dbRunQuery();
}

function dbFormatQuery() {
    const ta = document.getElementById('db-query');
    if (!ta) return;
    // Lightweight pretty-printer: newline before top-level clauses.
    // We don't pretend to be a full SQL formatter — sqlformatter-js
    // is 80kB and this covers 90% of ad-hoc queries.
    const keywords = [
        'SELECT','FROM','WHERE','GROUP BY','ORDER BY','HAVING','LIMIT','OFFSET',
        'LEFT JOIN','RIGHT JOIN','INNER JOIN','OUTER JOIN','JOIN','ON',
        'UNION','UNION ALL','INSERT INTO','VALUES','UPDATE','SET','DELETE FROM',
    ];
    let sql = ta.value.replace(/\s+/g, ' ').trim();
    for (const k of keywords) {
        const re = new RegExp('\\s+' + k.replace(/ /g, '\\s+') + '\\b', 'gi');
        sql = sql.replace(re, '\n' + k);
    }
    // Re-capitalise leading word if it starts the query.
    sql = sql.replace(/^\s*(select|from|update|delete|insert|with|explain|show|describe)/i, m => m.toUpperCase());
    ta.value = sql;
    dbScheduleValidate();
}

async function dbSaveCurrentQuery() {
    if (!_dbCurrentId) return;
    const sql = (document.getElementById('db-query') || {}).value || '';
    if (!sql.trim()) { showToast('Nothing to save', 'warning'); return; }
    // Pull the current saved list so we can hint about overwrites
    // and show the existing names alongside the name input.
    const saved = await dbLoadSaved();
    const existingList = saved.length
        ? `<div style="font-size:11px; color:var(--text-muted); margin-top:6px;">Existing: ${saved.map(s => escapeHtml(s.name)).join(', ')}</div>`
        : '';
    const existing = document.getElementById('db-save-modal');
    if (existing) existing.remove();
    const modal = document.createElement('div');
    modal.id = 'db-save-modal';
    modal.style.cssText = 'position:fixed; inset:0; background:rgba(0,0,0,0.6); z-index:10000; display:flex; align-items:center; justify-content:center;';
    modal.innerHTML = `
        <div style="background:var(--bg-card); border:1px solid var(--border); border-radius:10px; padding:18px; width:520px; max-width:95vw;">
            <h3 style="margin:0 0 12px;">Save query</h3>
            <label style="display:block; font-size:13px;">Name
                <input id="db-save-name" class="form-control" placeholder="Nightly active users" autocomplete="off">
            </label>
            ${existingList}
            <div style="margin-top:10px; font-size:12px; color:var(--text-muted);">Saved to your account — visible only to you, available across devices.</div>
            <details style="margin-top:10px;">
                <summary style="cursor:pointer; font-size:12px; color:var(--text-muted);">Preview SQL</summary>
                <pre style="margin-top:6px; padding:8px; background:var(--bg-primary); border:1px solid var(--border); border-radius:4px; font-size:11px; max-height:140px; overflow:auto;">${escapeHtml(sql)}</pre>
            </details>
            <div style="display:flex; gap:8px; justify-content:flex-end; margin-top:14px;">
                <button class="btn btn-sm" onclick="document.getElementById('db-save-modal').remove()">Cancel</button>
                <button class="btn btn-primary btn-sm" id="db-save-submit">Save</button>
            </div>
        </div>
    `;
    dbModalHost().appendChild(modal);
    const nameInput = modal.querySelector('#db-save-name');
    const submit = modal.querySelector('#db-save-submit');
    const doSave = async () => {
        const name = nameInput.value.trim();
        if (!name) { nameInput.focus(); return; }
        try {
            const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/saved-queries`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name, sql }),
            });
            const data = await resp.json();
            if (!resp.ok) { showToast(data.error || 'Save failed', 'error'); return; }
            modal.remove();
            await dbRefreshSavedDropdown();
            showToast(`Saved as "${name}"`, 'success');
        } catch (e) { showToast('Save failed: ' + e.message, 'error'); }
    };
    submit.addEventListener('click', doSave);
    nameInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); doSave(); } });
    setTimeout(() => nameInput.focus(), 0);
}

async function dbRefreshSavedDropdown() {
    const sel = document.getElementById('db-saved-select');
    if (!sel || !_dbCurrentId) return;
    const saved = await dbLoadSaved();
    let html = '<option value="">— Saved queries —</option>';
    for (const s of saved) html += `<option value="${escapeHtml(s.name)}">${escapeHtml(s.name)}</option>`;
    if (saved.length) html += '<option value="__manage">Manage saved…</option>';
    sel.innerHTML = html;
}

function dbLoadSavedSelected() {
    const sel = document.getElementById('db-saved-select');
    if (!sel || !_dbCurrentId) return;
    const val = sel.value;
    sel.value = '';
    if (!val) return;
    if (val === '__manage') { dbManageSavedQueries(); return; }
    const s = _dbSavedCache.find(x => x.name === val);
    if (!s) return;
    const ta = document.getElementById('db-query');
    if (ta) { ta.value = s.sql; dbScheduleValidate(); }
}

async function dbManageSavedQueries() {
    const saved = _dbSavedCache;
    if (!saved.length) { showToast('No saved queries', 'info'); return; }
    const existing = document.getElementById('db-manage-modal');
    if (existing) existing.remove();
    const modal = document.createElement('div');
    modal.id = 'db-manage-modal';
    modal.style.cssText = 'position:fixed; inset:0; background:rgba(0,0,0,0.6); z-index:10000; display:flex; align-items:center; justify-content:center;';
    const rows = saved.map(s => `
        <div style="display:flex; justify-content:space-between; align-items:flex-start; gap:10px; padding:8px 10px; border-bottom:1px solid var(--border);">
            <div style="min-width:0; flex:1;">
                <div style="font-weight:600; font-size:13px;">${escapeHtml(s.name)}</div>
                <pre style="margin:4px 0 0; font-size:11px; color:var(--text-muted); white-space:pre-wrap; max-height:80px; overflow:auto;">${escapeHtml(s.sql)}</pre>
            </div>
            <div style="display:flex; gap:4px; flex-shrink:0;">
                <button class="btn btn-sm" onclick="dbManageLoad('${escapeHtml(s.name).replace(/'/g, "\\'")}')">Load</button>
                <button class="btn btn-sm" onclick="dbManageDelete('${escapeHtml(s.name).replace(/'/g, "\\'")}')" style="color:var(--danger);">Delete</button>
            </div>
        </div>
    `).join('');
    modal.innerHTML = `
        <div style="background:var(--bg-card); border:1px solid var(--border); border-radius:10px; padding:18px; width:700px; max-width:95vw; max-height:80vh; display:flex; flex-direction:column;">
            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px;">
                <h3 style="margin:0;">Saved queries (${saved.length})</h3>
                <button class="btn btn-sm" onclick="document.getElementById('db-manage-modal').remove()">Close</button>
            </div>
            <div style="overflow:auto; border:1px solid var(--border); border-radius:6px;">${rows}</div>
        </div>
    `;
    dbModalHost().appendChild(modal);
}

function dbManageLoad(name) {
    const s = _dbSavedCache.find(x => x.name === name);
    if (!s) return;
    const ta = document.getElementById('db-query');
    if (ta) { ta.value = s.sql; if (_dbQueryTabs[_dbQueryActive]) _dbQueryTabs[_dbQueryActive].sql = s.sql; dbHighlightSql(); dbScheduleValidate(); }
    document.getElementById('db-manage-modal')?.remove();
    showToast(`Loaded "${name}"`, 'success');
}

async function dbManageDelete(name) {
    const ok = await wolfConfirm(`Delete saved query "${name}"?`, 'Delete saved query', { okText: 'Delete', danger: true });
    if (!ok) return;
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/saved-queries/${encodeURIComponent(name)}`, { method: 'DELETE' });
        if (resp.status === 404) { showToast('Already gone', 'warning'); return; }
        if (!resp.ok) { showToast('Delete failed', 'error'); return; }
        await dbRefreshSavedDropdown();
        // Re-open the manage modal with the updated list.
        document.getElementById('db-manage-modal')?.remove();
        await dbLoadSaved();
        if (_dbSavedCache.length) dbManageSavedQueries();
        showToast(`Deleted "${name}"`, 'success');
    } catch (e) { showToast('Delete failed: ' + e.message, 'error'); }
}

async function dbRefreshHistoryDropdown() {
    const sel = document.getElementById('db-hist-select');
    if (!sel || !_dbCurrentId) return;
    const h = await dbLoadHistory();
    let html = '<option value="">— Recent —</option>';
    for (let i = 0; i < h.length; i++) {
        const preview = h[i].sql.replace(/\s+/g, ' ').slice(0, 60);
        html += `<option value="${i}">${escapeHtml(preview)}${h[i].sql.length > 60 ? '…' : ''}</option>`;
    }
    sel.innerHTML = html;
}

function dbLoadHistSelected() {
    const sel = document.getElementById('db-hist-select');
    if (!sel || !_dbCurrentId) return;
    const idx = parseInt(sel.value, 10);
    sel.value = '';
    if (isNaN(idx)) return;
    if (!_dbHistoryCache[idx]) return;
    const ta = document.getElementById('db-query');
    if (ta) { ta.value = _dbHistoryCache[idx].sql; dbScheduleValidate(); }
}

// Heuristic check for "I hope you meant that" queries — TRUNCATE,
// unqualified DELETE, unqualified UPDATE, DROP TABLE, DROP DATABASE.
// Returns null if the query is safe, or a warning message string if
// the user should confirm. We strip string literals and comments
// before the regex test so the WHERE inside a quoted string doesn't
// count and a block-commented "WHERE" doesn't hide a naked DELETE.
function dbDangerousQueryWarning(sql) {
    const stripped = sql
        .replace(/--[^\n]*/g, '')
        .replace(/\/\*[\s\S]*?\*\//g, '')
        .replace(/'([^'\\]|\\.|'')*'/g, "''")
        .replace(/"([^"\\]|\\.|"")*"/g, '""')
        .replace(/`([^`]|``)*`/g, '``')
        .trim();
    if (/^\s*TRUNCATE\b/i.test(stripped)) return 'TRUNCATE deletes every row and is not transactional on most engines — you cannot roll back. Continue?';
    if (/^\s*DROP\s+(TABLE|DATABASE|SCHEMA)\b/i.test(stripped)) return 'DROP TABLE / DATABASE removes the object and all its data. Continue?';
    if (/^\s*DELETE\s+FROM\s+[^\s;]+\s*;?$/i.test(stripped)) return 'DELETE has no WHERE clause — every row will be deleted. Continue?';
    if (/^\s*DELETE\s+FROM\s+[^;]+$/i.test(stripped) && !/\bWHERE\b/i.test(stripped)) return 'DELETE has no WHERE clause — every row will be deleted. Continue?';
    if (/^\s*UPDATE\s+[^;]+\bSET\b[^;]+$/i.test(stripped) && !/\bWHERE\b/i.test(stripped)) return 'UPDATE has no WHERE clause — every row will be rewritten. Continue?';
    return null;
}

// Heuristic check for "you are about to pull a lot" — a SELECT /
// WITH query with no LIMIT / FETCH / TOP clause. We strip string
// literals and comments first so WHERE clauses can safely mention
// LIMIT without suppressing the warning. Always returns null if
// the query isn't a read statement — DML / DDL have their own
// danger warnings.
function dbHugeDatasetWarning(sql) {
    const stripped = sql
        .replace(/--[^\n]*/g, '')
        .replace(/\/\*[\s\S]*?\*\//g, '')
        .replace(/'([^'\\]|\\.|'')*'/g, "''")
        .replace(/"([^"\\]|\\.|"")*"/g, '""')
        .replace(/`([^`]|``)*`/g, '``')
        .trim();
    if (!/^\s*(SELECT|WITH|TABLE)\b/i.test(stripped)) return null;
    // Heuristic: LIMIT / FETCH / TOP keyword present anywhere.
    if (/\b(LIMIT|FETCH\s+FIRST|FETCH\s+NEXT|TOP\s+\d)\b/i.test(stripped)) return null;
    // Aggregates (COUNT, SUM, ...) implicitly return a small rowset
    // when paired with a scalar GROUP BY. Skip warning if the query
    // is clearly a SELECT COUNT(*) style summary.
    if (/^\s*SELECT\s+COUNT\s*\(/i.test(stripped) && !/\bGROUP\s+BY\b/i.test(stripped)) return null;
    return 'This query has no LIMIT — every matching row will be fetched.';
}

async function dbRunQuery() {
    if (!_dbCurrentId) return;
    const query = document.getElementById('db-query').value;
    const permission = document.getElementById('db-perm').value;
    const timeout_secs = parseInt(document.getElementById('db-timeout').value, 10) || 30;
    // Use THIS TAB's schema (set at tab creation), not the tree
    // selection, so running a query in an older tab doesn't accidentally
    // execute against whichever DB the operator last clicked on.
    const activeTab = _dbQueryTabs[_dbQueryActive];
    const schema = (activeTab && activeTab.schema) || undefined;
    const resultEl = document.getElementById('db-result');
    if (!query.trim()) return;
    // Danger check — give the operator one chance to cancel a
    // TRUNCATE / unqualified DELETE / etc. Never skip on a Run click.
    const danger = dbDangerousQueryWarning(query);
    if (danger) {
        const ok = await wolfConfirm(
            `${danger}\n\nQuery:\n${query.slice(0, 500)}${query.length > 500 ? '…' : ''}`,
            'Destructive query',
            { okText: 'Run anyway', danger: true }
        );
        if (!ok) return;
    }
    // Huge-dataset check — SELECT with no LIMIT on a potentially
    // large table can pull megabytes down the cluster proxy and
    // chew browser memory. The backend already caps at MAX_ROWS but
    // that's 10k rows; warn operators before they commit to a full
    // table scan even if they're under that ceiling.
    const huge = dbHugeDatasetWarning(query);
    if (huge) {
        const ok = await wolfConfirm(
            `${huge}\n\nConsider adding a LIMIT clause — the result table caps display at 1000 rows, but the full result still travels over the network first.`,
            'Unlimited query',
            { okText: 'Run anyway' }
        );
        if (!ok) return;
    }
    resultEl.innerHTML = '<div style="color:var(--text-muted);">Running…</div>';
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(_dbCurrentId)}/query`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query, permission, timeout_secs, schema }),
        });
        const data = await resp.json();
        if (!resp.ok) {
            _dbLastResult = null;
            document.getElementById('db-copy-csv').disabled = true;
            document.getElementById('db-copy-md').disabled = true;
            resultEl.innerHTML = `<div style="color:var(--danger); padding:10px; background:var(--bg-primary); border-radius:6px; white-space:pre-wrap; font-family:monospace;">${escapeHtml(data.error || 'Query failed')}</div>`;
            return;
        }
        _dbLastResult = data;
        document.getElementById('db-copy-csv').disabled = false;
        document.getElementById('db-copy-md').disabled = false;
        sqlConnRenderResult(resultEl, data);
        // Server pushed to per-user history inside the /query handler;
        // refresh the dropdown to pull the new entry.
        dbRefreshHistoryDropdown();
    } catch (e) {
        resultEl.innerHTML = `<div style="color:var(--danger);">${escapeHtml(e.message)}</div>`;
    }
}

async function dbTestConnection(id, btn) {
    if (btn) btn.disabled = true;
    try {
        const resp = await fetch(`/api/sql-connections/${encodeURIComponent(id)}/test`, { method: 'POST' });
        const data = await resp.json();
        if (data.ok) showToast(`${data.version || 'Connected'}`, 'success');
        else showToast(`${data.error || 'Connection failed'}`, 'error');
    } catch (e) {
        showToast(`${e.message}`, 'error');
    } finally {
        if (btn) btn.disabled = false;
    }
}

function dbCopyCsv() {
    if (!_dbLastResult) return;
    const { columns, rows } = _dbLastResult;
    const esc = (s) => {
        if (s == null) return '';
        const str = String(s);
        return (str.includes(',') || str.includes('"') || str.includes('\n'))
            ? `"${str.replace(/"/g, '""')}"` : str;
    };
    let csv = columns.map(esc).join(',') + '\n';
    for (const row of rows) csv += row.map(esc).join(',') + '\n';
    navigator.clipboard.writeText(csv).then(
        () => showToast('CSV copied to clipboard', 'success'),
        () => showToast('Clipboard write failed', 'error'),
    );
}

function dbCopyMarkdown() {
    if (!_dbLastResult) return;
    const { columns, rows } = _dbLastResult;
    let md = '| ' + columns.join(' | ') + ' |\n';
    md += '| ' + columns.map(() => '---').join(' | ') + ' |\n';
    for (const row of rows.slice(0, 200)) {
        md += '| ' + row.map(v => {
            if (v == null) return '';
            return String(v).replace(/\|/g, '\\|').replace(/\n/g, ' ');
        }).join(' | ') + ' |\n';
    }
    if (rows.length > 200) md += `\n_…${rows.length - 200} more rows_\n`;
    navigator.clipboard.writeText(md).then(
        () => showToast('Markdown copied to clipboard', 'success'),
        () => showToast('Clipboard write failed', 'error'),
    );
}


// ─── Predictive Inbox ───────────────────────────────────────────
//
// Renders the proposal inbox surfaced by `src/predictive/`. The
// backend handlers live near "Predictive ops" in `src/api/mod.rs`.
//
// State model:
//   predictiveState.proposals — the most recent inbox snapshot.
// Calls go to /api/proposals* and /api/proposal-acks*. All cookie-
// authed; no Authorization header.
//
// UI rules followed here:
//   • visible feedback for every user action (toast on success/error)
//   • dismiss requires a reason — matches the backend 400 contract
//     so the UI never lets the user submit something the server will
//     reject
//   • approve is a confirmation, not a one-click — v1 proposals are
//     `Manual` plans, "approve" only records that the operator
//     applied the suggested commands themselves
//   • snooze options are presets (4 h / 24 h / 1 w / 30 d) so the
//     common case is one click, not a date picker

// `predictiveState.proposals` is the flat list rendered by
// `predictiveRender()`. `nodes` carries per-node responded/failed
// status (with cluster_name) from the cluster aggregator so we can
// warn the operator when the Inbox is incomplete instead of silently
// showing partial data and so the UI can group by cluster. Filters
// stack: clusterFilter narrows to one cluster, nodeFilter narrows
// to a single node within whatever cluster is selected.
const predictiveState = {
    proposals: [], nodes: [], cachedForSeconds: 0,
    clusterFilter: null,  // null → all clusters
    nodeFilter: null,     // null → all nodes within the cluster filter
    loading: false,
    // expandedIds: which rows are currently showing their full body.
    // selectedIds: which rows are checked for a bulk action.
    // pendingUndoIds: proposals that have been optimistically removed
    //   but are still inside their undo window (deferred network call
    //   has not fired yet). The 60s badge poll filters these out so
    //   a cluster snapshot taken mid-undo doesn't re-add the row the
    //   operator thought they'd just dismissed/approved. Cleared by
    //   the undo handler when the operator hits Undo, or when the
    //   timeout fires and the API call goes out.
    // All three are kept on the client only — they don't survive reload.
    expandedIds: new Set(),
    selectedIds: new Set(),
    pendingUndoIds: new Set(),
};
let predictiveBadgeTimer = null;

function renderPredictiveInbox() {
    const container = document.getElementById('page-inbox');
    if (!container) return;
    // Constrain this page-view to the live height of `.main-content`
    // so the embedded terminal pane stays inside the viewport.
    //
    // `.main-content` has `min-height`/`max-height` (not `height`)
    // tied to viewport-minus-chrome, so a CSS `height: 100%` on a
    // child resolves against `auto` and the inner flex chain breaks
    // — the split grows to the intrinsic height of the proposals
    // list, pushing the terminal off the bottom of the screen.
    // Reading `clientHeight` (a pixel value, always defined) and
    // applying it as inline height side-steps the percentage
    // resolution rule. ResizeObserver keeps it in sync if the
    // operator resizes the window or expands the side-bar.
    container.style.display = 'flex';
    container.style.flexDirection = 'column';
    container.style.minHeight = '0';
    container.style.padding = '0';
    predictiveSetupHeightSync(container);
    if (!container.querySelector('.predictive-shell')) {
        // Two-column layout: left = proposals list, right = embedded
        // terminal. Replaces the per-command popup-window terminal so
        // a proposal with three non-destructive commands runs all
        // three in the same shell instead of spawning three windows.
        //
        // The shell is a flex column that fills `.main-content`
        // exactly (the dashboard's outer layer already accounts for
        // the top-bar and footer via max-height), and the split is
        // `flex:1` inside it. That keeps the terminal pane on screen
        // at all times and scrolls only the proposals list inside its
        // column. The contextual help <details> panels live inside
        // the list-scroll wrapper so they reach the user without
        // pushing the terminal off the bottom of the viewport.
        container.innerHTML = `
            <div class="predictive-shell" style="padding:20px 24px;max-width:1600px;margin:0 auto;height:100%;display:flex;flex-direction:column;min-height:0;">
                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px;gap:16px;flex-wrap:wrap;flex-shrink:0;">
                    <div style="flex:1;min-width:280px;">
                        <h2 style="margin:0 0 6px 0;font-size:22px;color:var(--text-primary);">Predictive Inbox</h2>
                        <div style="font-size:13px;color:var(--text-muted);line-height:1.5;">
                            Forward-looking findings the analyzer surfaces before they become incidents.
                            Every proposal carries the evidence used to produce it; nothing here executes
                            until you choose to apply it.
                        </div>
                    </div>
                    <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
                        <button class="btn btn-sm" onclick="predictiveRunNow()" id="predictive-run-now">Run analyzer now</button>
                        <span id="threat-intel-toggle-wrap" style="display:none;align-items:center;gap:8px;padding:6px 10px;background:rgba(96,165,250,0.08);border:1px solid rgba(96,165,250,0.25);border-radius:6px;font-size:12px;color:var(--text-secondary);">
                            <span id="threat-intel-status-label" style="font-weight:600;">Threat-intel blocklist</span>
                            <span id="threat-intel-status-detail" style="color:var(--text-muted);"></span>
                            <button class="btn btn-sm" id="threat-intel-toggle-btn" onclick="threatIntelOpenPanel()" style="margin-left:4px;">Loading…</button>
                        </span>
                    </div>
                </div>
                <div class="predictive-split" style="display:flex;align-items:stretch;flex:1;min-height:0;gap:0;">
                    <div id="predictive-list-scroll" style="flex:1 1 auto;min-width:0;overflow-y:auto;padding-right:6px;">
                        <div id="predictive-list">
                            <div style="color:var(--text-muted);padding:40px;text-align:center;">Loading…</div>
                        </div>
                        <details style="margin-top:24px;background:rgba(96,165,250,0.05);border:1px solid rgba(96,165,250,0.2);border-radius:8px;padding:0;">
                            <summary style="padding:10px 14px;cursor:pointer;font-size:12px;color:#60a5fa;font-weight:600;">ℹ How this works</summary>
                            <div style="padding:0 14px 12px 14px;font-size:12px;color:var(--text-secondary);line-height:1.55;">
                                The analyzer needs at least
                                <strong>3 samples spanning ≥30 minutes</strong> of history before it can fit a trend
                                line, and only emits a proposal when a resource is in a state worth flagging
                                (e.g. for disk-fill: ≥50% used <em>and</em> growing toward 95%). On a healthy
                                cluster, &quot;No predictions right now&quot; is the correct answer and clicking
                                <em>Run analyzer now</em> may produce nothing visible — that's working as
                                intended, not a bug.
                            </div>
                        </details>
                        <details style="margin-top:8px;background:rgba(6, 182, 212,0.04);border:1px solid rgba(6, 182, 212,0.2);border-radius:8px;padding:0;margin-bottom:8px;">
                            <summary style="padding:10px 14px;cursor:pointer;font-size:12px;color:#c084fc;font-weight:600;">What's currently watched</summary>
                            <div style="padding:0 14px 12px 14px;font-size:12px;color:var(--text-secondary);line-height:1.55;">
                                Every analyzer item from the original roadmap is live: host filesystem usage,
                                Docker / LXC container storage and memory pressure, restart-loops, host CPU/memory
                                thresholds, certificate expiry, backup freshness, VM disk-fill, security
                                posture (services on public IPs, sshd permissive auth), and CVE susceptibility
                                (pending security updates from apt / dnf on the host and inside running LXC
                                containers — Docker / VM scans need a guest agent or image scanner and aren't
                                wired up yet). Sampled every 5 minutes on each cluster node; aggregated cluster-wide
                                here. First-appearance Critical/High findings page Discord/Slack/Telegram/email
                                channels — once per finding, not on every refresh. Stale findings auto-resolve
                                when the analyzer no longer sees the condition.
                            </div>
                        </details>
                    </div>
                    <div id="predictive-splitter" title="Drag to resize · double-click to reset" style="flex:0 0 8px;cursor:col-resize;background:transparent;position:relative;margin:0 4px;user-select:none;touch-action:none;"></div>
                    <div id="predictive-terminal-pane" style="background:var(--bg-card,#1e2028);border:1px solid var(--border,#2d2f3a);border-radius:10px;overflow:hidden;display:flex;flex-direction:column;min-height:0;flex:0 0 560px;">
                        <div style="display:flex;align-items:center;justify-content:space-between;padding:10px 14px;border-bottom:1px solid var(--border,#2d2f3a);background:var(--bg-secondary,#16181f);flex-shrink:0;gap:8px;">
                            <div style="display:flex;align-items:center;gap:8px;font-size:13px;font-weight:600;min-width:0;">
                                <span id="predictive-term-spinner" style="display:none;width:14px;height:14px;border:2px solid rgba(96,165,250,0.25);border-top-color:#60a5fa;border-radius:50%;animation:predTermSpin 0.7s linear infinite;flex-shrink:0;"></span>
                                <span id="predictive-term-icon" style="font-size:16px;flex-shrink:0;"></span>
                                <span id="predictive-term-status" style="color:var(--text-muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">No active terminal</span>
                            </div>
                            <div style="display:flex;align-items:center;gap:6px;flex-shrink:0;">
                                <button class="btn btn-sm" onclick="predictiveToggleMaximize()" id="predictive-term-max" title="Maximize terminal" style="font-size:11px;padding:2px 8px;"><span class="ws-icon-clean-wrap" data-icon="terminal"></span></button>
                                <button class="btn btn-sm" onclick="predTermClose()" id="predictive-term-close" style="display:none;font-size:11px;padding:2px 8px;">Close</button>
                            </div>
                        </div>
                        <div id="predictive-term-container" style="flex:1;background:#0a0a0a;padding:8px 8px 14px 8px;overflow:hidden;min-height:0;">
                            <div style="color:var(--text-muted);padding:24px;text-align:center;font-size:13px;line-height:1.6;">
                                Click <strong>▶ Run</strong> or <strong>Open terminal</strong> on a proposal.<br>
                                <span style="font-size:11px;opacity:0.7;">Multiple commands on the same proposal share the session — no more 3-popup workflows.</span>
                            </div>
                        </div>
                    </div>
                </div>
                <style>
                    @keyframes predTermSpin {
                        from { transform: rotate(0deg); }
                        to   { transform: rotate(360deg); }
                    }
                    /* Drag splitter — invisible by default, lights up
                       on hover/active so it discoverable without being
                       visual noise at rest. */
                    #predictive-splitter::after {
                        content: '';
                        position: absolute;
                        top: 50%;
                        left: 50%;
                        transform: translate(-50%, -50%);
                        width: 2px;
                        height: 36px;
                        background: var(--border, #2d2f3a);
                        border-radius: 1px;
                        transition: background 0.15s, height 0.15s;
                    }
                    #predictive-splitter:hover::after,
                    #predictive-splitter.dragging::after {
                        background: #60a5fa;
                        height: 64px;
                    }
                    .predictive-split.maximized #predictive-list-scroll,
                    .predictive-split.maximized #predictive-splitter { display: none; }
                    .predictive-split.maximized #predictive-terminal-pane { flex: 1 1 auto !important; }
                    /* Tablet / small laptop — stack to one column. The
                       splitter and persisted width are not meaningful in
                       a single-column stack, so we hide the splitter and
                       reset the terminal pane to a fixed height. */
                    @media (max-width: 1100px) {
                        .predictive-split {
                            flex-direction: column !important;
                            height: auto !important;
                        }
                        #predictive-splitter { display: none !important; }
                        #predictive-list-scroll {
                            max-height: 60vh;
                            flex: 0 1 auto !important;
                        }
                        #predictive-terminal-pane {
                            flex: 0 0 380px !important;
                            height: 380px !important;
                        }
                    }
                    /* Phone — terminal hidden by default so the list
                       gets the full viewport. The list is the primary
                       view; the terminal only appears when the operator
                       runs a command (predictiveShowTerminalStub and
                       predTermOpen toggle .term-active on the split
                       container). Without this, the fixed 300-380px
                       terminal pane combined with flex-shrink:0 leaves
                       the list squeezed to ~20px on phones with the
                       address bar visible. */
                    @media (max-width: 640px) {
                        .predictive-shell { padding: 12px !important; }
                        /* No terminal active → list fills the inbox. */
                        .predictive-split:not(.term-active) #predictive-terminal-pane {
                            display: none !important;
                        }
                        .predictive-split:not(.term-active) #predictive-list-scroll {
                            max-height: none !important;
                            flex: 1 1 auto !important;
                        }
                        /* Terminal active → list compact above, terminal
                           takes the rest. The list still scrolls so the
                           operator can change which proposal is active
                           without dismissing the terminal first. */
                        .predictive-split.term-active #predictive-list-scroll {
                            max-height: 30vh !important;
                            flex: 0 1 auto !important;
                        }
                        .predictive-split.term-active #predictive-terminal-pane {
                            flex: 1 1 auto !important;
                            height: auto !important;
                            min-height: 50vh !important;
                        }
                        /* xterm uses fixed font sizing — drop one
                           notch on phones so an 80-col line fits the
                           pane width. */
                        #predictive-term-container .xterm,
                        #predictive-term-container .xterm-viewport,
                        #predictive-term-container .xterm-screen { font-size: 11px !important; }
                    }
                    /* Touch-target sizing for header buttons. */
                    @media (pointer: coarse) {
                        #predictive-term-close,
                        #predictive-term-max { min-height: 36px; min-width: 40px; }
                    }
                </style>
            </div>
        `;
    }
    predictiveSetupSplitter();
    predictiveLoad();
    // Surface the threat-intel safety switch in the header so the
    // operator can disable the blocklist immediately if it breaks
    // anything. Hides itself if the API isn't reachable.
    if (typeof threatIntelRefreshStatus === 'function') {
        try { threatIntelRefreshStatus(); } catch (_) {}
    }
}

/// Drag-to-resize between the proposals list and the embedded
/// terminal pane. Persists the chosen terminal-pane width in
/// localStorage so it survives page reloads. Bypassed on the
/// stacked single-column layout (≤1100px) — the splitter is hidden
/// via media query and we don't apply a persisted pixel width that
/// would fight with the column-direction layout.
///
/// Why pixels not percent: the inbox's outer width changes with the
/// sidebar collapse state and window resize. A persisted percentage
/// would survive both, but operators usually want "give me a wider
/// terminal" expressed as "this many columns of xterm" — a pixel
/// width is a closer proxy than a percent. We clamp on resize so a
/// previously-saved 800px terminal doesn't push the proposals list
/// to zero width on a narrower window.
const PRED_TERM_WIDTH_KEY = 'wolfstack.predictive.term_width_px';
const PRED_TERM_WIDTH_MIN = 360;
const PRED_TERM_WIDTH_DEFAULT = 560;
function predictiveSetupSplitter() {
    const split = document.querySelector('.predictive-split');
    const splitter = document.getElementById('predictive-splitter');
    const termPane = document.getElementById('predictive-terminal-pane');
    if (!split || !splitter || !termPane) return;
    if (splitter.dataset.wired === '1') {
        // Re-render of renderPredictiveInbox keeps the same DOM, so we
        // don't re-attach. Just re-apply the persisted width in case
        // we're back from a maximized state.
        predictiveApplyTermWidth();
        return;
    }
    splitter.dataset.wired = '1';

    predictiveApplyTermWidth();

    let dragStartX = 0;
    let dragStartWidth = 0;
    const onMove = (e) => {
        const x = e.touches ? e.touches[0].clientX : e.clientX;
        const splitWidth = split.clientWidth;
        // Drag LEFT increases terminal width (terminal is on the
        // right). Compute the new width from the delta and clamp so
        // the list pane keeps at least 360px of breathing room.
        const desired = dragStartWidth - (x - dragStartX);
        const maxTerm = Math.max(PRED_TERM_WIDTH_MIN, splitWidth - 360 - 16);
        const clamped = Math.max(PRED_TERM_WIDTH_MIN, Math.min(maxTerm, desired));
        termPane.style.flex = `0 0 ${clamped}px`;
        // Refit while dragging so the operator sees the column count
        // change in real time, not just on mouseup.
        try { predTermState.fitAddon && predTermState.fitAddon.fit(); } catch (_) {}
    };
    const onUp = () => {
        splitter.classList.remove('dragging');
        document.body.style.cursor = '';
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
        document.removeEventListener('touchmove', onMove);
        document.removeEventListener('touchend', onUp);
        // Persist the final width.
        const m = /0 0 (\d+(?:\.\d+)?)px/.exec(termPane.style.flex || '');
        if (m) {
            try { localStorage.setItem(PRED_TERM_WIDTH_KEY, String(Math.round(parseFloat(m[1])))); } catch (_) {}
        }
        try { predTermState.fitAddon && predTermState.fitAddon.fit(); } catch (_) {}
    };
    const onDown = (e) => {
        // Skip when the layout has stacked (mobile) — the splitter is
        // hidden via media query, but a stylus/keyboard route could
        // still trigger this. getBoundingClientRect().width === 0
        // when display:none.
        if (splitter.getBoundingClientRect().width === 0) return;
        if (split.classList.contains('maximized')) return;
        e.preventDefault();
        dragStartX = e.touches ? e.touches[0].clientX : e.clientX;
        dragStartWidth = termPane.getBoundingClientRect().width;
        splitter.classList.add('dragging');
        document.body.style.cursor = 'col-resize';
        document.addEventListener('mousemove', onMove);
        document.addEventListener('mouseup', onUp);
        document.addEventListener('touchmove', onMove, { passive: false });
        document.addEventListener('touchend', onUp);
    };
    splitter.addEventListener('mousedown', onDown);
    splitter.addEventListener('touchstart', onDown, { passive: false });
    splitter.addEventListener('dblclick', () => {
        try { localStorage.removeItem(PRED_TERM_WIDTH_KEY); } catch (_) {}
        termPane.style.flex = `0 0 ${PRED_TERM_WIDTH_DEFAULT}px`;
        try { predTermState.fitAddon && predTermState.fitAddon.fit(); } catch (_) {}
    });

    // Re-clamp on window resize so a previously-saved 900px terminal
    // doesn't push the list pane to zero on a narrower viewport.
    window.addEventListener('resize', () => {
        if (split.classList.contains('maximized')) return;
        const splitWidth = split.clientWidth;
        if (splitWidth <= 0) return;
        const cur = termPane.getBoundingClientRect().width;
        const maxTerm = Math.max(PRED_TERM_WIDTH_MIN, splitWidth - 360 - 16);
        if (cur > maxTerm) {
            termPane.style.flex = `0 0 ${maxTerm}px`;
            try { predTermState.fitAddon && predTermState.fitAddon.fit(); } catch (_) {}
        }
    });
}

function predictiveApplyTermWidth() {
    const termPane = document.getElementById('predictive-terminal-pane');
    if (!termPane) return;
    let saved = PRED_TERM_WIDTH_DEFAULT;
    try {
        const v = localStorage.getItem(PRED_TERM_WIDTH_KEY);
        if (v) {
            const n = parseInt(v, 10);
            if (Number.isFinite(n) && n >= PRED_TERM_WIDTH_MIN) saved = n;
        }
    } catch (_) {}
    termPane.style.flex = `0 0 ${saved}px`;
}

/// Toggle the terminal pane between split (default) and maximized
/// (full inbox width, list pane hidden). Refits xterm on each
/// transition so the visible column count matches the new pixel
/// width — without a refit the terminal looks "frozen" mid-line at
/// the old width until something else triggers a fit.
function predictiveToggleMaximize() {
    const split = document.querySelector('.predictive-split');
    const btn = document.getElementById('predictive-term-max');
    if (!split) return;
    const becomingMax = !split.classList.contains('maximized');
    split.classList.toggle('maximized', becomingMax);
    if (btn) {
        btn.title = becomingMax ? 'Restore split' : 'Maximize terminal';
        btn.textContent = becomingMax ? '⊟' : '';
    }
    // Two refits: one synchronous so xterm reflows immediately, one
    // after a frame so the post-layout final width is also picked up
    // (the flex transition is instant in CSS but layout still runs in
    // the next frame).
    const refit = () => { try { predTermState.fitAddon && predTermState.fitAddon.fit(); } catch (_) {} };
    refit();
    requestAnimationFrame(refit);
}

async function predictiveLoad() {
    predictiveState.loading = true;
    try {
        // Use the cluster-aggregating endpoint by default — every
        // node's orchestrator runs locally, this fan-outs to all
        // peers (cached 30s server-side so badge-polling doesn't
        // hammer peers per refresh).
        const r = await fetch('/api/proposals/cluster');
        if (r.status === 401) {
            showToast('Session expired — please log in', 'error');
            predictiveState.proposals = [];
            predictiveState.nodes = [];
            return;
        }
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            const list = document.getElementById('predictive-list');
            if (list) list.innerHTML = `<div style="color:#fbbf24;padding:24px;text-align:center;">Failed to load proposals: ${escapeHtml(data.error || r.statusText)}</div>`;
            return;
        }
        const body = await r.json();
        predictiveState.proposals = body.proposals || [];
        predictiveState.nodes = body.nodes || [];
        predictiveState.cachedForSeconds = body.cached_for_seconds || 0;
        predictiveRender();
        predictiveBadgeUpdate();
    } catch (e) {
        const list = document.getElementById('predictive-list');
        if (list) list.innerHTML = `<div style="color:#f87171;padding:24px;text-align:center;">Network error: ${escapeHtml(e.message || String(e))}</div>`;
    } finally {
        predictiveState.loading = false;
    }
}

function predictiveRender() {
    const list = document.getElementById('predictive-list');
    if (!list) return;

    // Build the node→cluster lookup once per render.
    const nodes = predictiveState.nodes || [];
    const clusterByNode = {};
    nodes.forEach(n => { clusterByNode[n.node_id] = n.cluster_name || 'WolfStack'; });

    // Apply filters in order: cluster, then node.
    const all = predictiveState.proposals || [];
    let filtered = all;
    if (predictiveState.clusterFilter) {
        filtered = filtered.filter(p =>
            (clusterByNode[p.scope?.node_id] || 'WolfStack') === predictiveState.clusterFilter
        );
    }
    if (predictiveState.nodeFilter) {
        filtered = filtered.filter(p => p.scope && p.scope.node_id === predictiveState.nodeFilter);
    }

    let html = '';

    // Per-peer warning, grouped by cluster so a multi-cluster
    // operator can see "all of staging is unreachable" at a glance.
    const failed = nodes.filter(n => !n.responded);
    if (failed.length > 0) {
        const total = nodes.length;
        const responded = total - failed.length;
        const byCluster = {};
        failed.forEach(n => {
            const c = n.cluster_name || 'WolfStack';
            (byCluster[c] = byCluster[c] || []).push(n);
        });
        const summary = Object.entries(byCluster).map(([c, ns]) =>
            `<strong>${escapeHtml(c)}</strong>: ${ns.map(n =>
                `${escapeHtml(n.hostname || n.node_id)} (${escapeHtml(n.error || 'unreachable')})`
            ).join(', ')}`
        ).join(' · ');
        html += `
            <div style="background:rgba(251,191,36,0.08);border:1px solid rgba(251,191,36,0.3);border-radius:8px;padding:10px 14px;margin-bottom:12px;font-size:12px;color:var(--text-secondary);line-height:1.5;">
                <strong style="color:#fbbf24;">Inbox may be incomplete</strong> — ${responded} of ${total} cluster node${total === 1 ? '' : 's'} responded. Unreachable: ${summary}.
            </div>
        `;
    }

    // Filter row — cluster + node. Cluster filter only renders when
    // there's more than one cluster in the response; node filter
    // only renders when there's more than one node in the currently-
    // selected cluster (so single-node clusters don't get clutter).
    const clusters = Array.from(new Set(nodes.map(n => n.cluster_name || 'WolfStack'))).sort();
    const nodesInScope = predictiveState.clusterFilter
        ? nodes.filter(n => (n.cluster_name || 'WolfStack') === predictiveState.clusterFilter)
        : nodes;

    if (clusters.length > 1 || nodesInScope.length > 1) {
        let row = '<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;font-size:12px;color:var(--text-secondary);flex-wrap:wrap;">';
        row += '<span>Filter:</span>';
        if (clusters.length > 1) {
            const clusterOpts = clusters.map(c => {
                const sel = predictiveState.clusterFilter === c ? ' selected' : '';
                const count = all.filter(p => (clusterByNode[p.scope?.node_id] || 'WolfStack') === c).length;
                return `<option value="${escapeAttr(c)}"${sel}>${escapeHtml(c)} (${count})</option>`;
            }).join('');
            row += `<select onchange="predictiveSetClusterFilter(this.value)" style="background:var(--bg-tertiary,#2d2f3a);color:var(--text-primary);border:1px solid var(--border-color);border-radius:6px;padding:4px 8px;font-size:12px;">
                <option value=""${predictiveState.clusterFilter ? '' : ' selected'}>All clusters (${all.length})</option>
                ${clusterOpts}
            </select>`;
        }
        if (nodesInScope.length > 1) {
            const nodeOpts = nodesInScope.map(n => {
                const label = n.hostname ? `${n.hostname} (${n.node_id})` : n.node_id;
                const sel = predictiveState.nodeFilter === n.node_id ? ' selected' : '';
                return `<option value="${escapeAttr(n.node_id)}"${sel}>${escapeHtml(label)}${n.is_self ? ' — this node' : ''}${n.responded ? '' : ' — unreachable'}</option>`;
            }).join('');
            row += `<select onchange="predictiveSetNodeFilter(this.value)" style="background:var(--bg-tertiary,#2d2f3a);color:var(--text-primary);border:1px solid var(--border-color);border-radius:6px;padding:4px 8px;font-size:12px;">
                <option value=""${predictiveState.nodeFilter ? '' : ' selected'}>All nodes${predictiveState.clusterFilter ? ' in ' + escapeHtml(predictiveState.clusterFilter) : ''}</option>
                ${nodeOpts}
            </select>`;
        }
        row += predictiveState.cachedForSeconds > 0
            ? `<span style="color:var(--text-muted);margin-left:auto;">cached ${predictiveState.cachedForSeconds}s ago</span>`
            : `<span style="color:#34d399;margin-left:auto;">fresh</span>`;
        row += '</div>';
        html += row;
    }

    // Bulk-action toolbar — always rendered (display toggles based on
    // selection size). Master checkbox toggles every VISIBLE row so a
    // filter scopes the bulk action; bar buttons fan out per-id but
    // optimistic-remove all selected rows in one go.
    if (filtered.length > 0) {
        html += `
            <div style="display:flex;align-items:center;gap:10px;padding:8px 12px;margin-bottom:10px;background:var(--bg-secondary,#16181f);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;">
                <input type="checkbox" id="predictive-bulk-master"
                       onchange="predictiveSelectAllVisible(this.checked)"
                       title="Select all visible"
                       style="margin:0;cursor:pointer;width:16px;height:16px;">
                <label for="predictive-bulk-master" style="font-size:11px;color:var(--text-muted);cursor:pointer;">Select all (${filtered.length})</label>
                <button class="btn btn-sm" onclick="osvSettingsOpen()" title="Tune the OSV CVE scanner — severity floor, KEV-only mode, suppress findings with no upstream patch" style="margin-left:8px;">OSV scanner</button>
                <div id="predictive-bulk-bar" style="display:none;align-items:center;gap:8px;margin-left:auto;flex-wrap:wrap;">
                    <span class="pred-bulk-count" style="font-size:12px;color:var(--text-secondary);font-weight:500;">0 selected</span>
                    <button id="predictive-autofix-btn" class="btn btn-sm" style="display:none;background:#10b981;color:#fff;border-color:#059669;" onclick="predictiveAutofixSelected()" title="Run package updates on every selected target — opens a terminal for each one in turn, runs ONLY the update command, then moves to the next. Nothing else is touched.">AUTOFIX (updates)</button>
                    <button class="btn btn-sm btn-primary" onclick="predictiveBulkApprove()" title="Mark every selected proposal as applied">Mark applied</button>
                    <button class="btn btn-sm" onclick="predictiveBulkSnooze(24)">Snooze 24h</button>
                    <button class="btn btn-sm" onclick="predictiveBulkSnooze(168)">Snooze 1w</button>
                    <button class="btn btn-sm" onclick="predictiveBulkDismiss()">Dismiss…</button>
                    <button class="btn btn-sm" onclick="predictiveClearSelection()" title="Clear selection without acting"><span class="ws-icon-clean-wrap" data-icon="check"></span></button>
                </div>
            </div>
        `;
    } else {
        // No findings — still expose the OSV settings button so
        // operators with quiet inboxes can change the noise floor.
        html += `<div style="display:flex;justify-content:flex-end;margin-bottom:10px;">
            <button class="btn btn-sm" onclick="osvSettingsOpen()" title="Tune the OSV CVE scanner — severity floor, KEV-only mode, suppress findings with no upstream patch">OSV scanner</button>
        </div>`;
    }

    if (filtered.length === 0) {
        const filterMsg = (predictiveState.clusterFilter || predictiveState.nodeFilter)
            ? `<div style="font-size:13px;line-height:1.55;max-width:520px;margin:0 auto;">No proposals match the current filter. Clear it to see findings from the rest of the cluster.</div>`
            : `<div style="font-size:13px;line-height:1.55;max-width:520px;margin:0 auto;">This is the correct state for a healthy cluster — see the <em>How this works</em> note above. Analyzers run every 5 minutes; the inbox will populate here when a resource enters a worth-surfacing state.</div>`;
        html += `
            <div style="text-align:center;padding:48px 20px;color:var(--text-muted);">
                <div style="font-size:48px;margin-bottom:12px;color:#34d399;"></div>
                <div style="font-size:16px;color:var(--text-primary);margin-bottom:6px;">No predictions right now.</div>
                ${filterMsg}
            </div>
        `;
    } else if (clusters.length > 1 && !predictiveState.clusterFilter && !predictiveState.nodeFilter) {
        // Multi-cluster, no filter — group by cluster header so the
        // operator's eye can split prod from staging from homelab
        // immediately.
        const groups = {};
        filtered.forEach(p => {
            const c = clusterByNode[p.scope?.node_id] || 'WolfStack';
            (groups[c] = groups[c] || []).push(p);
        });
        const orderedClusters = Object.keys(groups).sort();
        for (const c of orderedClusters) {
            html += `<div style="margin-top:14px;margin-bottom:6px;font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;">${escapeHtml(c)} — ${groups[c].length} finding${groups[c].length === 1 ? '' : 's'}</div>`;
            html += groups[c].map(predictiveRowHtml).join('');
        }
    } else {
        html += filtered.map(predictiveRowHtml).join('');
    }

    list.innerHTML = html;
    predictiveUpdateBulkBar();
    // Kick off the per-card history fetches for any expanded rows.
    // Fire-and-forget — populates each slot as its response arrives.
    predictivePopulateHistorySlots();
}

function predictiveSetClusterFilter(clusterName) {
    predictiveState.clusterFilter = clusterName || null;
    // Clear the node filter when changing clusters — a node id from
    // the previous cluster wouldn't be a valid match in the new one.
    predictiveState.nodeFilter = null;
    predictiveRender();
}

function predictiveSetNodeFilter(nodeId) {
    predictiveState.nodeFilter = nodeId || null;
    predictiveRender();
}

/// Open the OSV scanner settings modal. Pulls the current config from
/// /api/predictive/osv-config, renders a small form with the operator
/// knobs (severity floor, KEV-only, suppress-no-fix), and posts the
/// updated config back via PUT. Triggers a predictive refresh on save
/// so the inbox immediately reflects the new noise floor.
async function osvSettingsOpen() {
    let cfg;
    try {
        const resp = await fetch('/api/predictive/osv-config', { credentials: 'same-origin' });
        if (!resp.ok) throw new Error('HTTP ' + resp.status);
        cfg = await resp.json();
    } catch (e) {
        showModal('Could not load OSV scanner config: ' + (e.message || e), 'OSV scanner');
        return;
    }
    const sevFloor = cfg.severity_floor || 'high';
    const kevOnly = !!cfg.kev_only;
    const suppressNoFix = cfg.suppress_no_fix !== false;
    const enabled = cfg.enabled !== false;
    const sevOpt = (v, label, hint) =>
        `<option value="${v}"${sevFloor === v ? ' selected' : ''}>${label} — ${hint}</option>`;

    // Custom modal (NOT showModal) — showModal's body style sets
    // `white-space:pre-wrap` + `max-height:400px` which mangles HTML
    // forms (whitespace artifacts + clipping). Same pattern as the
    // Pool wizard and tenant-register modal; keeps the form properly
    // sized and styled.
    const overlay = document.createElement('div');
    // Don't add the `modal-overlay` class — the matching CSS rule sets
    // `opacity:0; pointer-events:none` and the fadeIn animation has no
    // `forwards` fill-mode, so the modal flashes for 150ms then snaps
    // back to invisible. The inline style below fully covers the look.
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.6);backdrop-filter:blur(4px);z-index:100000;display:flex;align-items:center;justify-content:center;animation:fadeIn 0.15s ease;';
    overlay.onclick = e => { if (e.target === overlay) overlay.remove(); };

    overlay.innerHTML = `
        <div style="background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:12px;padding:22px 26px;max-width:560px;width:94%;max-height:92vh;overflow-y:auto;color:var(--text-primary,#e4e4e7);font-family:inherit;box-shadow:0 20px 60px rgba(0,0,0,0.5);">
            <div style="font-size:16px;font-weight:600;margin-bottom:8px;display:flex;align-items:center;gap:10px;color:var(--text-primary,#e4e4e7);">
                <span style="font-size:22px;"></span>OSV scanner settings
            </div>
            <div style="font-size:12px;color:var(--text-secondary,#a1a1aa);line-height:1.55;margin-bottom:18px;">
                Tune the noise floor for OSV.dev CVE findings. These knobs apply <strong>after</strong> the scan — the scanner still queries OSV the same way; it just decides what to show in the inbox.
            </div>

            <div style="display:flex;flex-direction:column;gap:14px;">

                <div>
                    <label for="osv-cfg-enabled" style="display:block;font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.05em;margin-bottom:4px;">Scanner</label>
                    <select id="osv-cfg-enabled" style="width:100%;background:var(--bg-input,#0d1225);border:1px solid var(--border-color,#2d2f3a);border-radius:6px;padding:9px 11px;color:var(--text-primary,#e4e4e7);font-family:inherit;font-size:13px;">
                        <option value="true" ${enabled ? 'selected' : ''}>Enabled</option>
                        <option value="false" ${enabled ? '' : 'selected'}>Disabled</option>
                    </select>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:5px;line-height:1.45;">Disabling stops OSV inventory + HTTP queries entirely. The distro-pocket scanner still runs.</div>
                </div>

                <div>
                    <label for="osv-cfg-floor" style="display:block;font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.05em;margin-bottom:4px;">Severity floor</label>
                    <select id="osv-cfg-floor" style="width:100%;background:var(--bg-input,#0d1225);border:1px solid var(--border-color,#2d2f3a);border-radius:6px;padding:9px 11px;color:var(--text-primary,#e4e4e7);font-family:inherit;font-size:13px;${kevOnly ? 'opacity:0.5;cursor:not-allowed;' : ''}" ${kevOnly ? 'disabled' : ''}>
                        ${sevOpt('critical', 'Critical', 'CVSS ≥ 9.0, KEV-listed, or critical-class package')}
                        ${sevOpt('high',     'High',     'CVSS ≥ 7.0 + Critical (recommended)')}
                        ${sevOpt('warn',     'Warn',     'CVSS ≥ 4.0 — every scored CVE')}
                        ${sevOpt('info',     'All',      'every finding, including unscored')}
                    </select>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:5px;line-height:1.45;">KEV-listed CVEs always surface regardless of the floor.</div>
                </div>

                <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;background:var(--bg-input,#0d1225);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;padding:12px 14px;transition:border-color 0.12s;"
                       onmouseenter="this.style.borderColor='var(--accent,#3b82f6)';"
                       onmouseleave="this.style.borderColor='var(--border-color,#2d2f3a)';">
                    <input id="osv-cfg-suppress-no-fix" type="checkbox" ${suppressNoFix ? 'checked' : ''} style="margin-top:2px;cursor:pointer;width:16px;height:16px;flex-shrink:0;accent-color:var(--accent,#3b82f6);">
                    <div style="min-width:0;">
                        <div style="font-size:13px;color:var(--text-primary,#e4e4e7);font-weight:600;">Hide CVEs awaiting an upstream fix</div>
                        <div style="font-size:11px;color:var(--text-muted);margin-top:4px;line-height:1.5;">When OSV has no patched version yet, hide the finding until a fix is published. KEV-listed and Critical findings are <strong>never</strong> hidden by this filter — they need eyeballs even without a patch. The hidden count is shown on each card so you always see the real total.</div>
                    </div>
                </label>

                <label style="display:flex;align-items:flex-start;gap:10px;cursor:pointer;background:var(--bg-input,#0d1225);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;padding:12px 14px;transition:border-color 0.12s;"
                       onmouseenter="this.style.borderColor='var(--accent,#3b82f6)';"
                       onmouseleave="this.style.borderColor='var(--border-color,#2d2f3a)';">
                    <input id="osv-cfg-kev-only" type="checkbox" ${kevOnly ? 'checked' : ''}
                           onchange="(()=>{const f=document.getElementById('osv-cfg-floor');f.disabled=this.checked;f.style.opacity=this.checked?'0.5':'';f.style.cursor=this.checked?'not-allowed':'';})()"
                           style="margin-top:2px;cursor:pointer;width:16px;height:16px;flex-shrink:0;accent-color:var(--accent,#3b82f6);">
                    <div style="min-width:0;">
                        <div style="font-size:13px;color:var(--text-primary,#e4e4e7);font-weight:600;">KEV-only mode</div>
                        <div style="font-size:11px;color:var(--text-muted);margin-top:4px;line-height:1.5;">Show only CVEs that appear on CISA's Known Exploited Vulnerabilities list — attackers are actively exploiting these in the wild. Highest signal-to-noise; suppresses the severity-floor filter entirely.</div>
                    </div>
                </label>

            </div>

            <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:22px;padding-top:16px;border-top:1px solid var(--border-color,#2d2f3a);">
                <button class="btn" id="osv-cfg-cancel" style="font-size:13px;">Cancel</button>
                <button class="btn btn-primary" id="osv-cfg-save" style="font-size:13px;">Save</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);

    // Stash the original config so the save handler can preserve
    // fields we don't expose (endpoint, kev_endpoint, distro_overrides)
    // without requiring the operator to retype them.
    window._osvCfgOriginal = cfg;

    document.getElementById('osv-cfg-cancel').onclick = () => overlay.remove();
    document.getElementById('osv-cfg-save').onclick = (ev) => osvSettingsSave(ev.currentTarget);
}

async function osvSettingsSave(btn) {
    const cfg = Object.assign({}, window._osvCfgOriginal || {});
    cfg.enabled        = document.getElementById('osv-cfg-enabled').value === 'true';
    cfg.severity_floor = document.getElementById('osv-cfg-floor').value;
    cfg.kev_only       = document.getElementById('osv-cfg-kev-only').checked;
    cfg.suppress_no_fix = document.getElementById('osv-cfg-suppress-no-fix').checked;
    btn.disabled = true;
    btn.textContent = 'Saving…';
    try {
        const resp = await fetch('/api/predictive/osv-config', {
            method: 'PUT',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(cfg),
        });
        if (!resp.ok) {
            const j = await resp.json().catch(() => ({}));
            throw new Error(j.error || ('HTTP ' + resp.status));
        }
        const overlay = btn.closest('.modal-overlay');
        if (overlay) overlay.remove();
        showToast && showToast('OSV scanner settings saved — inbox will update on the next scan tick (≤5 min).');
        // Trigger a refresh now so the operator sees the new floor on
        // already-cached findings without waiting for the next tick.
        if (typeof predictiveLoad === 'function') predictiveLoad();
    } catch (e) {
        btn.disabled = false;
        btn.textContent = 'Save';
        showModal('Failed to save OSV scanner settings: ' + (e.message || e), 'OSV scanner');
    }
}

// Map a proposal's finding_type + scope to a (label, icon, color)
// tuple identifying *what* (host / Docker / LXC / VM / cert / …) so
// every card carries an at-a-glance "this is on Server X, in
// runtime Y" badge. Operators stop having to read the title to know
// where a problem lives.
function predictiveRuntimeBadge(p) {
    const ft = p.finding_type || '';
    const rid = (p.scope && p.scope.resource_id) || '';
    if (ft.startsWith('docker_'))         return { label: 'DOCKER',   icon: '', color: '#06b6d4' };
    if (ft.startsWith('lxc_'))            return { label: 'LXC',      icon: '', color: '#06b6d4' };
    if (ft === 'vm_disk_fill')            return { label: 'VM',       icon: '', color: '#f59e0b' };
    if (ft === 'cert_expiry_window')      return { label: 'CERT',     icon: '', color: '#10b981' };
    if (ft === 'backup_stale')            return { label: 'BACKUP',   icon: '', color: '#8b5cf6' };
    if (ft.startsWith('sshd_'))           return { label: 'SSH',      icon: '', color: '#ef4444' };
    if (ft === 'service_bound_publicly')  return { label: 'NETWORK',  icon: '', color: '#ef4444' };
    if (ft === 'systemd_unit_failed')     return { label: 'SERVICE',  icon: '', color: '#f97316' };
    if (ft.startsWith('host_'))           return { label: 'HOST',     icon: '', color: '#64748b' };
    if (ft === 'disk_fill_eta')           return { label: 'HOST',     icon: '', color: '#64748b' };
    // Fallback: surface the resource_id prefix so unknown finding
    // types still get *some* attribution — better than a blank.
    if (rid.includes(':')) return { label: rid.split(':')[0].toUpperCase(), icon: '', color: '#64748b' };
    return { label: 'FINDING', icon: '', color: '#64748b' };
}

/// Per-proposal severity colour + label. Used by both the compact
/// row and the expanded body so the eye carries the same meaning
/// across both states.
function predictiveSevStyle(p) {
    const sev = p.severity || 'info';
    const colors = { critical: '#ef4444', high: '#f97316', warn: '#fbbf24', info: '#60a5fa' };
    const labels = { critical: 'CRITICAL', high: 'HIGH', warn: 'WARN', info: 'INFO' };
    return { color: colors[sev] || '#94a3b8', label: labels[sev] || sev.toUpperCase() };
}

/// Resolve cluster + hostname for a proposal once. Hostname is the
/// human-friendly answer to "which server?"; cluster groups it. Both
/// the compact row and the expanded body reuse this.
function predictiveLocator(p) {
    const clusterByNode = {};
    const hostnameByNode = {};
    (predictiveState.nodes || []).forEach(n => {
        clusterByNode[n.node_id] = n.cluster_name || 'WolfStack';
        if (n.hostname) hostnameByNode[n.node_id] = n.hostname;
    });
    return {
        cluster: clusterByNode[p.scope.node_id] || '',
        host:    hostnameByNode[p.scope.node_id] || p.scope.node_id,
        resource: p.scope.resource_id || '',
    };
}

/// Compact row used in the new expandable-grid layout. Two-line
/// summary (server name → issue title) + checkbox + chevron. Click
/// anywhere except the checkbox / action buttons toggles the
/// expanded body. The actions move into the expanded body so the
/// row stays scannable; bulk actions are exposed via the master bar
/// when ≥1 row is checked.
function predictiveRowHtml(p) {
    const { color: c, label: sevLabel } = predictiveSevStyle(p);
    const { cluster, host, resource } = predictiveLocator(p);
    const expanded = predictiveState.expandedIds.has(p.id);
    const selected = predictiveState.selectedIds.has(p.id);

    const snoozedBadge = (p.status && p.status.kind === 'snoozed')
        ? '<span style="background:rgba(96,165,250,0.18);color:#60a5fa;padding:1px 6px;border-radius:4px;font-size:10px;font-weight:600;margin-left:6px;">SNOOZED</span>'
        : '';

    return `
        <div class="pred-row${expanded ? ' expanded' : ''}" data-pid="${escapeAttr(p.id)}"
             style="background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-left:4px solid ${c};border-radius:8px;margin-bottom:6px;overflow:hidden;">
            <div class="pred-row-head" onclick="predictiveToggleExpand('${escapeAttr(p.id)}', event)"
                 style="display:grid;grid-template-columns:auto auto 1fr auto;gap:10px;align-items:center;padding:10px 12px;cursor:pointer;">
                <input type="checkbox" class="pred-row-check"
                       onclick="event.stopPropagation();predictiveToggleSelect('${escapeAttr(p.id)}', this.checked)"
                       ${selected ? 'checked' : ''}
                       style="margin:0;cursor:pointer;width:16px;height:16px;flex-shrink:0;">
                <span style="background:${c};color:#fff;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;letter-spacing:0.5px;min-width:62px;text-align:center;">${sevLabel}</span>
                <div style="min-width:0;display:flex;flex-direction:column;gap:2px;">
                    <div style="font-size:11px;color:var(--text-muted);display:flex;align-items:center;gap:6px;flex-wrap:nowrap;overflow:hidden;">
                        ${cluster ? `<span style="color:#c084fc;font-weight:500;flex-shrink:0;">${escapeHtml(cluster)}</span><span style="opacity:0.5;flex-shrink:0;">·</span>` : ''}
                        <span title="${escapeAttr(p.scope.node_id)}" style="color:var(--text-secondary);font-weight:500;flex-shrink:0;">${escapeHtml(host)}</span>
                        ${resource ? `<span style="opacity:0.5;flex-shrink:0;">·</span><code style="background:var(--bg-tertiary,#2d2f3a);padding:1px 6px;border-radius:4px;font-size:11px;color:var(--text-muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;min-width:0;">${escapeHtml(resource)}</code>` : ''}
                    </div>
                    <div style="font-size:13px;color:var(--text-primary);font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(p.title)}${snoozedBadge}</div>
                </div>
                <span class="pred-row-chev" style="color:var(--text-muted);font-size:12px;transform:rotate(${expanded ? '90deg' : '0deg'});transition:transform 0.15s;flex-shrink:0;">▶</span>
            </div>
            ${expanded ? `<div class="pred-row-body" style="border-top:1px solid var(--border-color,#2d2f3a);padding:14px 16px;">${predictiveExpandedBody(p)}</div>` : ''}
        </div>
    `;
}

/// The full detail panel shown when a row is expanded — evidence,
/// why, history graph, remediation commands, and the per-proposal
/// action buttons. This is what the original card layout contained;
/// it's now hidden behind a click on the compact row.
function predictiveExpandedBody(p) {
    const sourceBadge = p.source === 'ai'
        ? '<span style="background:rgba(6, 182, 212,0.18);color:#c084fc;padding:1px 7px;border-radius:4px;font-size:10px;font-weight:600;margin-left:6px;">AI</span>'
        : '';
    const runtime = predictiveRuntimeBadge(p);
    const evidence = (p.evidence || []).map(e => {
        // Optional advisory / mitigation reference chips. Used by the
        // OSV analyzer to surface authoritative external links (Debian
        // security tracker, Red Hat advisory, CISA KEV) so the operator
        // can read mitigation guidance without leaving the inbox.
        // Other analyzers leave `links` empty and this renders nothing.
        // Only allow http(s) URLs through. OSV references are
        // expected to be vendor advisories / web pages, never
        // `javascript:` or `data:` URIs. Defense-in-depth even though
        // OSV.dev is a trusted source — the same rendering is reused
        // for any analyzer that ever populates `links`, so a strict
        // allowlist here keeps the surface tight forever.
        const isSafeUrl = u => typeof u === 'string' && /^https?:\/\//i.test(u);
        const linksHtml = (e.links && e.links.length)
            ? '<span style="margin-left:8px;display:inline-flex;gap:4px;flex-wrap:wrap;vertical-align:middle;">' +
              e.links.filter(l => l && isSafeUrl(l.url)).map(l =>
                  `<a href="${escapeAttr(l.url)}" target="_blank" rel="noopener noreferrer" `
                  + `style="display:inline-block;background:rgba(96,165,250,0.16);color:#60a5fa;`
                  + `padding:1px 7px;border-radius:4px;font-size:10px;font-weight:600;text-decoration:none;`
                  + `border:1px solid rgba(96,165,250,0.3);" title="${escapeAttr(l.url)}">`
                  + escapeHtml(l.label) + ' ↗</a>'
              ).join('') +
              '</span>'
            : '';
        // Section-header style for evidence rows whose label flags a
        // group split. The OSV analyzer emits these to delimit the
        // exploit-category buckets (unauth-remote, auth-remote, local,
        // unknown) plus the legacy patch-availability and hidden-no-fix
        // chips. Each gets a distinctive accent so the operator can
        // scan the inbox card by colour: red for unauth, amber for
        // anything else network-reachable, neutral for local-only.
        const isSection = e.label === 'Exploitable without login'
            || e.label === 'Needs an authenticated session'
            || e.label === 'Local access required'
            || e.label === 'Unknown attack vector'
            || (typeof e.label === 'string' && e.label.startsWith('More in '))
            || e.label === 'Patch availability'
            || e.label === 'Hidden — no upstream fix';
        if (isSection) {
            // Colour map matches the category urgency. Unauth-RCE gets
            // the strongest danger colour so it pops out of a long card.
            const accent = e.label === 'Exploitable without login' ? '#ef4444'
                : e.label === 'Needs an authenticated session' ? '#fbbf24'
                : e.label === 'Local access required' ? '#60a5fa'
                : e.label === 'Unknown attack vector' ? '#a1a1aa'
                : e.label === 'Patch availability' ? '#34d399'
                : e.label === 'Hidden — no upstream fix' ? '#a1a1aa'
                : '#94a3b8';  // overflow "More in …" chips
            return `<div style="display:block;width:100%;margin:10px 0 4px;padding:4px 8px;border-left:3px solid ${accent};background:rgba(255,255,255,0.02);font-size:12px;color:var(--text-primary);font-weight:600;">
                ${escapeHtml(e.label)} <span style="color:var(--text-muted);font-weight:normal;margin-left:6px;">${escapeHtml(e.value)}</span>
                ${e.detail ? `<div style="font-size:11px;color:var(--text-muted);font-weight:normal;margin-top:2px;">${escapeHtml(e.detail)}</div>` : ''}
            </div>`;
        }
        // Make CVE-shaped labels (CVE-YYYY-NNNNN, GHSA-…, OSV-…)
        // clickable straight through to OSV.dev's canonical record
        // — that's where the operator gets the full summary, CVSS
        // breakdown, every advisory link, and affected/fixed
        // versions in one page. Saves a copy-paste step that
        // operators were doing manually before this.
        const cveLike = /^(CVE-\d{4}-\d{4,}|GHSA-[a-z0-9]{4}(-[a-z0-9]{4}){2}|OSV-\d{4}-\d+|RUSTSEC-\d{4}-\d+)$/i;
        const labelHtml = cveLike.test(e.label)
            ? `<a href="https://osv.dev/vulnerability/${escapeAttr(e.label)}" target="_blank" rel="noopener noreferrer" `
              + `style="color:var(--accent-light,#60a5fa);text-decoration:none;border-bottom:1px dashed var(--accent-light,#60a5fa);" `
              + `title="Open ${escapeAttr(e.label)} on OSV.dev — full summary + advisories">`
              + `${escapeHtml(e.label)} ↗</a>`
            : `<span style="color:var(--text-muted);">${escapeHtml(e.label)}:</span>`;
        return `
        <div style="display:inline-block;background:var(--bg-tertiary,#2d2f3a);padding:4px 10px;border-radius:6px;margin-right:6px;margin-bottom:6px;font-size:12px;">
            ${labelHtml}
            <strong style="color:var(--text-primary);margin-left:4px;">${escapeHtml(e.value)}</strong>
            ${e.detail ? `<span style="color:var(--text-muted);margin-left:8px;font-size:11px;">${escapeHtml(e.detail)}</span>` : ''}
            ${linksHtml}
        </div>
    `;}).join('');
    const remediation = predictiveRemediationHtml(p.remediation, p.id);

    let snoozeNotice = '';
    if (p.status && p.status.kind === 'snoozed') {
        const until = new Date(p.status.until);
        const untilStr = isNaN(until.getTime()) ? p.status.until : until.toLocaleString();
        snoozeNotice = `<div style="background:rgba(96,165,250,0.1);padding:8px 12px;border-radius:6px;font-size:12px;color:#60a5fa;margin-bottom:12px;">Snoozed until ${escapeHtml(untilStr)} — will re-fire after.</div>`;
    }

    return `
        <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-bottom:10px;">
            <span style="background:${runtime.color};color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700;letter-spacing:0.5px;display:inline-flex;align-items:center;gap:4px;">${runtime.icon} ${runtime.label}</span>
            ${sourceBadge}
            <span style="opacity:0.5;font-size:11px;color:var(--text-muted);margin-left:auto;">${escapeHtml(p.finding_type)}</span>
        </div>
        ${snoozeNotice}
        <div style="font-size:13px;color:var(--text-secondary);line-height:1.55;margin-bottom:12px;">${escapeHtml(p.why)}</div>
        ${predictiveHistorySlot(p)}
        ${evidence ? `<div style="margin-bottom:12px;">${evidence}</div>` : ''}
        ${remediation}
        <div style="display:flex;gap:8px;flex-wrap:wrap;">
            <button class="btn btn-sm btn-primary" onclick="predictiveApprove('${escapeAttr(p.id)}')">Mark applied</button>
            <button class="btn btn-sm" onclick="predictiveOpenTerm('${escapeAttr(p.id)}')" title="Open an interactive shell on this proposal's target — host, container, or VM">Open terminal</button>
            <button class="btn btn-sm" onclick="predictiveSnoozeMenu('${escapeAttr(p.id)}', this)">Snooze</button>
            <button class="btn btn-sm" onclick="predictiveDismiss('${escapeAttr(p.id)}')">Dismiss</button>
            <button class="btn btn-sm" onclick="predictiveAck('${escapeAttr(p.finding_type)}', '${escapeAttr(p.scope.node_id)}', '${escapeAttr(p.scope.resource_id || '')}')">Ack as intentional</button>
        </div>
    `;
}

/// Toggle a row's expanded state. Click on a button or input inside
/// the row should NOT toggle — those have their own handlers and
/// have called event.stopPropagation, so we only re-check the
/// composedPath as a defensive measure.
function predictiveToggleExpand(id, ev) {
    if (ev) {
        const t = ev.target;
        if (t && (t.tagName === 'BUTTON' || t.tagName === 'INPUT' || t.closest('button') || t.closest('input'))) return;
    }
    if (predictiveState.expandedIds.has(id)) predictiveState.expandedIds.delete(id);
    else predictiveState.expandedIds.add(id);
    predictiveRender();
}

function predictiveToggleSelect(id, checked) {
    if (checked) predictiveState.selectedIds.add(id);
    else predictiveState.selectedIds.delete(id);
    predictiveUpdateBulkBar();
}

/// Select-all checkbox in the master toolbar — toggles selection for
/// every currently-VISIBLE proposal (so a filter narrows the bulk
/// scope, which matches the operator's mental model).
function predictiveSelectAllVisible(checked) {
    const visible = predictiveCurrentlyVisible();
    if (checked) visible.forEach(p => predictiveState.selectedIds.add(p.id));
    else visible.forEach(p => predictiveState.selectedIds.delete(p.id));
    predictiveRender();
}

/// Returns the proposals matching the current filter — used to scope
/// "select all" and to know what bulk actions apply to.
function predictiveCurrentlyVisible() {
    const all = predictiveState.proposals || [];
    const clusterByNode = {};
    (predictiveState.nodes || []).forEach(n => { clusterByNode[n.node_id] = n.cluster_name || 'WolfStack'; });
    let v = all;
    if (predictiveState.clusterFilter) v = v.filter(p => (clusterByNode[p.scope?.node_id] || 'WolfStack') === predictiveState.clusterFilter);
    if (predictiveState.nodeFilter)    v = v.filter(p => p.scope && p.scope.node_id === predictiveState.nodeFilter);
    return v;
}

function predictiveUpdateBulkBar() {
    const bar = document.getElementById('predictive-bulk-bar');
    if (!bar) return;
    const n = predictiveState.selectedIds.size;
    bar.style.display = n > 0 ? 'flex' : 'none';
    const label = bar.querySelector('.pred-bulk-count');
    if (label) label.textContent = `${n} selected`;
    // Sync the master checkbox: checked when every visible row is
    // selected, indeterminate when some are.
    const master = document.getElementById('predictive-bulk-master');
    if (master) {
        const visible = predictiveCurrentlyVisible();
        const selectedVisible = visible.filter(p => predictiveState.selectedIds.has(p.id)).length;
        master.checked = visible.length > 0 && selectedVisible === visible.length;
        master.indeterminate = selectedVisible > 0 && selectedVisible < visible.length;
    }
    // AUTOFIX button only renders if at least one selected proposal
    // is an update-eligible finding type. Keeps the button absent
    // when the operator's selection is purely informational
    // (snoozes / dismisses) so they can't accidentally fire it.
    const autofixBtn = document.getElementById('predictive-autofix-btn');
    if (autofixBtn) {
        const eligible = predictiveSelectedAutofixable();
        if (eligible.length > 0) {
            autofixBtn.style.display = '';
            autofixBtn.textContent = `AUTOFIX updates (${eligible.length})`;
        } else {
            autofixBtn.style.display = 'none';
        }
    }
}

// ─── AUTOFIX — bulk-run package updates ──────────────────────────
//
// Operator picks a set of "X security updates pending" / OSV-CVE
// findings and clicks AUTOFIX. We loop sequentially through each
// target, opening the inbox terminal on it, running the SUGGESTED
// FIRST REMEDIATION COMMAND ONLY (which for these finding types is
// always the package-manager update path: `apt-get upgrade -y`,
// `dnf upgrade -y`, etc.), then waiting for completion and
// advancing.
//
// Hard scope rules:
//   * Only finding types in PRED_AUTOFIX_TYPES are actioned. Anything
//     else in the selection is left alone.
//   * Only command index 0 is executed — the canonical update line
//     the analyzer recommended. We don't iterate through the full
//     remediation list (some include reboot or service-restart steps
//     that the operator should approve consciously).
//   * Sequential, not parallel, so the operator can watch the
//     terminal and abort if something looks wrong.

const PRED_AUTOFIX_TYPES = new Set([
    'host_security_updates_pending',  // src/predictive/vulnerability.rs:96
    'osv_vulnerability_detected',     // src/predictive/osv.rs:123
]);

function predictiveSelectedAutofixable() {
    const visible = predictiveCurrentlyVisible();
    return visible.filter(p =>
        predictiveState.selectedIds.has(p.id)
        && PRED_AUTOFIX_TYPES.has(p.finding_type)
        && p.remediation
        && Array.isArray(p.remediation.commands)
        && p.remediation.commands.length > 0
        // Skip comment-only first lines — they have no `▶ Run`
        // counterpart in the per-row UI and shouldn't be auto-run.
        && !p.remediation.commands[0].trim().startsWith('#')
    );
}

// ─── Trend graphs ───
//
// For trend-based proposals (disk-fill ETA on host mounts, Docker
// containers, LXC containers) we fetch the rolling sample series
// from the backend and render a small inline SVG sparkline so the
// operator can see how the resource is filling up + a dotted
// projection to the alert threshold. The textual "fills in ~5h" is
// already in the proposal title; the graph adds visual context.
//
// Lazy-fetched per card — the cluster aggregate already returns 30+
// proposals in the worst case and not all of them have history. We
// queue fetches via IntersectionObserver so off-screen graphs don't
// burn requests, and cache results in `predHistoryCache` keyed by
// proposal id so re-renders (badge polling) reuse the data.

const predHistoryCache = new Map(); // proposal_id → { fetchedAt, data }
const PRED_HISTORY_TYPES = new Set([
    'disk_fill_eta',
    'docker_storage_fill_eta',
    'lxc_storage_fill_eta',
]);
const PRED_HISTORY_TTL_MS = 60 * 1000;

function predictiveHistorySlot(p) {
    if (!PRED_HISTORY_TYPES.has(p.finding_type)) return '';
    return `<div class="predictive-history-slot" data-proposal-id="${escapeAttr(p.id)}" style="margin-bottom:12px;min-height:90px;background:rgba(96,165,250,0.04);border:1px solid rgba(96,165,250,0.15);border-radius:8px;padding:8px 10px;">
        <div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;font-weight:600;margin-bottom:6px;">Growth trend</div>
        <div class="predictive-history-body" style="color:var(--text-muted);font-size:12px;text-align:center;padding:14px 0;">Loading history…</div>
    </div>`;
}

async function predictivePopulateHistorySlots() {
    const slots = document.querySelectorAll('.predictive-history-slot[data-proposal-id]');
    for (const slot of slots) {
        // Avoid re-fetching the same slot during a single render pass.
        if (slot.dataset.fetched === '1') continue;
        slot.dataset.fetched = '1';
        const id = slot.dataset.proposalId;
        // Cache hit?
        const cached = predHistoryCache.get(id);
        if (cached && (Date.now() - cached.fetchedAt) < PRED_HISTORY_TTL_MS) {
            predictiveRenderHistorySlot(slot, cached.data);
            continue;
        }
        try {
            const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/history`);
            if (!r.ok) {
                slot.querySelector('.predictive-history-body').textContent = 'Trend data not available.';
                continue;
            }
            const data = await r.json();
            predHistoryCache.set(id, { fetchedAt: Date.now(), data });
            predictiveRenderHistorySlot(slot, data);
        } catch (e) {
            slot.querySelector('.predictive-history-body').textContent = 'Trend data not available.';
        }
    }
}

function predictiveRenderHistorySlot(slot, data) {
    const body = slot.querySelector('.predictive-history-body');
    if (!body) return;
    if (!data || !Array.isArray(data.samples) || data.samples.length < 2) {
        body.innerHTML = `<span style="color:var(--text-muted);">Not enough history yet — analyzer needs ≥3 samples spanning ≥30 minutes.</span>`;
        return;
    }
    body.innerHTML = predictiveHistorySvg(data);
}

/// Build an inline SVG showing the metric trend + a dotted projection
/// to the fill target. Pure function over the API response so a
/// future re-render with cached data doesn't re-fetch.
function predictiveHistorySvg(data) {
    const samples = data.samples || [];
    const target = Number.isFinite(data.fill_target_pct) ? data.fill_target_pct : 95;
    const eta = (typeof data.eta_hours === 'number' && !isNaN(data.eta_hours)) ? data.eta_hours : null;
    const slope = data.slope_per_hour || 0;
    const current = data.current || (samples[samples.length - 1] && samples[samples.length - 1].value) || 0;

    const W = 600, H = 100, PAD_L = 36, PAD_R = 12, PAD_T = 8, PAD_B = 22;

    // X domain: oldest-sample timestamp → projected ETA (or
    // newest-sample if no projection). Y domain: 0..100 (% used).
    const tsFirst = new Date(samples[0].ts).getTime();
    const tsLast  = new Date(samples[samples.length - 1].ts).getTime();
    const tsEta = (eta !== null && eta > 0)
        ? tsLast + eta * 3_600_000
        : tsLast;
    const xMin = tsFirst, xMax = Math.max(tsEta, tsLast + 60_000); // never zero range
    const yMin = 0, yMax = 100;

    const xScale = (t) => PAD_L + ((t - xMin) / (xMax - xMin)) * (W - PAD_L - PAD_R);
    const yScale = (v) => PAD_T + (1 - (v - yMin) / (yMax - yMin)) * (H - PAD_T - PAD_B);

    // History polyline.
    const pts = samples.map(s => `${xScale(new Date(s.ts).getTime()).toFixed(1)},${yScale(s.value).toFixed(1)}`).join(' ');

    // Projection line (newest sample → ETA point at target_pct), only
    // when slope is positive and ETA exists. Drawn dotted.
    let projectionLine = '';
    let etaMarker = '';
    if (eta !== null && eta > 0 && slope > 0) {
        const x1 = xScale(tsLast), y1 = yScale(current);
        const x2 = xScale(tsEta),  y2 = yScale(target);
        projectionLine = `<line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}" stroke="#fbbf24" stroke-width="1.5" stroke-dasharray="4 3" />`;
        etaMarker = `<circle cx="${x2.toFixed(1)}" cy="${y2.toFixed(1)}" r="4" fill="#ef4444" stroke="#0a0a0a" stroke-width="1.5"/>`;
    }

    // Fill-target horizontal line.
    const targetY = yScale(target);
    const targetLine = `<line x1="${PAD_L}" y1="${targetY.toFixed(1)}" x2="${W - PAD_R}" y2="${targetY.toFixed(1)}" stroke="#ef4444" stroke-width="1" stroke-dasharray="2 4" opacity="0.6"/>`;

    // Y-axis ticks at 0, 50, 100.
    const yTick = (v) => `<text x="${PAD_L - 6}" y="${(yScale(v) + 4).toFixed(1)}" font-size="10" fill="#94a3b8" text-anchor="end">${v}%</text>`;
    const yGrid = (v) => `<line x1="${PAD_L}" y1="${yScale(v).toFixed(1)}" x2="${W - PAD_R}" y2="${yScale(v).toFixed(1)}" stroke="#2d2f3a" stroke-width="1" opacity="0.4"/>`;

    // X labels: oldest, newest, ETA (if any).
    const fmtTs = (ms) => {
        const d = new Date(ms);
        const now = Date.now();
        const dayMs = 86_400_000;
        if (Math.abs(now - ms) < dayMs) {
            return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }
        return d.toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
    };
    const xLabel = (t, anchor) => `<text x="${xScale(t).toFixed(1)}" y="${(H - 6)}" font-size="10" fill="#94a3b8" text-anchor="${anchor}">${fmtTs(t)}</text>`;
    const labels = [
        xLabel(tsFirst, 'start'),
        xLabel(tsLast, 'middle'),
        eta !== null && eta > 0 ? xLabel(tsEta, 'end') : '',
    ].join('');

    // Caption — under the graph: slope + ETA in human terms.
    let caption = '';
    if (eta !== null && eta > 0) {
        const etaTxt = eta < 1 ? '<1 h' : eta < 24 ? `~${eta.toFixed(0)} h` : `~${(eta/24).toFixed(1)} d`;
        caption = `<span style="color:var(--text-secondary);">Currently <strong>${current.toFixed(1)}%</strong> · growing <strong>${slope >= 0 ? '+' : ''}${slope.toFixed(2)}%/h</strong> · projected to hit <strong>${target}%</strong> in <strong style="color:#fbbf24;">${etaTxt}</strong></span>`;
    } else if (slope <= 0) {
        caption = `<span style="color:#34d399;">Currently <strong>${current.toFixed(1)}%</strong> · flat or shrinking — no projected fill.</span>`;
    } else {
        caption = `<span style="color:var(--text-secondary);">Currently <strong>${current.toFixed(1)}%</strong> · growth rate <strong>${slope.toFixed(2)}%/h</strong></span>`;
    }

    return `
        <svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="none" style="width:100%;height:120px;display:block;">
            ${[0, 50, 100].map(yGrid).join('')}
            ${targetLine}
            <polyline points="${pts}" fill="none" stroke="#60a5fa" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
            ${projectionLine}
            ${etaMarker}
            ${[0, 50, 100].map(yTick).join('')}
            ${labels}
        </svg>
        <div style="font-size:11px;margin-top:4px;text-align:center;line-height:1.5;">${caption}</div>
    `;
}

function predictiveRemediationHtml(r, proposalId) {
    if (!r) return '';
    if (r.kind === 'manual') {
        const cmds = (r.commands || []).map((cmd, idx) => {
            // Comments and informational lines (lines starting with `#`)
            // get Copy but no Run — running a comment line is silly.
            const isComment = cmd.trim().startsWith('#');
            const runBtn = isComment ? '' :
                `<button class="btn btn-sm btn-primary" style="font-size:11px;padding:2px 8px;flex-shrink:0;" onclick="predictiveRunCmd('${escapeAttr(proposalId)}', ${idx})">▶ Run</button>`;
            return `
                <div style="display:flex;align-items:center;gap:8px;background:var(--bg-tertiary,#2d2f3a);padding:6px 10px;border-radius:6px;margin-bottom:4px;">
                    <code style="flex:1;font-family:var(--font-mono,monospace);font-size:12px;color:var(--text-primary);overflow-x:auto;white-space:nowrap;">${escapeHtml(cmd)}</code>
                    ${runBtn}
                    <button class="btn btn-sm" style="font-size:11px;padding:2px 8px;flex-shrink:0;" onclick="predictiveCopyCmd(this)" data-cmd="${escapeAttr(cmd)}">Copy</button>
                </div>
            `;
        }).join('');
        return `
            <div style="background:var(--bg-secondary,#16181f);padding:12px;border-radius:8px;margin-bottom:12px;border:1px solid var(--border-color,#2d2f3a);">
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px;font-weight:600;">Suggested remediation</div>
                <div style="font-size:13px;color:var(--text-secondary);line-height:1.5;margin-bottom:10px;">${escapeHtml(r.instructions)}</div>
                ${cmds}
            </div>
        `;
    }
    return `<div style="font-size:12px;color:var(--text-muted);font-style:italic;margin-bottom:12px;">[Remediation kind "${escapeHtml(r.kind)}" — UI pending]</div>`;
}

/// Embedded terminal for the Predictive Inbox right pane.
///
/// Holds a single live xterm + WebSocket session at a time. When a
/// proposal's "▶ Run" button is clicked the first time, this opens a
/// host/docker/lxc/vm console on the proposal's target node and
/// auto-runs the indexed command. Subsequent Runs on the SAME
/// proposal re-use the open shell — three non-destructive commands
/// → three lines in one terminal, not three popup windows.
///
/// Cross-cluster: proposals on a peer node use
/// `/ws/remote-console/{nodeId}/...`, which the local server's
/// console proxy already bridges. Federated proposals (different
/// cluster) aren't supported here — same-cluster fan-out only —
/// because we don't have a federation-aware WS proxy. Frontend
/// surfaces that as a clear toast pointing the operator to the
/// originating cluster's dashboard rather than a silent failure.
const predTermState = {
    proposalId: null,
    ws: null,
    term: null,
    fitAddon: null,
    fitHandler: null,
    target: null,
};

async function predictiveRunCmd(proposalId, cmdIdx) {
    // FAST PATH 1 — same proposal, WS already open. Pull the
    // command text from the client-side cache and fire it down the
    // existing WS without a server round-trip. The previous version
    // always fetched metadata first, which made the second/third
    // command on the same proposal feel like a fresh connection
    // (the spinner showed for the duration of the fetch).
    if (predTermState.proposalId === proposalId
        && predTermState.ws && predTermState.ws.readyState === WebSocket.OPEN) {
        const cached = (predictiveState.proposals || []).find(p => p.id === proposalId);
        const cmd = cached && cached.remediation && cached.remediation.commands
            ? cached.remediation.commands[cmdIdx] : null;
        if (cmd) {
            predTermState.ws.send(cmd + '\n');
            if (predTermState.term) predTermState.term.focus();
            return;
        }
        // Fall through to fetch — proposal not in client cache (very
        // recent badge-poll race) or remediation changed.
    }

    // FAST PATH 2 — same proposal, WS still CONNECTING. Don't tear
    // down and start over; queue the command to fire when the
    // existing handshake completes. Otherwise an impatient operator
    // who clicks twice during a slow connect ends up dropping the
    // first attempt and waiting for a second handshake.
    if (predTermState.proposalId === proposalId
        && predTermState.ws && predTermState.ws.readyState === WebSocket.CONNECTING) {
        const cached = (predictiveState.proposals || []).find(p => p.id === proposalId);
        const cmd = cached && cached.remediation && cached.remediation.commands
            ? cached.remediation.commands[cmdIdx] : null;
        if (cmd) {
            predTermState.pendingCommands = predTermState.pendingCommands || [];
            predTermState.pendingCommands.push(cmd);
            return;
        }
    }

    // Slow path — first connect, or different proposal. Spinner ON
    // before the await so the operator gets immediate feedback.
    // Otherwise nothing visible happens between click and WS open
    // (especially noticeable when the proposal lives on a peer:
    // cluster-secret round-trip first, then the WS hop). We also
    // paint a centered overlay into the terminal container itself,
    // so the pane changes within one frame instead of leaving the
    // "Click ▶ Run…" placeholder visible during the fetch.
    predictiveShowTerminalStub('Resolving target…');
    predTermShowSpinner('Resolving target…');
    let meta;
    try {
        const r = await fetch(`/api/proposals/${encodeURIComponent(proposalId)}/command/${encodeURIComponent(cmdIdx)}`);
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            const msg = data.error || r.statusText;
            predTermResetSpinner();
            // Federated proposals: pre-flight returns 404 because the
            // local store + same-cluster fan-out can't reach the
            // origin cluster. Tell the operator clearly instead of
            // a generic "couldn't open".
            if (r.status === 404) {
                showToast(
                    'This proposal lives on a federated cluster — open that cluster\'s dashboard to apply remediations from there.',
                    'warning', 5000,
                );
            } else {
                showToast(`Couldn't open terminal: ${msg}`, 'error');
            }
            return;
        }
        meta = await r.json();
    } catch (e) {
        predTermResetSpinner();
        showToast(`Open terminal errored: ${e.message || String(e)}`, 'error');
        return;
    }

    // Same-proposal re-use: just send the new command to the
    // existing shell. This is the whole point of the rebuild — three
    // non-destructive commands shouldn't open three windows.
    if (predTermState.proposalId === proposalId
        && predTermState.ws && predTermState.ws.readyState === WebSocket.OPEN) {
        predTermResetSpinner();
        predTermState.ws.send(meta.command + '\n');
        if (predTermState.term) predTermState.term.focus();
        return;
    }

    // Different proposal already running → just switch. A toast is
    // less interruptive than a modal for what's a non-destructive
    // action (the previous shell only had non-destructive commands
    // run in it; the operator can re-open it via Run on its proposal
    // again).
    if (predTermState.proposalId && predTermState.proposalId !== proposalId) {
        const where = meta.node_hostname || meta.console_name || 'target';
        showToast(`Switching terminal to ${where}`, 'info', 1800);
    }

    predTermClose();
    predTermOpen(proposalId, meta);
}

function predTermOpen(proposalId, meta) {
    const container = document.getElementById('predictive-term-container');
    if (!container) return;
    if (typeof Terminal === 'undefined') {
        showToast('xterm.js failed to load — refresh the page.', 'error');
        return;
    }
    // Reveal the terminal pane on phones (hidden by default; see the
    // `.term-active` rules in the inbox media query above). On desktop
    // this class is harmless — the terminal pane is already visible.
    const split = document.querySelector('.predictive-split');
    if (split) split.classList.add('term-active');
    container.innerHTML = '';

    const term = new Terminal({
        cursorBlink: true,
        fontSize: 13,
        fontFamily: '"JetBrains Mono", "Fira Code", "Cascadia Code", "Courier New", monospace',
        theme: { background: '#0a0a0a', foreground: '#f0f0f0', cursor: '#10b981', selectionBackground: 'rgba(16,185,129,0.3)' },
        scrollback: 5000,
        // disableStdin lets us write commands programmatically while
        // still allowing the operator to type. xterm interprets it as
        // a render-only flag; we need it FALSE so user keystrokes
        // reach the WS via term.onData below. Default is fine —
        // explicit here for clarity.
        disableStdin: false,
    });
    let fitAddon = null;
    if (typeof FitAddon !== 'undefined') {
        fitAddon = new FitAddon.FitAddon();
        term.loadAddon(fitAddon);
    }
    term.open(container);
    // FitAddon computes row count from the FALLBACK monospace font's
    // cell-height when xterm.open() runs, because JetBrains Mono /
    // Fira Code haven't necessarily loaded yet. Once they do load,
    // xterm reflows but doesn't refit — leaving the bottom row
    // partially clipped under the container's edge. Re-fitting on
    // `document.fonts.ready` and again after a settle delay catches
    // the load + final-layout case. The 50ms call covers the
    // synchronous-layout case for browsers that have the font
    // cached.
    const refit = () => { try { fitAddon && fitAddon.fit(); } catch (_) {} };
    setTimeout(refit, 50);
    setTimeout(refit, 250);
    if (document.fonts && document.fonts.ready) {
        document.fonts.ready.then(refit).catch(() => {});
    }

    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const isRemote = !!meta.remote_node_id;
    const wsUrl = isRemote
        ? `${protocol}//${window.location.host}/ws/remote-console/${encodeURIComponent(meta.remote_node_id)}/${encodeURIComponent(meta.console_type)}/${encodeURIComponent(meta.console_name)}`
        : `${protocol}//${window.location.host}/ws/console/${encodeURIComponent(meta.console_type)}/${encodeURIComponent(meta.console_name)}`;

    // Show the spinner (and hide the static 💻 icon) while the WS
    // negotiates — for a remote-console hop through the cluster
    // proxy this can take a noticeable second on a slow link.
    const spinner = document.getElementById('predictive-term-spinner');
    const icon    = document.getElementById('predictive-term-icon');
    if (spinner) spinner.style.display = '';
    if (icon)    icon.style.display    = 'none';

    const where = meta.node_hostname || meta.console_name;
    term.writeln(`\x1b[90m● Connecting to ${meta.console_type} on ${where}…\x1b[0m`);

    // Prominent centered overlay so the connect doesn't look hung.
    // The terminal's static "Connecting…" line plus the small status
    // bar spinner weren't visible enough on a slow remote-console
    // hop — the operator perceived a frozen terminal. This overlay
    // sits absolutely positioned over the terminal viewport and is
    // removed on ws.onopen / onclose / onerror.
    container.style.position = 'relative';
    const overlay = document.createElement('div');
    overlay.id = 'predictive-term-loading-overlay';
    overlay.style.cssText = 'position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px;background:rgba(10,10,10,0.85);backdrop-filter:blur(2px);z-index:5;color:#9ca3af;font-size:13px;pointer-events:none;';
    overlay.innerHTML = `
        <div style="width:36px;height:36px;border:3px solid rgba(96,165,250,0.25);border-top-color:#60a5fa;border-radius:50%;animation:predTermSpin 0.8s linear infinite;"></div>
        <div>Connecting to <strong style="color:#e5e7eb;">${escapeHtml(where)}</strong>…</div>
        <div style="font-size:11px;opacity:0.7;max-width:280px;text-align:center;">Cross-cluster connections route through the local cluster's proxy and may take a moment.</div>
    `;
    container.appendChild(overlay);

    const ws = new WebSocket(wsUrl);
    ws.binaryType = 'arraybuffer';
    ws.onopen = () => {
        if (spinner) spinner.style.display = 'none';
        if (icon)    icon.style.display    = '';
        // Hide the centered loading overlay (added below for visible
        // feedback during connect).
        const overlay = document.getElementById('predictive-term-loading-overlay');
        if (overlay) overlay.remove();
        term.writeln('\x1b[32m● Connected\x1b[0m');
        // Auto-run the requested remediation command if one was
        // supplied. Empty meta.command (e.g. from the "Open terminal"
        // button) leaves the operator at a clean prompt to poke
        // around manually. Append \n so the shell executes the
        // command instead of just buffering.
        if (meta.command) {
            ws.send(meta.command + '\n');
        }
        // Drain any commands the operator queued by clicking Run
        // additional times while the WS was still CONNECTING (fast
        // path 2 in predictiveRunCmd).
        if (Array.isArray(predTermState.pendingCommands)) {
            for (const cmd of predTermState.pendingCommands) {
                ws.send(cmd + '\n');
            }
            predTermState.pendingCommands = [];
        }
        try { fitAddon && fitAddon.fit(); } catch (_) {}
        term.focus();
    };
    ws.onmessage = (event) => {
        if (typeof event.data === 'string') term.write(event.data);
        else term.write(new Uint8Array(event.data));
    };
    ws.onclose = () => {
        if (spinner) spinner.style.display = 'none';
        if (icon)    icon.style.display    = '';
        const ov = document.getElementById('predictive-term-loading-overlay');
        if (ov) ov.remove();
        term.writeln('\r\n\x1b[31m● Disconnected\x1b[0m');
    };
    ws.onerror = () => {
        if (spinner) spinner.style.display = 'none';
        if (icon)    icon.style.display    = '';
        const ov = document.getElementById('predictive-term-loading-overlay');
        if (ov) ov.remove();
        term.writeln('\r\n\x1b[31m● Connection error — check the target node is online and try again.\x1b[0m');
    };
    term.onData(d => { if (ws.readyState === WebSocket.OPEN) ws.send(d); });

    const fitHandler = () => { try { fitAddon && fitAddon.fit(); } catch (_) {} };
    window.addEventListener('resize', fitHandler);

    predTermState.proposalId = proposalId;
    predTermState.ws = ws;
    predTermState.term = term;
    predTermState.fitAddon = fitAddon;
    predTermState.fitHandler = fitHandler;
    predTermState.target = meta;

    const status = document.getElementById('predictive-term-status');
    if (status) {
        // Prefer the friendly hostname the backend looked up; fall
        // back to console_name only if it's missing (older WolfStack
        // peer that doesn't yet return node_hostname).
        const host = meta.node_hostname || meta.console_name;
        const ctx  = meta.console_type === 'host' ? host
                  : `${meta.console_type}: ${meta.console_name} on ${host}`;
        status.textContent = `${meta.title || 'proposal'} → ${ctx}`;
        status.style.color = '';
    }
    const closeBtn = document.getElementById('predictive-term-close');
    if (closeBtn) closeBtn.style.display = '';
}

/// Pin #page-inbox's pixel height to the actual space available
/// inside `.main-content` BELOW the sticky top-bar (and any other
/// preceding sibling), re-syncing on window resize and on layout
/// shifts inside `.main-content` (sidebar collapse, theme switch,
/// task-log toggle).
///
/// Why measure dynamically: `.main-content` uses min-height /
/// max-height (not height), so percentage heights on children
/// resolve to `auto`. AND its first child is `<header class="top-bar">`,
/// which is in normal flow — naive `clientHeight` includes that
/// header's footprint, so sizing #page-inbox to clientHeight pushes
/// the terminal pane below the viewport bottom by the header's
/// height. Computing the remaining space relative to inbox's actual
/// top edge handles both issues at once and adapts to theme tweaks
/// of the top-bar.
function predictiveSetupHeightSync(inbox) {
    const main = document.querySelector('.main-content');
    if (!main) return;
    const apply = () => {
        // Reset any previous height so we measure inbox's natural
        // top position (its top is determined by what's above it,
        // not by its own height — but resetting first eliminates
        // any cached value affecting subsequent measurements).
        inbox.style.height = '';
        const mainRect  = main.getBoundingClientRect();
        const inboxRect = inbox.getBoundingClientRect();
        // Distance from inbox's top to main's content bottom.
        // main.clientHeight excludes any horizontal scrollbar but
        // not borders; mainRect.top + clientHeight is the bottom
        // edge of the content area.
        const inboxTopWithinMain = inboxRect.top - mainRect.top;
        const h = Math.max(200, main.clientHeight - inboxTopWithinMain);
        inbox.style.height = h + 'px';
    };
    apply();
    // Re-apply on a future paint to catch the case where this fires
    // before .main-content has finished its own layout pass.
    requestAnimationFrame(apply);

    // Already wired up on a previous render — don't double-attach.
    if (inbox._predHeightSync) return;
    inbox._predHeightSync = true;

    if (typeof ResizeObserver !== 'undefined') {
        const ro = new ResizeObserver(apply);
        ro.observe(main);
        inbox._predHeightObserver = ro;
    }
    // Window resize covers viewport changes that don't trigger a
    // .main-content size change directly (e.g. mobile browser
    // address bar showing/hiding).
    window.addEventListener('resize', apply);
    inbox._predHeightApply = apply;
}

/// Paint an immediate "Resolving…" / "Connecting…" overlay into
/// the terminal container BEFORE the metadata fetch runs, so the
/// pane visibly reacts to a click within one frame instead of
/// waiting for the cluster-proxy round-trip + WS handshake. Without
/// this the operator sees the static "Click ▶ Run…" placeholder
/// the whole time and concludes the click was lost.
///
/// Replaced as soon as predTermOpen() runs `container.innerHTML = ''`
/// to host xterm — no cleanup needed beyond that.
function predictiveShowTerminalStub(message) {
    const container = document.getElementById('predictive-term-container');
    if (!container) return;
    // Mark the split container as term-active so the mobile media
    // query reveals the terminal pane (it's hidden by default on
    // phones to stop a fixed-height terminal squeezing the list).
    const split = document.querySelector('.predictive-split');
    if (split) split.classList.add('term-active');
    container.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px;height:100%;color:#9ca3af;font-size:13px;text-align:center;padding:20px;">
            <div style="width:36px;height:36px;border:3px solid rgba(96,165,250,0.25);border-top-color:#60a5fa;border-radius:50%;animation:predTermSpin 0.8s linear infinite;"></div>
            <div>${escapeHtml(message || 'Connecting…')}</div>
        </div>
    `;
}

/// Show the inline spinner with a status message — used to give
/// immediate feedback while the metadata fetch is in flight, before
/// the WS even starts negotiating. Caller is responsible for
/// hiding it again on success (predTermOpen handles that on WS
/// open / close / error) or on early return (predTermResetSpinner).
function predTermShowSpinner(message) {
    const spinner = document.getElementById('predictive-term-spinner');
    const icon    = document.getElementById('predictive-term-icon');
    const status  = document.getElementById('predictive-term-status');
    if (spinner) spinner.style.display = '';
    if (icon)    icon.style.display    = 'none';
    if (status) {
        status.textContent = message || 'Connecting…';
        status.style.color = '';
    }
}

/// Hide the spinner without otherwise touching session state. Called
/// on early-return paths (fetch errors, federated 404s) so the
/// header doesn't keep spinning forever.
function predTermResetSpinner() {
    const spinner = document.getElementById('predictive-term-spinner');
    const icon    = document.getElementById('predictive-term-icon');
    if (spinner) spinner.style.display = 'none';
    if (icon)    icon.style.display    = '';
    // If no session is live, restore the idle status text.
    if (!predTermState.proposalId) {
        const status = document.getElementById('predictive-term-status');
        if (status) {
            status.textContent = 'No active terminal';
            status.style.color = 'var(--text-muted)';
        }
    }
}

/// "Open terminal" button on a proposal — same pane, same connection
/// model as predictiveRunCmd, but no command auto-runs. Operator
/// drops at a clean prompt on the proposal's actual target (host /
/// docker exec / lxc-attach / vm serial), so they can investigate or
/// remediate manually without leaving the inbox.
async function predictiveOpenTerm(proposalId) {
    // Visible stub BEFORE the metadata fetch so the operator sees the
    // terminal pane react inside one frame. The fetch can take 500ms
    // ‑ 2 s on a peer node (cluster proxy hop), and the previous
    // code only flipped the small header spinner — the pane's
    // contents stayed at "Click ▶ Run…" the whole time, which read
    // as a frozen click. We paint a centered spinner + status
    // immediately, then let the fetch + WS handshake replace it.
    predictiveShowTerminalStub('Resolving target…');
    predTermShowSpinner('Resolving target…');
    let meta;
    try {
        const r = await fetch(`/api/proposals/${encodeURIComponent(proposalId)}/console-target`);
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            predTermResetSpinner();
            if (r.status === 404) {
                showToast(
                    'This proposal lives on a federated cluster — open that cluster\'s dashboard to access its terminal.',
                    'warning', 5000,
                );
            } else {
                showToast(`Couldn't open terminal: ${data.error || r.statusText}`, 'error');
            }
            return;
        }
        meta = await r.json();
    } catch (e) {
        predTermResetSpinner();
        showToast(`Open terminal errored: ${e.message || String(e)}`, 'error');
        return;
    }

    // Same proposal already open → just focus, don't tear down.
    if (predTermState.proposalId === proposalId
        && predTermState.ws && predTermState.ws.readyState === WebSocket.OPEN) {
        predTermResetSpinner();
        if (predTermState.term) predTermState.term.focus();
        return;
    }
    if (predTermState.proposalId && predTermState.proposalId !== proposalId) {
        const where = meta.node_hostname || meta.console_name || 'target';
        showToast(`Switching terminal to ${where}`, 'info', 1800);
    }
    predTermClose();
    // Empty `command` so predTermOpen doesn't auto-send anything.
    predTermOpen(proposalId, { ...meta, command: '' });
}

function predTermClose() {
    if (predTermState.ws) {
        try { predTermState.ws.close(); } catch (_) {}
    }
    if (predTermState.term) {
        try { predTermState.term.dispose(); } catch (_) {}
    }
    if (predTermState.fitHandler) {
        window.removeEventListener('resize', predTermState.fitHandler);
    }
    predTermState.proposalId = null;
    predTermState.ws = null;
    predTermState.term = null;
    predTermState.fitAddon = null;
    predTermState.fitHandler = null;
    predTermState.target = null;
    predTermState.pendingCommands = [];
    const overlay = document.getElementById('predictive-term-loading-overlay');
    if (overlay) overlay.remove();

    const status = document.getElementById('predictive-term-status');
    if (status) {
        status.textContent = 'No active terminal';
        status.style.color = 'var(--text-muted)';
    }
    const spinner = document.getElementById('predictive-term-spinner');
    const icon    = document.getElementById('predictive-term-icon');
    if (spinner) spinner.style.display = 'none';
    if (icon)    icon.style.display    = '';
    const closeBtn = document.getElementById('predictive-term-close');
    if (closeBtn) closeBtn.style.display = 'none';
    // Hand the screen back to the proposals list on phones — without
    // this the terminal pane stays mounted (and visible) after Close.
    const split = document.querySelector('.predictive-split');
    if (split) split.classList.remove('term-active');
    const container = document.getElementById('predictive-term-container');
    if (container) {
        container.innerHTML = `
            <div style="color:var(--text-muted);padding:24px;text-align:center;font-size:13px;line-height:1.6;">
                Click <strong>▶ Run</strong> on a remediation command to open a terminal here.<br>
                <span style="font-size:11px;opacity:0.7;">Multiple commands from the same proposal share the session — no more 3-popup workflows.</span>
            </div>
        `;
    }
}

function predictiveCopyCmd(btn) {
    const cmd = btn.dataset.cmd || '';
    navigator.clipboard.writeText(cmd).then(
        () => showToast('Command copied', 'success', 1500),
        () => showToast('Clipboard write failed', 'error'),
    );
}

function predictiveSnoozeMenu(id, btn) {
    const existing = document.getElementById('predictive-snooze-menu');
    if (existing) existing.remove();
    const menu = document.createElement('div');
    menu.id = 'predictive-snooze-menu';
    menu.style.cssText = 'position:absolute;background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;padding:6px;box-shadow:0 8px 24px rgba(0,0,0,0.5);z-index:1000;min-width:140px;';
    const opts = [['4 hours', 4], ['24 hours', 24], ['1 week', 168], ['30 days', 720]];
    menu.innerHTML = opts.map(([label, h]) =>
        `<button class="btn btn-sm" style="display:block;width:100%;text-align:left;margin-bottom:2px;background:transparent;" onclick="predictiveSnooze('${escapeAttr(id)}', ${h})">${label}</button>`
    ).join('');
    document.body.appendChild(menu);
    const r = btn.getBoundingClientRect();
    menu.style.top = (r.bottom + window.scrollY + 4) + 'px';
    menu.style.left = (r.left + window.scrollX) + 'px';
    setTimeout(() => {
        const close = (e) => {
            if (!menu.contains(e.target) && e.target !== btn) {
                menu.remove();
                document.removeEventListener('click', close);
            }
        };
        document.addEventListener('click', close);
    }, 50);
}

async function predictiveSnooze(id, hours) {
    document.getElementById('predictive-snooze-menu')?.remove();
    // Optimistic UI: same pattern as dismiss. Note that
    // `predictiveOptimisticRemove` is defined further down — JS
    // function declarations are hoisted, so the forward reference is
    // safe.
    const point = predictiveOptimisticRemove(id);
    showToast(`Snoozed for ${hours} hour${hours === 1 ? '' : 's'}`, 'success', 2000);
    try {
        const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/snooze`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ hours }),
        });
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            predictiveOptimisticRestore(point);
            showToast(`Snooze failed: ${data.error || r.statusText}`, 'error');
        }
    } catch (e) {
        predictiveOptimisticRestore(point);
        showToast(`Snooze errored: ${e.message || String(e)}`, 'error');
    }
}

/// Optimistic-remove helper for inbox actions (dismiss / approve /
/// snooze / ack). The cluster-aggregate POST + fan-out to peers +
/// federations can take several seconds; waiting for it before
/// updating the UI made operators think the click had been lost.
/// We now drop the proposal locally + re-render, fire the API in
/// the background, and restore on failure.
///
/// Returns a "restore point" the caller can pass back to
/// `predictiveOptimisticRestore` if the API call fails.
function predictiveOptimisticRemove(id, opts) {
    const silent = opts && opts.silent;
    const list = predictiveState.proposals || [];
    const idx = list.findIndex(p => p.id === id);
    let removed = null;
    if (idx >= 0) {
        removed = list[idx];
        list.splice(idx, 1);
        if (!silent) {
            predictiveRender();
            predictiveBadgeUpdate();
        }
    }
    return { idx, removed };
}

function predictiveOptimisticRestore(point, opts) {
    const silent = opts && opts.silent;
    if (!point || !point.removed || point.idx < 0) return;
    const list = predictiveState.proposals || [];
    // Insert at the original index, but cap to current length in
    // case the list has shrunk further from another action.
    const insertAt = Math.min(point.idx, list.length);
    list.splice(insertAt, 0, point.removed);
    if (!silent) {
        predictiveRender();
        predictiveBadgeUpdate();
    }
}

async function predictiveDismiss(id) {
    const reason = await showPrompt(
        'Why are you dismissing this proposal? The reason is logged for the audit trail and helps the analyzer learn (eg. "false positive — this disk fills weekly and a cron clears it").',
        'Dismiss proposal',
        '',
    );
    if (reason === null) return;  // cancelled
    if (!reason.trim()) {
        showToast('A reason is required so the dismissal is auditable', 'warning', 3500);
        return;
    }
    // Optimistic UI: remove now, restore if the API rejects.
    const point = predictiveOptimisticRemove(id);
    showToast('Dismissed', 'success', 1500);
    try {
        const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/dismiss`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ reason: reason.trim() }),
        });
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            predictiveOptimisticRestore(point);
            showToast(`Dismiss failed: ${data.error || r.statusText}`, 'error');
        }
    } catch (e) {
        predictiveOptimisticRestore(point);
        showToast(`Dismiss errored: ${e.message || String(e)}`, 'error');
    }
}

/// Mark applied — instant action with a 6 s Undo window. The
/// previous flow showed a confirm modal first, which (with the
/// 150 ms fade-in) felt like a lag on every single click. The
/// outcome is non-destructive (just records that the operator
/// ran the remediation), so a Gmail-style "did, with undo"
/// pattern is the right tradeoff: zero clicks before the row
/// disappears, recoverable for 6 s if it was a mis-click.
async function predictiveApprove(id) {
    // Hold the network call for `undoWindowMs`. If the operator hits
    // Undo we restore the row and never fire the request. If the
    // window elapses, we fire — at that point the toast has gone and
    // there's no longer a way to recover client-side.
    //
    // Track the id in `pendingUndoIds` for the duration of the
    // window so the 60s badge poll doesn't re-introduce the row from
    // a cluster snapshot taken before the deferred POST landed.
    const undoWindowMs = 6000;
    const point = predictiveOptimisticRemove(id);
    predictiveState.pendingUndoIds.add(id);
    let undone = false;
    showUndoToast(
        'Marked applied',
        'Undo',
        undoWindowMs,
        () => {
            undone = true;
            predictiveState.pendingUndoIds.delete(id);
            predictiveOptimisticRestore(point);
        },
    );
    setTimeout(async () => {
        if (undone) return;
        try {
            const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/approve`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
            });
            if (!r.ok) {
                const data = await r.json().catch(() => ({}));
                predictiveOptimisticRestore(point);
                showToast(`Mark applied failed: ${data.error || r.statusText}`, 'error');
            }
        } catch (e) {
            predictiveOptimisticRestore(point);
            showToast(`Mark applied errored: ${e.message || String(e)}`, 'error');
        } finally {
            // Always clear the undo flag — successful POST means the
            // server agrees the row is gone (so badge poll won't
            // return it anyway), and a failed POST has already
            // restored the row (so we WANT future polls to keep it).
            predictiveState.pendingUndoIds.delete(id);
        }
    }, undoWindowMs);
}

/// Toast with an inline action button — used by Mark applied so the
/// operator can recover from a mis-click within `windowMs`. Built on
/// top of showToast (so positioning + dismiss-X stay consistent),
/// then we swap the auto-text-escaped message span for our own
/// markup containing the action button.
///
/// The callback runs at most once even if the operator double-
/// clicks. `windowMs` doubles as the toast's auto-hide duration —
/// the toast and the undo window share the same timer, so once the
/// toast slides away the action is no longer recoverable.
function showUndoToast(message, actionLabel, windowMs, onAction) {
    const id = `pred-undo-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    showToast(message, 'success', windowMs, id);
    let fired = false;
    // showToast text-escapes the message via msgSpan.textContent. We
    // need a real button beside it, so we locate the toast we just
    // created (by id) and append the button to its .toast-message
    // span. requestAnimationFrame defers until showToast has finished
    // building the toast node.
    requestAnimationFrame(() => {
        const node = document.getElementById(id);
        if (!node) return;
        const msg = node.querySelector('.toast-message');
        if (!msg) return;
        const btn = document.createElement('button');
        btn.textContent = actionLabel;
        btn.style.cssText = 'margin-left:10px;background:transparent;border:1px solid currentColor;color:inherit;padding:2px 10px;border-radius:4px;font-size:12px;font-weight:600;cursor:pointer;';
        btn.onclick = (e) => {
            e.stopPropagation();
            if (fired) return;
            fired = true;
            try { if (typeof onAction === 'function') onAction(); } finally {
                if (node.parentNode) node.parentNode.removeChild(node);
            }
        };
        msg.appendChild(btn);
    });
}

/// Bulk handlers — fan out the existing per-id endpoints, optimistic-
/// remove every selected row up front, restore on per-id failure.
/// We accept that a partial failure (one of N) leaves the rest
/// removed; the operator sees a per-id error toast and the failed
/// row reappears on the next badge poll anyway.
async function predictiveBulkApprove() {
    const ids = Array.from(predictiveState.selectedIds);
    if (ids.length === 0) return;
    predictiveState.selectedIds.clear();
    // Silent splice in a tight loop, then ONE render — beats N
    // separate renders when the operator selects 20+ rows.
    const points = ids.map(id => ({ id, point: predictiveOptimisticRemove(id, { silent: true }) }));
    // Track every id in pendingUndoIds so the badge poll doesn't
    // re-introduce any of them mid-window. See predictiveApprove for
    // the rationale; same pattern, fan-out to N ids.
    ids.forEach(id => predictiveState.pendingUndoIds.add(id));
    predictiveRender();
    predictiveBadgeUpdate();
    const undoWindowMs = 6000;
    let undone = false;
    showUndoToast(
        `Marked ${ids.length} applied`,
        'Undo',
        undoWindowMs,
        () => {
            undone = true;
            ids.forEach(id => predictiveState.pendingUndoIds.delete(id));
            points.forEach(p => predictiveOptimisticRestore(p.point, { silent: true }));
            predictiveRender();
            predictiveBadgeUpdate();
        },
    );
    setTimeout(async () => {
        if (undone) return;
        let fails = 0;
        for (const { id, point } of points) {
            try {
                const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/approve`, { method: 'POST' });
                if (!r.ok) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
            } catch (_) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
        }
        // Clear the undo flags — succeeded ids are gone server-side,
        // failed ids have been restored locally.
        ids.forEach(id => predictiveState.pendingUndoIds.delete(id));
        if (fails > 0) {
            showToast(`${fails} of ${ids.length} approvals failed`, 'error');
            predictiveRender();
            predictiveBadgeUpdate();
        }
    }, undoWindowMs);
}

async function predictiveBulkSnooze(hours) {
    const ids = Array.from(predictiveState.selectedIds);
    if (ids.length === 0) return;
    predictiveState.selectedIds.clear();
    const points = ids.map(id => ({ id, point: predictiveOptimisticRemove(id, { silent: true }) }));
    predictiveRender();
    predictiveBadgeUpdate();
    showToast(`Snoozed ${ids.length} for ${hours === 168 ? '1 week' : hours + ' hours'}`, 'success', 2000);
    let fails = 0;
    for (const { id, point } of points) {
        try {
            const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/snooze`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ hours }),
            });
            if (!r.ok) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
        } catch (_) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
    }
    if (fails > 0) {
        showToast(`${fails} of ${ids.length} snoozes failed`, 'error');
        predictiveRender();
        predictiveBadgeUpdate();
    }
}

async function predictiveBulkDismiss() {
    const ids = Array.from(predictiveState.selectedIds);
    if (ids.length === 0) return;
    const reason = await showPrompt(
        `Why are you dismissing these ${ids.length} proposals? The same reason is logged on each for the audit trail.`,
        `Dismiss ${ids.length} proposals`,
        '',
    );
    if (reason === null) return;
    if (!reason.trim()) {
        showToast('A reason is required so the dismissals are auditable', 'warning', 3500);
        return;
    }
    predictiveState.selectedIds.clear();
    const points = ids.map(id => ({ id, point: predictiveOptimisticRemove(id, { silent: true }) }));
    predictiveRender();
    predictiveBadgeUpdate();
    showToast(`Dismissed ${ids.length}`, 'success', 1500);
    let fails = 0;
    for (const { id, point } of points) {
        try {
            const r = await fetch(`/api/proposals/${encodeURIComponent(id)}/dismiss`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ reason: reason.trim() }),
            });
            if (!r.ok) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
        } catch (_) { predictiveOptimisticRestore(point, { silent: true }); fails++; }
    }
    if (fails > 0) {
        showToast(`${fails} of ${ids.length} dismissals failed`, 'error');
        predictiveRender();
        predictiveBadgeUpdate();
    }
}

function predictiveClearSelection() {
    predictiveState.selectedIds.clear();
    predictiveRender();
}

// ─── AUTOFIX runner ───────────────────────────────────────────────
//
// Sequential per-target loop. On each tick:
//
//   1. Show a progress toast ("Updating server N of M: hostname").
//   2. Fetch /api/proposals/{id}/command/0 to get the console
//      target metadata (node id, console type/name) AND the literal
//      remediation command the analyzer chose.
//   3. Append a sentinel echo to the command — `; printf
//      "\n__WSAFXDONE_<id>__\n"`. The shell prints the sentinel
//      after the update finishes, regardless of exit code.
//   4. Tear down any existing terminal session (different proposal
//      from the previous tick), open a fresh one with the combined
//      command, and wrap ws.onmessage to feed a buffer.
//   5. Wait for the sentinel in the buffer, with a 15-min ceiling
//      per target (apt/dnf upgrades are usually under 5 min but
//      slow networks / large queues can stretch).
//
// If a target's WS won't open, or the sentinel never appears, we
// surface a toast, leave the terminal as-is so the operator can
// inspect, and move on to the next target. Same shape as the
// existing predictiveBulkApprove fan-out: one bad target shouldn't
// abort the whole run.
async function predictiveAutofixSelected() {
    const eligible = predictiveSelectedAutofixable();
    if (eligible.length === 0) {
        showToast('No selected items are update-eligible. AUTOFIX only runs on host_security_updates_pending and osv_vulnerability_detected findings.', 'warning', 5000);
        return;
    }

    // Confirm popup with the safety scope spelled out + the list of
    // targets. Plain `confirm()` matches the existing
    // predictiveBulkDismiss flow and keeps us inside the SPA without
    // pulling in another modal layer.
    const lines = eligible.map((p, i) => {
        const where = predictiveLocator(p);
        const host = where.host || p.scope.node_id;
        const cmd0 = (p.remediation.commands[0] || '').trim();
        const truncCmd = cmd0.length > 70 ? cmd0.slice(0, 67) + '…' : cmd0;
        return `  ${i + 1}. ${host}  ·  ${truncCmd}`;
    }).join('\n');
    const ok = confirm(
        `AUTOFIX — run package updates on ${eligible.length} target${eligible.length === 1 ? '' : 's'}\n\n` +
        `WHAT WILL HAPPEN\n` +
        `  • Each target's terminal opens in turn (you can watch).\n` +
        `  • Only the analyzer's first remediation command runs — \n` +
        `    typically apt-get upgrade -y or dnf upgrade -y.\n` +
        `  • NOTHING ELSE is touched. No service restarts, no reboots,\n` +
        `    no config changes. Just package updates.\n` +
        `  • Sequential — one target finishes before the next starts.\n\n` +
        `TARGETS\n${lines}\n\n` +
        `Continue?`
    );
    if (!ok) return;

    let succeeded = 0, failed = 0;
    for (let i = 0; i < eligible.length; i++) {
        const p = eligible[i];
        const where = predictiveLocator(p);
        const host = where.host || p.scope.node_id;
        showToast(`AUTOFIX ${i + 1}/${eligible.length} — updating ${host}…`, 'info', 3500);
        try {
            await predictiveAutofixOne(p);
            succeeded++;
        } catch (e) {
            failed++;
            showToast(`AUTOFIX failed on ${host}: ${e.message || e}`, 'error', 6000);
            // Continue to next target — we don't tear down the
            // overall run on a single failure. The terminal stays
            // visible with whatever output the failed target left,
            // so the operator can inspect when the run completes.
        }
    }
    const summary = failed === 0
        ? `AUTOFIX complete — ${succeeded} target${succeeded === 1 ? '' : 's'} updated.`
        : `AUTOFIX finished — ${succeeded} ok, ${failed} failed (see terminal output).`;
    showToast(summary, failed === 0 ? 'success' : 'warning', 6000);
    // Refresh the inbox so successfully-updated targets reflect
    // their new state on the next analyzer cycle (the proposal
    // itself stays until the analyzer re-samples and confirms the
    // updates landed; this just pulls the latest state).
    if (typeof predictiveLoad === 'function') {
        try { await predictiveLoad(); } catch (_) {}
    }
}

/// Run AUTOFIX against a single proposal. Returns when the sentinel
/// appears in the terminal buffer, or rejects on timeout / failure.
function predictiveAutofixOne(p) {
    return new Promise(async (resolve, reject) => {
        // Resolve the proposal's console target via the same endpoint
        // the regular ▶ Run path uses, so we get the same auth /
        // remote-console hop / console_name resolution semantics.
        let meta;
        try {
            const r = await fetch(`/api/proposals/${encodeURIComponent(p.id)}/command/0`);
            if (!r.ok) {
                const data = await r.json().catch(() => ({}));
                return reject(new Error(data.error || `HTTP ${r.status} resolving target`));
            }
            meta = await r.json();
        } catch (e) {
            return reject(new Error(`couldn't resolve target: ${e.message || e}`));
        }
        if (!meta || !meta.command) {
            return reject(new Error('proposal returned no command to run'));
        }

        // Sentinel marker — pool a per-proposal id into the string so
        // a leftover from a previous target can't false-trigger ours.
        const sentinel = `__WSAFXDONE_${p.id.replace(/[^A-Za-z0-9_-]/g, '')}__`;
        // `; printf …\n` so the sentinel prints whether the update
        // exited 0 or non-zero (operator still sees the failure in
        // the terminal — we just want to know the command finished).
        const wrapped = `${meta.command} ; printf '\\n${sentinel}\\n'`;

        // Tear down any prior session (previous AUTOFIX target or a
        // manual ▶ Run from earlier) so the new target opens cleanly.
        if (predTermState.proposalId && predTermState.proposalId !== p.id) {
            predTermClose();
        }

        // Reuse predictiveShowTerminalStub for the immediate-feedback
        // overlay so the right pane visibly switches to the new
        // target within one frame.
        predictiveShowTerminalStub('Connecting…');
        predTermShowSpinner('Connecting…');

        // Open the terminal with the wrapped command. predTermOpen
        // sets predTermState.ws synchronously, so we can wrap
        // .onmessage immediately after.
        predTermOpen(p.id, { ...meta, command: wrapped });

        if (!predTermState.ws) {
            return reject(new Error('terminal failed to open — see toast'));
        }

        // Wrap ws.onmessage so the original (xterm write) still fires
        // AND we accumulate text into a buffer to scan for the sentinel.
        const ws = predTermState.ws;
        const origOnMessage = ws.onmessage;
        let buffer = '';
        let settled = false;
        const TIMEOUT_MS = 15 * 60 * 1000;  // 15 min per target
        const timeoutId = setTimeout(() => {
            if (settled) return;
            settled = true;
            ws.onmessage = origOnMessage;
            reject(new Error(`timed out after 15 min waiting for update to finish`));
        }, TIMEOUT_MS);

        // Also reject if the WS closes before the sentinel arrives —
        // that means the target shell died, not that the update is
        // done. predTermOpen already writes "● Disconnected" to the
        // term so the operator sees what happened.
        const origOnClose = ws.onclose;
        ws.onclose = (ev) => {
            try { origOnClose && origOnClose.call(ws, ev); } catch (_) {}
            if (settled) return;
            settled = true;
            clearTimeout(timeoutId);
            reject(new Error('terminal closed before update finished'));
        };

        ws.onmessage = (ev) => {
            try { origOnMessage && origOnMessage.call(ws, ev); } catch (_) {}
            if (settled) return;
            // Most console WS messages are strings; remote-console
            // hops can deliver ArrayBuffer. Decode to text either way.
            let text = '';
            if (typeof ev.data === 'string') text = ev.data;
            else if (ev.data instanceof ArrayBuffer) {
                try { text = new TextDecoder().decode(new Uint8Array(ev.data)); }
                catch (_) { text = ''; }
            }
            buffer += text;
            // Trim the buffer so it can't grow without bound on a
            // very long apt log. We only need the tail to spot the
            // sentinel — keep the last 16 KB.
            if (buffer.length > 16384) buffer = buffer.slice(-16384);
            if (buffer.includes(sentinel)) {
                settled = true;
                clearTimeout(timeoutId);
                ws.onmessage = origOnMessage;
                ws.onclose = origOnClose;
                resolve();
            }
        };
    });
}

async function predictiveAck(findingType, nodeId, resourceId) {
    // Refuse the Node-scope fallback. When a proposal has no
    // resource_id, falling through to AckScope::Node would suppress
    // EVERY future finding of this type on this node — which is
    // almost never what the operator intends and clears the inbox in
    // a single click. If the proposal lacks a resource_id, the right
    // action is Dismiss (one-off) or Snooze (temporary), not Ack.
    if (!resourceId || !String(resourceId).trim()) {
        showToast(
            'This finding has no specific resource, so an Ack would suppress every "' + findingType + '" on this node — use Dismiss for a one-off, or Snooze for temporary suppression.',
            'warning', 6000,
        );
        return;
    }
    const reason = await showPrompt(
        `Acknowledge "${findingType}" on ${resourceId} as intentional? Future findings with the SAME finding type AND resource will be suppressed for 180 days. Other findings on this node are not affected.`,
        'Permanent acknowledgement',
        '',
    );
    if (reason === null) return;
    if (!reason.trim()) {
        showToast('A reason is required for an acknowledgement', 'warning', 3500);
        return;
    }
    const scope = { kind: 'resource', node_id: nodeId, resource_id: resourceId };
    // Optimistic UI: ack-as-intentional on a Resource scope filters
    // the matching proposal at read time, so removing it now matches
    // what the next predictiveLoad will return. Find the proposal id
    // by (finding_type, node_id, resource_id) since the ack scope
    // doesn't carry the id.
    const matched = (predictiveState.proposals || []).find(p =>
        p.finding_type === findingType
        && p.scope && p.scope.node_id === nodeId
        && (p.scope.resource_id || '') === resourceId
    );
    const point = matched ? predictiveOptimisticRemove(matched.id) : null;
    showToast('Acknowledged for 180 days', 'success', 2000);
    try {
        const r = await fetch('/api/proposal-acks', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                finding_type: findingType,
                scope,
                reason: reason.trim(),
            }),
        });
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            if (point) predictiveOptimisticRestore(point);
            showToast(`Ack failed: ${data.error || r.statusText}`, 'error');
        }
    } catch (e) {
        if (point) predictiveOptimisticRestore(point);
        showToast(`Ack errored: ${e.message || String(e)}`, 'error');
    }
}

async function predictiveRunNow() {
    const btn = document.getElementById('predictive-run-now');
    if (btn) { btn.disabled = true; btn.textContent = 'Running…'; }
    const before = (predictiveState.proposals || []).length;
    try {
        const r = await fetch('/api/proposals/run-now', { method: 'POST' });
        if (!r.ok) {
            const data = await r.json().catch(() => ({}));
            showToast(`Run failed: ${data.error || r.statusText}`, 'error');
            return;
        }
        await predictiveLoad();
        const after = (predictiveState.proposals || []).length;
        if (after === before && after === 0) {
            // Differentiate "ran cleanly, found nothing" from "ran and
            // surfaced new findings" — the first case is what an idle
            // healthy cluster always looks like, and operators expect
            // visible feedback that the click did something.
            showToast('Analyzer ran — no new findings (this is normal)', 'success', 2500);
        } else if (after > before) {
            showToast(`Analyzer ran — ${after - before} new finding${after - before === 1 ? '' : 's'}`, 'success', 2500);
        } else {
            showToast('Analyzer run complete', 'success', 1500);
        }
    } catch (e) {
        showToast(`Run errored: ${e.message || String(e)}`, 'error');
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = 'Run analyzer now'; }
    }
}

function predictiveBadgeUpdate() {
    const badge = document.getElementById('predictive-badge');
    if (!badge) return;
    const count = (predictiveState.proposals || []).filter(p =>
        p.status && p.status.kind === 'pending'
    ).length;
    if (count > 0) {
        badge.textContent = count > 99 ? '99+' : String(count);
        badge.style.display = 'inline-block';
    } else {
        badge.style.display = 'none';
    }
}

// Background poll so the badge updates even when the user isn't on
// the Inbox page. Keep cadence slow — 60s — so we don't burn the
// orchestrator's read locks. The orchestrator itself runs the
// analyzer every 5 min; checking the resulting state every 60 s
// gives near-real-time badge updates.
function predictiveStartBadgePoll() {
    if (predictiveBadgeTimer) return;
    const tick = async () => {
        try {
            // Cluster endpoint — server caches for 30s so this 60s
            // poll across N operators only costs at most two peer
            // round-trips per minute regardless of operator count.
            const r = await fetch('/api/proposals/cluster');
            if (r.ok) {
                const body = await r.json();
                // Filter out proposals the operator has already
                // optimistically removed but whose deferred API call
                // hasn't fired yet (Mark-applied undo window). Without
                // this filter, a cluster snapshot taken between the
                // click and the deferred POST re-introduces the row,
                // which makes it flicker — disappear, reappear,
                // disappear again 6s later when the API finally fires.
                const fresh = body.proposals || [];
                if (predictiveState.pendingUndoIds && predictiveState.pendingUndoIds.size > 0) {
                    predictiveState.proposals = fresh.filter(p => !predictiveState.pendingUndoIds.has(p.id));
                } else {
                    predictiveState.proposals = fresh;
                }
                predictiveState.nodes = body.nodes || [];
                predictiveBadgeUpdate();
            }
        } catch (_) { /* network blips are silent — the next tick retries */ }
    };
    tick();
    predictiveBadgeTimer = setInterval(tick, 60000);
}

// ─── Threat-intel blocklist UI (v23.2.2 per-cluster) ──────────────
//
// v23.2.2 inverts the v23.2.0/v23.2.1 default of "auto-enable on
// first boot" to "off everywhere unless the operator explicitly
// enables per cluster". The chip in the Predictive Inbox header
// summarises aggregate state across every cluster this dashboard
// can see; clicking it opens a panel for per-cluster management.
// The panel guides the operator through a three-step flow:
//   1. Off → Enable in DryRun (safe: no traffic blocked).
//   2. DryRun → Run preflight (fans out to every node in cluster,
//      shows feed counts + auto-allowlist + overlap report).
//   3. DryRun → Promote to Enforce (requires typed cluster name AND
//      a fresh <5min preflight). Server enforces both gates.
// Disable is one-click and tears down kernel state immediately.

const threatIntelState = {
    // Map<cluster_name, { state, nodes:[{node_id, hostname, is_self, status?, error?}], preflight:{ generatedAt, perNode:[{node_id, hostname, report?, error?}] } | null }>
    clusters: new Map(),
    panelOpen: false,
    // The node hostname the operator is currently typing into the
    // promote-confirmation field, keyed by cluster name. We track it
    // here so React-style re-renders don't lose what they typed.
    confirmInput: new Map(),
};

async function threatIntelRefreshStatus() {
    const wrap = document.getElementById('threat-intel-toggle-wrap');
    const detail = document.getElementById('threat-intel-status-detail');
    const btn = document.getElementById('threat-intel-toggle-btn');
    if (!wrap || !btn) return;
    try {
        // Local node's status — gives us this node's own cluster's
        // state cheaply and also tells us whether the chip is
        // worth surfacing at all (predictive endpoints must be
        // reachable).
        const resp = await fetch('/api/predictive/threat-intel/status');
        if (!resp.ok) {
            wrap.style.display = 'none';
            return;
        }
        const localStatus = await resp.json();
        // Seed the per-cluster map with what we know about THIS
        // node's cluster. Other clusters are discovered when the
        // operator opens the panel (lazy fan-out — no point
        // hammering every remote node for the chip).
        if (localStatus.cluster) {
            const existing = threatIntelState.clusters.get(localStatus.cluster) || {};
            existing.state = localStatus.state || 'off';
            existing.localNodeStatus = localStatus;
            threatIntelState.clusters.set(localStatus.cluster, existing);
        }
        wrap.style.display = 'inline-flex';
        // Aggregate label across all clusters we currently know
        // about. The panel will list everything; the chip is just a
        // glance summary.
        const counts = { off: 0, 'dry-run': 0, enforce: 0 };
        for (const [, c] of threatIntelState.clusters) {
            counts[c.state] = (counts[c.state] || 0) + 1;
        }
        const enforcing = counts.enforce || 0;
        const dryRun = counts['dry-run'] || 0;
        if (enforcing > 0) {
            detail.textContent = `${enforcing} enforcing · ${dryRun} dry-run`;
            btn.style.background = 'rgba(239,68,68,0.15)';
            btn.style.color = '#fca5a5';
        } else if (dryRun > 0) {
            detail.textContent = `${dryRun} dry-run · 0 enforcing`;
            btn.style.background = 'rgba(251,191,36,0.15)';
            btn.style.color = '#fde047';
        } else {
            detail.textContent = 'off everywhere';
            btn.style.background = '';
            btn.style.color = '';
        }
        btn.textContent = 'Manage…';
        btn.onclick = threatIntelOpenPanel;
    } catch (e) {
        wrap.style.display = 'none';
    }
}

/// Aggregate-state escape helper for the chip and modal labels.
/// Centralised so a future state addition doesn't drift between
/// callers.
function threatIntelStateLabel(s) {
    if (s === 'enforce') return 'Enforcing';
    if (s === 'dry-run') return 'DryRun (no traffic blocked)';
    return 'Off';
}

function threatIntelStateColor(s) {
    if (s === 'enforce') return '#f87171';
    if (s === 'dry-run') return '#fbbf24';
    return '#9ca3af';
}

/// Open the per-cluster management modal. Lazily fetches status
/// from every node in every cluster the Predictive Inbox knows
/// about; renders progressively.
async function threatIntelOpenPanel() {
    threatIntelState.panelOpen = true;
    threatIntelRenderPanel(); // initial frame with spinners
    // Build the list of (cluster, node) pairs we need to query.
    const nodes = (typeof predictiveState !== 'undefined' && predictiveState.nodes) || [];
    if (nodes.length === 0) {
        // No predictive nodes yet — fall back to single-node mode.
        // The local /status call we already did in
        // threatIntelRefreshStatus has populated the local cluster.
        threatIntelRenderPanel();
        return;
    }
    // Group nodes by cluster.
    const byCluster = new Map();
    for (const n of nodes) {
        const c = n.cluster_name || 'WolfStack';
        if (!byCluster.has(c)) byCluster.set(c, []);
        byCluster.get(c).push(n);
    }
    // For each cluster, fetch status from every node (in parallel
    // per-cluster, sequential across clusters to avoid hammering
    // when there are many).
    for (const [cluster, clusterNodes] of byCluster) {
        const entry = threatIntelState.clusters.get(cluster) || { state: 'off' };
        entry.nodes = clusterNodes.map(n => ({
            node_id: n.node_id, hostname: n.hostname, is_self: !!n.is_self, status: null, error: null
        }));
        threatIntelState.clusters.set(cluster, entry);
        threatIntelRenderPanel();
        const results = await Promise.all(clusterNodes.map(async (n) => {
            const url = n.is_self
                ? '/api/predictive/threat-intel/status'
                : `/api/nodes/${encodeURIComponent(n.node_id)}/proxy/predictive/threat-intel/status`;
            try {
                const r = await fetch(url);
                if (!r.ok) return { node_id: n.node_id, error: `HTTP ${r.status}` };
                const j = await r.json();
                return { node_id: n.node_id, status: j };
            } catch (e) {
                return { node_id: n.node_id, error: (e && e.message) || String(e) };
            }
        }));
        const map = new Map(results.map(r => [r.node_id, r]));
        entry.nodes = entry.nodes.map(n => {
            const r = map.get(n.node_id);
            if (!r) return n;
            return { ...n, status: r.status || null, error: r.error || null };
        });
        // Update cluster-level state from whichever node reported one.
        // All nodes in the same cluster should agree; if they don't,
        // we surface the disagreement in the per-node rows but treat
        // the loudest state (enforce > dry-run > off) as the cluster
        // state for action-button purposes.
        const seen = entry.nodes.map(n => n.status?.state).filter(Boolean);
        if (seen.includes('enforce')) entry.state = 'enforce';
        else if (seen.includes('dry-run')) entry.state = 'dry-run';
        else if (seen.length > 0) entry.state = 'off';
        threatIntelState.clusters.set(cluster, entry);
        threatIntelRenderPanel();
    }
}

function threatIntelClosePanel() {
    threatIntelState.panelOpen = false;
    const m = document.getElementById('threat-intel-panel-modal');
    if (m) m.remove();
    // Refresh the chip so any state changes the operator made are
    // reflected immediately.
    threatIntelRefreshStatus();
}

function threatIntelRenderPanel() {
    if (!threatIntelState.panelOpen) return;
    let modal = document.getElementById('threat-intel-panel-modal');
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'threat-intel-panel-modal';
        modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.65);z-index:10000;display:flex;align-items:flex-start;justify-content:center;overflow-y:auto;padding:40px 20px;';
        modal.addEventListener('click', (e) => { if (e.target === modal) threatIntelClosePanel(); });
        document.body.appendChild(modal);
    }

    const clusters = Array.from(threatIntelState.clusters.entries())
        .sort(([a], [b]) => a.localeCompare(b));

    let body = '';
    if (clusters.length === 0) {
        body = `<div style="color:var(--text-muted);padding:24px;text-align:center;">Loading clusters…</div>`;
    } else {
        body = clusters.map(([name, c]) => threatIntelRenderClusterCard(name, c)).join('');
    }

    modal.innerHTML = `
        <div style="background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:12px;max-width:960px;width:100%;color:var(--text-primary);box-shadow:0 25px 70px rgba(0,0,0,0.5);">
            <div style="padding:20px 24px;border-bottom:1px solid var(--border-color,#2d2f3a);display:flex;align-items:center;gap:12px;">
                <div style="flex:1;">
                    <h2 style="margin:0 0 4px 0;font-size:18px;">FireHOL Level 1 threat-intel blocklist</h2>
                    <div style="font-size:12px;color:var(--text-muted);line-height:1.5;">
                        Per-cluster enforcement. Default <strong>Off</strong>. Move a cluster to <strong>DryRun</strong> to download the feed and review what would be blocked, then <strong>Promote to Enforce</strong> after reviewing the per-node preflight.
                    </div>
                </div>
                <button class="btn btn-sm" onclick="threatIntelClosePanel()" style="flex-shrink:0;">Close</button>
            </div>
            <div style="padding:18px 24px;">
                ${body}
            </div>
        </div>
    `;
}

function threatIntelRenderClusterCard(name, c) {
    const color = threatIntelStateColor(c.state || 'off');
    const stateLabel = threatIntelStateLabel(c.state || 'off');
    const nodes = c.nodes || [];
    const nodesHtml = nodes.length === 0
        ? `<div style="color:var(--text-muted);padding:8px 0;font-size:12px;">Loading nodes…</div>`
        : nodes.map(n => threatIntelRenderNodeRow(n)).join('');

    const actions = threatIntelRenderClusterActions(name, c);
    const preflight = c.preflight ? threatIntelRenderPreflight(name, c) : '';
    const confirmRow = c.state === 'dry-run' ? threatIntelRenderPromoteRow(name, c) : '';

    return `
        <div style="background:var(--bg-secondary,#16181f);border:1px solid var(--border-color,#2d2f3a);border-radius:10px;padding:14px 16px;margin-bottom:14px;">
            <div style="display:flex;align-items:center;gap:12px;margin-bottom:10px;flex-wrap:wrap;">
                <div style="flex:1;min-width:200px;">
                    <div style="font-weight:600;font-size:14px;">Cluster <code style="background:var(--bg-tertiary,#2d2f3a);padding:1px 6px;border-radius:4px;font-size:12px;">${escapeHtml(name)}</code></div>
                    <div style="font-size:12px;color:${color};margin-top:2px;">${escapeHtml(stateLabel)}</div>
                </div>
                ${actions}
            </div>
            <div style="border-top:1px solid var(--border-color,#2d2f3a);padding-top:10px;">
                ${nodesHtml}
            </div>
            ${preflight}
            ${confirmRow}
        </div>
    `;
}

function threatIntelRenderNodeRow(n) {
    if (n.error) {
        return `<div style="display:flex;gap:8px;align-items:center;font-size:12px;padding:4px 0;">
            <span style="color:#f87171;">⚠</span>
            <span style="font-family:monospace;">${escapeHtml(n.hostname || n.node_id)}</span>
            <span style="color:#fca5a5;">unreachable: ${escapeHtml(n.error)}</span>
        </div>`;
    }
    if (!n.status) {
        return `<div style="display:flex;gap:8px;align-items:center;font-size:12px;padding:4px 0;color:var(--text-muted);">
            <span>·</span>
            <span style="font-family:monospace;">${escapeHtml(n.hostname || n.node_id)}</span>
            <span>loading…</span>
        </div>`;
    }
    const s = n.status;
    const parts = [];
    parts.push(threatIntelStateLabel(s.state || 'off'));
    if (s.state === 'enforce') {
        parts.push(`${(s.ipset_entry_count || 0).toLocaleString()} IPs in ipset`);
        if (!s.iptables_rules_present) parts.push('rules MISSING');
    } else if (s.state === 'dry-run') {
        parts.push(`feed: ${(s.feed_entry_count || 0).toLocaleString()} entries`);
    }
    if (!s.ipset_available) parts.push('ipset not installed');
    if (s.migration_completed) parts.push('v23.2.2 migrated');
    return `<div style="display:flex;gap:8px;align-items:center;font-size:12px;padding:4px 0;flex-wrap:wrap;">
        <span style="font-family:monospace;color:var(--text-primary);">${escapeHtml(n.hostname || n.node_id)}</span>
        <span style="color:var(--text-muted);">·</span>
        <span style="color:${threatIntelStateColor(s.state || 'off')};">${escapeHtml(parts.join(' · '))}</span>
    </div>`;
}

function threatIntelRenderClusterActions(name, c) {
    const buttons = [];
    const state = c.state || 'off';
    // Cluster names are operator-controlled. We pass them through
    // JSON.stringify so any special characters (', ", \, newline)
    // become valid JS-literal escapes, then escapeAttr for the
    // HTML-attribute layer. Without this, a cluster named e.g.
    // `prod'X` would break out of the onclick="...('...')" pattern.
    const jsName = escapeAttr(JSON.stringify(name));
    // Common: preflight is always available (runs the dry analysis
    // even on Off clusters so the operator can preview before
    // committing to DryRun).
    buttons.push(`<button class="btn btn-sm" onclick="threatIntelRunPreflight(${jsName})">Run preflight</button>`);
    if (state === 'off') {
        buttons.push(`<button class="btn btn-sm" style="background:rgba(34,197,94,0.18);color:#86efac;" onclick="threatIntelSetState(${jsName}, 'dry-run')">Enable in DryRun</button>`);
    } else if (state === 'dry-run') {
        buttons.push(`<button class="btn btn-sm" onclick="threatIntelSetState(${jsName}, 'off')">Disable</button>`);
    } else if (state === 'enforce') {
        buttons.push(`<button class="btn btn-sm" style="background:rgba(239,68,68,0.18);color:#fca5a5;" onclick="threatIntelSetState(${jsName}, 'off')">Disable enforcement</button>`);
    }
    return `<div style="display:flex;gap:6px;flex-wrap:wrap;">${buttons.join('')}</div>`;
}

function threatIntelRenderPreflight(name, c) {
    const pf = c.preflight;
    if (!pf) return '';
    if (pf.loading) {
        return `<div style="margin-top:12px;padding:10px 12px;background:rgba(96,165,250,0.06);border:1px solid rgba(96,165,250,0.25);border-radius:8px;font-size:12px;color:var(--text-secondary);">
            Running preflight across cluster nodes…
        </div>`;
    }
    if (pf.error) {
        return `<div style="margin-top:12px;padding:10px 12px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.3);border-radius:8px;font-size:12px;color:#fca5a5;">
            Preflight failed: ${escapeHtml(pf.error)}
        </div>`;
    }
    const rows = (pf.perNode || []).map(r => {
        if (r.error) {
            return `<div style="padding:6px 0;font-size:12px;color:#fca5a5;">
                ⚠ <code>${escapeHtml(r.hostname || r.node_id)}</code> — ${escapeHtml(r.error)}
            </div>`;
        }
        const rep = r.report || {};
        const ageStr = rep.feed_age_secs == null ? 'no feed' : `${Math.round((rep.feed_age_secs || 0) / 60)} min`;
        const warningsHtml = (rep.warnings || []).map(w => `<li style="color:#fde047;">${escapeHtml(w)}</li>`).join('');
        const overlapHtml = (rep.feed_overlaps_local || []).length === 0
            ? '<li style="color:#86efac;">no overlap between feed and your cluster IPs (clean)</li>'
            : (rep.feed_overlaps_local || []).map(ip => `<li style="color:#fde047;">${escapeHtml(ip)} — IN the feed, auto-allowlisted (likely cloud-IP reuse)</li>`).join('');
        const allowlistHtml = (rep.local_interface_ips || []).slice(0, 8).map(escapeHtml).join(', ');
        const moreLocal = Math.max(0, (rep.local_interface_ips || []).length - 8);
        const peerHtml = (rep.peer_ips || []).slice(0, 8).map(escapeHtml).join(', ');
        const morePeer = Math.max(0, (rep.peer_ips || []).length - 8);
        const sampleHtml = (rep.sample_block_entries || []).slice(0, 6).map(escapeHtml).join(', ');
        return `<details style="margin:6px 0;background:var(--bg-tertiary,#11131a);border:1px solid var(--border-color,#2d2f3a);border-radius:6px;">
            <summary style="padding:6px 10px;cursor:pointer;font-size:12px;">
                <code>${escapeHtml(r.hostname || r.node_id)}</code> — would block <strong>${(rep.would_block_count || 0).toLocaleString()}</strong> IPs · feed ${ageStr} · ${(rep.feed_overlaps_local || []).length} overlap${(rep.feed_overlaps_local || []).length === 1 ? '' : 's'}
            </summary>
            <div style="padding:8px 12px;font-size:12px;color:var(--text-secondary);line-height:1.6;">
                <div><strong>Local interface IPs</strong> (auto-allowlisted): ${allowlistHtml || '(none)'}${moreLocal > 0 ? ` <em>+ ${moreLocal} more</em>` : ''}</div>
                <div><strong>Peer IPs</strong> (auto-allowlisted): ${peerHtml || '(none)'}${morePeer > 0 ? ` <em>+ ${morePeer} more</em>` : ''}</div>
                <div><strong>Feed overlaps with your IPs:</strong>
                    <ul style="margin:4px 0 0 18px;padding:0;">${overlapHtml}</ul>
                </div>
                <div><strong>Sample of would-be-blocked IPs</strong>: ${sampleHtml || '(none)'}</div>
                ${warningsHtml ? `<div><strong>Warnings:</strong><ul style="margin:4px 0 0 18px;padding:0;">${warningsHtml}</ul></div>` : ''}
            </div>
        </details>`;
    }).join('');
    const ageSecs = Math.max(0, Math.round(Date.now() / 1000) - (pf.generatedAt || 0));
    const freshness = ageSecs <= 300
        ? `<span style="color:#86efac;">fresh (${ageSecs}s old)</span>`
        : `<span style="color:#fde047;">stale (${ageSecs}s — re-run before promoting)</span>`;
    return `<div style="margin-top:12px;padding:10px 12px;background:rgba(96,165,250,0.05);border:1px solid rgba(96,165,250,0.2);border-radius:8px;">
        <div style="font-size:12px;color:var(--text-secondary);margin-bottom:8px;">
            <strong>Preflight</strong> · ${freshness}
        </div>
        ${rows}
    </div>`;
}

function threatIntelRenderPromoteRow(name, c) {
    const typed = threatIntelState.confirmInput.get(name) || '';
    const matches = typed === name;
    const pf = c.preflight;
    const ageSecs = pf ? Math.max(0, Math.round(Date.now() / 1000) - (pf.generatedAt || 0)) : null;
    const fresh = pf && !pf.loading && !pf.error && ageSecs !== null && ageSecs <= 300;
    const canPromote = matches && fresh;
    const hint = !pf
        ? 'Run preflight first.'
        : pf.loading ? 'Preflight running…'
        : pf.error ? 'Preflight failed — fix the errors above then re-run.'
        : !fresh ? 'Preflight is stale (>5 min) — re-run.'
        : !matches ? `Type the exact cluster name to confirm.`
        : 'Ready. Promoting will install iptables DROP rules on every node in this cluster.';
    return `<div style="margin-top:12px;padding:10px 12px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.25);border-radius:8px;">
        <div style="font-size:12px;color:var(--text-secondary);margin-bottom:6px;line-height:1.5;">
            <strong style="color:#fca5a5;">Promote to Enforce</strong> — installs DROP rules cluster-wide.
            Requires a fresh (≤5 min) preflight AND typing the exact cluster name.
        </div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
            <input type="text" placeholder="${escapeAttr(name)}"
                   value="${escapeAttr(typed)}"
                   data-threat-intel-cluster="${escapeAttr(name)}"
                   oninput="threatIntelConfirmInput(${escapeAttr(JSON.stringify(name))}, this.value)"
                   style="background:var(--bg-tertiary,#2d2f3a);color:var(--text-primary);border:1px solid var(--border-color);border-radius:6px;padding:6px 10px;font-size:12px;font-family:monospace;min-width:200px;">
            <button class="btn btn-sm" ${canPromote ? '' : 'disabled'}
                    style="${canPromote ? 'background:rgba(239,68,68,0.25);color:#fecaca;' : 'opacity:0.5;cursor:not-allowed;'}"
                    onclick="threatIntelPromote(${escapeAttr(JSON.stringify(name))})">Promote to Enforce</button>
            <span style="font-size:11px;color:var(--text-muted);">${escapeHtml(hint)}</span>
        </div>
    </div>`;
}

function threatIntelConfirmInput(cluster, value) {
    threatIntelState.confirmInput.set(cluster, value);
    threatIntelRenderPanel();
    // Refocus the input that the user was typing into so re-render
    // doesn't steal their cursor mid-word. Match by the dedicated
    // data attribute, not placeholder text — robust against any
    // other field happening to share a placeholder.
    const modal = document.getElementById('threat-intel-panel-modal');
    if (!modal) return;
    // CSS.escape handles every CSS-selector metacharacter (`]`, `[`,
    // `\`, etc.) — naive quote-escaping would throw SyntaxError on a
    // cluster name like `prod[eu-west]`. CSS.escape is widely
    // supported (every browser we target); the catch is defensive.
    try {
        const sel = `input[data-threat-intel-cluster="${CSS.escape(cluster)}"]`;
        const target = modal.querySelector(sel);
        if (target) {
            target.focus();
            try { target.setSelectionRange(value.length, value.length); } catch (_) {}
        }
    } catch (_) {
        // Selector or DOM API failure — focus restoration is a
        // nice-to-have, not load-bearing for the promote flow.
    }
}

/// Fan out the preflight call to every node in the cluster, in
/// parallel. Updates threatIntelState.clusters[cluster].preflight
/// incrementally so the modal renders partial results as nodes
/// respond.
async function threatIntelRunPreflight(cluster) {
    const entry = threatIntelState.clusters.get(cluster) || {};
    entry.preflight = { loading: true, perNode: [] };
    threatIntelState.clusters.set(cluster, entry);
    threatIntelRenderPanel();
    const nodes = entry.nodes || [];
    if (nodes.length === 0) {
        entry.preflight = { loading: false, error: 'No nodes available for this cluster.', perNode: [] };
        threatIntelState.clusters.set(cluster, entry);
        threatIntelRenderPanel();
        return;
    }
    const results = await Promise.all(nodes.map(async (n) => {
        // node_proxy's handler re-prepends "/api/" to {path:.*}, so the
        // proxy path must NOT include the leading /api/ — otherwise the
        // remote receives /api/api/predictive/... which falls through to
        // the static-files handler (HTTP 405 on POST). Same bug pattern
        // as the antivirus 405 fixed in v23.12.7.
        const url = n.is_self
            ? '/api/predictive/threat-intel/preflight'
            : `/api/nodes/${encodeURIComponent(n.node_id)}/proxy/predictive/threat-intel/preflight`;
        try {
            const r = await fetch(url, { method: 'POST' });
            if (!r.ok) {
                let detail = `HTTP ${r.status}`;
                try { const j = await r.json(); if (j.error) detail = j.error; } catch (_) {}
                return { node_id: n.node_id, hostname: n.hostname, error: detail };
            }
            const j = await r.json();
            return { node_id: n.node_id, hostname: n.hostname, report: j };
        } catch (e) {
            return { node_id: n.node_id, hostname: n.hostname, error: (e && e.message) || String(e) };
        }
    }));
    // Compute the freshness anchor as the MAX generated_at across
    // all successful per-node reports. Server-side gate uses the
    // value we pass in; we pick the most-recent so it's most likely
    // to stay within the 5-minute window.
    const generatedAt = results
        .map(r => r.report?.generated_at || 0)
        .reduce((a, b) => Math.max(a, b), 0);
    entry.preflight = { loading: false, perNode: results, generatedAt };
    threatIntelState.clusters.set(cluster, entry);
    threatIntelRenderPanel();
    showToast(`Preflight complete for cluster "${cluster}"`, 'success', 3000);
}

/// Move a cluster between states. For Off / DryRun this is a
/// one-click action; for Enforce see threatIntelPromote which adds
/// the typed-confirmation + fresh-preflight gates.
async function threatIntelSetState(cluster, target) {
    if (target === 'enforce') {
        // Should never reach here — the UI never wires "Enforce"
        // to this function; promote is via threatIntelPromote.
        showToast('Use the Promote button (typed confirmation required).', 'error');
        return;
    }
    const verbed = target === 'off' ? 'Disabling' : 'Enabling DryRun on';
    showToast(`${verbed} cluster "${cluster}"…`, 'info', 2000);
    try {
        const r = await fetch('/api/predictive/threat-intel/state', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ cluster, state: target }),
        });
        const j = await r.json().catch(() => ({}));
        if (!r.ok) {
            showToast(`Failed: ${j.error || r.statusText}`, 'error');
            return;
        }
        showToast(`Cluster "${cluster}" set to ${threatIntelStateLabel(target)}.`, 'success', 4000);
        // Optimistically update local state, then re-fetch.
        const entry = threatIntelState.clusters.get(cluster) || {};
        entry.state = target;
        threatIntelState.clusters.set(cluster, entry);
        threatIntelRenderPanel();
        // Re-fetch status across the cluster to confirm propagation
        // landed on remote peers.
        setTimeout(() => threatIntelOpenPanel(), 1500);
    } catch (e) {
        showToast(`Request failed: ${(e && e.message) || String(e)}`, 'error');
    }
}

async function threatIntelPromote(cluster) {
    const entry = threatIntelState.clusters.get(cluster);
    if (!entry || !entry.preflight || entry.preflight.loading || entry.preflight.error) {
        showToast('Preflight required before promoting.', 'error');
        return;
    }
    const typed = threatIntelState.confirmInput.get(cluster) || '';
    if (typed !== cluster) {
        showToast(`Type "${cluster}" exactly to confirm.`, 'error');
        return;
    }
    const generatedAt = entry.preflight.generatedAt || 0;
    try {
        const r = await fetch('/api/predictive/threat-intel/state', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                cluster,
                state: 'enforce',
                confirm_cluster_name: cluster,
                preflight_generated_at: generatedAt,
            }),
        });
        const j = await r.json().catch(() => ({}));
        if (!r.ok) {
            showToast(`Promote failed: ${j.error || r.statusText}`, 'error', 8000);
            return;
        }
        showToast(`Cluster "${cluster}" promoted to Enforce. iptables rules will install on the next tick (≤5 min).`, 'success', 6000);
        threatIntelState.confirmInput.delete(cluster);
        entry.state = 'enforce';
        threatIntelState.clusters.set(cluster, entry);
        threatIntelRenderPanel();
        setTimeout(() => threatIntelOpenPanel(), 1500);
    } catch (e) {
        showToast(`Request failed: ${(e && e.message) || String(e)}`, 'error');
    }
}

window.threatIntelRefreshStatus = threatIntelRefreshStatus;
window.threatIntelOpenPanel = threatIntelOpenPanel;
window.threatIntelClosePanel = threatIntelClosePanel;
window.threatIntelRunPreflight = threatIntelRunPreflight;
