function appDrawerTileHtml(t) {
    return `
        <button class="app-drawer-tile" onclick="appDrawerNav('${escapeAttr(t.id)}')"
            style="background:var(--bg-secondary,#16181f);border:1px solid var(--border-color,#2d2f3a);border-radius:10px;padding:14px 12px;cursor:pointer;text-align:left;color:var(--text-primary);font-family:inherit;display:flex;flex-direction:column;gap:6px;transition:transform 0.12s ease, border-color 0.12s ease, background 0.12s ease;"
            onmouseenter="this.style.borderColor='var(--accent,#3b82f6)';this.style.background='var(--bg-tertiary,#2d2f3a)';this.style.transform='translateY(-1px)';"
            onmouseleave="this.style.borderColor='var(--border-color,#2d2f3a)';this.style.background='var(--bg-secondary,#16181f)';this.style.transform='translateY(0)';">
            <div style="font-size:28px;line-height:1;">${escapeHtml(t.icon || '')}</div>
            <div style="font-size:14px;font-weight:600;">${escapeHtml(t.name)}</div>
            <div style="font-size:11px;color:var(--text-muted);line-height:1.4;">${escapeHtml(t.desc || '')}</div>
        </button>
    `;
}

function renderAppDrawer(pluginTiles) {
    const grid = document.getElementById('app-drawer-grid');
    if (!grid) return;
    let html = `<div style="grid-column:1/-1;font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin:4px 0 -4px 4px;">Built-in views</div>`;
    html += APP_DRAWER_TILES.map(appDrawerTileHtml).join('');
    if (pluginTiles && pluginTiles.length > 0) {
        html += `<div style="grid-column:1/-1;font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin:18px 0 -4px 4px;">Plugins</div>`;
        html += pluginTiles.map(appDrawerTileHtml).join('');
    }
    grid.innerHTML = html;
}

/// Fetch enabled plugins that expose a top-level menu entry, normalise
/// to the same `{id, icon, name, desc}` shape the built-in tiles use.
/// Returns [] silently on any error so a broken plugin endpoint never
/// breaks the launcher.
async function loadAppDrawerPluginTiles() {
    try {
        const r = await fetch('/api/plugins');
        if (!r.ok) return [];
        const all = await r.json();
        if (!Array.isArray(all)) return [];
        return all
            .filter(p => p && p.manifest && p.manifest.enabled !== false)
            .filter(p => p.manifest.menu && p.manifest.menu.view)
            .map(p => {
                const m = p.manifest;
                // Datacenter-section plugins navigate to the standalone
                // page `page-plugin-{view}` created by `addPluginNavItem`.
                // Settings-section plugins have NO standalone page (it
                // would collide on the `${viewId}-content` id with the
                // tab panel) — route the drawer click to the Settings
                // page and let it switch to the right tab instead.
                const id = m.menu.section === 'settings'
                    ? `settings-tab:plugin-${m.menu.view}`
                    : `plugin-${m.menu.view}`;
                return {
                    id,
                    icon: m.icon || '',
                    name: m.menu.label || m.name || m.id,
                    desc: m.description || '',
                };
            });
    } catch (_) { return []; }
}

function openAppDrawer() {
    console.log('[apps-drawer] openAppDrawer() called');
    const backdrop = document.getElementById('app-drawer-backdrop');
    const drawer = document.getElementById('app-drawer');
    console.log('[apps-drawer] elements:', { backdrop: !!backdrop, drawer: !!drawer });
    if (!backdrop || !drawer) {
        console.warn('[apps-drawer] elements missing — index.html out of sync? Hard-refresh.');
        return;
    }

    // Defensively re-parent the drawer + backdrop to <body> so any
    // ancestor with `transform`/`filter`/`will-change` (which breaks
    // `position: fixed` per the CSS containing-block spec) can't clip
    // them. This is the most common cause of "the drawer is in the
    // DOM but invisible" — the .main-content or .sidebar parent
    // creates a containing block and the fixed-positioned drawer
    // anchors to that instead of the viewport.
    if (drawer.parentElement !== document.body) {
        document.body.appendChild(drawer);
    }
    if (backdrop.parentElement !== document.body) {
        document.body.appendChild(backdrop);
    }

    // Render built-ins immediately so the drawer feels responsive.
    renderAppDrawer([]);

    backdrop.style.display = 'block';
    // Trigger transition on next frame so the opacity/transform
    // animations actually run instead of jumping.
    requestAnimationFrame(() => {
        backdrop.style.opacity = '1';
        drawer.style.transform = 'translateX(0)';
    });
    document.addEventListener('keydown', appDrawerEscHandler);

    // Enrich with plugins (async, fire-and-forget).
    loadAppDrawerPluginTiles().then(plugins => renderAppDrawer(plugins));
}

function closeAppDrawer() {
    const backdrop = document.getElementById('app-drawer-backdrop');
    const drawer = document.getElementById('app-drawer');
    if (!backdrop || !drawer) return;
    backdrop.style.opacity = '0';
    drawer.style.transform = 'translateX(100%)';
    document.removeEventListener('keydown', appDrawerEscHandler);
    setTimeout(() => { backdrop.style.display = 'none'; }, 220);
}

function appDrawerEscHandler(e) {
    if (e.key === 'Escape') closeAppDrawer();
}

function appDrawerNav(pageId) {
    closeAppDrawer();
    // Tiny delay so the drawer's slide-out animation starts before
    // selectView re-renders the underlying view — feels less jarring
    // than the two transitions racing.
    setTimeout(() => {
        // Settings-section plugin tiles encode their route as
        // `settings-tab:<tabId>` — `loadAppDrawerPluginTiles` builds
        // them that way because those plugins have no standalone page.
        // Land on Settings and switch to the right tab.
        // The Getting Started tile opens the follow-along drawer, not a
        // full page — same "read while you click around" experience.
        if (pageId === 'learn') { openLearnDrawer(); return; }
        if (typeof pageId === 'string' && pageId.startsWith('settings-tab:')) {
            const tabName = pageId.slice('settings-tab:'.length);
            selectView('settings');
            if (typeof switchSettingsTab === 'function') switchSettingsTab(tabName);
            return;
        }
        selectView(pageId);
    }, 60);
}

window.openAppDrawer = openAppDrawer;
window.closeAppDrawer = closeAppDrawer;
window.appDrawerNav = appDrawerNav;

// ─── Dashboard Sync ───────────────────────────────────────────────
//
// Operator picks which peer nodes mirror this node's dashboard, then
// presses Push now. Nothing automatic — no on-write replication, no
// pull. The page is a checkbox tree of every known node grouped by
// cluster, plus the last-push outcome per ticked node.

const _dsState = {
    config: null,        // {targets, last_push, bundle_files, self_node}
    nodes: [],           // /api/nodes payload
    selection: new Set(),// node ids currently ticked in the UI
};

function dsAgoLabel(unixSec) {
    if (!unixSec) return '';
    const diff = Math.max(0, Math.floor(Date.now() / 1000 - unixSec));
    if (diff < 60) return `${diff}s ago`;
    if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
    return `${Math.floor(diff / 86400)}d ago`;
}

async function dashboardSyncLoad() {
    const tree = document.getElementById('dashboard-sync-tree');
    if (tree) tree.innerHTML = '<div style="color:var(--text-muted);text-align:center;padding:30px;">Loading…</div>';
    try {
        const [cfgR, nodesR] = await Promise.all([
            fetch(apiUrl('/api/dashboard-sync/targets')),
            fetch(apiUrl('/api/nodes')),
        ]);
        if (!cfgR.ok) throw new Error(`targets: HTTP ${cfgR.status}`);
        if (!nodesR.ok) throw new Error(`nodes: HTTP ${nodesR.status}`);
        _dsState.config = await cfgR.json();
        const np = await nodesR.json();
        _dsState.nodes = Array.isArray(np.nodes) ? np.nodes : [];
        // Initialise the in-memory selection from the persisted list so
        // the operator can tick/untick freely and only press Save when
        // they want the change to land.
        _dsState.selection = new Set(_dsState.config.targets || []);
    } catch (e) {
        if (tree) tree.innerHTML = `<div style="color:var(--danger,#ef4444);padding:20px;">Failed to load: ${escapeHtml(e.message || String(e))}</div>`;
        return;
    }
    dashboardSyncRender();
}

function dashboardSyncRender() {
    const tree = document.getElementById('dashboard-sync-tree');
    const bundle = document.getElementById('dashboard-sync-bundle-list');
    if (!tree || !_dsState.config) return;

    const selfId = _dsState.config.self_node;
    const lastPush = _dsState.config.last_push || {};

    // Group nodes by cluster_name (fall back to "Unassigned").
    const groups = new Map();
    for (const n of _dsState.nodes) {
        const key = n.cluster_name || 'Unassigned';
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key).push(n);
    }
    // Stable order: alphabetical cluster, hostname within.
    const orderedClusters = Array.from(groups.keys()).sort((a, b) => a.localeCompare(b));

    const rows = [];
    rows.push(`
        <div style="background:var(--bg-secondary,#16181f);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;padding:12px 14px;">
            <div style="font-size:12px;color:var(--text-muted);">This node</div>
            <div style="font-size:14px;font-weight:600;margin-top:2px;">
                ${escapeHtml(selfId || 'unknown')}
                <span style="background:#16a34a;color:#fff;font-size:10px;font-weight:700;padding:2px 8px;border-radius:8px;margin-left:8px;text-transform:uppercase;letter-spacing:0.5px;">Origin</span>
            </div>
        </div>
    `);

    for (const cluster of orderedClusters) {
        const members = groups.get(cluster)
            .filter(n => n.id !== selfId)
            .sort((a, b) => (a.hostname || a.id).localeCompare(b.hostname || b.id));
        if (members.length === 0) continue;

        const ticked = members.filter(n => _dsState.selection.has(n.id)).length;
        const clusterState = ticked === 0 ? 'none' : (ticked === members.length ? 'all' : 'some');
        const clusterMark = clusterState === 'all'
            ? '<span style="color:#3b82f6;">☑</span>'
            : (clusterState === 'some'
                ? '<span style="color:#3b82f6;">◪</span>'
                : '<span style="color:var(--text-muted);">☐</span>');

        const memberRows = members.map(n => {
            const isOn = _dsState.selection.has(n.id);
            const mark = isOn
                ? '<span style="color:#3b82f6;">☑</span>'
                : '<span style="color:var(--text-muted);">☐</span>';
            const out = lastPush[n.id];
            let statusHtml = '<span style="color:var(--text-muted);">No push yet</span>';
            if (out) {
                if (out.ok) {
                    statusHtml = `<span style="color:#16a34a;">&#10003; ${out.files} files · ${escapeHtml(dsAgoLabel(out.at))}</span>`;
                } else {
                    statusHtml = `<span style="color:#ef4444;" title="${escapeAttr(out.error || '')}">&#10007; ${escapeHtml(out.error || 'error')} · ${escapeHtml(dsAgoLabel(out.at))}</span>`;
                }
            }
            const onlineDot = n.online
                ? '<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#16a34a;margin-right:6px;"></span>'
                : '<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#ef4444;margin-right:6px;" title="Offline"></span>';
            return `
                <div onclick="dashboardSyncToggleNode('${escapeAttr(n.id)}')"
                     style="display:flex;align-items:center;gap:10px;padding:8px 12px 8px 28px;cursor:pointer;border-radius:6px;"
                     onmouseenter="this.style.background='var(--bg-tertiary,#2d2f3a)'"
                     onmouseleave="this.style.background='transparent'">
                    <span style="font-size:16px;line-height:1;">${mark}</span>
                    ${onlineDot}
                    <span style="font-weight:600;flex:1;">${escapeHtml(n.hostname || n.id)}</span>
                    <span style="font-size:12px;">${statusHtml}</span>
                </div>
            `;
        }).join('');

        rows.push(`
            <div style="background:var(--bg-secondary,#16181f);border:1px solid var(--border-color,#2d2f3a);border-radius:8px;overflow:hidden;">
                <div onclick="dashboardSyncToggleCluster('${escapeAttr(cluster)}')"
                     style="display:flex;align-items:center;gap:10px;padding:10px 12px;cursor:pointer;background:var(--bg-tertiary,#2d2f3a);"
                     onmouseenter="this.style.filter='brightness(1.1)'"
                     onmouseleave="this.style.filter='brightness(1.0)'">
                    <span style="font-size:16px;line-height:1;">${clusterMark}</span>
                    <span style="font-weight:600;flex:1;">${escapeHtml(cluster)}</span>
                    <span style="font-size:11px;color:var(--text-muted);">${ticked}/${members.length} ticked</span>
                </div>
                ${memberRows}
            </div>
        `);
    }

    if (rows.length === 1) {
        rows.push('<div style="color:var(--text-muted);text-align:center;padding:30px;">No peer nodes known to this dashboard yet.</div>');
    }
    tree.innerHTML = rows.join('');

    // Bundle-file disclosure. Pure data list — backend is the source
    // of truth so a build that adds a new file shows up here without
    // a frontend change.
    if (bundle) {
        const files = _dsState.config.bundle_files || [];
        bundle.innerHTML = files.length === 0
            ? '<em>(bundle file list unavailable)</em>'
            : files.map(f => `<code style="background:var(--bg-tertiary,#2d2f3a);padding:1px 6px;border-radius:4px;margin:0 4px 4px 0;display:inline-block;">${escapeHtml(f)}</code>`).join('');
    }
}

function dashboardSyncToggleNode(nodeId) {
    if (_dsState.selection.has(nodeId)) _dsState.selection.delete(nodeId);
    else _dsState.selection.add(nodeId);
    dashboardSyncRender();
}

function dashboardSyncToggleCluster(cluster) {
    const selfId = _dsState.config && _dsState.config.self_node;
    const members = _dsState.nodes
        .filter(n => (n.cluster_name || 'Unassigned') === cluster && n.id !== selfId);
    const allOn = members.every(n => _dsState.selection.has(n.id));
    for (const n of members) {
        if (allOn) _dsState.selection.delete(n.id);
        else _dsState.selection.add(n.id);
    }
    dashboardSyncRender();
}

async function dashboardSyncSaveTargets(silent = false) {
    const statusEl = document.getElementById('dashboard-sync-status');
    const targets = Array.from(_dsState.selection);
    try {
        const r = await fetch(apiUrl('/api/dashboard-sync/targets'), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ targets }),
        });
        const j = await r.json().catch(() => ({}));
        if (!r.ok) throw new Error(j.error || `HTTP ${r.status}`);
        if (!silent) {
            showToast(`Saved ${j.targets.length} target${j.targets.length === 1 ? '' : 's'}.`, 'success');
        }
        if (statusEl) statusEl.textContent = '';
        if (_dsState.config) _dsState.config.targets = j.targets;
        return true;
    } catch (e) {
        showToast(`Save failed: ${e.message || String(e)}`, 'error', 8000);
        if (statusEl) statusEl.innerHTML = `<div style="color:var(--danger,#ef4444);">Save failed: ${escapeHtml(e.message || String(e))}</div>`;
        return false;
    }
}

async function dashboardSyncPushNow() {
    const statusEl = document.getElementById('dashboard-sync-status');
    // Save first (silent — we only want the failure toast, not the
    // success one, since the user pressed Push, not Save). If save
    // fails, abort: pushing with stale targets would be confusing.
    const saved = await dashboardSyncSaveTargets(true);
    if (!saved) return;
    if (statusEl) statusEl.innerHTML = '<div style="color:var(--text-muted);">Pushing…</div>';
    try {
        const r = await fetch(apiUrl('/api/dashboard-sync/push'), { method: 'POST' });
        const j = await r.json().catch(() => ({}));
        if (!r.ok) throw new Error(j.error || `HTTP ${r.status}`);
        const outcomes = j.outcomes || {};
        const ok = Object.values(outcomes).filter(o => o.ok).length;
        const fail = Object.values(outcomes).filter(o => !o.ok).length;
        if (fail === 0 && ok > 0) {
            showToast(`Pushed to ${ok} node${ok === 1 ? '' : 's'}.`, 'success');
        } else if (ok > 0) {
            showToast(`Pushed to ${ok} node${ok === 1 ? '' : 's'}, ${fail} failed.`, 'error', 8000);
        } else {
            showToast(`Push failed on all ${fail} target${fail === 1 ? '' : 's'}.`, 'error', 8000);
        }
        if (statusEl) statusEl.textContent = '';
        // Refresh to show the new per-target last_push line.
        await dashboardSyncLoad();
    } catch (e) {
        showToast(`Push failed: ${e.message || String(e)}`, 'error', 8000);
        if (statusEl) statusEl.innerHTML = `<div style="color:var(--danger,#ef4444);">Push failed: ${escapeHtml(e.message || String(e))}</div>`;
    }
}

window.dashboardSyncLoad = dashboardSyncLoad;
window.dashboardSyncSaveTargets = dashboardSyncSaveTargets;
window.dashboardSyncPushNow = dashboardSyncPushNow;
window.dashboardSyncToggleNode = dashboardSyncToggleNode;
window.dashboardSyncToggleCluster = dashboardSyncToggleCluster;

// ─── Shares (WolfStack Gateway) ───────────────────────────────────
//
// Universal SMB/NFS re-export. The page is cluster-aggregated by
// default — `/api/gateways/cluster` fans out to every wolfstack peer
// and merges the lists, so the operator sees every share across the
// cluster from any node.

const _gwState = {
    gateways: [],     // last cluster-aggregated snapshot
    status:   { smb: { installed: false, running: false }, nfs: { installed: false, running: false } },
    loading:  false,
};
// Cluster name when viewing the cluster-aggregated Shares rollup (sidebar →
// cluster → Shares); null in the normal per-node view. Cluster mode is
// read-only — every row links to its owner node's Shares view to manage.
let _gwClusterMode = null;

function showSharesForCluster(clusterName) {
    closeSidebarMobile();
    _gwClusterMode = clusterName;
    currentPage = 'shares';
    currentNodeId = null;
    currentComponent = null;
    document.querySelectorAll('.page-view').forEach(p => p.style.display = 'none');
    const el = document.getElementById('page-shares');
    if (el) el.style.display = 'block';
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const item = document.querySelector(`.shares-cluster-item[data-cluster="${CSS.escape(clusterName)}"]`);
    if (item) item.classList.add('active');
    const t = document.getElementById('page-title');
    if (t) t.textContent = `Shares — ${clusterName}`;
    gwLoad();
}
window.showSharesForCluster = showSharesForCluster;

async function gwLoad() {
    _gwState.loading = true;
    const list = document.getElementById('gw-list');
    if (list) list.innerHTML = '<div style="color:var(--text-muted);text-align:center;padding:30px;">Loading shares…</div>';

    // Adapt the shared page chrome to the mode.
    const pageTitle = document.getElementById('gw-page-title');
    if (pageTitle) pageTitle.textContent = _gwClusterMode ? 'Shares across this cluster' : 'Shares on this node';
    const newBtn = document.getElementById('gw-new-share-btn');
    if (newBtn) newBtn.style.display = _gwClusterMode ? 'none' : '';

    if (_gwClusterMode) {
        // Cluster rollup — /api/gateways/cluster fans out to every online
        // node from the node we're logged into and tags each share with its
        // origin node. Read-only here; click a row to manage on its node.
        try {
            const r = await fetch('/api/gateways/cluster');
            if (!r.ok) throw new Error('HTTP ' + r.status);
            const data = await r.json();
            const all = Array.isArray(data) ? data : (data.gateways || []);
            // The endpoint aggregates the WHOLE fleet (plus federated
            // clusters). Resolve each share's origin node — peers report
            // their global self_id, local rows the node record id — and keep
            // only shares served by members of the cluster being viewed.
            const wanted = _gwClusterMode.toLowerCase();
            _gwState.gateways = all.filter(g => {
                const n = (allNodes || []).find(x =>
                    x.id === g.origin_node_id || x.self_id === g.origin_node_id);
                if (!n) return false; // federated/unknown origin — other clusters
                if (((n.cluster_name || 'WolfStack')).toLowerCase() !== wanted) return false;
                g._nodeId = n.id;
                g._nodeLabel = n.display_name || n.hostname || n.id;
                return true;
            });
        } catch (e) {
            if (list) list.innerHTML = `<div style="color:var(--danger,#ef4444);padding:20px;">Failed to load: ${escapeHtml(e.message || String(e))}</div>`;
            _gwState.loading = false;
            return;
        }
        _gwState.loading = false;
        gwRender();
        return;
    }

    // Per-node — Shares is scoped to currentNodeId. apiUrl() proxies
    // to the right node automatically, so /api/gateways always returns
    // shares belonging to the node we're viewing. No cluster fan-out
    // here: cross-cluster discovery belongs in WolfRun, not Shares.
    try {
        const [statusR, listR] = await Promise.all([
            fetch(apiUrl('/api/gateways/status')),
            fetch(apiUrl('/api/gateways')),
        ]);
        if (statusR.ok) _gwState.status = await statusR.json();
        if (listR.ok) {
            const data = await listR.json();
            // /api/gateways returns a bare array, /api/gateways/cluster
            // returns { gateways: [...] }. Handle both.
            _gwState.gateways = Array.isArray(data) ? data : (data.gateways || []);
        }
    } catch (e) {
        if (list) list.innerHTML = `<div style="color:var(--danger,#ef4444);padding:20px;">Failed to load: ${escapeHtml(e.message || String(e))}</div>`;
        _gwState.loading = false;
        return;
    }
    _gwState.loading = false;
    gwRender();
}

function gwRender() {
    const list = document.getElementById('gw-list');
    let statusBox = document.getElementById('gw-daemon-status');
    if (!list) return;

    // The daemon banner reports THIS node's samba/nfs state — meaningless
    // in the cluster rollup, where every row may live on a different node.
    if (_gwClusterMode && statusBox) {
        statusBox.innerHTML = '';
        statusBox = null;
    }

    // Daemon-status banner — flag missing samba/nfs-kernel-server so
    // operators get a clear "install this" prompt with a one-click
    // install button that opens an inline terminal showing live
    // package-manager output.
    if (statusBox) {
        const s = _gwState.status || {};
        const cards = [];
        if (!s.smb || !s.smb.installed) {
            cards.push(`<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
                <span style="color:#f59e0b;">Samba is not installed on this node</span>
                <span style="font-size:11px;color:var(--text-muted);">SMB shares need <code>samba</code>.</span>
                <button class="btn btn-sm btn-primary" onclick="gwInstallDaemon('samba')">Install Samba</button>
            </div>`);
        } else if (!s.smb.running) {
            cards.push(`<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
                <span style="color:#f59e0b;">smbd is not running</span>
                <span style="font-size:11px;color:var(--text-muted);"><code>systemctl start smbd</code></span>
            </div>`);
        }
        if (!s.nfs || !s.nfs.installed) {
            cards.push(`<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
                <span style="color:var(--text-muted);">ℹ️ NFS server is not installed</span>
                <span style="font-size:11px;color:var(--text-muted);">Only needed for NFS shares.</span>
                <button class="btn btn-sm" onclick="gwInstallDaemon('nfs')">Install NFS server</button>
            </div>`);
        }
        statusBox.innerHTML = cards.length === 0 ? '' :
            `<div class="card"><div class="card-body" style="padding:12px 14px;font-size:12px;display:flex;flex-direction:column;gap:8px;">${cards.join('')}</div></div>`;
    }

    if (!_gwState.gateways || _gwState.gateways.length === 0) {
        list.innerHTML = `
            <div class="card"><div class="card-body" style="text-align:center;padding:40px 20px;">
                <div style="font-size:48px;line-height:1;margin-bottom:12px;"></div>
                <h3 style="margin:0 0 8px;">${_gwClusterMode ? `No shares in ${escapeHtml(_gwClusterMode)} yet` : 'No shares on this node yet'}</h3>
                <p style="color:var(--text-muted);max-width:520px;margin:0 auto 18px;">
                    ${_gwClusterMode
                        ? 'Shares are created per node — open a node in the sidebar and pick <strong>Shares</strong> to create one. Every share in this cluster then shows up here.'
                        : `Create a share to expose any storage on this node — local dirs, Docker volumes,
                    LXC mountpoints, VM disk dirs, WolfDisk volumes, or CephFS — as an SMB or NFS
                    network share to your LAN.`}
                </p>
                ${_gwClusterMode ? '' : '<button class="btn btn-primary" onclick="gwOpenWizard()">+ New Share</button>'}
            </div></div>
        `;
        return;
    }

    let html = '';
    for (const g of _gwState.gateways) html += gwRenderRow(g);
    list.innerHTML = html;
}

function gwTierBadge(tier) {
    const colors = { fast: '#22c55e', ok: '#3b82f6', slow: '#f59e0b', cold: '#94a3b8' };
    const c = colors[tier] || '#64748b';
    return `<span style="display:inline-block;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;text-transform:uppercase;background:${c}22;color:${c};border:1px solid ${c}55;">${escapeHtml(tier || 'unknown')}</span>`;
}

function gwStatusBadge(g) {
    const rt = g.runtime || {};
    if (g.disabled) return `<span style="color:#64748b;">disabled</span>`;
    if (!rt.serving) return `<span style="color:#94a3b8;">not running</span>`;
    if (!rt.healthy) return `<span style="color:#f59e0b;">unhealthy</span>`;
    return `<span style="color:#22c55e;">● running</span>`;
}

function gwRenderRow(g) {
    const protos = (g.protocols || []).map(p => `<span style="display:inline-block;padding:1px 7px;border-radius:4px;font-size:10px;font-weight:700;background:rgba(59,130,246,0.15);color:#3b82f6;border:1px solid rgba(59,130,246,0.3);">${escapeHtml(p.toUpperCase())}</span>`).join(' ');
    const sourceLabel = (g.sources && g.sources[0]) ? gwSourceLabel(g.sources[0]) : '(no source)';
    const sessions = g.runtime && g.runtime.active_sessions ? `${g.runtime.active_sessions} sessions` : '';
    const safeId = escapeAttr(g.id);
    // Cluster rollup: the detail/edit APIs live on the share's OWNER node,
    // so the row badges its node and clicking jumps to that node's Shares
    // view (which handles management) instead of opening the local detail.
    const nodeBadge = (_gwClusterMode && g._nodeLabel)
        ? `<span style="display:inline-block;padding:1px 7px;border-radius:4px;font-size:10px;font-weight:700;background:rgba(168,85,247,0.15);color:#a855f7;border:1px solid rgba(168,85,247,0.3);" title="Served by this node">${escapeHtml(g._nodeLabel)}</span>`
        : '';
    const rowOnclick = (_gwClusterMode && g._nodeId)
        ? `selectServerView('${escapeAttr(g._nodeId)}', 'shares')`
        : `gwOpenDetail('${safeId}')`;
    return `
        <div class="card" style="cursor:pointer;" onclick="${rowOnclick}" ${_gwClusterMode ? 'title="Open this share\'s node to manage it"' : ''}>
            <div class="card-body" style="display:flex;align-items:center;gap:14px;padding:14px 18px;">
                <div style="font-size:24px;"></div>
                <div style="flex:1;min-width:0;">
                    <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
                        <strong style="font-size:14px;">${escapeHtml(g.name)}</strong>
                        ${nodeBadge}
                        ${protos}
                        ${gwTierBadge(g.performance_tier)}
                    </div>
                    <div style="font-size:12px;color:var(--text-muted);margin-top:4px;display:flex;gap:14px;flex-wrap:wrap;">
                        <span>↳ ${escapeHtml(sourceLabel)}</span>
                        <span>${gwStatusBadge(g)}</span>
                        ${sessions ? `<span>${escapeHtml(sessions)}</span>` : ''}
                    </div>
                </div>
            </div>
        </div>
    `;
}

function gwSourceLabel(s) {
    if (!s || !s.type) return '(unknown source)';
    switch (s.type) {
        case 'local':    return `Local: ${s.path}`;
        case 'wolfdisk': return `WolfDisk: ${s.volume_id}${s.subpath ? ':' + s.subpath : ''}`;
        case 'cephfs':   return `CephFS: ${s.cluster_id}/${s.fs_name}${s.subpath ? ':' + s.subpath : ''}`;
        case 'smb':      return `SMB: //${s.server}/${s.share}`;
        case 'nfs':      return `NFS: ${s.server}:${s.export}`;
        default:         return `${s.type}`;
    }
}

// ─── Wizard ───

let _gwWizardStep = 1;
let _gwWizardData = null;

function gwOpenWizard() {
    _gwWizardStep = 1;
    _gwWizardEditId = null;
    _gwWizardData = {
        name: '',
        protocols: ['smb'],
        source_type: 'local',
        source: { type: 'local', node_id: '', path: '' },
        auth_mode: 'anonymous',
        anon_writable: false,
        users: [],
        options: { readonly: false, guest_ok: true, time_machine: false, recycle_bin: false, allow_hosts: [], smb_workgroup: 'WORKGROUP', nfs_extra_options: '', nfs_no_root_squash: false },
    };
    gwRenderWizard();
}

/// Open the wizard pre-populated with an existing gateway's config —
/// shares the wizard with create, only the submit verb (POST vs PUT)
/// and starting state differ.
function gwOpenEdit(g) {
    _gwWizardStep = 1;
    _gwWizardEditId = g.id;
    const auth = g.auth || { mode: 'anonymous' };
    _gwWizardData = {
        name: g.name || '',
        protocols: g.protocols || ['smb'],
        source_type: (g.sources && g.sources[0] && g.sources[0].type) || 'local',
        source: (g.sources && g.sources[0]) || { type: 'local', node_id: '', path: '' },
        auth_mode: auth.mode || 'anonymous',
        anon_writable: !!auth.writable,
        users: (auth.users || []).map(u => ({ username: u.username, writable: !!u.writable })),
        options: Object.assign(
            { readonly: false, guest_ok: true, time_machine: false, recycle_bin: false, allow_hosts: [], smb_workgroup: 'WORKGROUP', nfs_extra_options: '', nfs_no_root_squash: false },
            g.options || {}
        ),
    };
    gwRenderWizard();
}

let _gwWizardEditId = null;

function gwCloseWizard() {
    const m = document.getElementById('gw-wizard');
    if (m) m.remove();
}

async function gwRenderWizard() {
    let m = document.getElementById('gw-wizard');
    if (!m) {
        m = document.createElement('div');
        m.id = 'gw-wizard';
        m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:10000;display:flex;align-items:center;justify-content:center;';
        document.body.appendChild(m);
    }
    const stepNames = ['1. Name & sources', '2. Protocol & auth', '3. Options & confirm'];
    const stepBadge = stepNames.map((s, i) => {
        const active = i + 1 === _gwWizardStep;
        const done = i + 1 < _gwWizardStep;
        const color = active ? '#3b82f6' : done ? '#22c55e' : 'var(--text-muted)';
        return `<span style="font-size:11px;font-weight:600;color:${color};">${escapeHtml(s)}</span>`;
    }).join(`<span style="color:var(--text-muted);">→</span>`);

    let body = '';
    if (_gwWizardStep === 1)      body = await gwWizardStep1();
    else if (_gwWizardStep === 2) body = gwWizardStep2();
    else                          body = gwWizardStep3();

    const isEdit = !!_gwWizardEditId;
    const submitLabel = isEdit ? 'Save changes' : 'Create Share';
    const titleLabel  = isEdit ? `Edit Share` : 'New Share';
    m.innerHTML = `
        <div class="card" style="width:680px;max-width:95vw;max-height:90vh;display:flex;flex-direction:column;">
            <div class="card-body" style="border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;">
                <h3 style="margin:0;display:flex;align-items:center;gap:8px;">${titleLabel}</h3>
                <button class="btn btn-sm" onclick="gwCloseWizard()"><span class="ws-icon-clean-wrap" data-icon="close"></span></button>
            </div>
            <div class="card-body" style="padding:12px 18px;display:flex;align-items:center;gap:8px;border-bottom:1px solid var(--border);">${stepBadge}</div>
            <div class="card-body" style="overflow:auto;flex:1;">${body}</div>
            <div class="card-body" style="border-top:1px solid var(--border);display:flex;justify-content:space-between;gap:8px;">
                <div>${_gwWizardStep > 1 ? `<button class="btn btn-sm" onclick="gwWizardBack()">← Back</button>` : ''}</div>
                <div style="display:flex;gap:8px;">
                    <button class="btn btn-sm" onclick="gwCloseWizard()">Cancel</button>
                    ${_gwWizardStep < 3
                        ? `<button class="btn btn-sm btn-primary" onclick="gwWizardNext()">Next →</button>`
                        : `<button class="btn btn-sm btn-primary" onclick="gwWizardSubmit()">${submitLabel}</button>`}
                </div>
            </div>
        </div>
    `;
}

async function gwWizardStep1() {
    let discovered = { sources: [] };
    try {
        const r = await fetch(apiUrl('/api/gateways/sources/discover'));
        if (r.ok) discovered = await r.json();
    } catch (_) {}
    // Stash structured source dicts so the picker handler can adopt
    // them directly — no regex-parsing the label text, which would
    // break the moment we changed the label format.
    window._gwDiscoveredSources = discovered.sources || [];
    const d = _gwWizardData;

    // Group sources by category so the dropdown isn't a wall of text
    // when a node has lots of Docker volumes / LXC containers / VMs.
    // Bucket by label prefix — backend gives stable, human-readable
    // labels we can match without coupling the frontend to source
    // type names.
    const list = discovered.sources || [];
    const buckets = {
        'Host paths':     [],
        'Docker volumes': [],
        'LXC containers': [],
        'VM disk dirs':   [],
        'WolfDisk':       [],
        'CephFS':         [],
        'Other':          [],
    };
    list.forEach((s, i) => {
        const label = s.label || '(unlabelled)';
        let bucket;
        if (label.startsWith('Docker volume:'))      bucket = 'Docker volumes';
        else if (label.startsWith('LXC rootfs:'))    bucket = 'LXC containers';
        else if (label.startsWith('PVE VM ') || label.startsWith('libvirt VM')) bucket = 'VM disk dirs';
        else if (label.startsWith('WolfDisk volume:')) bucket = 'WolfDisk';
        else if (label.startsWith('CephFS:'))        bucket = 'CephFS';
        else if (label.startsWith('Local directory')) bucket = 'Host paths';
        else                                          bucket = 'Other';
        buckets[bucket].push({ idx: i, label });
    });
    const optgroups = Object.entries(buckets)
        .filter(([, items]) => items.length > 0)
        .map(([name, items]) =>
            `<optgroup label="${escapeHtml(name)}">` +
            items.map(it => `<option value="${it.idx}">${escapeHtml(it.label)}</option>`).join('') +
            `</optgroup>`
        ).join('');

    return `
        <label style="display:block;font-size:12px;font-weight:600;margin-bottom:4px;">Share name</label>
        <input id="gw-w-name" class="form-control" style="width:100%;margin-bottom:14px;"
            value="${escapeAttr(d.name)}" placeholder="e.g. media, ops-share, finance"
            oninput="_gwWizardData.name=this.value;">
        <small style="color:var(--text-muted);display:block;margin-top:-10px;margin-bottom:14px;">
            Letters, numbers, hyphens, underscores. This is what clients will see (e.g. <code>\\\\server\\${escapeHtml(d.name || 'name')}</code>).
        </small>

        <label style="display:block;font-size:12px;font-weight:600;margin-bottom:4px;">Source</label>
        <select id="gw-w-source-pick" class="form-control" style="width:100%;margin-bottom:10px;" onchange="gwWizardSourcePick(this)">
            <option value="">— pick a discovered source, or use a custom one below —</option>
            ${optgroups}
        </select>

        <details style="margin-bottom:8px;" ${d.source.type === 'local' || d.source.type === 'smb' || d.source.type === 'nfs' ? 'open' : ''}>
            <summary style="cursor:pointer;font-size:12px;font-weight:600;">Custom source</summary>
            <div style="display:flex;gap:8px;align-items:center;margin:10px 0;">
                <label style="font-size:12px;">Type:</label>
                <select class="form-control" style="width:auto;" onchange="gwWizardCustomType(this.value)">
                    <option value="local"   ${d.source.type === 'local'   ? 'selected' : ''}>Local directory</option>
                    <option value="smb"     ${d.source.type === 'smb'     ? 'selected' : ''}>SMB re-export</option>
                    <option value="nfs"     ${d.source.type === 'nfs'     ? 'selected' : ''}>NFS re-export</option>
                </select>
            </div>
            <div id="gw-w-custom-fields">${gwWizardCustomFieldsHtml()}</div>
        </details>
    `;
}

function gwWizardCustomFieldsHtml() {
    const d = _gwWizardData.source;
    if (d.type === 'local') {
        return `
            <input class="form-control" style="width:100%;margin:6px 0;" placeholder="Absolute path on this node, e.g. /srv/data"
                value="${escapeAttr(d.path || '')}" oninput="_gwWizardData.source.path=this.value;">
            <small style="color:var(--text-muted);">Path must exist on the node that will serve this share. /etc, /proc, /sys, /dev are blocked.</small>
        `;
    }
    if (d.type === 'smb') {
        return `
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">
                <input class="form-control" placeholder="server (e.g. nas.lan or 10.0.0.20)" value="${escapeAttr(d.server || '')}" oninput="_gwWizardData.source.server=this.value;">
                <input class="form-control" placeholder="share name (e.g. media)" value="${escapeAttr(d.share || '')}" oninput="_gwWizardData.source.share=this.value;">
                <input class="form-control" placeholder="username (blank = guest)" value="${escapeAttr(d.username || '')}" oninput="_gwWizardData.source.username=this.value;">
                <input type="password" class="form-control" placeholder="password" value="${escapeAttr(d.password || '')}" oninput="_gwWizardData.source.password=this.value;">
            </div>
            <input class="form-control" style="width:100%;margin-top:6px;" placeholder="optional subpath" value="${escapeAttr(d.subpath || '')}" oninput="_gwWizardData.source.subpath=this.value;">
        `;
    }
    if (d.type === 'nfs') {
        return `
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">
                <input class="form-control" placeholder="server (e.g. nas.lan)" value="${escapeAttr(d.server || '')}" oninput="_gwWizardData.source.server=this.value;">
                <input class="form-control" placeholder="export path (e.g. /export/data)" value="${escapeAttr(d.export || '')}" oninput="_gwWizardData.source.export=this.value;">
            </div>
            <input class="form-control" style="width:100%;margin-top:6px;" placeholder="optional subpath" value="${escapeAttr(d.subpath || '')}" oninput="_gwWizardData.source.subpath=this.value;">
        `;
    }
    return '';
}

function gwWizardCustomType(t) {
    _gwWizardData.source = { type: t };
    document.getElementById('gw-w-custom-fields').innerHTML = gwWizardCustomFieldsHtml();
}

function gwWizardSourcePick(sel) {
    const idx = parseInt(sel.value, 10);
    const list = window._gwDiscoveredSources || [];
    const src = (Number.isInteger(idx) && list[idx]) ? list[idx] : null;
    if (!src) return;
    // Adopt the structured source directly — no regex over labels.
    // Strip the "label" field which is presentational only.
    const { label, ...rest } = src;
    _gwWizardData.source = rest;
    document.getElementById('gw-w-custom-fields').innerHTML = gwWizardCustomFieldsHtml();
}

function gwWizardStep2() {
    const d = _gwWizardData;
    return `
        <label style="display:block;font-size:12px;font-weight:600;margin-bottom:6px;">Protocols</label>
        <div style="display:flex;gap:14px;margin-bottom:18px;">
            <label style="display:flex;align-items:center;gap:6px;">
                <input type="checkbox" ${d.protocols.includes('smb') ? 'checked' : ''} onchange="gwWizardToggleProto('smb', this.checked)"> SMB (Windows / Mac / Linux clients)
            </label>
            <label style="display:flex;align-items:center;gap:6px;">
                <input type="checkbox" ${d.protocols.includes('nfs') ? 'checked' : ''} onchange="gwWizardToggleProto('nfs', this.checked)"> NFS (Linux / VM clients)
            </label>
        </div>

        <label style="display:block;font-size:12px;font-weight:600;margin-bottom:6px;">Authentication</label>
        <div style="display:flex;gap:14px;margin-bottom:14px;">
            <label><input type="radio" name="gw-w-auth" ${d.auth_mode === 'anonymous' ? 'checked' : ''} onchange="_gwWizardData.auth_mode='anonymous';gwRenderWizard();"> Anonymous (anyone on the LAN)</label>
            <label><input type="radio" name="gw-w-auth" ${d.auth_mode === 'users' ? 'checked' : ''} onchange="_gwWizardData.auth_mode='users';gwRenderWizard();"> Users (require login)</label>
        </div>
        ${d.auth_mode === 'anonymous' ? `
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;">
                <input type="checkbox" ${d.anon_writable ? 'checked' : ''} onchange="_gwWizardData.anon_writable=this.checked;"> Allow writes (anonymous users can modify files)
            </label>
            <small style="color:var(--text-muted);display:block;margin-top:4px;">NFS export uses these settings too. Restrict by IP/CIDR on the next step if you don't want world-writable.</small>
        ` : `
            <div id="gw-w-users" style="margin-bottom:8px;">
                ${(d.users || []).map((u, i) => `
                    <div style="display:flex;gap:6px;align-items:center;margin-bottom:4px;">
                        <input class="form-control" placeholder="username" value="${escapeAttr(u.username)}" oninput="_gwWizardData.users[${i}].username=this.value;" style="flex:1;">
                        <label style="font-size:11px;display:flex;align-items:center;gap:4px;">
                            <input type="checkbox" ${u.writable ? 'checked' : ''} onchange="_gwWizardData.users[${i}].writable=this.checked;"> writable
                        </label>
                        <button class="btn btn-sm" onclick="_gwWizardData.users.splice(${i},1);gwRenderWizard();"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
                    </div>
                `).join('')}
            </div>
            <button class="btn btn-sm" onclick="_gwWizardData.users.push({username:'',writable:true});gwRenderWizard();">+ Add user</button>
            <small style="color:var(--text-muted);display:block;margin-top:6px;">
                NFS export will be skipped — NFSv3/v4 IP-based auth doesn't honour user grants. SMB is the only protocol active when "users" auth is selected. AD/Kerberos integration is a future release.
            </small>
            <small style="color:var(--text-muted);display:block;margin-top:6px;">
                Set passwords AFTER creating the share — the dashboard prompts you. Plaintext is piped straight to <code>smbpasswd</code> and never stored by WolfStack.
            </small>
        `}
    `;
}

function gwWizardToggleProto(p, on) {
    const set = new Set(_gwWizardData.protocols);
    if (on) set.add(p); else set.delete(p);
    _gwWizardData.protocols = Array.from(set);
}

function gwWizardStep3() {
    const d = _gwWizardData;
    return `
        <h4 style="margin:0 0 8px;">Options</h4>
        <label style="display:flex;align-items:center;gap:6px;font-size:13px;margin-bottom:6px;">
            <input type="checkbox" ${d.options.readonly ? 'checked' : ''} onchange="_gwWizardData.options.readonly=this.checked;"> Read-only
        </label>
        <label style="display:flex;align-items:center;gap:6px;font-size:13px;margin-bottom:6px;">
            <input type="checkbox" ${d.options.guest_ok ? 'checked' : ''} onchange="_gwWizardData.options.guest_ok=this.checked;"> Browseable / guest OK (SMB only)
        </label>
        <label style="display:flex;align-items:center;gap:6px;font-size:13px;margin-bottom:6px;">
            <input type="checkbox" ${d.options.recycle_bin ? 'checked' : ''} onchange="_gwWizardData.options.recycle_bin=this.checked;"> Server-side recycle bin (SMB)
        </label>
        <label style="display:flex;align-items:center;gap:6px;font-size:13px;margin-bottom:14px;">
            <input type="checkbox" ${d.options.time_machine ? 'checked' : ''} onchange="_gwWizardData.options.time_machine=this.checked;"> Apple Time Machine target (SMB / fruit)
        </label>

        <h4 style="margin:14px 0 8px;">Network restrictions</h4>
        <input class="form-control" style="width:100%;" placeholder="Allowed CIDRs (comma-separated). Empty = anyone on the LAN."
            value="${escapeAttr((d.options.allow_hosts || []).join(', '))}"
            oninput="_gwWizardData.options.allow_hosts=this.value.split(',').map(s=>s.trim()).filter(Boolean);">

        <h4 style="margin:14px 0 8px;">NFS export options (advanced)</h4>
        <label style="display:flex;align-items:center;gap:6px;font-size:13px;margin-bottom:6px;">
            <input type="checkbox" ${d.options.nfs_no_root_squash ? 'checked' : ''} onchange="_gwWizardData.options.nfs_no_root_squash=this.checked;"> Preserve client ownership (<code>no_root_squash</code>)
        </label>
        <small style="color:var(--text-muted);font-size:11px;display:block;margin:-2px 0 8px;">
            Off (default): every client is squashed to <code>nobody</code> — safest, anonymous. On: client UIDs/GIDs (including root) pass through, matching a hand-written <code>/etc/exports</code>. Only enable on trusted networks or with an allow-host list above.
        </small>
        <input class="form-control" style="width:100%;" placeholder="Extra exports(5) options, e.g. no_root_squash or fsid=7"
            value="${escapeAttr(d.options.nfs_extra_options || '')}"
            oninput="_gwWizardData.options.nfs_extra_options=this.value.trim();">
        <small style="color:var(--text-muted);font-size:11px;display:block;margin-top:2px;">
            Appended to the export's option list (NFS only). WolfStack already sets a unique
            <code>fsid</code> per share automatically; supply your own <code>fsid=</code> here only to
            override it. Comma-separated, no spaces — see <code>man exports</code>.
        </small>

        <h4 style="margin:14px 0 8px;">SMB workgroup</h4>
        <input class="form-control" style="width:100%;" placeholder="WORKGROUP" value="${escapeAttr(d.options.smb_workgroup || 'WORKGROUP')}"
            oninput="_gwWizardData.options.smb_workgroup=this.value || 'WORKGROUP';">
        <small style="color:var(--text-muted);font-size:11px;display:block;margin-top:2px;">Default WORKGROUP. Override for AD-joined or non-default home networks. Applies cluster-wide on the [global] section.</small>

        <h4 style="margin:14px 0 8px;">Summary</h4>
        <div style="background:var(--bg-secondary);padding:12px 14px;border-radius:8px;font-family:ui-monospace,SFMono-Regular,Menlo,monospace;font-size:12px;line-height:1.6;">
            <div><strong>Name:</strong> ${escapeHtml(d.name || '(none)')}</div>
            <div><strong>Source:</strong> ${escapeHtml(gwSourceLabel(d.source))}</div>
            <div><strong>Protocols:</strong> ${escapeHtml(d.protocols.join(' + ').toUpperCase()) || '(none)'}</div>
            <div><strong>Auth:</strong> ${escapeHtml(d.auth_mode)}${d.auth_mode === 'users' ? ' (' + d.users.length + ' user' + (d.users.length === 1 ? '' : 's') + ')' : ''}</div>
            <div><strong>Read-only:</strong> ${d.options.readonly ? 'yes' : 'no'}</div>
            <div><strong>Allow:</strong> ${(d.options.allow_hosts && d.options.allow_hosts.length) ? d.options.allow_hosts.join(', ') : 'any'}</div>
        </div>
    `;
}

function gwWizardBack() { if (_gwWizardStep > 1) { _gwWizardStep--; gwRenderWizard(); } }
function gwWizardNext() {
    if (_gwWizardStep === 1) {
        if (!_gwWizardData.name || !_gwWizardData.name.trim()) { showToast('Name is required', 'error'); return; }
        if (!_gwWizardData.source || !_gwWizardData.source.type) { showToast('Pick a source', 'error'); return; }
        if (_gwWizardData.source.type === 'local' && !_gwWizardData.source.path) { showToast('Local source: path is required', 'error'); return; }
        if (_gwWizardData.source.type === 'smb' && (!_gwWizardData.source.server || !_gwWizardData.source.share)) { showToast('SMB source: server and share are required', 'error'); return; }
        if (_gwWizardData.source.type === 'nfs' && (!_gwWizardData.source.server || !_gwWizardData.source.export)) { showToast('NFS source: server and export are required', 'error'); return; }
    }
    if (_gwWizardStep === 2) {
        if (!_gwWizardData.protocols || _gwWizardData.protocols.length === 0) { showToast('Pick at least one protocol', 'error'); return; }
        if (_gwWizardData.auth_mode === 'users' && _gwWizardData.users.length === 0) { showToast('Users mode requires at least one user', 'error'); return; }
    }
    _gwWizardStep++;
    gwRenderWizard();
}

async function gwWizardSubmit() {
    const d = _gwWizardData;
    const auth = d.auth_mode === 'anonymous'
        ? { mode: 'anonymous', writable: !!d.anon_writable }
        : { mode: 'users', users: d.users.map(u => ({ username: u.username, writable: !!u.writable })), default_writable: true };

    const body = {
        name: d.name.trim(),
        cluster: '',
        mode: 'single',
        protocols: d.protocols,
        sources: [d.source],
        serve_nodes: [],
        auth,
        options: d.options,
    };
    const isEdit = !!_gwWizardEditId;
    const url = isEdit ? `/api/gateways/${encodeURIComponent(_gwWizardEditId)}` : '/api/gateways';
    const method = isEdit ? 'PUT' : 'POST';
    try {
        const r = await fetch(apiUrl(url), {
            method,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        const data = await r.json();
        if (!r.ok) {
            const msg = data.error || (data.errors ? data.errors.join('; ') : (isEdit ? 'Failed to save' : 'Failed to create'));
            showToast((isEdit ? 'Save' : 'Create') + ' failed: ' + msg, 'error');
            return;
        }
        gwCloseWizard();
        showToast((isEdit ? 'Share saved: ' : 'Share created: ') + d.name, 'success');
        await gwLoad();
        // For new gateways with users-mode auth, prompt for each
        // password. For edits we skip — operator already set them
        // before, and adding new users via edit is equally explicit.
        if (!isEdit && auth.mode === 'users') {
            for (const u of d.users) {
                await gwSetPasswordPrompt(data.id, u.username);
            }
        }
    } catch (e) {
        showToast((isEdit ? 'Save' : 'Create') + ' failed: ' + (e.message || String(e)), 'error');
    }
}

// ─── Detail panel ───

async function gwOpenDetail(id) {
    const g = _gwState.gateways.find(x => x.id === id);
    if (!g) {
        showToast('Share not found — it may have been removed; refreshing.', 'warning');
        await gwLoad();
        return;
    }
    const m = document.createElement('div');
    m.id = 'gw-detail';
    m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:10000;display:flex;align-items:center;justify-content:center;';
    document.body.appendChild(m);
    const protos = (g.protocols || []).join('+').toUpperCase();
    // Connect commands target the node hosting the share, not the
    // dashboard — for remote nodes we'd otherwise tell users to mount
    // from the wrong host.
    const _node = (typeof allNodes !== 'undefined') ? allNodes.find(n => n.id === currentNodeId) : null;
    const ip = (_node && _node.address) ? _node.address : window.location.hostname;
    const userBlock = (g.auth && g.auth.mode === 'users') ? `
        <h4 style="margin:14px 0 6px;">Users</h4>
        <div style="display:flex;flex-direction:column;gap:6px;">
            ${(g.auth.users || []).map(u => `
                <div style="display:flex;gap:6px;align-items:center;background:var(--bg-secondary);padding:6px 10px;border-radius:6px;">
                    <strong style="flex:1;">${escapeHtml(u.username)}</strong>
                    <span style="font-size:11px;color:${u.writable ? '#22c55e' : '#94a3b8'};">${u.writable ? 'rw' : 'ro'}</span>
                    <button class="btn btn-sm" onclick="gwSetPasswordPrompt('${escapeAttr(g.id)}','${escapeAttr(u.username)}')">Set password</button>
                </div>
            `).join('')}
        </div>
    ` : '';
    m.innerHTML = `
        <div class="card" style="width:680px;max-width:95vw;max-height:90vh;display:flex;flex-direction:column;">
            <div class="card-body" style="border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;">
                <h3 style="margin:0;display:flex;align-items:center;gap:8px;">${escapeHtml(g.name)}</h3>
                <button class="btn btn-sm" onclick="document.getElementById('gw-detail').remove()"><span class="ws-icon-clean-wrap" data-icon="trash"></span></button>
            </div>
            <div class="card-body" style="overflow:auto;flex:1;">
                <div style="display:grid;grid-template-columns:max-content 1fr;gap:6px 14px;font-size:13px;">
                    <strong>Status:</strong> <span>${gwStatusBadge(g)}</span>
                    <strong>Tier:</strong> <span>${gwTierBadge(g.performance_tier)}</span>
                    <strong>Protocols:</strong> <span>${escapeHtml(protos || '(none)')}</span>
                    <strong>Source:</strong> <span>${escapeHtml(gwSourceLabel(g.sources && g.sources[0]))}</span>
                    <strong>Mount path:</strong> <code style="font-size:11px;">${escapeHtml((g.runtime && g.runtime.mount_path) || '—')}</code>
                    <strong>Auth:</strong> <span>${escapeHtml(g.auth && g.auth.mode || 'anonymous')}</span>
                    <strong>Created:</strong> <span style="font-size:11px;color:var(--text-muted);">${escapeHtml(g.created_at || '—')}</span>
                </div>
                ${userBlock}
                <h4 style="margin:14px 0 6px;">Connect</h4>
                <div style="background:var(--bg-secondary);padding:10px 14px;border-radius:6px;font-family:ui-monospace,SFMono-Regular,Menlo,monospace;font-size:12px;display:flex;flex-direction:column;gap:4px;">
                    ${(g.protocols || []).includes('smb') ? `
                        <div>Linux:   <code>sudo mount -t cifs //${escapeHtml(ip)}/${escapeHtml(g.name)} /mnt</code></div>
                        <div>Mac:     <code>open smb://${escapeHtml(ip)}/${escapeHtml(g.name)}</code></div>
                        <div>Windows: <code>\\\\${escapeHtml(ip)}\\${escapeHtml(g.name)}</code></div>
                    ` : ''}
                    ${(g.protocols || []).includes('nfs') ? `
                        <div>NFS:     <code>sudo mount -t nfs ${escapeHtml(ip)}:/exports/${escapeHtml(g.name)} /mnt</code></div>
                    ` : ''}
                </div>
                ${g.runtime && g.runtime.last_error ? `
                    <h4 style="margin:14px 0 6px;color:#f59e0b;">Last warning</h4>
                    <div style="background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.25);padding:8px 12px;border-radius:6px;font-size:12px;">${escapeHtml(g.runtime.last_error)}</div>
                ` : ''}
            </div>
            <div class="card-body" style="border-top:1px solid var(--border);display:flex;justify-content:space-between;flex-wrap:wrap;gap:6px;">
                <div style="display:flex;gap:6px;flex-wrap:wrap;">
                    <button class="btn btn-sm" onclick="gwEditFrom('${escapeAttr(g.id)}')">Edit</button>
                    <button class="btn btn-sm" onclick="gwReload('${escapeAttr(g.id)}')">Reload</button>
                    ${g.disabled
                        ? `<button class="btn btn-sm" onclick="gwEnable('${escapeAttr(g.id)}')">▶ Enable</button>`
                        : `<button class="btn btn-sm" onclick="gwDisable('${escapeAttr(g.id)}')">Disable</button>`}
                </div>
                <button class="btn btn-sm" style="background:#ef4444;color:white;" onclick="gwDelete('${escapeAttr(g.id)}','${escapeAttr(g.name)}')">Delete</button>
            </div>
        </div>
    `;
}

function gwEditFrom(id) {
    const g = _gwState.gateways.find(x => x.id === id);
    if (!g) { showToast('Share not found', 'error'); return; }
    document.getElementById('gw-detail')?.remove();
    gwOpenEdit(g);
}

async function gwReload(id) {
    try {
        const r = await fetch(apiUrl(`/api/gateways/${encodeURIComponent(id)}/reload`), { method: 'POST' });
        const d = await r.json();
        if (!r.ok) { showToast('Reload failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Reloaded', 'success');
        document.getElementById('gw-detail')?.remove();
        await gwLoad();
    } catch (e) { showToast('Reload failed: ' + (e.message || String(e)), 'error'); }
}

async function gwDisable(id) {
    if (!await confirmModal('Disable this share? Clients will be disconnected. Configuration is kept.')) return;
    try {
        const r = await fetch(apiUrl(`/api/gateways/${encodeURIComponent(id)}/disable`), { method: 'POST' });
        if (!r.ok) { const d = await r.json().catch(()=>({})); showToast('Disable failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Disabled', 'success');
        document.getElementById('gw-detail')?.remove();
        await gwLoad();
    } catch (e) { showToast('Disable failed: ' + (e.message || String(e)), 'error'); }
}

async function gwEnable(id) {
    try {
        const r = await fetch(apiUrl(`/api/gateways/${encodeURIComponent(id)}/enable`), { method: 'POST' });
        if (!r.ok) { const d = await r.json().catch(()=>({})); showToast('Enable failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Enabled', 'success');
        document.getElementById('gw-detail')?.remove();
        await gwLoad();
    } catch (e) { showToast('Enable failed: ' + (e.message || String(e)), 'error'); }
}

async function gwDelete(id, name) {
    if (!await confirmModal(`Delete share "${name}"? Clients will lose access. The underlying data is NOT deleted — only the gateway config and mounts are removed.`)) return;
    try {
        const r = await fetch(apiUrl(`/api/gateways/${encodeURIComponent(id)}`), { method: 'DELETE' });
        if (!r.ok) { const d = await r.json().catch(()=>({})); showToast('Delete failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Deleted', 'success');
        document.getElementById('gw-detail')?.remove();
        await gwLoad();
    } catch (e) { showToast('Delete failed: ' + (e.message || String(e)), 'error'); }
}

async function gwSetPasswordPrompt(gatewayId, username) {
    const pw = await promptModal(`Set password for "${username}"`, '', { type: 'password' });
    if (!pw) return;
    try {
        const r = await fetch(apiUrl(`/api/gateways/${encodeURIComponent(gatewayId)}/users/${encodeURIComponent(username)}/password`), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password: pw }),
        });
        const d = await r.json().catch(() => ({}));
        if (!r.ok) { showToast('Set password failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Password set for ' + username, 'success');
    } catch (e) { showToast('Set password failed: ' + (e.message || String(e)), 'error'); }
}

// Modal helpers. Always use the dashboard's built-in styled modals
// (showConfirm / showPrompt). When showConfirm is unavailable we
// build a small DOM modal inline rather than falling back to
// window.confirm — browser-chrome dialogs are blocked in iframes,
// look terrible on mobile, and are sometimes suppressible.
async function confirmModal(msg) {
    if (typeof window.showConfirm === 'function') return window.showConfirm(msg);
    return new Promise(resolve => {
        const overlay = document.createElement('div');
        overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:100002;display:flex;align-items:center;justify-content:center;';
        const modal = document.createElement('div');
        modal.style.cssText = 'background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:12px;padding:24px 28px;max-width:480px;width:90%;color:var(--text-primary,#e4e4e7);font-family:inherit;box-shadow:0 20px 60px rgba(0,0,0,0.5);';
        const body = document.createElement('div');
        body.style.cssText = 'font-size:13px;line-height:1.55;color:var(--text-secondary,#a1a1aa);white-space:pre-wrap;';
        body.textContent = msg;
        const btnWrap = document.createElement('div');
        btnWrap.style.cssText = 'margin-top:18px;display:flex;justify-content:flex-end;gap:8px;';
        const cancelBtn = document.createElement('button');
        cancelBtn.className = 'btn btn-sm';
        cancelBtn.textContent = 'Cancel';
        const okBtn = document.createElement('button');
        okBtn.className = 'btn btn-sm btn-primary';
        okBtn.textContent = 'Confirm';
        cancelBtn.onclick = () => { overlay.remove(); resolve(false); };
        okBtn.onclick = () => { overlay.remove(); resolve(true); };
        overlay.onclick = (e) => { if (e.target === overlay) { overlay.remove(); resolve(false); } };
        document.addEventListener('keydown', function esc(e) {
            if (e.key === 'Escape') { overlay.remove(); document.removeEventListener('keydown', esc); resolve(false); }
        });
        btnWrap.appendChild(cancelBtn);
        btnWrap.appendChild(okBtn);
        modal.appendChild(body);
        modal.appendChild(btnWrap);
        overlay.appendChild(modal);
        document.body.appendChild(overlay);
        okBtn.focus();
    });
}
async function promptModal(label, initial, opts) {
    if (opts && opts.type === 'password') return passwordPrompt(label);
    if (typeof window.showPrompt === 'function') return window.showPrompt(label, '', initial || '');
    return window.prompt(label, initial || '');
}
function passwordPrompt(label) {
    return new Promise(resolve => {
        const overlay = document.createElement('div');
        overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);backdrop-filter:blur(4px);z-index:100001;display:flex;align-items:center;justify-content:center;';
        const modal = document.createElement('div');
        modal.style.cssText = 'background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:12px;padding:24px 28px;max-width:440px;width:90%;box-shadow:0 20px 60px rgba(0,0,0,0.5);color:var(--text-primary,#e4e4e7);font-family:inherit;';
        const h = document.createElement('div');
        h.style.cssText = 'font-size:15px;font-weight:600;margin-bottom:14px;color:var(--accent-light,#60a5fa);';
        h.textContent = label;
        const input = document.createElement('input');
        input.type = 'password';
        input.className = 'form-control';
        input.style.cssText = 'width:100%;box-sizing:border-box;';
        input.autocomplete = 'new-password';
        const hint = document.createElement('small');
        hint.style.cssText = 'display:block;color:var(--text-muted,#a1a1aa);font-size:11px;margin-top:8px;line-height:1.5;';
        hint.textContent = 'Plaintext is sent once over your authenticated session and piped straight into smbpasswd. WolfStack never persists it.';
        const btnWrap = document.createElement('div');
        btnWrap.style.cssText = 'margin-top:16px;display:flex;justify-content:flex-end;gap:8px;';
        const cancelBtn = document.createElement('button');
        cancelBtn.className = 'btn btn-sm';
        cancelBtn.textContent = 'Cancel';
        const okBtn = document.createElement('button');
        okBtn.className = 'btn btn-sm btn-primary';
        okBtn.textContent = 'Set password';
        cancelBtn.onclick = () => { overlay.remove(); resolve(null); };
        okBtn.onclick = () => { overlay.remove(); resolve(input.value); };
        input.onkeydown = (e) => { if (e.key === 'Enter') { overlay.remove(); resolve(input.value); } };
        overlay.onclick = (e) => { if (e.target === overlay) { overlay.remove(); resolve(null); } };
        btnWrap.appendChild(cancelBtn);
        btnWrap.appendChild(okBtn);
        modal.appendChild(h);
        modal.appendChild(input);
        modal.appendChild(hint);
        modal.appendChild(btnWrap);
        overlay.appendChild(modal);
        document.body.appendChild(overlay);
        input.focus();
    });
}

// Install Samba or the NFS server on the current node by opening an
// inline terminal that runs the package manager live. Once the
// terminal closes, we re-poll daemon status so the install banner
// disappears without the operator hitting refresh.
async function gwInstallDaemon(component) {
    if (component !== 'samba' && component !== 'nfs') {
        showToast('Unknown daemon: ' + component, 'error');
        return;
    }
    const node = (typeof allNodes !== 'undefined') ? allNodes.find(n => n.id === currentNodeId) : null;
    const hostname = node ? node.hostname : 'this node';
    // 'install' console type expects the component as the "name" param
    // and routes through /ws/remote-console/{nodeId}/install/{component}
    // automatically when currentNodeId points at a non-self peer.
    // Switch to the per-node terminal view first so the inline terminal
    // container exists in the DOM.
    selectServerView(currentNodeId, 'terminal');
    // The terminal view-switch above clears the container; defer one
    // tick so the new container is in place before we open the install
    // session, otherwise openInlineTerminal writes into the old DOM.
    setTimeout(() => {
        openInlineTerminal('install', component);
        showToast(`Installing ${component} on ${hostname} — watch the terminal for progress. Re-open Shares when done.`, 'info', 6000);
    }, 50);
}

window.gwInstallDaemon = gwInstallDaemon;
window.gwLoad = gwLoad;
window.gwOpenWizard = gwOpenWizard;
window.gwOpenEdit = gwOpenEdit;
window.gwEditFrom = gwEditFrom;
window.gwCloseWizard = gwCloseWizard;
window.gwRenderWizard = gwRenderWizard;
window.gwWizardBack = gwWizardBack;
window.gwWizardNext = gwWizardNext;
window.gwWizardSubmit = gwWizardSubmit;
window.gwWizardSourcePick = gwWizardSourcePick;
window.gwWizardCustomType = gwWizardCustomType;
window.gwWizardToggleProto = gwWizardToggleProto;
window.gwOpenDetail = gwOpenDetail;
window.gwReload = gwReload;
window.gwDisable = gwDisable;
window.gwEnable = gwEnable;
window.gwDelete = gwDelete;
window.gwSetPasswordPrompt = gwSetPasswordPrompt;

// ─── Cross-cluster federation ───
//
// A "federated cluster" is another WolfStack cluster (different site,
// different admin domain) this dashboard pulls share data from.
// Shows up alongside local-cluster shares in the unified list.

function gwRenderFederationSection() {
    const section = document.getElementById('gw-fed-section');
    const count = document.getElementById('gw-fed-count');
    if (!section) return;
    const list = _gwState.federations || [];
    if (count) count.textContent = list.length === 0 ? '— add another WolfStack cluster to manage all your sites from one place' : `— ${list.length} connected`;

    let rows = '';
    for (const f of list) {
        const ok = f.last_ok_unix && (!f.last_error || f.last_error === '');
        const badge = f.last_error ? `<span style="color:#ef4444;">${escapeHtml(f.last_error.slice(0, 80))}</span>`
                  : ok ? `<span style="color:#22c55e;">connected</span>`
                  : `<span style="color:var(--text-muted);">○ not yet tested</span>`;
        rows += `
            <div class="card" style="margin-bottom:6px;">
                <div class="card-body" style="padding:10px 14px;display:flex;align-items:center;gap:12px;">
                    <div style="font-size:18px;"></div>
                    <div style="flex:1;min-width:0;">
                        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
                            <strong>${escapeHtml(f.name)}</strong>
                            <code style="font-size:11px;color:var(--text-muted);">${escapeHtml(f.base_url)}</code>
                            ${f.insecure_tls ? `<span style="font-size:10px;color:#f59e0b;">[insecure-tls]</span>` : ''}
                        </div>
                        <div style="font-size:11px;margin-top:2px;">${badge}</div>
                    </div>
                    <button class="btn btn-sm" onclick="gwFedTest('${escapeAttr(f.id)}')">Test</button>
                    <button class="btn btn-sm" onclick="gwFedRemove('${escapeAttr(f.id)}','${escapeAttr(f.name)}')" style="color:#ef4444;">Remove</button>
                </div>
            </div>
        `;
    }
    section.innerHTML = `
        ${rows}
        <button class="btn btn-sm btn-primary" onclick="gwFedAddPrompt()">+ Add cluster</button>
        <small style="display:block;margin-top:8px;color:var(--text-muted);font-size:11px;line-height:1.5;">
            Connect another WolfStack cluster here to see its shares alongside this one.
            On the remote cluster: Settings → API Keys → create a read-scope key, then paste its base URL + the key here.
            Federated shares are read-only from this view — open the remote cluster's dashboard to edit them.
        </small>
    `;
}

async function gwFedAddPrompt() {
    const m = document.createElement('div');
    m.id = 'gw-fed-add';
    m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.55);z-index:10000;display:flex;align-items:center;justify-content:center;';
    m.innerHTML = `
        <div class="card" style="width:520px;max-width:95vw;">
            <div class="card-body" style="border-bottom:1px solid var(--border);">
                <h3 style="margin:0;">Connect another cluster</h3>
            </div>
            <div class="card-body" style="display:flex;flex-direction:column;gap:8px;">
                <label style="font-size:12px;font-weight:600;">Display name</label>
                <input id="gw-fed-name" class="form-control" placeholder="e.g. Datacenter Bay 1, Home Lab, Office London">

                <label style="font-size:12px;font-weight:600;margin-top:6px;">Base URL</label>
                <input id="gw-fed-url" class="form-control" placeholder="https://wolfstack.example.com:8553">
                <small style="color:var(--text-muted);font-size:11px;">No trailing slash. Use the URL you'd open in a browser.</small>

                <label style="font-size:12px;font-weight:600;margin-top:6px;">API key from that cluster</label>
                <input id="gw-fed-key" class="form-control" placeholder="wsk_…" type="password">
                <small style="color:var(--text-muted);font-size:11px;">On the remote cluster: Settings → API Keys → "+ New key" with read scope. Paste it here.</small>

                <label style="margin-top:6px;display:flex;align-items:center;gap:6px;font-size:12px;">
                    <input type="checkbox" id="gw-fed-insecure">
                    Allow self-signed TLS certificate
                </label>
            </div>
            <div class="card-body" style="border-top:1px solid var(--border);display:flex;justify-content:flex-end;gap:8px;">
                <button class="btn btn-sm" onclick="document.getElementById('gw-fed-add').remove()">Cancel</button>
                <button class="btn btn-sm btn-primary" onclick="gwFedSubmit()">Add &amp; test</button>
            </div>
        </div>
    `;
    document.body.appendChild(m);
}

async function gwFedSubmit() {
    const name = document.getElementById('gw-fed-name').value.trim();
    const baseUrl = document.getElementById('gw-fed-url').value.trim();
    const key = document.getElementById('gw-fed-key').value;
    const insecure = document.getElementById('gw-fed-insecure').checked;
    if (!name || !baseUrl || !key) { showToast('All fields required', 'error'); return; }
    try {
        const r = await fetch('/api/federations', {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, base_url: baseUrl, api_key: key, insecure_tls: insecure }),
        });
        const d = await r.json();
        if (!r.ok) {
            const msg = d.error || (d.errors ? d.errors.join('; ') : 'Failed to add');
            showToast('Add failed: ' + msg, 'error');
            return;
        }
        document.getElementById('gw-fed-add').remove();
        // Probe immediately and surface the result before reload — the
        // operator gets ✓/✗ feedback in the same flow rather than
        // having to click "Test" themselves to see if it worked.
        try {
            const t = await fetch(`/api/federations/${encodeURIComponent(d.id)}/test`, { method: 'POST' });
            const tr = await t.json();
            if (tr.ok) {
                showToast(`${name} connected (${tr.elapsed_ms}ms)`, 'success');
            } else {
                showToast(`${name} added but probe failed: ${tr.error || 'unknown'}`, 'error', 6500);
            }
        } catch (probeErr) {
            showToast(`Added ${name}; probe failed: ${probeErr.message || probeErr}`, 'error');
        }
        await gwLoad();
    } catch (e) { showToast('Add failed: ' + (e.message || String(e)), 'error'); }
}

async function gwFedTest(id) {
    try {
        const r = await fetch(`/api/federations/${encodeURIComponent(id)}/test`, { method: 'POST' });
        const d = await r.json();
        if (d.ok) {
            showToast(`${d.name} — ${d.elapsed_ms}ms`, 'success');
        } else {
            showToast(`${d.name}: ${d.error || 'unknown'}`, 'error', 6000);
        }
        await gwLoad();
    } catch (e) { showToast('Test failed: ' + (e.message || String(e)), 'error'); }
}

async function gwFedRemove(id, name) {
    if (!await confirmModal(`Remove "${name}" from connected clusters? Their shares will stop appearing here. The remote cluster is unaffected.`)) return;
    try {
        const r = await fetch(`/api/federations/${encodeURIComponent(id)}`, { method: 'DELETE' });
        if (!r.ok) { const d = await r.json().catch(()=>({})); showToast('Remove failed: ' + (d.error || r.statusText), 'error'); return; }
        showToast('Removed', 'success');
        await gwLoad();
    } catch (e) { showToast('Remove failed: ' + (e.message || String(e)), 'error'); }
}

window.gwRenderFederationSection = gwRenderFederationSection;
window.gwFedAddPrompt = gwFedAddPrompt;
window.gwFedSubmit = gwFedSubmit;
window.gwFedTest = gwFedTest;
window.gwFedRemove = gwFedRemove;

// ─── Storage Array (mdadm / NoNRAID) ───────────────────────────────
//
// Klas's request: a small GUI inside WolfStack to manage Unraid →
// Debian + NoNRAID migrations. Same UI works for vanilla Linux mdadm
// since both expose identical /proc/mdstat semantics. Backend
// auto-detects mdcmd vs mdadm.

const _arrayState = {
    backend: 'mdadm',
    arrays: [],
    config: { schedules: [], alert_overrides: [] },
};

async function arrayLoad() {
    const list = document.getElementById('array-list');
    if (list) list.innerHTML = '<div style="color:var(--text-muted);text-align:center;padding:30px;">Loading…</div>';
    try {
        // /api/array/cluster aggregates THIS cluster (every node)
        // AND every federated remote cluster — one round-trip
        // surfaces every array from every connected site.
        const [r, cfgR] = await Promise.all([
            fetch('/api/array/cluster'),
            fetch('/api/array/config'),
        ]);
        if (r.ok) {
            const d = await r.json();
            _arrayState.arrays = d.arrays || [];
            // Backend label is per-array now; pick the local node's
            // for the header badge (or fall back to the first entry).
            const local = (_arrayState.arrays || []).find(a => a.origin_self !== false);
            _arrayState.backend = (local && local.backend)
                || ((_arrayState.arrays[0] || {}).backend)
                || 'mdadm';
        }
        if (cfgR.ok) _arrayState.config = await cfgR.json();
    } catch (e) {
        if (list) list.innerHTML = `<div style="color:var(--danger,#ef4444);padding:20px;">Failed: ${escapeHtml(e.message || String(e))}</div>`;
        return;
    }
    arrayRender();
}

async function arrayDiagnoseInline() {
    const inline = document.getElementById('array-diagnose-inline');
    if (!inline) return;
    // If we already have output, hide it (toggle).
    if (inline.innerHTML.trim()) { inline.innerHTML = ''; return; }
    inline.innerHTML = '<div id="array-diagnose-out"></div>';
    await arrayDiagnose();
}

async function arrayDiagnose() {
    const out = document.getElementById('array-diagnose-out');
    if (!out) return;
    out.innerHTML = '<div style="color:var(--text-muted);font-size:12px;">Running detection report…</div>';
    let report;
    try {
        const r = await fetch('/api/array/diagnose');
        if (!r.ok) throw new Error('HTTP ' + r.status);
        report = await r.json();
    } catch (e) {
        out.innerHTML = '<div style="color:var(--danger,#ef4444);font-size:13px;">Diagnose failed: ' + escapeHtml(e.message || String(e)) + '</div>';
        return;
    }
    const row = (k, v) => '<tr><td style="padding:4px 10px 4px 0;color:var(--text-muted);white-space:nowrap;vertical-align:top;font-size:12px;">' + escapeHtml(k) + '</td><td style="padding:4px 0;font-size:12px;color:var(--text-primary);word-break:break-all;">' + v + '</td></tr>';
    const yes = '<span style="color:#22c55e;font-weight:600;">yes</span>';
    const no = '<span style="color:#ef4444;font-weight:600;">no</span>';
    const envCell = (val, exists) => val
        ? '<code>' + escapeHtml(val) + '</code> (' + (exists ? yes + ' exists' : no + ' missing') + ')'
        : '<span style="color:var(--text-muted);">not set</span>';
    let html = '<div class="card" style="margin-top:8px;"><div class="card-body">';
    html += '<h4 style="margin:0 0 10px;font-size:14px;">Detection report</h4>';
    html += '<table style="width:100%;border-collapse:collapse;">';
    html += row('Detected backend', '<code>' + escapeHtml(report.detected_backend || '?') + '</code>');
    html += row('Arrays parsed', String(report.parsed_array_count));
    html += '<tr><td colspan="2" style="padding:10px 0 4px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);">NoNRAID signals</td></tr>';
    html += row('md_nonraid kernel module', report.nonraid_kernel_module_loaded ? yes : no);
    html += row('/proc/nmdstat', report.procfs_nmdstat_present
        ? yes + ' (' + report.procfs_nmdstat_bytes + ' bytes)'
        : no + ' — md_nonraid module not loaded?');
    html += row('nmdctl path', report.nmdctl_path
        ? '<code>' + escapeHtml(report.nmdctl_path) + '</code>'
        : no + ' — install nonraid-tools (Debian: apt install nonraid-tools)');
    html += row('WOLFSTACK_NMDCTL env', envCell(report.nmdctl_env_override, report.nmdctl_env_override_exists));
    html += '<tr><td colspan="2" style="padding:10px 0 4px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);">mdadm / legacy Unraid signals</td></tr>';
    html += row('mdadm path', report.mdadm_path ? '<code>' + escapeHtml(report.mdadm_path) + '</code>' : no);
    html += row('/proc/mdstat', report.procfs_mdstat_present
        ? yes + ' (' + report.procfs_mdstat_bytes + ' bytes)'
        : no + ' — md kernel module not loaded');
    html += row('mdcmd path (legacy)', report.mdcmd_path ? '<code>' + escapeHtml(report.mdcmd_path) + '</code>' : no + ' — only present on commercial Unraid');
    html += row('WOLFSTACK_MDCMD env', envCell(report.mdcmd_env_override, report.mdcmd_env_override_exists));
    html += '<tr><td colspan="2" style="padding:10px 0 4px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);">Environment</td></tr>';
    html += row('Searched dirs', '<code style="font-size:11px;">' + escapeHtml((report.which_searched_dirs || []).join(':')) + '</code>');
    html += row('Process $PATH', '<code style="font-size:11px;">' + escapeHtml(report.process_path_env || '(empty)') + '</code>');
    html += '</table>';
    if (report.procfs_nmdstat_head) {
        html += '<details style="margin-top:12px;" open><summary style="cursor:pointer;font-size:12px;font-weight:600;">Show /proc/nmdstat (head)</summary>';
        html += '<pre style="background:var(--bg-card);border:1px solid var(--border);border-radius:6px;padding:10px;margin-top:8px;font-size:11px;overflow:auto;max-height:300px;white-space:pre-wrap;">' + escapeHtml(report.procfs_nmdstat_head) + '</pre></details>';
    }
    if (report.procfs_mdstat_head) {
        html += '<details style="margin-top:12px;"><summary style="cursor:pointer;font-size:12px;font-weight:600;">Show /proc/mdstat (head)</summary>';
        html += '<pre style="background:var(--bg-card);border:1px solid var(--border);border-radius:6px;padding:10px;margin-top:8px;font-size:11px;overflow:auto;max-height:300px;white-space:pre-wrap;">' + escapeHtml(report.procfs_mdstat_head) + '</pre></details>';
    }
    if (report.hints && report.hints.length) {
        html += '<div style="margin-top:14px;padding:12px;background:rgba(234,179,8,0.12);border:1px solid rgba(234,179,8,0.45);border-radius:6px;font-size:12px;color:var(--text-primary);">';
        html += '<strong style="color:#fbbf24;">Suggestions</strong><ul style="margin:6px 0 0 18px;padding:0;">';
        for (const h of report.hints) html += '<li style="margin:4px 0;">' + escapeHtml(h) + '</li>';
        html += '</ul></div>';
    }
    html += '</div></div>';
    out.innerHTML = html;
}

function arrayRender() {
    const list = document.getElementById('array-list');
    const badge = document.getElementById('array-backend-badge');
    if (!list) return;
    if (badge) {
        badge.textContent = _arrayState.backend === 'nonraid' ? 'Backend: NoNRAID (mdcmd)' : 'Backend: Linux mdadm';
    }
    if (!_arrayState.arrays || _arrayState.arrays.length === 0) {
        list.innerHTML = `
            <div class="card"><div class="card-body" style="text-align:center;padding:40px 20px;">
                <div style="font-size:48px;line-height:1;margin-bottom:12px;"></div>
                <h3 style="margin:0 0 8px;">No arrays detected</h3>
                <p style="color:var(--text-muted);max-width:520px;margin:0 auto 16px;">
                    No mdadm or NoNRAID arrays are present on any node in this cluster, and none of your federated clusters reported any.
                    To create one, use <code>mdadm --create</code> or NoNRAID's setup tooling at the CLI —
                    WolfStack will pick up the array as soon as it's assembled and visible in <code>/proc/mdstat</code> on any node.
                </p>
                <button onclick="arrayDiagnose()" style="background:var(--accent,#3b82f6);color:#fff;border:none;border-radius:6px;padding:10px 20px;cursor:pointer;font-size:13px;font-weight:600;">Diagnose detection</button>
                <div style="color:var(--text-muted);font-size:12px;margin-top:6px;">Use this if you know NoNRAID / mdadm IS installed but it's not being picked up</div>
                <div id="array-diagnose-out" style="margin-top:18px;text-align:left;"></div>
            </div></div>
        `;
        return;
    }

    // Group by (cluster, hostname) so multi-node + multi-cluster
    // setups stay readable. Same pattern as the Shares page.
    const groups = new Map();
    for (const a of _arrayState.arrays) {
        const cluster = a.origin_cluster || a.origin_federation_name || 'WolfStack';
        const host    = a.origin_hostname || a.origin_node_id || 'this node';
        const key = `${cluster} / ${host}`;
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key).push(a);
    }
    let html = '';
    for (const [groupName, arrs] of groups) {
        html += `<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--text-muted);margin:8px 4px -2px;">${escapeHtml(groupName)}</div>`;
        for (const a of arrs) html += arrayRowHtml(a);
    }
    list.innerHTML = html;
}

function arrayStateBadge(s) {
    const map = {
        clean:        ['#22c55e', ''],
        active:       ['#22c55e', ''],
        degraded:     ['#ef4444', ''],
        recovering:   ['#f59e0b', '↻'],
        resyncing:    ['#3b82f6', '↻'],
        reshaping:    ['#3b82f6', '↻'],
        checking:     ['#3b82f6', ''],
        inactive:     ['#94a3b8', ''],
        stopped:      ['#94a3b8', ''],
        unreachable:  ['#ef4444', ''],
    };
    const [c, icon] = map[s] || ['#94a3b8', '?'];
    return `<span style="display:inline-block;padding:2px 10px;border-radius:10px;font-size:11px;font-weight:700;background:${c}22;color:${c};border:1px solid ${c}55;">${icon} ${escapeHtml(s)}</span>`;
}

function bytesPretty(n) {
    if (!n) return '0';
    const u = ['B','KiB','MiB','GiB','TiB','PiB'];
    let i = 0; let v = n;
    while (v >= 1024 && i < u.length - 1) { v /= 1024; i++; }
    return v.toFixed(v < 10 ? 1 : 0) + ' ' + u[i];
}

function arrayRowHtml(a) {
    // Federation-error placeholder rows render slightly differently —
    // no disks, no actions, just the failure reason.
    if (a.federation_error) {
        return `
            <div class="card" style="border-left:3px solid #ef4444;">
                <div class="card-body" style="display:flex;align-items:center;gap:14px;padding:14px 18px;">
                    <div style="font-size:24px;"></div>
                    <div style="flex:1;min-width:0;">
                        <div><strong style="font-size:14px;color:#ef4444;">${escapeHtml(a.name)}</strong></div>
                        <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${escapeHtml(a.federation_error)}</div>
                    </div>
                </div>
            </div>
        `;
    }
    const isLocal = a.origin_self !== false;
    const isFederated = !!a.federated;
    // Ceph entries are read-only from this UI — start/stop/parity
    // are mdadm/NoNRAID specific. Ceph cluster mgmt has its own page.
    const isCeph = a.backend === 'ceph';
    const sched = (isLocal && !isCeph) ? (_arrayState.config.schedules || []).find(s => s.array === a.name) : null;
    const sync = (a.sync_progress != null)
        ? `<div style="margin-top:6px;height:6px;background:rgba(59,130,246,0.15);border-radius:3px;overflow:hidden;">
                <div style="width:${a.sync_progress}%;height:100%;background:#3b82f6;"></div>
            </div>
            <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${a.sync_progress}%${a.sync_speed_kbs ? ` · ${(a.sync_speed_kbs/1024).toFixed(1)} MiB/s` : ''}</div>` : '';
    const disksHtml = (a.disks || []).map(d => {
        const stateColor = d.state === 'faulty' ? '#ef4444'
            : d.state === 'spare' ? '#94a3b8'
            : d.state === 'in_sync' || d.state === 'active' ? '#22c55e' : '#f59e0b';
        const smartColor = d.smart_status === 'PASSED' ? '#22c55e'
            : d.smart_status === 'FAILED' ? '#ef4444' : '#94a3b8';
        return `
            <tr>
                <td style="padding:4px 10px;font-family:ui-monospace,Menlo,monospace;">${escapeHtml(d.device)}</td>
                <td style="padding:4px 10px;">${escapeHtml(d.role)}</td>
                <td style="padding:4px 10px;color:${stateColor};">${escapeHtml(d.state)}</td>
                <td style="padding:4px 10px;">${bytesPretty(d.size_bytes)}</td>
                <td style="padding:4px 10px;color:${smartColor};">${escapeHtml(d.smart_status)}${d.temperature_c != null ? ` · ${d.temperature_c}°C` : ''}</td>
                <td style="padding:4px 10px;font-size:11px;color:var(--text-muted);">${escapeHtml(d.model || '')}</td>
            </tr>
        `;
    }).join('');
    const remoteBadge = isFederated
        ? `<span style="font-size:10px;color:#3b82f6;">${escapeHtml(a.origin_federation_name || 'federated')}${a.origin_hostname ? ' / ' + escapeHtml(a.origin_hostname) : ''}</span>`
        : (!isLocal ? `<span style="font-size:10px;color:var(--text-muted);">on ${escapeHtml(a.origin_hostname || a.origin_node_id || 'peer')}</span>` : '');
    return `
        <div class="card" style="${isFederated ? 'border-left:3px solid #3b82f6;' : ''}">
            <div class="card-body" style="padding:14px 18px;">
                <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;">
                    <strong style="font-size:15px;">/dev/${escapeHtml(a.name)}</strong>
                    <span style="font-size:12px;color:var(--text-muted);">${escapeHtml(a.level)}</span>
                    ${arrayStateBadge(a.state)}
                    ${remoteBadge}
                    <span style="font-size:11px;color:var(--text-muted);margin-left:auto;">
                        ${bytesPretty(a.used_bytes)} / ${bytesPretty(a.size_bytes)}
                    </span>
                </div>
                ${sync}
                <table style="width:100%;margin-top:10px;border-collapse:collapse;font-size:12px;">
                    <thead>
                        <tr style="text-align:left;color:var(--text-muted);">
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">Device</th>
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">Role</th>
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">State</th>
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">Size</th>
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">SMART</th>
                            <th style="padding:6px 10px;font-size:11px;font-weight:600;border-bottom:1px solid var(--border);">Model</th>
                        </tr>
                    </thead>
                    <tbody>${disksHtml}</tbody>
                </table>
                ${isCeph ? `<div style="margin-top:8px;font-size:11px;color:var(--text-muted);">${escapeHtml(a.ceph_health_detail || '')} · v${escapeHtml(a.ceph_version || '?')}</div>` : ''}
                <div style="margin-top:12px;display:flex;gap:6px;flex-wrap:wrap;align-items:center;">
                    ${isCeph
                        ? (isFederated
                            ? `<a class="btn btn-sm" href="${escapeAttr(a.origin_federation_url || '#')}" target="_blank" rel="noopener" style="text-decoration:none;">Open Ceph manager on ${escapeHtml(a.origin_federation_name || 'remote cluster')} →</a>
                               <span style="font-size:11px;color:var(--text-muted);">Cluster-managed; mutating ops live on the originating cluster</span>`
                            : `<button class="btn btn-sm" onclick="selectServerView('${escapeAttr(a.origin_node_id || currentNodeId || '')}', 'ceph')">Open Ceph manager →</button>
                               <span style="font-size:11px;color:var(--text-muted);">Cluster-managed; mutating ops live in the Ceph page</span>`)
                        : isLocal
                        ? `${a.state === 'stopped'
                                ? `<button class="btn btn-sm" onclick="arrayStart('${escapeAttr(a.name)}')">▶ Start</button>`
                                : `<button class="btn btn-sm" onclick="arrayStop('${escapeAttr(a.name)}')">Stop</button>`}
                            ${a.state === 'checking' || a.state === 'resyncing' || a.state === 'recovering' || a.state === 'reshaping'
                                ? `<button class="btn btn-sm" onclick="arrayParityCancel('${escapeAttr(a.name)}')">Cancel parity</button>`
                                : `<button class="btn btn-sm" onclick="arrayParity('${escapeAttr(a.name)}','check')">Parity check</button>
                                   <button class="btn btn-sm" onclick="arrayParity('${escapeAttr(a.name)}','repair')" title="Overwrite mismatches with parity">Parity repair</button>`}
                            <button class="btn btn-sm" onclick="arraySchedulePrompt('${escapeAttr(a.name)}')">
                                Schedule${sched ? ` <small style="color:var(--text-muted);">(${escapeHtml(sched.cron)})</small>` : ''}
                            </button>`
                        : `<span style="font-size:11px;color:var(--text-muted);">Read-only view — manage from ${escapeHtml(a.origin_hostname || a.origin_node_id || 'the originating dashboard')}${isFederated ? ` (open <a href="${escapeAttr(a.origin_federation_url || '#')}" target="_blank" rel="noopener">${escapeHtml(a.origin_federation_name || 'remote cluster')}</a>)` : ''}</span>`}
                </div>
            </div>
        </div>
    `;
}

async function arrayStart(name) {
    if (!await confirmModal(`Start /dev/${name}? This will assemble the array and bring its filesystems online.`)) return;
    const r = await fetch(`/api/array/${encodeURIComponent(name)}/start`, { method: 'POST' });
    const d = await r.json();
    if (d.ok) showToast('Array started', 'success'); else showToast(d.error || 'Start failed', 'error');
    await arrayLoad();
}

async function arrayStop(name) {
    if (!await confirmModal(`Stop /dev/${name}? Mounted filesystems on this array will become inaccessible. This is destructive — only do it if you know what you're doing.`)) return;
    const r = await fetch(`/api/array/${encodeURIComponent(name)}/stop`, { method: 'POST' });
    const d = await r.json();
    if (d.ok) showToast('Array stopped', 'success'); else showToast(d.error || 'Stop failed', 'error');
    await arrayLoad();
}

async function arrayParity(name, action) {
    const verb = action === 'repair' ? 'parity REPAIR (will overwrite mismatches with parity-derived values)' : 'parity check (read-only verify)';
    if (!await confirmModal(`Start ${verb} on /dev/${name}? This can take many hours on a large array. Other I/O still works during the scan but at reduced speed.`)) return;
    const r = await fetch(`/api/array/${encodeURIComponent(name)}/parity`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action }),
    });
    const d = await r.json();
    if (d.ok) showToast(`${action === 'repair' ? 'Repair' : 'Check'} started`, 'success'); else showToast(d.error || 'Parity start failed', 'error');
    await arrayLoad();
}

async function arrayParityCancel(name) {
    if (!await confirmModal(`Cancel the parity operation on /dev/${name}? You can re-run it later — the array stays operational either way.`)) return;
    const r = await fetch(`/api/array/${encodeURIComponent(name)}/parity/cancel`, { method: 'POST' });
    const d = await r.json();
    if (d.ok) showToast('Parity cancelled', 'success'); else showToast(d.error || 'Cancel failed', 'error');
    await arrayLoad();
}

async function arraySchedulePrompt(name) {
    const existing = (_arrayState.config.schedules || []).find(s => s.array === name);
    const cron = await promptModal(
        `Cron expression for parity check on /dev/${name}\n\nExamples:\n  0 3 * * 0   — every Sunday 03:00\n  0 4 1 * *   — first of month at 04:00\n  (empty to remove schedule)`,
        existing ? existing.cron : '0 3 * * 0',
    );
    if (cron === null) return;
    let cfg = JSON.parse(JSON.stringify(_arrayState.config));
    cfg.schedules = (cfg.schedules || []).filter(s => s.array !== name);
    if (cron && cron.trim()) {
        cfg.schedules.push({ array: name, cron: cron.trim(), action: 'check', enabled: true });
    }
    const r = await fetch('/api/array/config', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(cfg),
    });
    const d = await r.json();
    if (d.ok) {
        _arrayState.config = cfg;
        showToast(cron && cron.trim() ? 'Schedule saved' : 'Schedule removed', 'success');
        arrayRender();
    } else {
        showToast(d.error || 'Schedule save failed', 'error');
    }
}

window.arrayLoad = arrayLoad;
window.arrayRender = arrayRender;
window.arrayStart = arrayStart;
window.arrayStop = arrayStop;
window.arrayParity = arrayParity;
window.arrayParityCancel = arrayParityCancel;
window.arraySchedulePrompt = arraySchedulePrompt;

// ─── Galera cluster manager ───────────────────────────────────────────
//
// Build/adopt and run MariaDB Galera clusters made of LXC containers. A
// cluster is "owned" by one WolfStack host: its galera.json definition and
// (for provisioned clusters) its containers live there. Lifecycle + recovery
// shell out to lxc-attach on that host, so every call is directed at it via
// the node proxy. Live status is queried over MySQL TCP, which works
// cross-host. The host selector at the top picks which host to manage.

// Galera is managed per WolfStack cluster (reached from the cluster in the
// sidebar). Each Galera cluster's definition lives on the host it was built/
// adopted on (its owner_node); this view aggregates definitions across the WS
// cluster's hosts and routes each cluster's ops back to its owner. Containers
// can sit on different hosts — the backend dispatches lifecycle/recovery to the
// right host automatically.
const galeraState = { cluster: '', clusters: [], statuses: {}, statusErrors: {}, loading: false, gen: 0, activeJobAbort: null };

// The WS cluster a node belongs to (matches buildServerTree's grouping key).
function galeraNodeCluster(n) { return n.cluster_name || 'WolfStack'; }

// WolfStack hosts (not Proxmox) in the currently-viewed WS cluster.
function galeraClusterNodes() {
    return (Array.isArray(allNodes) ? allNodes : [])
        .filter(n => galeraNodeCluster(n) === galeraState.cluster && n.node_type !== 'proxmox');
}

function galeraHostName(id) {
    // Match the locally-assigned key OR the peer's stable self_id — a Galera
    // node's stored node_id may be either (adopt stamps the portable self_id).
    const n = (Array.isArray(allNodes) ? allNodes : []).find(x => x.id === id || x.self_id === id);
    return n ? (n.hostname || n.id) : (id || 'this host');
}

// Route a galera API call to a SPECIFIC host. Proxy path is WITHOUT the /api/
// prefix; local API when it's self or the host isn't in allNodes yet.
function galeraNodeBase(hostId, path) {
    // Match either the browser's local key OR the stable self_id — host pickers
    // now send self_ids so a build/op routes correctly from any node. The
    // node-proxy resolves a self_id via get_node, so passing it through works.
    const node = (Array.isArray(allNodes) ? allNodes : []).find(n => n.id === hostId || n.self_id === hostId);
    if (!hostId || !node || node.is_self) return '/api/galera/' + path;
    return `/api/nodes/${encodeURIComponent(hostId)}/proxy/galera/${path}`;
}

// Enter the Galera view for a WolfStack cluster (sidebar → cluster → Galera).
async function showGaleraForCluster(clusterName) {
    if (typeof closeSidebarMobile === 'function') closeSidebarMobile();
    // Fresh chart history when switching to a different cluster's view.
    if (galeraState.cluster !== clusterName) galeraState.history = {};
    galeraState.cluster = clusterName;
    currentPage = 'galera-cluster';
    currentNodeId = null;
    try { if (typeof updateClusterPill === 'function') updateClusterPill(); } catch (_) {}
    document.querySelectorAll('.page-view').forEach(p => p.style.display = 'none');
    const el = document.getElementById('page-galera');
    if (el) el.style.display = 'block';
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const item = document.querySelector('.galera-cluster-item[data-cluster="' + (typeof CSS !== 'undefined' && CSS.escape ? CSS.escape(clusterName) : clusterName) + '"]');
    if (item) item.classList.add('active');
    const t = document.getElementById('page-title');
    if (t) t.textContent = 'Galera — ' + clusterName;
    if (!Array.isArray(allNodes) || allNodes.length === 0) {
        try { const r = await fetch('/api/nodes'); if (r.ok) allNodes = await r.json(); } catch (_) {}
    }
    await galeraLoadClusters();
    // Periodic status refresh while viewing — keeps status live and grows the
    // per-node replication charts. Self-cancels when you leave the view.
    if (galeraState.timer) clearInterval(galeraState.timer);
    galeraState.timer = setInterval(() => {
        if (currentPage !== 'galera-cluster') { clearInterval(galeraState.timer); galeraState.timer = null; return; }
        galeraRefreshStatus();
    }, 12000);
}

// Refresh the currently-viewed cluster.
function galeraInit() { return galeraLoadClusters(); }

async function galeraLoadClusters() {
    const content = document.getElementById('galera-content');
    if (!content) return;
    // Generation guard: a re-entrant load must not be painted over by a stale one.
    const myGen = ++galeraState.gen;
    galeraState.loading = true;
    galeraState.statuses = {};
    galeraState.statusErrors = {};
    galeraState.loadError = '';
    galeraRender();
    // Aggregate Galera definitions across every host in this WS cluster (each
    // cluster lives on the host it was built/adopted on).
    const hosts = galeraClusterNodes();
    const targets = Array.from(new Set([''].concat(hosts.map(h => h.id)))); // always include the local node so browser-owned (adopted-here) clusters show
    try {
        const scope = 'clusters?cluster=' + encodeURIComponent(galeraState.cluster);
        const lists = await Promise.all(targets.map(id =>
            fetch(galeraNodeBase(id, scope))
                .then(r => (r.ok ? r.json() : []))
                .catch(() => [])
        ));
        if (myGen !== galeraState.gen) return; // superseded
        // Dedup by id across hosts. A cluster's definition normally lives on one
        // host (owner_node). If a stray copy exists elsewhere, prefer the copy
        // whose owner_node matches the host it came from — that's the one ops
        // route to correctly.
        const byId = {};
        lists.forEach((list, i) => {
            const fetchHost = targets[i];
            (Array.isArray(list) ? list : []).forEach(c => {
                // Route this cluster's ops to the host we ACTUALLY found its
                // config on — that host holds the galera.json definition (it just
                // returned it), so status/recover/etc. resolve there. The stored
                // owner_node can be stale or point at the build host rather than
                // the config host (the cause of "owning host 404").
                if (fetchHost) c.owner_node = fetchHost;
                if (!byId[c.id]) byId[c.id] = c;
            });
        });
        galeraState.clusters = Object.keys(byId).map(k => byId[k]);
    } catch (e) {
        if (myGen !== galeraState.gen) return;
        galeraState.clusters = [];
        galeraState.loadError = (e && e.message) || String(e);
    }
    galeraState.loading = false;
    galeraRender();
    // Live status per cluster → routed to the host that owns its definition.
    (galeraState.clusters || []).forEach(c => {
        fetch(galeraNodeBase(galeraClusterOwner(c), 'clusters/' + encodeURIComponent(c.id) + '/status'))
            .then(r => (r.ok ? r.json() : Promise.reject(new Error('HTTP ' + r.status))))
            .then(st => { if (myGen === galeraState.gen) { galeraState.statuses[c.id] = st; galeraState.statusErrors[c.id] = ''; galeraPushHistory(st); galeraUpdateLive(c.id); } })
            .catch(e => { if (myGen === galeraState.gen) { galeraState.statusErrors[c.id] = (e && e.message) || 'unreachable'; galeraUpdateLive(c.id); } });
    });
}

// Append the latest per-node replication metrics to a rolling history (capped),
// so the sparklines build up over successive status refreshes.
// The metrics dashboard — one time-series panel per metric, a line per node.
// `gauge` metrics plot the stored value; `rate` metrics derive per-second from
// a cumulative counter (`src`).
const GALERA_METRICS = [
    { key: 'fcp',       title: 'Flow Control Pause %',  kind: 'gauge',                fmt: v => v.toFixed(0) + '%' },
    { key: 'recvq',     title: 'Replication Queue',     kind: 'gauge',                fmt: v => Math.round(v).toString() },
    { key: 'txns',      title: 'Transactions / sec',    kind: 'rate', src: 'received', fmt: v => v.toFixed(1) },
    { key: 'conns',     title: 'Connections',           kind: 'gauge',                fmt: v => Math.round(v).toString() },
    { key: 'size',      title: 'Cluster Size',          kind: 'gauge',                fmt: v => Math.round(v).toString() },
    { key: 'conflicts', title: 'Write Conflicts / sec', kind: 'rate', src: 'cfail',   fmt: v => v.toFixed(2) },
];

function galeraPushHistory(st) {
    if (!st || !Array.isArray(st.nodes)) return;
    galeraState.history = galeraState.history || {};
    const CAP = 60;
    st.nodes.forEach(ns => {
        // Key by cluster id + container so two clusters with a same-named node
        // don't share a history bucket.
        const key = st.cluster_id + '|' + ns.container;
        const h = galeraState.history[key] = galeraState.history[key]
            || { t: [], fcp: [], recvq: [], conns: [], size: [], received: [], cfail: [] };
        const up = ns.reachable;
        h.t.push(Date.now());
        h.fcp.push(up ? (ns.flow_control_paused || 0) * 100 : 0);
        h.recvq.push(up ? (ns.recv_queue_avg || 0) : 0);
        h.conns.push(up ? (ns.threads_connected || 0) : 0);
        h.size.push(up ? (ns.cluster_size || 0) : 0);
        h.received.push(up ? (ns.received || 0) : 0);
        h.cfail.push(up ? (ns.cert_failures || 0) : 0);
        Object.keys(h).forEach(k => { while (h[k].length > CAP) h[k].shift(); });
    });
}

// Per-second rate from a cumulative counter array + matching timestamps.
// Negatives (counter reset on restart) clamp to 0.
function galeraRateSeries(counter, t) {
    const out = [0];
    for (let i = 1; i < (counter || []).length; i++) {
        const dt = ((t[i] - t[i - 1]) || 12000) / 1000;
        const dv = counter[i] - counter[i - 1];
        out.push(dv >= 0 && dt > 0 ? dv / dt : 0);
    }
    return out;
}

// Draw one metric panel: auto-scaled Y axis, gridlines, time axis, a filled
// line per node, legend with the latest value. Uses the app's chart scaffolding.
function galeraDrawMetricChart(canvasId, legendId, seriesByNode, fmt) {
    const setup = setupCanvas(canvasId);
    if (!setup) return;
    const { ctx, rect } = setup;
    const padding = { top: 12, right: 10, bottom: 22, left: 46 };
    const w = rect.width - padding.left - padding.right;
    const h = rect.height - padding.top - padding.bottom;
    if (w <= 0 || h <= 0) return;
    let max = 0, len = 0;
    Object.values(seriesByNode).forEach(s => { (s || []).forEach(v => { if (v > max) max = v; }); if ((s || []).length > len) len = s.length; });
    if (max <= 0) max = 1;
    drawGrid(ctx, padding, w, h);
    drawYLabels(ctx, padding, h, [fmt(max), fmt(max * 0.75), fmt(max * 0.5), fmt(max * 0.25), fmt(0)]);
    if (len >= 2) {
        ctx.fillStyle = 'rgba(255,255,255,0.3)'; ctx.font = '10px Inter, sans-serif';
        ctx.textAlign = 'center'; ctx.textBaseline = 'top';
        for (let i = 0; i <= 4; i++) {
            const frac = i / 4, x = padding.left + frac * w;
            const secsAgo = Math.round(len * 12 * (1 - frac)); // ~12s sample interval
            ctx.fillText(secsAgo >= 60 ? '-' + Math.round(secsAgo / 60) + 'm' : '-' + secsAgo + 's', x, padding.top + h + 5);
        }
    }
    const colors = ['#22c55e', '#f59e0b', '#3b82f6', '#8b5cf6', '#ec4899', '#ef4444'];
    const legend = document.getElementById(legendId); if (legend) legend.innerHTML = '';
    let ci = 0;
    Object.keys(seriesByNode).forEach(node => {
        const arr = seriesByNode[node] || [];
        const color = colors[ci % colors.length]; ci++;
        if (arr.length >= 2) {
            ctx.beginPath();
            arr.forEach((v, idx) => {
                const x = padding.left + (idx / (arr.length - 1)) * w;
                const y = padding.top + h - (v / max) * h;
                if (idx === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            });
            ctx.strokeStyle = color; ctx.lineWidth = 1.6; ctx.lineJoin = 'round'; ctx.stroke();
            ctx.lineTo(padding.left + w, padding.top + h); ctx.lineTo(padding.left, padding.top + h); ctx.closePath();
            ctx.fillStyle = color + '18'; ctx.fill();
        }
        const cur = arr.length ? arr[arr.length - 1] : 0;
        if (legend) legend.innerHTML += `<span style="display:inline-flex;align-items:center;gap:4px;font-size:10px;color:var(--text-muted);"><span style="width:8px;height:8px;border-radius:2px;background:${color};"></span>${escapeHtml(node)} <b style="color:${color};">${escapeHtml(fmt(cur))}</b></span>`;
    });
}

// Redraw one cluster's metric grid from accumulated history.
function galeraDrawClusterCharts(c) {
    GALERA_METRICS.forEach(m => {
        const seriesByNode = {};
        (c.nodes || []).forEach(n => {
            const h = (galeraState.history || {})[c.id + '|' + n.container];
            if (!h) return;
            seriesByNode[n.container] = (m.kind === 'rate') ? galeraRateSeries(h[m.src], h.t) : (h[m.key] || []);
        });
        galeraDrawMetricChart('galera-chart-' + c.id + '-' + m.key, 'galera-legend-' + c.id + '-' + m.key, seriesByNode, m.fmt);
    });
}

// Redraw every cluster's metric grid.
function galeraDrawCharts() {
    (galeraState.clusters || []).forEach(galeraDrawClusterCharts);
}

// The cluster's health badge HTML (status-dependent).
function galeraBadgeHtml(st, statusErr) {
    if (!st && statusErr) return `<span title="${escapeAttr(statusErr)}" style="display:inline-block;padding:2px 9px;border-radius:4px;font-size:11px;font-weight:600;background:#6b728022;color:#9ca3af;">status unavailable</span>`;
    if (!st) return `<span style="display:inline-block;padding:2px 9px;border-radius:4px;font-size:11px;font-weight:600;background:#6b728022;color:#9ca3af;">checking…</span>`;
    if (st.split_brain) return `<span title="Reachable nodes disagree on cluster identity or size" style="display:inline-block;padding:2px 9px;border-radius:4px;font-size:11px;font-weight:700;background:#ef444422;color:#ef4444;">⚠ SPLIT-BRAIN</span>`;
    if (st.healthy) return `<span style="display:inline-block;padding:2px 9px;border-radius:4px;font-size:11px;font-weight:600;background:#22c55e22;color:#22c55e;">● healthy</span>`;
    return `<span style="display:inline-block;padding:2px 9px;border-radius:4px;font-size:11px;font-weight:600;background:#f59e0b22;color:#f59e0b;">degraded</span>`;
}

// The cluster's summary line HTML (status-dependent).
function galeraSummaryHtml(st, statusErr) {
    return st ? escapeHtml(st.summary || '')
        : (statusErr ? `<span style="color:var(--danger);">Couldn't reach the owning host for status: ${escapeHtml(statusErr)}</span>`
                     : 'Querying node status…');
}

// Update a cluster card's status-dependent bits IN PLACE (badge, summary,
// per-node cells) + redraw its charts — no innerHTML rebuild, so no flashing.
function galeraUpdateLive(cid) {
    const c = (galeraState.clusters || []).find(x => x.id === cid);
    if (!c) return;
    const st = galeraState.statuses[cid];
    const statusErr = galeraState.statusErrors[cid];
    const set = (id, html) => { const el = document.getElementById(id); if (el) el.innerHTML = html; };
    set('gbadge-' + cid, galeraBadgeHtml(st, statusErr));
    set('gsum-' + cid, galeraSummaryHtml(st, statusErr));
    const byC = {};
    if (st && Array.isArray(st.nodes)) st.nodes.forEach(ns => { byC[ns.container] = ns; });
    (c.nodes || []).forEach(n => {
        const ns = byC[n.container];
        set('gst-' + cid + '-' + n.container, galeraNodeStateBadge(ns));
        set('gcl-' + cid + '-' + n.container, escapeHtml(ns && ns.reachable ? (ns.cluster_status || '—') : '—'));
        set('gsz-' + cid + '-' + n.container, escapeHtml(ns && ns.reachable ? String(ns.cluster_size) : '—'));
    });
    galeraDrawClusterCharts(c);
}

// Lightweight periodic status refresh (keeps status live + grows the charts)
// WITHOUT re-aggregating the whole cluster list. Bound to the galera view.
function galeraRefreshStatus() {
    if (currentPage !== 'galera-cluster') { return; }
    const myGen = galeraState.gen;
    (galeraState.clusters || []).forEach(c => {
        fetch(galeraNodeBase(galeraClusterOwner(c), 'clusters/' + encodeURIComponent(c.id) + '/status'))
            .then(r => (r.ok ? r.json() : Promise.reject(new Error('HTTP ' + r.status))))
            .then(st => { if (galeraState.gen === myGen && currentPage === 'galera-cluster') { galeraState.statuses[c.id] = st; galeraState.statusErrors[c.id] = ''; galeraPushHistory(st); galeraUpdateLive(c.id); } })
            .catch(e => { if (galeraState.gen === myGen && currentPage === 'galera-cluster') { galeraState.statusErrors[c.id] = (e && e.message) || 'unreachable'; galeraUpdateLive(c.id); } });
    });
}

function galeraContextBarHtml() {
    const n = galeraClusterNodes().length;
    return `<div style="display:flex; align-items:center; gap:10px; margin-bottom:14px; flex-wrap:wrap;">
        <span style="font-size:11px; color:var(--text-muted);">Galera in cluster <b>${escapeHtml(galeraState.cluster)}</b> · ${n} host${n === 1 ? '' : 's'}. Containers can live on any host; lifecycle &amp; recovery route automatically.</span>
    </div>`;
}

function galeraNodeStateBadge(ns) {
    if (!ns) return `<span style="color:var(--text-muted);">—</span>`;
    if (!ns.reachable) {
        return `<span title="${escapeAttr(ns.error || 'unreachable')}" style="display:inline-block;padding:1px 7px;border-radius:3px;font-size:10px;font-weight:600;background:#6b728022;color:#9ca3af;">unreachable</span>`;
    }
    const synced = (ns.state || '').toLowerCase() === 'synced' && ns.ready;
    const color = synced ? '#22c55e' : ((ns.state || '').toLowerCase().includes('join') || (ns.state || '').toLowerCase().includes('donor') ? '#f59e0b' : '#ef4444');
    // Tooltip carries the wsrep details useful when diagnosing split-brain.
    const tip = `connected: ${ns.connected ? 'yes' : 'no'} · ready: ${ns.ready ? 'yes' : 'no'}${ns.cluster_uuid ? ' · uuid: ' + ns.cluster_uuid : ''}`;
    return `<span title="${escapeAttr(tip)}" style="display:inline-block;padding:1px 7px;border-radius:3px;font-size:10px;font-weight:600;background:${color}22;color:${color};">${escapeHtml(ns.state || 'unknown')}</span>`;
}

function galeraClusterCardHtml(c) {
    const st = galeraState.statuses[c.id];
    const statusErr = galeraState.statusErrors[c.id];
    const nodeCount = (c.nodes || []).length;
    const badge = galeraBadgeHtml(st, statusErr);

    const statusById = {};
    if (st && Array.isArray(st.nodes)) st.nodes.forEach(ns => { statusById[ns.container] = ns; });

    const rows = (c.nodes || []).map(n => {
        const ns = statusById[n.container];
        const size = ns && ns.reachable ? ns.cluster_size : '—';
        const prim = ns && ns.reachable ? (ns.cluster_status || '—') : '—';
        // Identifiers ride in data-* attributes (safe via escapeAttr) and are
        // dispatched by a delegated listener — never interpolated into a JS
        // string inside an onclick, where `&#39;` decodes back to `'` and a
        // crafted name could break out. See galeraBindDelegation().
        const cid = escapeAttr(c.id), cont = escapeAttr(n.container);
        const act = (label, action, cls) =>
            `<button class="btn btn-sm" title="${label} MariaDB on ${escapeAttr(n.container)}" data-galera-act="node" data-cid="${cid}" data-cont="${cont}" data-action="${action}" style="padding:2px 8px;font-size:11px;${cls || ''}">${label}</button>`;
        const hostLabel = n.node_id ? galeraHostName(n.node_id) : '—';
        return `<tr style="border-top:1px solid var(--border);">
            <td style="padding:6px 8px;font-family:var(--font-mono,monospace);font-size:12px;">${escapeHtml(n.container)}</td>
            <td style="padding:6px 8px;font-family:var(--font-mono,monospace);font-size:12px;color:var(--text-muted);">${escapeHtml(n.address)}:${escapeHtml(String(n.port || 3306))}</td>
            <td style="padding:6px 8px;font-size:12px;color:var(--text-muted);" title="Host that runs this container (updates automatically if it's migrated)">${escapeHtml(hostLabel)}</td>
            <td id="gst-${c.id}-${n.container}" style="padding:6px 8px;">${galeraNodeStateBadge(ns)}</td>
            <td id="gcl-${c.id}-${n.container}" style="padding:6px 8px;font-size:12px;">${escapeHtml(String(prim))}</td>
            <td id="gsz-${c.id}-${n.container}" style="padding:6px 8px;font-size:12px;text-align:center;">${escapeHtml(String(size))}</td>
            <td style="padding:6px 8px;text-align:right;white-space:nowrap;">
                <button class="btn btn-sm" title="Open a terminal on ${escapeAttr(n.container)} (run mariadb there to reach the database)" data-galera-act="console" data-cid="${cid}" data-cont="${cont}" data-kind="${escapeAttr(n.kind || 'lxc')}" data-host="${escapeAttr(n.node_id || '')}" style="padding:2px 8px;font-size:11px;border-color:var(--accent,#3b82f6);color:var(--accent,#60a5fa);"><span class="ws-icon-clean-wrap" data-icon="terminal"></span> Console</button>
                ${act('Start', 'start')}
                ${act('Stop', 'stop')}
                ${act('Restart', 'restart')}
            </td>
        </tr>`;
    }).join('');

    const summary = galeraSummaryHtml(st, statusErr);
    const splitWarn = st && st.split_brain
        ? `<div role="alert" style="margin:10px 0;padding:8px 12px;border:1px solid #ef4444;border-radius:6px;background:#ef444411;color:#fca5a5;font-size:12px;">
             Split-brain detected — the cluster has fractured into separate components. Use <b>Recover</b> to stop every node, find the most up-to-date one, and rebuild around it. WolfStack will refuse to bootstrap a node whose position is unknown.
           </div>` : '';

    // Galera Metrics grid — one time-series panel per metric, a line per node.
    const connMax = (st && Array.isArray(st.nodes)) ? Math.max(0, ...st.nodes.map(n => n.max_connections || 0)) : 0;
    const metricsGrid = `
        <div style="margin-top:14px;">
            <div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.4px;margin-bottom:8px;">Galera Metrics</div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;">
                ${GALERA_METRICS.map(m => `
                    <div style="border:1px solid var(--border);border-radius:8px;padding:10px;">
                        <div style="font-size:12px;font-weight:600;margin-bottom:6px;">${escapeHtml(m.title)}${m.key === 'conns' && connMax ? ` <span style="font-weight:400;color:var(--text-muted);font-size:10px;">/ ${connMax} max</span>` : ''}</div>
                        <div style="width:100%;height:120px;"><canvas id="galera-chart-${c.id}-${m.key}"></canvas></div>
                        <div id="galera-legend-${c.id}-${m.key}" style="display:flex;gap:10px;flex-wrap:wrap;margin-top:6px;"></div>
                    </div>`).join('')}
            </div>
        </div>`;

    // MaxScale proxies provisioned for this cluster (NOT Galera members).
    const proxies = c.proxies || [];
    const proxiesHtml = proxies.length ? `
        <div style="margin-top:14px;">
            <div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px;">MaxScale proxies</div>
            <div style="display:flex;flex-direction:column;gap:6px;">
                ${proxies.map(px => {
                    const pcont = escapeAttr(px.container);
                    return `<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;border:1px solid var(--border);border-radius:8px;padding:8px 10px;font-size:12px;">
                        <span style="font-family:var(--font-mono,monospace);font-weight:600;">${escapeHtml(px.container)}</span>
                        <span style="color:var(--text-muted);">apps connect to <b style="font-family:var(--font-mono,monospace);color:var(--text-primary);">${escapeHtml(px.address)}:${escapeHtml(String(px.listener_port || 3306))}</b></span>
                        <span style="font-size:10px;color:var(--text-muted);">${escapeHtml(px.node_id ? galeraHostName(px.node_id) : '')}</span>
                        <span style="margin-left:auto;display:flex;gap:6px;">
                            <button class="btn btn-sm" title="Open a terminal on ${pcont}" data-galera-act="console" data-cid="${escapeAttr(c.id)}" data-cont="${pcont}" data-kind="lxc" data-host="${escapeAttr(px.node_id || '')}" style="padding:2px 8px;font-size:11px;border-color:var(--accent,#3b82f6);color:var(--accent,#60a5fa);"><span class="ws-icon-clean-wrap" data-icon="terminal"></span> Console</button>
                            <button class="btn btn-sm" title="Stop and remove this proxy" data-galera-act="rmproxy" data-cid="${escapeAttr(c.id)}" data-cont="${pcont}" style="padding:2px 8px;font-size:11px;border-color:var(--danger);color:var(--danger);">Remove</button>
                        </span>
                    </div>`;
                }).join('')}
            </div>
        </div>` : '';

    return `<div class="card" style="margin-bottom:16px;">
        <div class="card-body">
            <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;">
                <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;">
                    <h3 style="margin:0;font-size:16px;">${escapeHtml(c.name)}</h3>
                    <span id="gbadge-${c.id}">${badge}</span>
                    <span style="font-size:11px;color:var(--text-muted);">${nodeCount} node${nodeCount === 1 ? '' : 's'} · SST ${escapeHtml(c.sst_method || 'mariabackup')} · ${c.provisioned ? 'provisioned' : 'adopted'}</span>
                </div>
                <div style="display:flex;gap:6px;flex-wrap:wrap;">
                    <button class="btn btn-sm" data-galera-act="refresh" title="Refresh status">↻</button>
                    <button class="btn btn-sm" data-galera-act="addnode" data-cid="${escapeAttr(c.id)}" title="Add more MariaDB+Galera nodes to this cluster">+ Add node</button>
                    <button class="btn btn-sm" data-galera-act="maxscale" data-cid="${escapeAttr(c.id)}" title="Provision a MaxScale proxy pre-configured for this cluster">+ MaxScale</button>
                    <button class="btn btn-sm" data-galera-act="analyze" data-cid="${escapeAttr(c.id)}" title="Check cache, threads and other settings against this cluster's resources">Analyze</button>
                    <button class="btn btn-sm" data-galera-act="recover" data-cid="${escapeAttr(c.id)}" style="border-color:#f59e0b;color:#f59e0b;">Recover</button>
                    <button class="btn btn-sm" data-galera-act="forget" data-cid="${escapeAttr(c.id)}" title="Forget this cluster (does not destroy containers)" style="border-color:var(--danger);color:var(--danger);">Forget</button>
                </div>
            </div>
            <div id="gsum-${c.id}" style="font-size:12px;color:var(--text-muted);margin-top:6px;">${summary}</div>
            ${splitWarn}
            <div style="overflow-x:auto;margin-top:10px;">
                <table style="width:100%;border-collapse:collapse;font-size:13px;">
                    <thead><tr style="text-align:left;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.4px;">
                        <th style="padding:4px 8px;">Container</th>
                        <th style="padding:4px 8px;">Address</th>
                        <th style="padding:4px 8px;">Host</th>
                        <th style="padding:4px 8px;">State</th>
                        <th style="padding:4px 8px;">Cluster</th>
                        <th style="padding:4px 8px;text-align:center;">Size</th>
                        <th style="padding:4px 8px;text-align:right;">Lifecycle</th>
                    </tr></thead>
                    <tbody>${rows || `<tr><td colspan="7" style="padding:10px;color:var(--text-muted);">No nodes registered.</td></tr>`}</tbody>
                </table>
            </div>
            ${(c.nodes && c.nodes.length) ? metricsGrid : ''}
            ${proxiesHtml}
        </div>
    </div>`;
}

function galeraRender() {
    const content = document.getElementById('galera-content');
    if (!content) return;
    let html = galeraContextBarHtml();
    if (galeraState.loading) {
        html += `<div style="color:var(--text-muted);text-align:center;padding:30px;font-size:13px;">Loading Galera clusters in ${escapeHtml(galeraState.cluster)}…</div>`;
    } else if (galeraState.loadError) {
        // Don't clear the error here — a racing status repaint would erase it
        // before the operator reads it. It's reset when the next load starts.
        html += `<div role="alert" class="card"><div class="card-body" style="color:var(--danger);font-size:13px;">Couldn't load clusters: ${escapeHtml(galeraState.loadError)}</div></div>`;
    } else if (!galeraState.clusters || galeraState.clusters.length === 0) {
        html += `<div class="card"><div class="card-body" style="text-align:center;padding:40px 20px;color:var(--text-muted);">
            <div style="font-size:36px;margin-bottom:8px;"><span class="ws-icon-clean-wrap" data-icon="database"></span></div>
            <div style="font-size:14px;">No Galera clusters in ${escapeHtml(galeraState.cluster)} yet.</div>
            <div style="font-size:12px;margin-top:4px;">Spin up a fresh one, or adopt containers you already run.</div>
            <div style="margin-top:14px;display:flex;gap:8px;justify-content:center;">
                <button class="btn btn-primary btn-sm" onclick="galeraCreateOpen()">+ New cluster</button>
                <button class="btn btn-sm" onclick="galeraAdoptOpen()">Adopt existing</button>
            </div>
        </div></div>`;
    } else {
        html += galeraState.clusters.map(galeraClusterCardHtml).join('');
    }
    content.innerHTML = html;
    galeraBindDelegation();
    galeraDrawCharts();
    // `data-icon` placeholders are hydrated automatically by the global
    // observeForDataIcons MutationObserver — no manual pass needed.
}

/// Attach ONE delegated click listener to #galera-content (which persists
/// across re-renders). Card buttons carry their identifiers in data-* attrs,
/// so no untrusted value is ever placed in a JS-string onclick. Idempotent.
function galeraBindDelegation() {
    const content = document.getElementById('galera-content');
    if (!content || content.dataset.galeraBound) return;
    content.dataset.galeraBound = '1';
    content.addEventListener('click', ev => {
        const btn = ev.target.closest('[data-galera-act]');
        if (!btn) return;
        const act = btn.getAttribute('data-galera-act');
        const cid = btn.getAttribute('data-cid') || '';
        if (act === 'node') galeraNodeAction(cid, btn.getAttribute('data-cont') || '', btn.getAttribute('data-action') || '');
        else if (act === 'recover') galeraRecover(cid);
        else if (act === 'forget') galeraDelete(cid);
        else if (act === 'refresh') galeraLoadClusters();
        else if (act === 'analyze') galeraAnalyze(cid);
        else if (act === 'addnode') galeraAddNodesOpen(cid);
        else if (act === 'maxscale') galeraMaxScaleOpen(cid);
        else if (act === 'rmproxy') galeraRemoveProxy(cid, btn.getAttribute('data-cont') || '');
        else if (act === 'console') galeraOpenConsole(btn.getAttribute('data-cont') || '', btn.getAttribute('data-kind') || 'lxc', btn.getAttribute('data-host') || '');
    });
}

// Open a terminal into a node's container (on its host) — reuses the standard
// container console, which already handles per-node routing + remote bridging.
// The operator runs the MariaDB client there; we hint the exact command.
function galeraOpenConsole(container, kind, host) {
    if (!container) return;
    let url = '/console.html?type=' + encodeURIComponent(kind || 'lxc') + '&name=' + encodeURIComponent(container);
    const node = (Array.isArray(allNodes) ? allNodes : []).find(n => n.id === host || n.self_id === host);
    if (host && node && !node.is_self) url += '&node_id=' + encodeURIComponent(host);
    window.open(url, 'galera_sql_' + container.replace(/[^a-zA-Z0-9_.-]/g, '_'), 'width=980,height=620,menubar=no,toolbar=no');
    showToast('Terminal opened on ' + container + ' — run:  mariadb -u root -p', 'info', 8000);
}

// ── Modal scaffolding ────────────────────────────────────────────────

function galeraCloseModal() {
    const o = document.getElementById('galera-modal-overlay');
    if (o) o.remove();
    document.removeEventListener('keydown', galeraModalEsc);
    // If a streaming job (provision/recover) is being watched, stop watching —
    // the server-side job continues; we just release the SSE connection.
    if (galeraState.activeJobAbort) {
        try { galeraState.activeJobAbort.abort(); } catch (_) {}
        galeraState.activeJobAbort = null;
    }
}
function galeraModalEsc(e) { if (e.key === 'Escape') galeraCloseModal(); }

function galeraOpenModal(title, innerHtml, widthPx) {
    galeraCloseModal();
    const overlay = document.createElement('div');
    overlay.id = 'galera-modal-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.6);backdrop-filter:blur(4px);z-index:100000;display:flex;align-items:flex-start;justify-content:center;padding:5vh 16px;overflow-y:auto;';
    overlay.onclick = e => { if (e.target === overlay) galeraCloseModal(); };
    const modal = document.createElement('div');
    modal.style.cssText = `background:var(--bg-card,#1e2028);border:1px solid var(--border-color,#2d2f3a);border-radius:12px;padding:22px 24px;max-width:${widthPx || 560}px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,0.5);color:var(--text-primary,#e4e4e7);font-family:inherit;`;
    modal.innerHTML = `<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;">
            <div style="font-size:15px;font-weight:600;color:var(--accent-light,#60a5fa);">${escapeHtml(title)}</div>
            <button onclick="galeraCloseModal()" style="background:none;border:none;color:var(--text-muted);font-size:20px;cursor:pointer;line-height:1;">×</button>
        </div>${innerHtml}`;
    overlay.appendChild(modal);
    (document.fullscreenElement || document.body).appendChild(overlay);
    document.addEventListener('keydown', galeraModalEsc);
    return modal;
}

// Self if it's in this cluster, else the first cluster host — the node that
// will store/serve a newly-adopted cluster's definition.
function galeraPrimaryHost() {
    const hosts = galeraClusterNodes();
    const self = hosts.find(h => h.is_self);
    return self ? self.id : (hosts[0] ? hosts[0].id : '');
}

// ── Create (provision) wizard ────────────────────────────────────────

// Host <option> list for the create wizard. Values are the STABLE self_id
// (falling back to the local key for the self node, whose key already is its
// self_id) so per-node placement resolves on whichever host orchestrates.
function galeraCreateHostOptions(selected) {
    return galeraClusterNodes().map(n => {
        const val = n.self_id || n.id;
        const sel = (selected && selected === val) ? ' selected' : '';
        return `<option value="${escapeAttr(val)}"${sel}>${escapeHtml(n.hostname || n.id)}${n.is_self ? ' (this host)' : ''}</option>`;
    }).join('') || `<option value="">no hosts in this cluster</option>`;
}

let _gcNodeRow = 0;
function galeraCreateAddRow(name) {
    const w = document.getElementById('gc-rows'); if (!w) return;
    const idx = _gcNodeRow++;
    // New rows default their host to the current home host.
    const home = (document.getElementById('gc-host') || {}).value || '';
    w.insertAdjacentHTML('beforeend', `<div class="gc-node-row" data-idx="${idx}" style="display:flex;gap:8px;margin-bottom:6px;align-items:center;">
        <input class="form-control gc-cname" value="${escapeAttr(name || '')}" placeholder="container name" style="font-size:12px;flex:1;">
        <select class="form-control gc-chost" title="Host this node runs on (build here, migrate later if you like)" style="font-size:12px;flex:1;">${galeraCreateHostOptions(home)}</select>
        <button class="btn btn-sm" onclick="galeraCreateRemoveRow(${idx})" title="Remove" style="padding:4px 10px;">×</button>
    </div>`);
}
function galeraCreateRemoveRow(idx) {
    const r = document.querySelector(`.gc-node-row[data-idx="${idx}"]`); if (r) r.remove();
}

function galeraCreateOpen() {
    _gcNodeRow = 0;
    const html = `
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;font-size:13px;">
            <label style="grid-column:1/-1;">Cluster name
                <input id="gc-name" class="form-control" placeholder="my-galera" style="margin-top:4px;">
            </label>
            <label>Home host <span style="color:var(--text-muted);font-weight:400;font-size:11px;">(stores + orchestrates)</span>
                <select id="gc-host" class="form-control" style="margin-top:4px;">${galeraCreateHostOptions(galeraPrimaryHost())}</select>
            </label>
            <label>Distribution
                <select id="gc-distro" class="form-control" style="margin-top:4px;" onchange="galeraDistroChanged()">
                    <option value="debian">Debian</option>
                    <option value="ubuntu">Ubuntu</option>
                    <option value="rocky">Rocky / RHEL</option>
                    <option value="alpine">Alpine</option>
                </select>
            </label>
            <label>Release
                <input id="gc-release" class="form-control" value="bookworm" style="margin-top:4px;">
            </label>
            <label>SST method
                <select id="gc-sst" class="form-control" style="margin-top:4px;">
                    <option value="mariabackup">mariabackup (recommended)</option>
                    <option value="rsync">rsync</option>
                </select>
            </label>
            <label>Root DB password
                <input id="gc-pw" type="password" class="form-control" style="margin-top:4px;" autocomplete="new-password">
            </label>
        </div>
        <div style="margin-top:12px;">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                <span style="font-size:12px;color:var(--text-muted);">Nodes — name each and pick the host it runs on</span>
                <button class="btn btn-sm" onclick="galeraCreateAddRow()" style="padding:2px 10px;">+ Add node</button>
            </div>
            <div id="gc-rows"></div>
        </div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:10px;line-height:1.5;">
            Each node is built as an LXC container on its chosen host (spread them across hosts for hardware HA), wired onto WolfNet, installed with MariaDB + Galera; the first is bootstrapped and the rest join by SST. The cluster definition lives on the home host.
        </div>
        <div id="gc-error" role="alert" style="display:none;color:var(--danger);font-size:12px;margin-top:10px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px;">
            <button class="btn btn-sm" onclick="galeraCloseModal()">Cancel</button>
            <button class="btn btn-primary btn-sm" onclick="galeraCreateSubmit()">Build cluster</button>
        </div>`;
    galeraOpenModal('New Galera cluster in ' + galeraState.cluster, html, 580);
    galeraCreateAddRow('galera-1');
    galeraCreateAddRow('galera-2');
    galeraCreateAddRow('galera-3');
}

// Default the release box to a sensible value when the distro changes.
function galeraDistroChanged() {
    const d = (document.getElementById('gc-distro') || {}).value;
    const rel = { debian: 'bookworm', ubuntu: 'noble', rocky: '9', alpine: '3.20' }[d] || '';
    const relEl = document.getElementById('gc-release');
    if (relEl) relEl.value = rel;
}

function galeraCreateSubmit() {
    const name = (document.getElementById('gc-name').value || '').trim();
    const host = document.getElementById('gc-host').value;
    const distro = document.getElementById('gc-distro').value;
    const release = (document.getElementById('gc-release').value || '').trim();
    const sst = document.getElementById('gc-sst').value;
    const pw = document.getElementById('gc-pw').value || '';
    const err = document.getElementById('gc-error');
    const fail = m => { if (err) { err.textContent = m; err.style.display = 'block'; } };
    const nameOk = /^[A-Za-z0-9._-]+$/;
    // Pair each node's name with the host it runs on (one .gc-node-row each).
    const names = [];
    const chosts = [];
    document.querySelectorAll('.gc-node-row').forEach(row => {
        const nm = (row.querySelector('.gc-cname')?.value || '').trim();
        if (!nm) return;
        names.push(nm);
        chosts.push((row.querySelector('.gc-chost')?.value || '').trim());
    });
    if (!name) return fail('Cluster name is required.');
    if (!nameOk.test(name)) return fail('Cluster name may only contain letters, digits, - _ .');
    if (!host) return fail('Pick a home host.');
    if (names.length < 1 || names.length > 9) return fail('A cluster needs between 1 and 9 nodes.');
    for (const n of names) if (!nameOk.test(n)) return fail(`Container name "${n}" may only contain letters, digits, - _ .`);
    if (new Set(names).size !== names.length) return fail('Container names must be unique.');
    if (chosts.some(h => !h)) return fail('Every node needs a host.');
    if (!release) return fail('Release is required.');
    if (!pw) return fail('A root password is required.');
    const body = {
        cluster_name: name, cluster: galeraState.cluster, container_names: names, container_hosts: chosts, node_count: names.length,
        distribution: distro, release: release, root_password: pw, sst_method: sst, node_id: host,
    };
    galeraCloseModal();
    const spread = new Set(chosts).size;
    galeraStreamJob('Building “' + name + '”' + (spread > 1 ? ' across ' + spread + ' hosts' : ''), galeraNodeBase(host, 'provision'), body);
}

// ── Add nodes to an existing cluster ─────────────────────────────────

let _ganRow = 0;
function galeraAddNodeRow(name) {
    const w = document.getElementById('gan-rows'); if (!w) return;
    const idx = _ganRow++;
    w.insertAdjacentHTML('beforeend', `<div class="gan-node-row" data-idx="${idx}" style="display:flex;gap:8px;margin-bottom:6px;align-items:center;">
        <input class="form-control gan-cname" value="${escapeAttr(name || '')}" placeholder="container name" style="font-size:12px;">
        <button class="btn btn-sm" onclick="galeraAddNodeRemoveRow(${idx})" title="Remove" style="padding:4px 10px;">×</button>
    </div>`);
}
function galeraAddNodeRemoveRow(idx) { const r = document.querySelector(`.gan-node-row[data-idx="${idx}"]`); if (r) r.remove(); }

function galeraAddNodesOpen(cid) {
    const c = (galeraState.clusters || []).find(x => x.id === cid);
    if (!c) return;
    _ganRow = 0;
    const ownerHost = galeraHostName(galeraClusterOwner(c));
    const existing = (c.nodes || []).length;
    const html = `
        <input type="hidden" id="gan-cid" value="${escapeAttr(cid)}">
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;">
            New nodes are built on <b>${escapeHtml(ownerHost)}</b> (this cluster's home host), installed, then joined to
            <b>${escapeHtml(c.name)}</b> by SST — each copies the full dataset from a synced member. To place a node on
            different hardware, build it here then migrate the container. Cluster has ${existing} node${existing === 1 ? '' : 's'} now (max 9).
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;font-size:13px;">
            <label>Distribution
                <select id="gan-distro" class="form-control" style="margin-top:4px;" onchange="galeraAddNodeDistroChanged()">
                    <option value="debian">Debian</option>
                    <option value="ubuntu">Ubuntu</option>
                    <option value="rocky">Rocky / RHEL</option>
                    <option value="alpine">Alpine</option>
                </select>
            </label>
            <label>Release
                <input id="gan-release" class="form-control" value="bookworm" style="margin-top:4px;">
            </label>
        </div>
        <div style="margin-top:12px;">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                <span style="font-size:12px;color:var(--text-muted);">New containers to add</span>
                <button class="btn btn-sm" onclick="galeraAddNodeRow()" style="padding:2px 10px;">+ Add node</button>
            </div>
            <div id="gan-rows"></div>
        </div>
        <div id="gan-error" role="alert" style="display:none;color:var(--danger);font-size:12px;margin-top:10px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px;">
            <button class="btn btn-sm" onclick="galeraCloseModal()">Cancel</button>
            <button class="btn btn-primary btn-sm" onclick="galeraAddNodesSubmit()">Add to cluster</button>
        </div>`;
    galeraOpenModal('Add nodes to ' + c.name, html, 560);
    galeraAddNodeRow('galera-' + (existing + 1));
}

function galeraAddNodeDistroChanged() {
    const d = (document.getElementById('gan-distro') || {}).value;
    const rel = { debian: 'bookworm', ubuntu: 'noble', rocky: '9', alpine: '3.20' }[d] || '';
    const el = document.getElementById('gan-release'); if (el) el.value = rel;
}

function galeraAddNodesSubmit() {
    const cid = (document.getElementById('gan-cid') || {}).value || '';
    const c = (galeraState.clusters || []).find(x => x.id === cid);
    const err = document.getElementById('gan-error');
    const fail = m => { if (err) { err.textContent = m; err.style.display = 'block'; } };
    if (!c) return fail('Cluster not found — refresh and retry.');
    const distro = document.getElementById('gan-distro').value;
    const release = (document.getElementById('gan-release').value || '').trim();
    const nameOk = /^[A-Za-z0-9._-]+$/;
    const names = [];
    document.querySelectorAll('.gan-cname').forEach(i => { const v = (i.value || '').trim(); if (v) names.push(v); });
    if (!names.length) return fail('Name at least one new node.');
    for (const n of names) if (!nameOk.test(n)) return fail(`Container name "${n}" may only contain letters, digits, - _ .`);
    if (new Set(names).size !== names.length) return fail('New container names must be unique.');
    const existingNames = new Set([...(c.nodes || []).map(n => n.container), ...(c.proxies || []).map(x => x.container)]);
    for (const n of names) if (existingNames.has(n)) return fail(`"${n}" already exists in this cluster.`);
    if ((c.nodes || []).length + names.length > 9) return fail('A cluster is capped at 9 nodes.');
    if (!release) return fail('Release is required.');
    galeraCloseModal();
    galeraStreamJob('Adding nodes to “' + c.name + '”', galeraOwnerBase(cid, 'clusters/' + encodeURIComponent(cid) + '/add-nodes'),
        { container_names: names, distribution: distro, release: release });
}

// ── Provision a MaxScale proxy ───────────────────────────────────────

function galeraMaxScaleOpen(cid) {
    const c = (galeraState.clusters || []).find(x => x.id === cid);
    if (!c) return;
    const ownerHost = galeraHostName(galeraClusterOwner(c));
    const members = (c.nodes || []).length;
    const suggested = (c.name || 'galera').replace(/[^A-Za-z0-9._-]/g, '-') + '-maxscale';
    const html = `
        <input type="hidden" id="gmx-cid" value="${escapeAttr(cid)}">
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;">
            Builds a MaxScale proxy container on <b>${escapeHtml(ownerHost)}</b>, pre-configured for <b>${escapeHtml(c.name)}</b>:
            a galeramon monitor over all ${members} member${members === 1 ? '' : 's'} and a read/write-split router. Apps point at
            the proxy; writes go to the elected primary, reads spread across the synced members.
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;font-size:13px;">
            <label style="grid-column:1/-1;">Proxy container name
                <input id="gmx-name" class="form-control" value="${escapeAttr(suggested)}" style="margin-top:4px;">
            </label>
            <label>Distribution
                <select id="gmx-distro" class="form-control" style="margin-top:4px;" onchange="galeraMaxScaleDistroChanged()">
                    <option value="debian">Debian</option>
                    <option value="ubuntu">Ubuntu</option>
                    <option value="rocky">Rocky / RHEL</option>
                </select>
            </label>
            <label>Release
                <input id="gmx-release" class="form-control" value="bookworm" style="margin-top:4px;">
            </label>
            <label>MaxScale's own DB user <span style="color:var(--text-muted);font-weight:400;">(internal)</span>
                <input id="gmx-user" class="form-control" value="maxscale" style="margin-top:4px;">
            </label>
            <label>…and its password
                <input id="gmx-pw" type="password" class="form-control" style="margin-top:4px;" autocomplete="new-password">
            </label>
            <label>Listener port
                <input id="gmx-port" type="number" class="form-control" value="3306" min="1" max="65535" style="margin-top:4px;">
            </label>
        </div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:10px;line-height:1.5;">
            MaxScale only ships for Debian/Ubuntu and RHEL/Rocky bases. <b>This user/password is MaxScale's own internal account</b>
            (it monitors the cluster + reads the user table) — <b>not</b> the login you use day-to-day. Once it's up, connect your
            apps to the proxy with <b>root</b> (the cluster password) or your own app users — over TCP, e.g.
            <code style="font-family:var(--font-mono,monospace);">mariadb -h PROXY_IP -P 3306 -u root -p</code>. Password chars: letters, digits and . _ - @ % + = ! ~
        </div>
        <div id="gmx-error" role="alert" style="display:none;color:var(--danger);font-size:12px;margin-top:10px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px;">
            <button class="btn btn-sm" onclick="galeraCloseModal()">Cancel</button>
            <button class="btn btn-primary btn-sm" onclick="galeraMaxScaleSubmit()">Create MaxScale</button>
        </div>`;
    galeraOpenModal('Create MaxScale proxy for ' + c.name, html, 580);
}

function galeraMaxScaleDistroChanged() {
    const d = (document.getElementById('gmx-distro') || {}).value;
    const rel = { debian: 'bookworm', ubuntu: 'noble', rocky: '9' }[d] || '';
    const el = document.getElementById('gmx-release'); if (el) el.value = rel;
}

function galeraMaxScaleSubmit() {
    const cid = (document.getElementById('gmx-cid') || {}).value || '';
    const c = (galeraState.clusters || []).find(x => x.id === cid);
    const err = document.getElementById('gmx-error');
    const fail = m => { if (err) { err.textContent = m; err.style.display = 'block'; } };
    if (!c) return fail('Cluster not found — refresh and retry.');
    const name = (document.getElementById('gmx-name').value || '').trim();
    const distro = document.getElementById('gmx-distro').value;
    const release = (document.getElementById('gmx-release').value || '').trim();
    const user = (document.getElementById('gmx-user').value || 'maxscale').trim();
    const pw = document.getElementById('gmx-pw').value || '';
    const port = parseInt(document.getElementById('gmx-port').value, 10);
    const nameOk = /^[A-Za-z0-9._-]+$/;
    const pwOk = /^[A-Za-z0-9._@%+=!~-]{1,128}$/;
    if (!nameOk.test(name)) return fail('Proxy container name may only contain letters, digits, - _ .');
    if ((c.nodes || []).some(n => n.container === name) || (c.proxies || []).some(x => x.container === name)) return fail('That name already exists in this cluster.');
    if (!nameOk.test(user)) return fail('Proxy user may only contain letters, digits, - _ .');
    if (!pwOk.test(pw)) return fail('Password must be 1–128 chars from letters, digits and . _ - @ % + = ! ~');
    if (!release) return fail('Release is required.');
    if (!(port >= 1 && port <= 65535)) return fail('Listener port must be 1–65535.');
    galeraCloseModal();
    galeraStreamJob('Creating MaxScale for “' + c.name + '”', galeraOwnerBase(cid, 'clusters/' + encodeURIComponent(cid) + '/maxscale'),
        { container_name: name, distribution: distro, release: release, proxy_user: user, proxy_password: pw, listener_port: port });
}

async function galeraRemoveProxy(cid, container) {
    if (!container) return;
    const ok = await showConfirm(
        `Remove MaxScale proxy “${container}”?\n\nThis stops MaxScale and removes it from WolfStack. The container is left stopped — delete it from the Containers view if you no longer need it. The cluster and its data are untouched.`,
        'Remove proxy');
    if (!ok) return;
    try {
        const r = await fetch(galeraOwnerBase(cid, 'clusters/' + encodeURIComponent(cid) + '/proxies/' + encodeURIComponent(container)), { method: 'DELETE' });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        showToast('Proxy removed', 'success');
        galeraLoadClusters();
    } catch (e) {
        showToast('Remove failed: ' + ((e && e.message) || e), 'error', 0);
    }
}

// ── Adopt from a container picker ────────────────────────────────────

let _galeraAdoptInv = [];
function galeraAdoptOpen() {
    _galeraAdoptInv = [];
    const html = `
        <div style="font-size:13px;display:grid;gap:10px;">
            <label>Cluster name (wsrep_cluster_name)
                <input id="ga-name" class="form-control" placeholder="my-galera" style="margin-top:4px;">
            </label>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
                <label>DB user <input id="ga-user" class="form-control" value="root" style="margin-top:4px;"></label>
                <label>DB password <input id="ga-pw" type="password" class="form-control" style="margin-top:4px;" autocomplete="new-password"></label>
            </div>
            <div>
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                    <span style="font-size:12px;color:var(--text-muted);">Pick the MariaDB containers to adopt</span>
                    <button class="btn btn-sm" onclick="galeraAdoptLoadInventory()" style="padding:2px 10px;">↻ Refresh</button>
                </div>
                <div id="ga-picker" style="max-height:38vh;overflow:auto;border:1px solid var(--border);border-radius:8px;padding:8px;">
                    <div style="color:var(--text-muted);font-size:12px;padding:10px;">Loading containers…</div>
                </div>
            </div>
        </div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:10px;line-height:1.5;">
            WolfStack resolves each container's address on its host — no typing IPs. Docker nodes get status + start/stop/restart; automated recovery is LXC-only.
        </div>
        <div id="ga-error" role="alert" style="display:none;color:var(--danger);font-size:12px;margin-top:10px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px;">
            <button class="btn btn-sm" onclick="galeraCloseModal()">Cancel</button>
            <button class="btn btn-primary btn-sm" onclick="galeraAdoptSubmit()">Adopt selected</button>
        </div>`;
    galeraOpenModal('Adopt into a Galera cluster — ' + galeraState.cluster, html, 640);
    galeraAdoptLoadInventory();
}

async function galeraAdoptLoadInventory() {
    const picker = document.getElementById('ga-picker');
    if (picker) picker.innerHTML = `<div style="color:var(--text-muted);font-size:12px;padding:10px;">Loading containers…</div>`;
    const hosts = galeraClusterNodes();
    try {
        const results = await Promise.all(hosts.map(h =>
            fetch('/api/control-panel/inventory/node/' + encodeURIComponent(h.id))
                .then(r => (r.ok ? r.json() : { items: [] }))
                .catch(() => ({ items: [] }))
        ));
        const inv = [];
        results.forEach(d => (d.items || []).forEach(it => {
            if (it.kind === 'lxc' || it.kind === 'docker') inv.push(it);
        }));
        _galeraAdoptInv = inv;
        galeraAdoptRenderPicker();
    } catch (e) {
        if (picker) picker.innerHTML = `<div role="alert" style="color:var(--danger);font-size:12px;padding:10px;">Couldn't load containers: ${escapeHtml((e && e.message) || String(e))}</div>`;
    }
}

function galeraAdoptRenderPicker() {
    const picker = document.getElementById('ga-picker');
    if (!picker) return;
    if (!_galeraAdoptInv.length) {
        picker.innerHTML = `<div style="color:var(--text-muted);font-size:12px;padding:10px;">No LXC or Docker containers found in this cluster.</div>`;
        return;
    }
    const byHost = {};
    _galeraAdoptInv.forEach((it, i) => { (byHost[it.node_id] = byHost[it.node_id] || []).push({ it, i }); });
    let html = '';
    Object.keys(byHost).forEach(hostId => {
        html += `<div style="font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:.4px;margin:6px 0 4px;">${escapeHtml(galeraHostName(hostId))}</div>`;
        byHost[hostId].forEach(({ it, i }) => {
            const kindColor = it.kind === 'docker' ? '#3b82f6' : '#22c55e';
            const running = (it.status || '').toLowerCase() === 'running';
            html += `<label style="display:flex;align-items:center;gap:8px;padding:5px 6px;border-radius:6px;cursor:pointer;font-size:12px;" onmouseover="this.style.background='var(--bg-card-hover,#2a2d3a)'" onmouseout="this.style.background='transparent'">
                <input type="checkbox" class="ga-pick" data-idx="${i}">
                <span style="font-family:var(--font-mono,monospace);">${escapeHtml(it.name)}</span>
                <span style="padding:0 6px;border-radius:3px;font-size:10px;font-weight:600;background:${kindColor}22;color:${kindColor};">${escapeHtml(it.kind)}</span>
                <span style="margin-left:auto;font-size:10px;color:${running ? '#22c55e' : 'var(--text-muted)'};">${escapeHtml(it.status || '')}</span>
            </label>`;
        });
    });
    picker.innerHTML = html;
}

async function galeraAdoptSubmit() {
    const err = document.getElementById('ga-error');
    const fail = m => { if (err) { err.textContent = m; err.style.display = 'block'; } };
    const name = (document.getElementById('ga-name').value || '').trim();
    const user = (document.getElementById('ga-user').value || 'root').trim();
    const pw = document.getElementById('ga-pw').value || '';
    const nameOk = /^[A-Za-z0-9._-]+$/;
    if (!name) return fail('Cluster name is required.');
    if (!nameOk.test(name)) return fail('Cluster name may only contain letters, digits, - _ .');
    // Send each container's host as its STABLE self_id (not the browser's
    // local node-{uuid} key), so the host that runs adopt — which may not share
    // this browser's key namespace — can still resolve where each container
    // lives. self_id is the same on every host; the local key is not.
    const stableHostId = (hid) => {
        const n = (Array.isArray(allNodes) ? allNodes : []).find(x => x.id === hid || x.self_id === hid);
        return (n && n.self_id) ? n.self_id : hid;
    };
    const nodes = [];
    document.querySelectorAll('.ga-pick:checked').forEach(cb => {
        const it = _galeraAdoptInv[parseInt(cb.getAttribute('data-idx'), 10)];
        if (it) nodes.push({ node_id: stableHostId(it.node_id), container: it.name, kind: it.kind });
    });
    if (!nodes.length) return fail('Tick at least one container.');
    const payload = { cluster_name: name, cluster: galeraState.cluster, db_user: user, db_password: pw, sst_method: 'mariabackup', nodes };
    try {
        // Adopt runs on THIS (browser) node — it loaded the inventory, so it can
        // reach every picked container's host and probe-locate them. Routing to a
        // different primary host could land on one that hasn't polled some peer.
        const r = await fetch('/api/galera/adopt', {
            method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload),
        });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        showToast('Cluster adopted', 'success');
        galeraCloseModal();
        galeraLoadClusters();
    } catch (e) {
        fail((e && e.message) || String(e));
        showToast('Adopt failed', 'error', 0);
    }
}

// ── Lifecycle + recovery ─────────────────────────────────────────────

// The host whose galera.json owns a cluster's definition. Falls back to the
// first node's host for older configs written without owner_node.
function galeraClusterOwner(c) {
    return (c && c.owner_node) || (c && c.nodes && c.nodes[0] && c.nodes[0].node_id) || '';
}

// Route a cluster's ops to the host that owns its definition.
function galeraOwnerBase(clusterId, path) {
    const c = (galeraState.clusters || []).find(x => x.id === clusterId);
    return galeraNodeBase(galeraClusterOwner(c), path);
}

async function galeraNodeAction(clusterId, container, action) {
    if (action === 'stop' || action === 'restart') {
        const ok = await showConfirm(`${action === 'stop' ? 'Stop' : 'Restart'} MariaDB on “${container}”?\n\nStopping a node removes it from the cluster until it rejoins.`, `${action[0].toUpperCase() + action.slice(1)} node`);
        if (!ok) return;
    }
    try {
        const r = await fetch(galeraOwnerBase(clusterId, 'clusters/' + encodeURIComponent(clusterId) + '/nodes/' + encodeURIComponent(container) + '/' + encodeURIComponent(action)), { method: 'POST' });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        showToast(`${container}: ${action} ok`, 'success');
        setTimeout(galeraLoadClusters, 1200);
    } catch (e) {
        showToast(`${action} failed: ${(e && e.message) || e}`, 'error', 0);
    }
}

async function galeraRecover(clusterId) {
    const c = (galeraState.clusters || []).find(x => x.id === clusterId);
    const name = c ? c.name : clusterId;
    const ok = await showConfirm(
        `Recover cluster “${name}”?\n\nThis STOPS MariaDB on every node, reads each node's last-committed position, then bootstraps the most up-to-date one and rejoins the rest. There will be a brief outage. WolfStack refuses to act if no node reports a known position.`,
        'Recover cluster');
    if (!ok) return;
    galeraStreamJob('Recovering “' + name + '”', galeraOwnerBase(clusterId, 'clusters/' + encodeURIComponent(clusterId) + '/recover'), {});
}

async function galeraDelete(clusterId) {
    const c = (galeraState.clusters || []).find(x => x.id === clusterId);
    const name = c ? c.name : clusterId;
    const ok = await showConfirm(`Forget cluster “${name}”?\n\nThis only removes it from WolfStack — the containers and their data are left untouched.`, 'Forget cluster');
    if (!ok) return;
    try {
        const r = await fetch(galeraOwnerBase(clusterId, 'clusters/' + encodeURIComponent(clusterId)), { method: 'DELETE' });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        showToast('Cluster forgotten', 'success');
        galeraLoadClusters();
    } catch (e) {
        showToast('Forget failed: ' + ((e && e.message) || e), 'error', 0);
    }
}

/// Shared SSE-streaming job modal (provision + recover). POSTs `body` to `url`,
/// streams `data:` lines into a live log, and resolves on RESULT:OK/ERR.
async function galeraStreamJob(title, url, body) {
    const modal = galeraOpenModal(title, `
        <pre id="galera-job-log" role="log" aria-live="polite" style="background:var(--bg-input,#0d0f14);border:1px solid var(--border);border-radius:8px;padding:12px;font-size:12px;line-height:1.5;max-height:50vh;overflow:auto;white-space:pre-wrap;word-break:break-word;margin:0;">Starting…</pre>
        <div id="galera-job-result" style="margin-top:12px;font-size:13px;"></div>
        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:14px;">
            <button id="galera-job-close" class="btn btn-sm" onclick="galeraCloseModal()" disabled>Close</button>
        </div>`, 640);
    const log = modal.querySelector('#galera-job-log');
    const resultEl = modal.querySelector('#galera-job-result');
    const closeBtn = modal.querySelector('#galera-job-close');
    const append = line => {
        if (!log) return;
        if (log.textContent === 'Starting…') log.textContent = '';
        log.textContent += (log.textContent ? '\n' : '') + line;
        log.scrollTop = log.scrollHeight;
    };
    // Abortable so closing the modal releases the SSE connection (the job
    // itself continues server-side). galeraCloseModal() calls .abort().
    const ctrl = new AbortController();
    galeraState.activeJobAbort = ctrl;
    let ok = null, finalMsg = '', aborted = false;
    try {
        const resp = await fetch(url, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body), signal: ctrl.signal,
        });
        if (!resp.ok && (resp.headers.get('content-type') || '').includes('application/json')) {
            const d = await resp.json();
            throw new Error(d.error || ('HTTP ' + resp.status));
        }
        if (!resp.body) throw new Error('HTTP ' + resp.status + ' (no response body)');
        const reader = resp.body.getReader();
        const dec = new TextDecoder();
        let buf = '';
        for (;;) {
            const { done, value } = await reader.read();
            if (done) break;
            buf += dec.decode(value, { stream: true });
            const lines = buf.split('\n'); buf = lines.pop();
            for (const line of lines) {
                if (!line.startsWith('data: ')) continue;
                const msg = line.slice(6);
                if (msg.startsWith('RESULT:OK:')) { ok = true; finalMsg = msg.slice(10); }
                else if (msg.startsWith('RESULT:ERR:')) { ok = false; finalMsg = msg.slice(11); }
                else append(msg);
            }
        }
    } catch (e) {
        if (ctrl.signal.aborted) { aborted = true; } // user closed the modal
        else { ok = false; finalMsg = (e && e.message) || String(e); }
    }
    if (galeraState.activeJobAbort === ctrl) galeraState.activeJobAbort = null;
    if (!aborted && resultEl) {
        if (ok === true) {
            resultEl.innerHTML = `<div style="color:var(--success);">✅ ${escapeHtml(finalMsg || 'Done')}</div>`;
            showToast('Galera: ' + (finalMsg || 'done'), 'success');
        } else {
            resultEl.innerHTML = `<div role="alert" style="color:var(--danger);">❌ ${escapeHtml(finalMsg || 'Failed')}</div>`;
            showToast('Galera job failed', 'error', 0);
        }
    }
    if (closeBtn) closeBtn.disabled = false;
    galeraLoadClusters();
}

// ── Tuning analyzer ──────────────────────────────────────────────────

function galeraFmtBytes(b) {
    if (!b) return '?';
    const G = 1 << 30, M = 1 << 20;
    if (b >= G) return (b / G).toFixed(1) + 'G';
    if (b >= M) return Math.round(b / M) + 'M';
    if (b >= 1024) return Math.round(b / 1024) + 'K';
    return b + 'B';
}

async function galeraAnalyze(clusterId) {
    const c = (galeraState.clusters || []).find(x => x.id === clusterId);
    const name = c ? c.name : clusterId;
    galeraState.analyzeId = clusterId;
    galeraOpenModal('Tuning analysis — ' + name,
        '<div id="galera-analyze-body"><div style="color:var(--text-muted);padding:24px;text-align:center;">Analysing nodes…</div></div>', 720);
    try {
        const r = await fetch(galeraOwnerBase(clusterId, 'clusters/' + encodeURIComponent(clusterId) + '/analyze'));
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        galeraRenderAnalysis(d);
    } catch (e) {
        const b = document.getElementById('galera-analyze-body');
        if (b) b.innerHTML = `<div role="alert" style="color:var(--danger);padding:16px;">Analysis failed: ${escapeHtml((e && e.message) || String(e))}</div>`;
    }
}

function galeraRenderAnalysis(a) {
    const b = document.getElementById('galera-analyze-body');
    if (!b) return;
    if (!a.nodes || !a.nodes.length) { b.innerHTML = '<div style="padding:16px;color:var(--text-muted);">No nodes.</div>'; return; }
    const sevColor = { ok: '#22c55e', improve: '#f59e0b', warn: '#ef4444' };
    let html = '';
    a.nodes.forEach(n => {
        html += `<div style="margin-bottom:14px;">
            <div style="font-weight:600;font-size:13px;margin-bottom:6px;">${escapeHtml(n.container)}
                <span style="font-weight:400;color:var(--text-muted);font-size:11px;">${n.reachable ? (galeraFmtBytes(n.ram_bytes) + ' RAM · ' + escapeHtml(String(n.cores)) + ' cores') : 'unreachable'}</span>
            </div>`;
        if (!n.reachable) { html += `<div style="font-size:12px;color:var(--text-muted);padding:2px 0;">${escapeHtml(n.error || 'unreachable')}</div></div>`; return; }
        const recs = n.recommendations || [];
        const actionable = recs.filter(r => r.severity !== 'ok');
        if (!actionable.length) { html += `<div style="font-size:12px;color:#22c55e;">All checked settings look good. ✓</div></div>`; return; }
        actionable.forEach(rec => {
            const col = sevColor[rec.severity] || '#9ca3af';
            html += `<div style="border:1px solid var(--border);border-radius:6px;padding:8px 10px;margin-bottom:6px;">
                <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
                    <span style="width:8px;height:8px;border-radius:50%;background:${col};display:inline-block;flex-shrink:0;"></span>
                    <code style="font-size:12px;">${escapeHtml(rec.key)}</code>
                    <span style="font-size:11px;color:var(--text-muted);">${escapeHtml(rec.current_display)} → <b style="color:${col};">${escapeHtml(rec.recommended_display)}</b></span>
                    ${rec.dynamic ? '' : '<span style="font-size:10px;color:#f59e0b;" title="needs a node restart">restart</span>'}
                    <button class="btn btn-sm galera-tune-btn" style="margin-left:auto;padding:2px 10px;font-size:11px;" data-galera-tune="${escapeAttr(rec.key)}" data-val="${escapeAttr(rec.recommended)}">Apply</button>
                </div>
                <div style="font-size:11px;color:var(--text-muted);margin-top:4px;line-height:1.4;">${escapeHtml(rec.why)}</div>
            </div>`;
        });
        html += `</div>`;
    });
    html += `<div style="font-size:11px;color:var(--text-muted);margin-top:6px;line-height:1.5;">Apply sets the value live on every reachable node and writes it to a managed config include so it persists. <b>restart</b> settings are written to config only — restart the node to take effect.</div>`;
    b.innerHTML = html;
    b.querySelectorAll('.galera-tune-btn').forEach(btn => {
        btn.addEventListener('click', () => galeraApplyTuning(galeraState.analyzeId, btn.getAttribute('data-galera-tune'), btn.getAttribute('data-val'), btn));
    });
}

async function galeraApplyTuning(clusterId, key, value, btn) {
    if (btn) { btn.disabled = true; btn.textContent = 'Applying…'; }
    try {
        const r = await fetch(galeraOwnerBase(clusterId, 'clusters/' + encodeURIComponent(clusterId) + '/tune'), {
            method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ key, value }),
        });
        const d = await r.json().catch(() => ({}));
        if (!r.ok || d.error) throw new Error(d.error || ('HTTP ' + r.status));
        const issues = (d.nodes || []).filter(n => n.applied_live === false || n.persisted === false);
        if (issues.length) showToast(`${key}: applied with ${issues.length} node issue(s) — see analysis`, 'warning', 0);
        else showToast(`${key} → ${value}` + (d.requires_restart ? ' — written to config; restart nodes to take effect' : ''), 'success');
        // Re-analyse for dynamic settings (the runtime value changed). For
        // restart-required ones the runtime value is unchanged, so re-analysing
        // would just re-show the same recommendation — mark the row instead.
        if (d.requires_restart) {
            if (btn) { btn.textContent = 'Restart pending'; btn.disabled = true; btn.style.color = 'var(--text-muted)'; }
        } else {
            galeraAnalyze(clusterId);
        }
    } catch (e) {
        showToast('Apply failed: ' + ((e && e.message) || e), 'error', 0);
        if (btn) { btn.disabled = false; btn.textContent = 'Apply'; }
    }
}

